// Trust the first proxy hop (Cloudflare, nginx, Railway, etc.) so that
// req.ip returns the real client IP instead of the proxy's IP.  Without
// this, rate limiting treats ALL users as a single IP behind any reverse
// proxy — effectively blocking legitimate traffic after one user hits
// the limit.  Also fixes req.protocol and req.secure for HTTPS detection.
if (process.env.TRUST_PROXY) {
  app.set('trust proxy', isNaN(process.env.TRUST_PROXY)
    ? process.env.TRUST_PROXY      // string values like 'loopback', 'linklocal', etc.
    : parseInt(process.env.TRUST_PROXY, 10));   // numeric hop count
} else if (process.env.NODE_ENV === 'production') {
  app.set('trust proxy', 1);       // sensible default: trust one proxy hop
}

