const INBOX_PATH = process.env.INBOX_PATH || path.join(__dirname, '..', 'Teams inbox:Result');
const OUTBOX_PATH = process.env.OUTBOX_PATH || path.join(__dirname, '..', "Stew's inbox:Owner");

let db;
function openDatabase(dbPath) {
  const d = new Database(dbPath, { fileMustExist: false });
  d.pragma('journal_mode = WAL');
  d.pragma('foreign_keys = ON');
  d.pragma(`busy_timeout = ${parseInt(process.env.DB_BUSY_TIMEOUT || '5000', 10)}`);
  d.pragma('synchronous = NORMAL');
  d.pragma(`cache_size = ${parseInt(process.env.DB_CACHE_SIZE || '-65536', 10)}`);
  d.pragma('temp_store = MEMORY');
  d.pragma(`mmap_size = ${parseInt(process.env.DB_MMAP_SIZE || '268435456', 10)}`);
  return d;
}

try {
  db = openDatabase(DB_PATH);
} catch (err) {
  console.error('Failed to open database:', err.message);

  // AUTO-RECOVERY: If DB is corrupted, try to restore from latest backup
  console.warn('[Recovery] Attempting auto-recovery from backup...');
  const backupDir = process.env.BACKUP_DIR || path.join(path.dirname(DB_PATH), 'backups');
  try {
    const backups = fs.readdirSync(backupDir)
      .filter(f => f.startsWith('the_team_') && f.endsWith('.db'))
      .sort()
      .reverse(); // newest first

    let recovered = false;
    for (const backup of backups) {
      const backupPath = path.join(backupDir, backup);
      console.warn(`[Recovery] Trying backup: ${backup}...`);
      try {
        // Remove corrupted DB and WAL/SHM files
        try { fs.unlinkSync(DB_PATH); } catch (_) {}
        try { fs.unlinkSync(DB_PATH + '-wal'); } catch (_) {}
        try { fs.unlinkSync(DB_PATH + '-shm'); } catch (_) {}

        // Copy backup to main DB location
        fs.copyFileSync(backupPath, DB_PATH);

        // Try to open it
        db = openDatabase(DB_PATH);
        const check = db.pragma('integrity_check');
        if (check && check[0] && check[0].integrity_check === 'ok') {
          console.warn(`[Recovery] SUCCESS — restored from ${backup}`);
          recovered = true;
          break;
        } else {
          console.warn(`[Recovery] Backup ${backup} failed integrity check, trying next...`);
          try { db.close(); } catch (_) {}
        }
      } catch (restoreErr) {
        console.warn(`[Recovery] Backup ${backup} failed: ${restoreErr.message}`);
      }
    }

    if (!recovered) {
      console.error('[Recovery] All backups failed. Cannot start server.');
      process.exit(1);
    }
  } catch (recoveryErr) {
    console.error(`[Recovery] Auto-recovery failed: ${recoveryErr.message}`);
    process.exit(1);
  }
}

// ── Prepared Statement Cache ──────────────────────────────────
// better-sqlite3's db.prepare() parses and compiles SQL on every call.
// With 1700+ inline prepare() calls, hot endpoints re-parse the same SQL
// on every request. This cache ensures each unique SQL string is parsed
// only once for the lifetime of the process.
const _stmtCache = new Map();
function stmt(sql) {
  let s = _stmtCache.get(sql);
  if (!s) {
    s = db.prepare(sql);
    _stmtCache.set(sql, s);
  }
  return s;
}

// ── In-Memory Cache (team_members & system_settings) ─────────
// Short-lived TTL cache for the two most-read, least-written tables.
// Eliminates repeated DB round-trips on hot paths (isLocalMode, roster
// lookups, settings checks) without requiring explicit invalidation on
// every write path.  Stale data is bounded by the TTL values below.
const _memCache = {
  team_members:   { data: null, expiresAt: 0 },
  system_settings: { data: null, expiresAt: 0 },
};
const CACHE_TTL_MS = {
  team_members:    parseInt(process.env.CACHE_TTL_TEAM_MEMBERS_MS    || '30000', 10),  // default 30 s
  system_settings: parseInt(process.env.CACHE_TTL_SETTINGS_MS        || '10000', 10),  // default 10 s
};

/** Force-expire a cache entry so the next read hits the DB. */
function invalidateCache(table) {
  if (_memCache[table]) _memCache[table].expiresAt = 0;
}

/**
 * Returns all system_settings rows as a Map<key, value>.
 * The map is rebuilt from the DB once per TTL window.
 */
function getCachedSettings() {
  const entry = _memCache.system_settings;
  if (Date.now() < entry.expiresAt) return entry.data;
  try {
    const rows = stmt('SELECT key, value FROM system_settings').all();
    entry.data = new Map(rows.map(r => [r.key, r.value]));
    entry.expiresAt = Date.now() + CACHE_TTL_MS.system_settings;
  } catch (_) {
    entry.data = entry.data || new Map();
  }
  return entry.data;
}

/** Returns the value for a single system_settings key, or null. */
function getCachedSetting(key) {
  return getCachedSettings().get(key) ?? null;
}

/**
 * Returns all active team_members as a Map<id, row>.
 * The map is rebuilt from the DB once per TTL window.
 */
function getCachedTeamMembers() {
  const entry = _memCache.team_members;
  if (Date.now() < entry.expiresAt) return entry.data;
  try {
    const rows = stmt("SELECT * FROM team_members WHERE status = 'active'").all();
    entry.data = new Map(rows.map(r => [r.id, r]));
    entry.expiresAt = Date.now() + CACHE_TTL_MS.team_members;
  } catch (_) {
    entry.data = entry.data || new Map();
  }
  return entry.data;
}

/** Returns a single active team_member by id, or null. */
function getCachedMember(id) {
  return getCachedTeamMembers().get(Number(id)) ?? null;
}

