// ── Daily Auto-Backup ──────────────────────────────────────────
// Backup directory resolves (in priority order):
//   1. BACKUP_DIR environment variable  — ideal for Docker / containerized deployments
//   2. backup_dir system setting         — configurable at runtime without restart
//   3. Default: <repo-root>/backups/
const DEFAULT_BACKUP_DIR = path.join(__dirname, '..', 'backups');

function getBackupDir() {
  if (process.env.BACKUP_DIR) return process.env.BACKUP_DIR;
  try {
    const setting = getCachedSetting('backup_dir');
    if (setting && setting.trim()) return setting.trim();
  } catch (_) {}
  return DEFAULT_BACKUP_DIR;
}

function verifyBackupIntegrity(backupPath) {
  let backupDb;
  try {
    backupDb = new Database(backupPath, { readonly: true, fileMustExist: true });
    const result = backupDb.pragma('integrity_check');
    const status = result && result.length === 1 && result[0].integrity_check === 'ok' ? 'ok' : JSON.stringify(result);
    if (status !== 'ok') {
      console.error(`[Backup] Integrity check FAILED: ${path.basename(backupPath)} — ${status}`);
      try {
        db.prepare(`INSERT INTO notifications (type, title, message, read, created_at) VALUES ('system', ?, ?, 0, ?)`)
          .run('Backup Integrity Check Failed', `Daily backup ${path.basename(backupPath)} failed integrity check: ${status}`, localNow());
        broadcast('notification.new', { type: 'system', title: 'Backup Integrity Check Failed' });
      } catch(notifErr) {
        console.error(`[Backup] Failed to create integrity failure notification: ${notifErr.message}`);
      }
    }
  } catch(e) {
    console.error(`[Backup] Integrity check error for ${path.basename(backupPath)}: ${e.message}`);
    try {
      db.prepare(`INSERT INTO notifications (type, title, message, read, created_at) VALUES ('system', ?, ?, 0, ?)`)
        .run('Backup Integrity Check Error', `Could not verify backup ${path.basename(backupPath)}: ${e.message}`, new Date().toISOString());
      broadcast('notification.new', { type: 'system', title: 'Backup Integrity Check Error' });
    } catch(notifErr) {
      console.error(`[Backup] Failed to create integrity error notification: ${notifErr.message}`);
    }
  } finally {
    if (backupDb) {
      try { backupDb.close(); } catch(_) {}
    }
  }
}

function runDailyBackup() {
  const resolvedDir = getBackupDir();
  if (!fs.existsSync(resolvedDir)) {
    try { fs.mkdirSync(resolvedDir, { recursive: true }); }
    catch(e) { console.error(`[Backup] Cannot create backup directory ${resolvedDir}: ${e.message}`); return; }
  }

  const dateStr = new Date().toLocaleString('sv-SE', { timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone }).slice(0, 10);
  const backupPath = path.join(resolvedDir, `the_team_${dateStr}.db`);
  if (fs.existsSync(backupPath)) return; // already done today

  // CORRUPTION FIX: NEVER use fs.copyFileSync on a WAL-mode SQLite database.
  // It copies only the main file without the WAL, creating a corrupted snapshot.
  // Under heavy write load (35+ intervals), this is guaranteed to corrupt.
  // ONLY use db.backup() which is SQLite's native online backup API.
  try {
    // Force WAL checkpoint before backup — flush all pending writes to main DB file
    try { db.pragma('wal_checkpoint(TRUNCATE)'); } catch (cpErr) {
      console.warn(`[Backup] WAL checkpoint warning: ${cpErr.message}`);
    }

    db.backup(backupPath)
      .then(() => {
        console.log(`[Backup] Created: ${path.basename(backupPath)}`);
        try { verifyBackupIntegrity(backupPath); } catch (ve) { console.warn(`[Backup] Integrity check error: ${ve.message}`); }
        try { pruneOldBackups(resolvedDir); } catch (pe) { console.warn(`[Backup] Prune error: ${pe.message}`); }
      })
      .catch(e => {
        // db.backup() failed — DO NOT fall back to fs.copyFileSync (causes corruption)
        // Log the failure and skip this backup cycle. Next cycle will try again.
        console.error(`[Backup] SQLite backup API failed: ${e.message}. Skipping this cycle (will retry next interval). DO NOT use fs.copyFileSync on WAL databases.`);
        // Clean up partial backup file if it was created
        try { if (fs.existsSync(backupPath)) fs.unlinkSync(backupPath); } catch (_) {}
      });
  } catch(e) {
    console.error(`[Backup] Backup error: ${e.message}. Skipping this cycle.`);
  }
}

function getBackupRetentionDays() {
  const val = parseInt(process.env.BACKUP_RETENTION_DAYS || getCachedSetting('backup_retention_days') || '7', 10);
  return isNaN(val) || val < 1 ? 7 : val;
}

function pruneOldBackups(dir) {
  const targetDir = dir || getBackupDir();
  const retain = getBackupRetentionDays();
  try {
    const files = fs.readdirSync(targetDir)
      .filter(f => f.startsWith('the_team_') && f.endsWith('.db'))
      .sort();
    while (files.length > retain) {
      const old = files.shift();
      try {
        fs.unlinkSync(path.join(targetDir, old));
        console.log(`[Backup] Pruned old backup: ${old} (retention: ${retain} days)`);
      } catch (unlinkErr) {
        console.warn(`[Backup] Failed to prune ${old}: ${unlinkErr.message}`);
      }
    }
  } catch(e) {
    console.error(`[Backup] Prune error: ${e.message}`);
  }
}

// Run on startup
runDailyBackup();

// Schedule backup checks using configurable interval (default: 1 hour).
// Reads backup_interval_hours from env or system_settings so it can be
// changed at runtime without restarting the server.
function getBackupIntervalMs() {
  const val = parseFloat(process.env.BACKUP_INTERVAL_HOURS || getCachedSetting('backup_interval_hours') || '1');
  const hours = isNaN(val) || val <= 0 ? 1 : val;
  return Math.round(hours * 60 * 60 * 1000);
}

let _backupIntervalId = setInterval(runDailyBackup, getBackupIntervalMs());

// Re-evaluate the interval every 5 minutes so setting changes take effect
// without a full server restart.
setInterval(() => {
  const newMs = getBackupIntervalMs();
  clearInterval(_backupIntervalId);
  _backupIntervalId = setInterval(runDailyBackup, newMs);
}, 5 * 60 * 1000);

// ── WAL Checkpoint Scheduler (3 AM daily) ─────────────────────
// SQLite auto-checkpoints at 1000 pages by default, which can cause brief
// latency spikes under load. Running PASSIVE checkpoint at 3 AM keeps the
// WAL file size manageable without blocking any active readers or writers.
function runWalCheckpoint() {
  try {
    const result = db.pragma('wal_checkpoint(PASSIVE)');
    const info = result && result[0] ? result[0] : {};
  } catch (e) {
    console.error(`[WAL] Checkpoint error: ${e.message}`);
  }
}

function scheduleWalCheckpoint() {
  const now = new Date();
  const next3am = new Date(now);
  next3am.setHours(3, 0, 0, 0);
  if (next3am <= now) next3am.setDate(next3am.getDate() + 1);
  const msUntil3am = next3am - now;
  setTimeout(() => {
    runWalCheckpoint();
    setInterval(runWalCheckpoint, 24 * 60 * 60 * 1000);
  }, msUntil3am);
}

scheduleWalCheckpoint();

