// ── Migration: Fix team_members.reports_to broken FK ──
try {
  const tmSchema = db.prepare("SELECT sql FROM sqlite_master WHERE name='team_members' AND type='table'").get();
  if (tmSchema && tmSchema.sql && (tmSchema.sql.includes('team_members_new') || tmSchema.sql.includes('team_members_fixed'))) {
    db.pragma('foreign_keys = OFF');
    db.exec('BEGIN TRANSACTION');
    const cols = db.pragma('table_info(team_members)').map(c => c.name);
    const colList = cols.join(', ');
    db.exec(`CREATE TABLE team_members_clean (
        id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE, role TEXT NOT NULL,
        profile_path TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'active' CHECK(status IN ('active','inactive','retired')),
        created_at TEXT NOT NULL DEFAULT (datetime('now','localtime')),
        execution_mode TEXT NOT NULL DEFAULT 'system' CHECK(execution_mode IN ('system','terminal','autonomous')),
        tier TEXT NOT NULL DEFAULT 'specialist' CHECK(tier IN ('board','c-suite','specialist','orchestrator','leader','co-leader','subagent')),
        reports_to INTEGER, did_identity TEXT, dedicated_role INTEGER NOT NULL DEFAULT 0,
        llm_provider_id INTEGER REFERENCES llm_providers(id), llm_model TEXT, adapter_type TEXT DEFAULT 'claude_local',
        adapter_config TEXT DEFAULT '{}', runtime_config TEXT DEFAULT '{}', capabilities TEXT DEFAULT '[]',
        permissions TEXT DEFAULT '[]', icon TEXT, metadata TEXT DEFAULT '{}', department TEXT
    )`);
    db.exec(`INSERT INTO team_members_clean (${colList}) SELECT ${colList} FROM team_members`);
    db.exec(`DROP TABLE team_members`);
    db.exec(`ALTER TABLE team_members_clean RENAME TO team_members`);
    db.exec(`CREATE INDEX IF NOT EXISTS idx_team_members_status ON team_members(status)`);
    db.exec('COMMIT');
    db.pragma('foreign_keys = ON');
  }
} catch (e) {
  try { db.exec('ROLLBACK'); } catch (_) {}
  db.pragma('foreign_keys = ON');
  console.error('[Migration] team_members FK fix failed:', e.message);
}

