// Seed skills from Paperclip repo SKILL.md files
(function seedSkillsFromRepo() {
  const skillsDir = path.join(__dirname, '..', 'repos', 'paperclip-1', 'skills');
  try {
    if (!fs.existsSync(skillsDir)) return;
    const skillDirs = fs.readdirSync(skillsDir).filter(d => {
      const fullPath = path.join(skillsDir, d);
      return fs.statSync(fullPath).isDirectory() && fs.existsSync(path.join(fullPath, 'SKILL.md'));
    });

    for (const dir of skillDirs) {
      const skillMd = fs.readFileSync(path.join(skillsDir, dir, 'SKILL.md'), 'utf-8');
      // Parse simple frontmatter
      let skillName = dir;
      let skillDesc = '';
      let skillContent = skillMd;
      const fmMatch = skillMd.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
      if (fmMatch) {
        const fm = fmMatch[1];
        skillContent = fmMatch[2].trim();
        const nameMatch = fm.match(/^name:\s*(.+)$/m);
        if (nameMatch) skillName = nameMatch[1].trim();
        const descMatch = fm.match(/description:\s*>\s*\n([\s\S]*?)(?=\n\w|$)/);
        if (descMatch) skillDesc = descMatch[1].trim().replace(/\n\s*/g, ' ');
        else {
          const descSimple = fm.match(/^description:\s*(.+)$/m);
          if (descSimple) skillDesc = descSimple[1].trim();
        }
      }
      const displayName = skillName.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
      db.prepare('INSERT OR IGNORE INTO skills (name, display_name, description, category, skill_content, version, status) VALUES (?,?,?,?,?,?,?)')
        .run(skillName, displayName, skillDesc, 'paperclip', skillContent, '1.0', 'active');
    }
  } catch (e) {
  }
})();

