// Migration: recreate budget_policies with richer schema (keeps old data if columns match)
try {
  const bpSchema = db.prepare("SELECT sql FROM sqlite_master WHERE name='budget_policies'").get();
  if (bpSchema && bpSchema.sql && !bpSchema.sql.includes('action_at_limit')) {
    // Old schema — migrate
    db.exec(`CREATE TABLE IF NOT EXISTS budget_policies_new (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL DEFAULT 'Budget Policy',
      member_id INTEGER REFERENCES team_members(id),
      project_id INTEGER REFERENCES projects(id),
      scope TEXT NOT NULL DEFAULT 'global' CHECK(scope IN ('global','member','project','adapter')),
      period TEXT NOT NULL DEFAULT 'monthly' CHECK(period IN ('daily','weekly','monthly','quarterly','yearly')),
      limit_cents INTEGER NOT NULL DEFAULT 10000,
      spent_cents INTEGER DEFAULT 0,
      threshold_percent INTEGER DEFAULT 80,
      action_at_limit TEXT DEFAULT 'warn' CHECK(action_at_limit IN ('pause','warn','block','notify')),
      status TEXT DEFAULT 'active' CHECK(status IN ('active','paused','exhausted','disabled')),
      reset_at TEXT,
      created_at TEXT NOT NULL DEFAULT (datetime('now','localtime')),
      updated_at TEXT NOT NULL DEFAULT (datetime('now','localtime'))
    )`);
    // Migrate old rows
    try {
      const oldRows = db.prepare('SELECT * FROM budget_policies').all();
      for (const row of oldRows) {
        db.prepare(`INSERT INTO budget_policies_new (name, scope, limit_cents, threshold_percent, action_at_limit, status, created_at) VALUES (?,?,?,?,?,?,?)`)
          .run(row.scope === 'global' ? 'Global Monthly Budget' : `${row.scope} Policy`, row.scope, row.monthly_limit_cents || 10000, row.warn_at_percent || 80, row.hard_stop ? 'block' : 'warn', 'active', row.created_at);
      }
    } catch (_) {}
    db.exec('DROP TABLE budget_policies');
    db.exec('ALTER TABLE budget_policies_new RENAME TO budget_policies');
  } else if (!bpSchema) {
    db.exec(`CREATE TABLE IF NOT EXISTS budget_policies (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL DEFAULT 'Budget Policy',
      member_id INTEGER REFERENCES team_members(id),
      project_id INTEGER REFERENCES projects(id),
      scope TEXT NOT NULL DEFAULT 'global' CHECK(scope IN ('global','member','project','adapter')),
      period TEXT NOT NULL DEFAULT 'monthly' CHECK(period IN ('daily','weekly','monthly','quarterly','yearly')),
      limit_cents INTEGER NOT NULL DEFAULT 10000,
      spent_cents INTEGER DEFAULT 0,
      threshold_percent INTEGER DEFAULT 80,
      action_at_limit TEXT DEFAULT 'warn' CHECK(action_at_limit IN ('pause','warn','block','notify')),
      status TEXT DEFAULT 'active' CHECK(status IN ('active','paused','exhausted','disabled')),
      reset_at TEXT,
      created_at TEXT NOT NULL DEFAULT (datetime('now','localtime')),
      updated_at TEXT NOT NULL DEFAULT (datetime('now','localtime'))
    )`);
  }
} catch (e) {
}

