// ── Performance Indexes ─────────────────────────────────────────
// Tasks table — the most queried table in the system.
// status is filtered in 20+ queries; priority and created_at are used in every ORDER BY.
db.exec(`CREATE INDEX IF NOT EXISTS idx_tasks_status ON tasks(status)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_tasks_assigned_to ON tasks(assigned_to)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_tasks_priority ON tasks(priority)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_tasks_created_at ON tasks(created_at)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_tasks_updated_at ON tasks(updated_at)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_tasks_source_file ON tasks(source_file)`);
// Composite covering the dominant query shape: filter by status → sort by priority, created_at DESC
// DESC on created_at matches the ORDER BY in /api/dashboard openTasks & completedToday queries
db.exec(`DROP INDEX IF EXISTS idx_tasks_status_priority_created`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_tasks_status_priority_created ON tasks(status, priority, created_at DESC)`);
// Covers completedToday query: WHERE status IN (...) ORDER BY updated_at DESC
db.exec(`CREATE INDEX IF NOT EXISTS idx_tasks_status_updated ON tasks(status, updated_at DESC)`);

