db.exec(`CREATE INDEX IF NOT EXISTS idx_activity_log_created_at ON activity_log(created_at)`);
// Composite for the common "WHERE task_id = ? ORDER BY created_at DESC" pattern
db.exec(`CREATE INDEX IF NOT EXISTS idx_activity_log_task_created ON activity_log(task_id, created_at)`);

// task_files table — fetched for every task in the task list loop.
db.exec(`CREATE INDEX IF NOT EXISTS idx_task_files_task_id ON task_files(task_id)`);


// notifications table — always fetched ORDER BY created_at DESC.
db.exec(`CREATE INDEX IF NOT EXISTS idx_notifications_created_at ON notifications(created_at)`);

// decisions table — dashboard filters WHERE status = 'pending'.
db.exec(`CREATE INDEX IF NOT EXISTS idx_decisions_status ON decisions(status)`);

// notifications table — unread count badge uses WHERE read = 0; task deletes use WHERE task_id = ?
db.exec(`CREATE INDEX IF NOT EXISTS idx_notifications_read ON notifications(read)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_notifications_task_id ON notifications(task_id)`);

// ── Migration: Add 'mentioned' type to notifications CHECK constraint ──
try {
  const notifSchema = db.prepare("SELECT sql FROM sqlite_master WHERE name='notifications' AND type='table'").get();
  if (notifSchema && notifSchema.sql && !notifSchema.sql.includes("'mentioned'")) {
    db.pragma('foreign_keys = OFF');
    db.exec('BEGIN TRANSACTION');
    db.exec(`CREATE TABLE notifications_new (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      type TEXT NOT NULL CHECK(type IN ('task_delivered','task_status','decision_needed','hire_completed','system','mentioned')),
      title TEXT NOT NULL,
      message TEXT,
      task_id INTEGER REFERENCES tasks(id),
      read INTEGER NOT NULL DEFAULT 0,
      created_at TEXT NOT NULL DEFAULT (datetime('now','localtime'))
    )`);
    db.exec(`INSERT INTO notifications_new SELECT * FROM notifications`);
    db.exec(`DROP TABLE notifications`);
    db.exec(`ALTER TABLE notifications_new RENAME TO notifications`);
    db.exec(`CREATE INDEX IF NOT EXISTS idx_notifications_created_at ON notifications(created_at)`);
    db.exec(`CREATE INDEX IF NOT EXISTS idx_notifications_read ON notifications(read)`);
    db.exec(`CREATE INDEX IF NOT EXISTS idx_notifications_task_id ON notifications(task_id)`);
    db.exec('COMMIT');
    db.pragma('foreign_keys = ON');
  }
} catch (e) {
  try { db.exec('ROLLBACK'); } catch (_) {}
  db.pragma('foreign_keys = ON');
  console.error('[Migration] notifications mentioned type error:', e.message);
}

// active_processes — no indexes existed; queried heavily for WHERE status='running',
// WHERE task_id=? AND status='running', WHERE member_id=? AND status='running'
db.exec(`CREATE INDEX IF NOT EXISTS idx_active_processes_status ON active_processes(status)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_active_processes_task_status ON active_processes(task_id, status)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_active_processes_member_status ON active_processes(member_id, status)`);

// task_assignments — WHERE task_id=? and WHERE member_id=? are the two dominant patterns
db.exec(`CREATE INDEX IF NOT EXISTS idx_task_assignments_task_id ON task_assignments(task_id)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_task_assignments_member_id ON task_assignments(member_id)`);

// task_dependencies — WHERE task_id=? (get deps) and WHERE depends_on=? (find what unblocks)
db.exec(`CREATE INDEX IF NOT EXISTS idx_task_dependencies_task_id ON task_dependencies(task_id)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_task_dependencies_depends_on ON task_dependencies(depends_on)`);

// task_goals — WHERE goal_id=? and WHERE task_id=? both appear in goal progress queries
db.exec(`CREATE INDEX IF NOT EXISTS idx_task_goals_goal_id ON task_goals(goal_id)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_task_goals_task_id ON task_goals(task_id)`);

// session_phases — WHERE session_id=? on every workspace load; status sub-filter is frequent
db.exec(`CREATE INDEX IF NOT EXISTS idx_session_phases_session_id ON session_phases(session_id)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_session_phases_session_status ON session_phases(session_id, status)`);
