// workspace_sessions — list view ORDER BY created_at DESC; status filter on dashboard
db.exec(`CREATE INDEX IF NOT EXISTS idx_workspace_sessions_created_at ON workspace_sessions(created_at)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_workspace_sessions_status ON workspace_sessions(status)`);

// heartbeat_runs — WHERE task_id=? AND status='running' ORDER BY id DESC for active run lookup
db.exec(`CREATE INDEX IF NOT EXISTS idx_heartbeat_runs_task_status ON heartbeat_runs(task_id, status)`);

// team_members — WHERE status='active' runs on every dashboard load and heartbeat cycle
db.exec(`CREATE INDEX IF NOT EXISTS idx_team_members_status ON team_members(status)`);

db.exec(`CREATE INDEX IF NOT EXISTS idx_notes_created_at ON notes(created_at)`);

// contacts — list endpoint ORDER BY name ASC
db.exec(`CREATE INDEX IF NOT EXISTS idx_contacts_name ON contacts(name)`);

// taggables — WHERE tag_id=? (tag detail page) and WHERE entity_type=? AND entity_id=? (entity tags)
db.exec(`CREATE INDEX IF NOT EXISTS idx_taggables_tag_id ON taggables(tag_id)`);
db.exec(`CREATE INDEX IF NOT EXISTS idx_taggables_entity ON taggables(entity_type, entity_id)`);

// cost_events — time-range queries for budget period aggregations
