// ═══════════════════════════════════════════════════════════════
// ── ExoChain P1: Decision Forum Schema Migration ─────────────
// ═══════════════════════════════════════════════════════════════
// Full BCTS-compliant governance tables mirroring the ExoChain
// decision-forum crate domain model (14-state lifecycle, quorum
// policies, accountability, challenges, emergency actions).

// P1-1. Decision Objects — 14-state BCTS lifecycle
//    States: Draft → Submitted → IdentityResolved → ConsentValidated →
//    Deliberated → Verified → Governed → Approved → Executed → Recorded → Closed
//    Branch states: Denied, Escalated, Remediated
db.exec(`CREATE TABLE IF NOT EXISTS decision_objects (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    uuid TEXT NOT NULL UNIQUE,
    title TEXT NOT NULL,
    description TEXT,
    decision_class TEXT NOT NULL CHECK(decision_class IN ('Routine','Operational','Strategic','Constitutional')),
    state TEXT NOT NULL DEFAULT 'Draft' CHECK(state IN (
        'Draft','Submitted','IdentityResolved','ConsentValidated',
        'Deliberated','Verified','Governed','Approved',
        'Executed','Recorded','Closed',
        'Denied','Escalated','Remediated'
    )),
    constitutional_hash TEXT NOT NULL,
    author_id INTEGER REFERENCES team_members(id),
    author_did TEXT,
    branch TEXT DEFAULT 'executive' CHECK(branch IN ('legislative','executive','judicial')),
    authority_chain TEXT DEFAULT '[]',
    evidence_bundle TEXT DEFAULT '[]',
    receipt_chain TEXT DEFAULT '[]',
    metadata TEXT DEFAULT '{}',
    content_hash TEXT,
    receipt_id INTEGER REFERENCES governance_receipts(id),
    created_at TEXT NOT NULL DEFAULT (datetime('now','localtime')),
    updated_at TEXT NOT NULL DEFAULT (datetime('now','localtime'))
)`);

// P1-2. Independence Attestations — 3 mandatory fields per GOV-010/TNC-07
//    no_common_control, no_coordination, identity_verified
db.exec(`CREATE TABLE IF NOT EXISTS independence_attestations (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    attestor_id INTEGER REFERENCES team_members(id),
    attestor_did TEXT NOT NULL,
    decision_object_id INTEGER REFERENCES decision_objects(id),
    no_common_control INTEGER NOT NULL DEFAULT 0,
    no_coordination INTEGER NOT NULL DEFAULT 0,
    identity_verified INTEGER NOT NULL DEFAULT 0,
    signature_hash TEXT,
    created_at TEXT NOT NULL DEFAULT (datetime('now','localtime'))
)`);

// P1-3. Votes — voter, choice, signature, independence_attestation
//    Actor kinds: Human vs AiAgent (with delegation ceiling)
//    Unique constraint: one vote per DID per decision
db.exec(`CREATE TABLE IF NOT EXISTS votes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    decision_object_id INTEGER NOT NULL REFERENCES decision_objects(id) ON DELETE CASCADE,
    voter_id INTEGER REFERENCES team_members(id),
    voter_did TEXT NOT NULL,
    choice TEXT NOT NULL CHECK(choice IN ('Approve','Reject','Abstain')),
    actor_kind TEXT NOT NULL DEFAULT 'Human' CHECK(actor_kind IN ('Human','AiAgent')),
    delegation_id TEXT,
    ceiling_class TEXT CHECK(ceiling_class IS NULL OR ceiling_class IN ('Routine','Operational','Strategic','Constitutional')),
    signature_hash TEXT NOT NULL,
    independence_attestation_id INTEGER REFERENCES independence_attestations(id),
    rationale TEXT,
    timestamp TEXT NOT NULL DEFAULT (datetime('now','localtime')),
    UNIQUE(decision_object_id, voter_did)
)`);

// P1-4. Quorum Policies — per-class thresholds
//    Routine: 1 vote/51%/0 human, Operational: 3/51%/1, Strategic: 5/67%/3, Constitutional: 7/75%/5
db.exec(`CREATE TABLE IF NOT EXISTS quorum_policies (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    decision_class TEXT NOT NULL UNIQUE CHECK(decision_class IN ('Routine','Operational','Strategic','Constitutional')),
    min_votes INTEGER NOT NULL,
    min_approve_pct INTEGER NOT NULL,
    min_human_votes INTEGER NOT NULL DEFAULT 0,
    description TEXT,
    created_at TEXT NOT NULL DEFAULT (datetime('now','localtime')),
    updated_at TEXT NOT NULL DEFAULT (datetime('now','localtime'))
)`);

// Seed default quorum policies from ExoChain QuorumRegistry::with_defaults()
db.exec(`INSERT OR IGNORE INTO quorum_policies (decision_class, min_votes, min_approve_pct, min_human_votes, description) VALUES
    ('Routine', 1, 51, 0, 'Day-to-day operational decisions'),
    ('Operational', 3, 51, 1, 'Decisions affecting operations or resources'),
    ('Strategic', 5, 67, 3, 'Long-term or high-impact decisions'),
    ('Constitutional', 7, 75, 5, 'Decisions that modify the constitutional corpus')
`);

// P1-5. Authority Delegations upgrade — add chain_depth, delegation_hash, decision_class_ceiling
try { db.exec(`ALTER TABLE authority_delegations ADD COLUMN chain_depth INTEGER DEFAULT 0`); } catch (_) {}
try { db.exec(`ALTER TABLE authority_delegations ADD COLUMN delegation_hash TEXT`); } catch (_) {}
try { db.exec(`ALTER TABLE authority_delegations ADD COLUMN decision_class_ceiling TEXT CHECK(decision_class_ceiling IS NULL OR decision_class_ceiling IN ('Routine','Operational','Strategic','Constitutional'))`); } catch (_) {}
try { db.exec(`ALTER TABLE authority_delegations ADD COLUMN constitutional_hash TEXT`); } catch (_) {}
try { db.exec(`ALTER TABLE authority_delegations ADD COLUMN actor_kind TEXT DEFAULT 'Human' CHECK(actor_kind IN ('Human','AiAgent'))`); } catch (_) {}
try { db.exec(`ALTER TABLE authority_delegations ADD COLUMN delegator_did TEXT`); } catch (_) {}
try { db.exec(`ALTER TABLE authority_delegations ADD COLUMN delegate_did TEXT`); } catch (_) {}

// P1-6. Challenge Records — 6 grounds (GOV-008 contestation & reversal)
//    Grounds: AuthorityChainInvalid, QuorumViolation, UndisclosedConflict,
//             ProceduralError, SybilAllegation, ConsentViolation
db.exec(`CREATE TABLE IF NOT EXISTS challenge_records (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    uuid TEXT NOT NULL UNIQUE,
    decision_object_id INTEGER NOT NULL REFERENCES decision_objects(id),
    challenger_id INTEGER REFERENCES team_members(id),
    challenger_did TEXT NOT NULL,
    ground TEXT NOT NULL CHECK(ground IN (
        'AuthorityChainInvalid','QuorumViolation','UndisclosedConflict',
        'ProceduralError','SybilAllegation','ConsentViolation'
    )),
    evidence_hash TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'Filed' CHECK(status IN ('Filed','UnderReview','Sustained','Overruled','Withdrawn')),
    resolution TEXT,
    resolution_decision_id INTEGER REFERENCES decision_objects(id),
    created_at TEXT NOT NULL DEFAULT (datetime('now','localtime')),
    resolved_at TEXT
)`);

// Reversal links — connects original decisions to reversal decisions via challenges
db.exec(`CREATE TABLE IF NOT EXISTS reversal_links (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    original_decision_id INTEGER NOT NULL REFERENCES decision_objects(id),
    reversal_decision_id INTEGER NOT NULL REFERENCES decision_objects(id),
    challenge_id INTEGER NOT NULL REFERENCES challenge_records(id),
    reversed_at TEXT NOT NULL DEFAULT (datetime('now','localtime'))
)`);

// P1-7. Accountability Actions — censure/suspension/revocation/recall (GOV-012)
//    Suspension must be enacted within 60s. Due process window: 7 days.
db.exec(`CREATE TABLE IF NOT EXISTS accountability_actions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    uuid TEXT NOT NULL UNIQUE,
    action_type TEXT NOT NULL CHECK(action_type IN ('Censure','Suspension','Revocation','Recall')),
    target_id INTEGER REFERENCES team_members(id),
    target_did TEXT NOT NULL,
    proposer_id INTEGER REFERENCES team_members(id),
    proposer_did TEXT NOT NULL,
    reason TEXT NOT NULL,
    evidence_hash TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'Proposed' CHECK(status IN ('Proposed','DueProcess','Enacted','Reversed')),
    decision_object_id INTEGER REFERENCES decision_objects(id),
    proposed_at TEXT NOT NULL DEFAULT (datetime('now','localtime')),
    enacted_at TEXT,
    due_process_deadline TEXT NOT NULL,
    created_at TEXT NOT NULL DEFAULT (datetime('now','localtime'))
)`);

// P1-8. Conflict Disclosures — signed, timestamped conflict-of-interest declarations
db.exec(`CREATE TABLE IF NOT EXISTS conflict_disclosures (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    discloser_id INTEGER REFERENCES team_members(id),
    discloser_did TEXT NOT NULL,
    decision_object_id INTEGER REFERENCES decision_objects(id),
    conflict_type TEXT NOT NULL,
    description TEXT NOT NULL,
    affected_parties TEXT DEFAULT '[]',
    signature_hash TEXT NOT NULL,
    disclosed_at TEXT NOT NULL DEFAULT (datetime('now','localtime')),
    created_at TEXT NOT NULL DEFAULT (datetime('now','localtime'))
)`);

// P1-9. Emergency Actions — ratification_required, auto_expiry (GOV-009)
