// Generate DIDs for existing team members that don't have them
try {
  const membersWithoutDid = db.prepare(`SELECT id, name FROM team_members WHERE id NOT IN (SELECT member_id FROM member_identities)`).all();
  for (const member of membersWithoutDid) {
    const didHash = crypto.createHash('sha256').update(`team:${member.id}:${member.name}:${Date.now()}`).digest('hex').slice(0, 32);
    const did = `did:exo:${didHash}`;
    const keyPair = crypto.generateKeyPairSync('ed25519');
    const publicKey = keyPair.publicKey.export({ type: 'spki', format: 'pem' });
    try {
      db.prepare('INSERT INTO member_identities (member_id, did, public_key, key_type, status) VALUES (?,?,?,?,?)')
        .run(member.id, did, publicKey, 'ed25519', 'active');
    } catch (_) { /* already has DID */ }
  }
} catch (e) { console.warn('[ExoChain] DID generation error:', e.message); }


// ── Structured HTTP Errors ──────────────────────────────────────
class HttpError extends Error {
  constructor(status, message, details) {
    super(message);
    this.status = status;
    this.details = details;
  }
}
function badRequest(msg, details) { return new HttpError(400, msg, details); }
function notFound(msg) { return new HttpError(404, msg || 'Not found'); }
function forbidden(msg) { return new HttpError(403, msg || 'Forbidden'); }
function conflict(msg) { return new HttpError(409, msg, null); }

// ── Sensitive Data Masking Helpers ──────────────────────────────
// Prevent accidental exposure of credentials, tokens, and secrets in API responses.

// Field names in tool/integration config objects that must be masked
const SENSITIVE_CONFIG_FIELDS = new Set([
  'key', 'api_key', 'apiKey', 'secret', 'password', 'passwd',
  'token', 'auth_token', 'access_token', 'refresh_token', 'id_token',
  'private_key', 'client_secret', 'webhook_url', 'account_sid'
]);

// System settings keys whose values must never be returned in plaintext
const SENSITIVE_SETTING_KEYS = new Set([
  'webhook_secret', 'anthropic_api_key', 'oauth_token'
]);

// Pattern-based detection for settings keys not in the static set above.
// Catches dynamically-stored credentials like 'stripe_secret_key', 'twilio_auth_token', etc.
const SENSITIVE_KEY_SUFFIXES = ['_token', '_key', '_secret', '_password', '_passwd', '_auth', '_sid', '_apikey'];
const SENSITIVE_KEY_PREFIXES = ['auth_', 'secret_', 'token_', 'api_key_'];
const SENSITIVE_KEY_SUBSTRINGS = ['api_key', 'apikey', 'access_key', 'client_secret'];

function isSensitiveSettingKey(key) {
  if (SENSITIVE_SETTING_KEYS.has(key)) return true;
  const lower = key.toLowerCase();
  if (SENSITIVE_KEY_SUFFIXES.some(s => lower.endsWith(s))) return true;
  if (SENSITIVE_KEY_PREFIXES.some(p => lower.startsWith(p))) return true;
  if (SENSITIVE_KEY_SUBSTRINGS.some(sub => lower.includes(sub))) return true;
  return false;
}

// Mask sensitive fields inside a config/credential object before returning in API responses.
// Recursively handles nested objects so deeply-nested secrets are also masked.
// Uses maskCredential (defined below, hoisted as a function declaration)
function maskSensitiveConfig(config) {
  if (!config || typeof config !== 'object' || Array.isArray(config)) return config;
  const masked = {};
  for (const [k, v] of Object.entries(config)) {
    if (SENSITIVE_CONFIG_FIELDS.has(k) && v) {
      masked[k] = maskCredential(String(v));
    } else if (v && typeof v === 'object' && !Array.isArray(v)) {
      masked[k] = maskSensitiveConfig(v);
    } else {
      masked[k] = v;
    }
  }
  return masked;
}

// ── Middleware ──────────────────────────────────────────────────
// Dual compression: brotli for modern clients (better ratio), gzip fallback for the rest.
// Brotli delivers ~20-26% better compression than gzip on JSON payloads.
//
// Ordering matters:
//   1. compression() runs first — it skips brotli clients via the filter function,
//      so gzip is only applied to clients that don't advertise 'br'.
//   2. brotliMiddleware runs second — for 'br' clients, it buffers the response,
//      compresses with brotli at quality 4, and rewrites Content-Encoding.
//
// Responses < 1KB are left uncompressed — compression overhead exceeds savings.
const BROTLI_COMPRESSIBLE = /^(text\/(plain|html|css|javascript|xml|csv)|application\/(json|javascript|xml|xhtml\+xml|rss\+xml|manifest\+json)|image\/svg\+xml)/;
const BROTLI_MIN_SIZE = 1024; // bytes
const BROTLI_QUALITY = 4;    // 0–11; 4 = fast with solid compression (11 is too slow for dynamic content)

function brotliMiddleware(req, res, next) {
  if (!(req.headers['accept-encoding'] || '').includes('br')) return next();

  const _write = res.write;
  const _end = res.end;
  const chunks = [];
  let decided = false;
  let shouldCompress = null;

  function decide() {
    if (decided) return;
    decided = true;
    const ct = (res.getHeader('content-type') || '').split(';')[0].trim();
    shouldCompress = !res.getHeader('content-encoding') && BROTLI_COMPRESSIBLE.test(ct);
  }

  res.write = function (chunk, encoding, cb) {
    decide();
    if (!shouldCompress) {
      res.write = _write;
      return _write.call(res, chunk, encoding, cb);
    }
    if (typeof encoding === 'function') { cb = encoding; encoding = 'utf8'; }
    if (chunk) chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk, encoding || 'utf8'));
    if (cb) setImmediate(cb);
    return true;
  };

  res.end = function (chunk, encoding, cb) {
    if (typeof chunk === 'function') { cb = chunk; chunk = null; encoding = null; }
    else if (typeof encoding === 'function') { cb = encoding; encoding = null; }
    decide();
    res.write = _write;
    res.end = _end;

    if (!shouldCompress) return _end.call(res, chunk || undefined, encoding || undefined, cb);

    if (chunk) chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk, encoding || 'utf8'));
    const body = Buffer.concat(chunks);

    if (body.length < BROTLI_MIN_SIZE) return _end.call(res, body, cb);

    zlib.brotliCompress(body, { params: { [zlib.constants.BROTLI_PARAM_QUALITY]: BROTLI_QUALITY } }, (err, compressed) => {
      if (err) return _end.call(res, body, cb);
      res.setHeader('Content-Encoding', 'br');
      res.setHeader('Vary', 'Accept-Encoding');
      res.setHeader('Content-Length', compressed.length);
      res.removeHeader('Transfer-Encoding');
      _end.call(res, compressed, cb);
    });
  };

  next();
}

// Gzip for clients that don't support brotli
app.use(compression({
  level: 6,
  threshold: BROTLI_MIN_SIZE,
  filter: (req, res) => {
    if ((req.headers['accept-encoding'] || '').includes('br')) return false;
    return compression.filter(req, res);
  }
}));

// Brotli for modern clients (all major browsers since 2017)
app.use(brotliMiddleware);

// 50MB limit — Max sends large plans and project imports through the Board Room
app.use(express.json({ limit: '50mb' }));
app.use(express.urlencoded({ extended: false, limit: '50mb' }));

