// ── Request Duration & Latency Tracking ──────────────────────────
// Tracks per-request timing and maintains a rolling window of endpoint
// latency stats for the /health endpoint and operational visibility.
const SLOW_REQUEST_THRESHOLD_MS = parseInt(process.env.SLOW_REQUEST_MS || '1000', 10);
const requestLatency = {
  // Rolling window: last 1000 request durations for p50/p95/p99 calculation
  _durations: [],
  _maxWindow: 1000,
  // Top slow endpoints (path → { count, totalMs, maxMs })
  slowEndpoints: new Map(),
  record(durationMs, path) {
    this._durations.push(durationMs);
    if (this._durations.length > this._maxWindow) this._durations.shift();
    if (durationMs >= SLOW_REQUEST_THRESHOLD_MS) {
      const entry = this.slowEndpoints.get(path) || { count: 0, totalMs: 0, maxMs: 0 };
      entry.count += 1;
      entry.totalMs += durationMs;
      entry.maxMs = Math.max(entry.maxMs, durationMs);
      this.slowEndpoints.set(path, entry);
    }
  },
  percentile(p) {
    if (this._durations.length === 0) return 0;
    const sorted = [...this._durations].sort((a, b) => a - b);
    const idx = Math.ceil((p / 100) * sorted.length) - 1;
    return sorted[Math.max(0, idx)];
  },
  stats() {
    const n = this._durations.length;
    if (n === 0) return { count: 0, p50: 0, p95: 0, p99: 0, avg: 0 };
    const sum = this._durations.reduce((a, b) => a + b, 0);
    return {
      count: n,
      p50: this.percentile(50),
      p95: this.percentile(95),
      p99: this.percentile(99),
      avg: Math.round(sum / n)
    };
  },
  topSlow(limit = 10) {
    return [...this.slowEndpoints.entries()]
      .sort((a, b) => b[1].count - a[1].count)
      .slice(0, limit)
      .map(([path, s]) => ({ path, count: s.count, avgMs: Math.round(s.totalMs / s.count), maxMs: s.maxMs }));
  }
};

app.use((req, res, next) => {
  const startTime = process.hrtime.bigint();
  res.on('finish', () => {
    requestCounters.total += 1;
    const bucket = `${Math.floor(res.statusCode / 100)}xx`;
    if (requestCounters.by_status[bucket] !== undefined) {
      requestCounters.by_status[bucket] += 1;
    }
    const method = req.method.toUpperCase();
    requestCounters.by_method[method] = (requestCounters.by_method[method] || 0) + 1;

    // Duration tracking for API routes
    const durationMs = Number(process.hrtime.bigint() - startTime) / 1e6;
    if (req.path.startsWith('/api/')) {
      requestLatency.record(Math.round(durationMs), `${method} ${req.route ? req.route.path : req.path}`);
      if (durationMs >= SLOW_REQUEST_THRESHOLD_MS) {
        logger.warn(`[slow-request] ${method} ${req.path} — ${Math.round(durationMs)}ms (status ${res.statusCode})`);
      }
    }
  });
  next();
});

// ── Security headers middleware ───────────────────────────────────
// Applied to every response. Covers clickjacking, MIME sniffing, referrer
// leakage, XSS, cross-origin isolation, and browser feature policy.
// Headers are declared once as a static map and applied in a single loop
// so adding/removing a header is a one-line change.

const SECURITY_HEADERS = {
  // Content-Security-Policy: mitigate XSS from innerHTML / inline injection.
  //
  // 'unsafe-inline' in script-src: retained because index.html contains two
  // static inline <script> blocks (service-worker registration + pre-paint
  // theme detection).  Removing it would require either nonces (needs per-
  // request HTML injection) or SHA-256 hashes — both are future-work items.
  //
  // 'unsafe-inline' in style-src: app.js inserts a dynamic <style> tag via
  // style.textContent for search-highlight keyframes.  Refactoring that to a
  // static stylesheet would allow removal of this allowance.
  //
  // object-src 'none': explicitly blocks Flash, Java applets, and any other
  // plugin-based content.  Not inherited from default-src in all browsers.
  //
  // base-uri 'self': prevents <base> tag injection — base-uri is NOT covered
  // by default-src, so an XSS that injects <base href="..."> could redirect
  // every relative resource load.
  //
  // worker-src 'self': controls where service workers (/sw.js) may be loaded
  // from.  default-src doesn't consistently cover workers across browsers.
  //
  // form-action 'self': restricts where HTML forms may submit to.  This
  // directive is also NOT covered by default-src.
  //
  // connect-src ws: wss:: permits same-host WebSocket upgrades.  'self' alone
  // doesn't reliably cover WebSocket origins in all browsers.  Tightening to
  // explicit ws(s)://hostname requires build-time config; deferred.
  'Content-Security-Policy': [
    "default-src 'self'",
    "script-src 'self' 'unsafe-inline'",
    "style-src 'self' 'unsafe-inline' https://fonts.googleapis.com",
    "font-src 'self' https://fonts.gstatic.com",
    "img-src 'self' data:",
    "connect-src 'self' ws: wss:",
    "object-src 'none'",
    "base-uri 'self'",
    "worker-src 'self'",
    "form-action 'self'",
    "frame-ancestors 'none'"
  ].join('; '),

  // Prevents clickjacking in older browsers that don't support CSP frame-ancestors.
  'X-Frame-Options': 'DENY',

  // Prevents MIME-type sniffing attacks.
  'X-Content-Type-Options': 'nosniff',

  // Limits referrer information sent on cross-origin navigations.
  'Referrer-Policy': 'strict-origin-when-cross-origin',

  // Disables the legacy XSS auditor (removed in modern browsers; can itself
  // introduce vulnerabilities — CSP is the correct XSS defence).
  'X-XSS-Protection': '0',

  // Cross-Origin-Opener-Policy: isolates the browsing context from cross-
  // origin popups — enables SharedArrayBuffer and mitigates Spectre-class
  // side-channel attacks on the renderer process.
  'Cross-Origin-Opener-Policy': 'same-origin',

  // Cross-Origin-Resource-Policy: prevents other origins from reading this
  // server's responses via no-cors fetches (protects against Spectre leaks).
  'Cross-Origin-Resource-Policy': 'same-origin',

  // Permissions-Policy: opt out of every browser feature this app doesn't use.
  // Reduces attack surface if XSS occurs — an injected script can't silently
  // access camera, microphone, or location.
  'Permissions-Policy': [
    'camera=()',
    'microphone=()',
    'geolocation=()',
    'payment=()',
    'usb=()',
    'bluetooth=()',
    'interest-cohort=()'
  ].join(', ')
};

function securityHeadersMiddleware(req, res, next) {
  for (const [name, value] of Object.entries(SECURITY_HEADERS)) {
    res.setHeader(name, value);
  }
  next();
}

app.use(securityHeadersMiddleware);

// ── HTTPS redirect (production only) ──────────────────────────
// When deployed behind a TLS-terminating proxy (Cloudflare, nginx, etc.),
// redirect plain HTTP requests to HTTPS.  The health endpoint is excluded
// so load-balancer probes that hit HTTP still get a 200.
// Requires `trust proxy` to be set (above) so req.secure works correctly.
if (process.env.FORCE_HTTPS === '1' || process.env.FORCE_HTTPS === 'true') {
  app.use((req, res, next) => {
    if (req.secure || req.path === '/health') return next();
    res.redirect(301, 'https://' + req.hostname + req.originalUrl);
  });
}

// ── Secure cookie defaults ─────────────────────────────────────
// Intercept every res.cookie() call and enforce HttpOnly, Secure, and
// SameSite=Strict regardless of what the caller specified.  The app
// currently issues no cookies (tokens are returned in JSON bodies), but
// this middleware ensures any future cookie additions are secure by
// default rather than relying on each call-site to remember the attributes.
//
// HttpOnly — prevents JavaScript (including XSS payloads) from reading
//            the cookie via document.cookie.
// Secure   — restricts the cookie to HTTPS connections only, preventing
//            transmission over plaintext HTTP.
// SameSite=Strict — blocks the cookie from being sent on cross-site
//                   requests, mitigating CSRF attacks.
app.use((req, res, next) => {
  const origCookie = res.cookie.bind(res);
  res.cookie = function secureCookie(name, value, options = {}) {
    const secureOptions = Object.assign({}, options, {
      httpOnly: true,
      secure: true,
      sameSite: 'Strict'
    });
    return origCookie(name, value, secureOptions);
  };
  next();
});

// ── API v1 versioning — backward-compatible alias ──────────────
// /api/v1/* is a transparent alias for /api/*. Rewrites req.url so all
// existing routes serve both paths without duplication. req.originalUrl
// is untouched so logs always record the client's actual request URL.
app.use((req, res, next) => {
  if (req.path.startsWith('/api/v1/') || req.path === '/api/v1') {
    req.url = req.url.replace('/api/v1', '/api');
  }
  next();
});

// ── Request/response logging middleware ───────────────────────
// Logs method, URL, status, response time, and content-length for every request.
// Skips static asset paths to keep logs signal-rich (no .js/.css noise).
// Uses info for 2xx/3xx, warn for 4xx, error for 5xx.
// Emits an additional warn for any request exceeding SLOW_REQUEST_MS.
// Each request gets a unique X-Request-ID header for log correlation.
const SLOW_REQUEST_MS = parseInt(process.env.SLOW_REQUEST_MS || '1000', 10);
const HTTP_STATIC_EXTS = new Set(['js', 'css', 'html', 'ico', 'png', 'jpg', 'jpeg', 'gif', 'svg', 'woff', 'woff2', 'ttf', 'map']);

app.use((req, res, next) => {
  const start = Date.now();
  const ip = req.ip || req.socket?.remoteAddress || 'unknown';
  // Determine once at request entry whether this is a static asset so the
  // finish handler does not recompute it on every response.
  const extMatch = req.path.match(/\.([a-z0-9]+)$/i);
  const isStatic = extMatch !== null && HTTP_STATIC_EXTS.has(extMatch[1].toLowerCase()) && !req.path.startsWith('/api/');

  // Assign a unique request ID for log correlation. Honour a forwarded
  // X-Request-ID from a proxy/load-balancer if present; otherwise generate one.
  const requestId = req.headers['x-request-id'] || crypto.randomBytes(8).toString('hex');
  req.requestId = requestId;
  res.set('X-Request-ID', requestId);

  // Log request arrival at debug level. Useful for spotting requests that
  // never produce a finish event (e.g. hung handlers).
  if (!isStatic) {
    const ua = req.headers['user-agent'] ? ` ua="${req.headers['user-agent'].slice(0, 80)}"` : '';
    logger.debug(`[http] --> ${req.method} ${req.originalUrl} [${ip}] id=${requestId}${ua}`);
  }

  let logged = false;

  function logCompletion(outcome) {
    if (logged) return;
    logged = true;

    const ms     = Date.now() - start;
    const status = res.statusCode;
    const bytes  = res.get('content-length') || '-';
    const msg    = `${req.method} ${req.originalUrl} ${status} ${ms}ms ${bytes}b [${ip}] id=${requestId}${outcome ? ` (${outcome})` : ''}`;

    if (status >= 500) {
      logger.error(`[http] ${msg}`);
    } else if (status >= 400) {
      logger.warn(`[http] ${msg}`);
    } else {
      logger.info(`[http] ${msg}`);
    }

    if (ms > SLOW_REQUEST_MS) {
      logger.warn(`[http] slow request: ${req.method} ${req.originalUrl} took ${ms}ms id=${requestId}`);
    }
  }

  res.on('finish', () => {
    if (isStatic) return;
    logCompletion(null);
  });

  // Client disconnected before the response was sent.
  res.on('close', () => {
    if (isStatic || res.writableEnded) return;
    logCompletion('aborted');
  });

  next();
});

// ── In-flight request tracking ────────────────────────────────
// Counts active requests so gracefulShutdown can wait for them to finish
// before closing the DB.  Also rejects new requests with 503 once shutdown
// has been initiated so callers can retry against another instance.
let isShuttingDown     = false;
let activeRequestCount = 0;

app.use((req, res, next) => {
  if (isShuttingDown) {
    res.set('Connection', 'close');
    return res.status(503).json({ error: 'Server is shutting down. Please retry.' });
  }
  activeRequestCount++;
  // Use a flag to ensure we only decrement once. Both 'finish' and 'close'
  // fire on normal requests — without this guard the counter goes negative,
  // which causes gracefulShutdown to finalize prematurely while requests
  // are still in-flight.
  let decremented = false;
  function decrement() {
    if (!decremented) { decremented = true; activeRequestCount--; }
  }
  res.on('finish', decrement);
  res.on('close',  decrement);
  next();
});

// ── Per-request timeout middleware ────────────────────────────
// Complements the server-level timeouts (server.requestTimeout / server.timeout)
// by returning a graceful 503 JSON response before the socket is forcibly
// destroyed. This prevents hung handlers from silently blocking the event loop
// and gives API clients a well-formed error they can act on.
//
//   REQUEST_HANDLER_TIMEOUT (default 30 s) — max time any single API request
//   handler may run before the middleware sends 503 and ends the response.
//   Long-poll / streaming endpoints that intentionally exceed this limit
//   should set req.noHandlerTimeout = true before the middleware fires.
const REQUEST_HANDLER_TIMEOUT_MS = parseInt(process.env.REQUEST_HANDLER_TIMEOUT || '30000', 10);

app.use((req, res, next) => {
  // Skip WebSocket upgrade requests and explicitly opted-out routes.
  if (req.noHandlerTimeout) return next();

  const timer = setTimeout(() => {
    if (res.headersSent) return; // response already started — nothing to do
    logger.warn(`[timeout] ${req.method} ${req.originalUrl} exceeded ${REQUEST_HANDLER_TIMEOUT_MS}ms`);
    res.status(503).json({ error: 'Request timed out. Please retry.' });
  }, REQUEST_HANDLER_TIMEOUT_MS);

  // Clear timer as soon as the response is committed so we don't fire on
  // slow-but-progressing streaming responses.
  res.on('finish', () => clearTimeout(timer));
  res.on('close',  () => clearTimeout(timer));

  next();
});

// ── API Auth — simple key-based auth for local security ────────
let _apiAuthKey = null;
function getApiAuthKey() {
  if (_apiAuthKey) return _apiAuthKey;
  const row = db.prepare(`SELECT value FROM system_settings WHERE key = 'api_auth_key'`).get();
  if (row && row.value) { _apiAuthKey = row.value; return _apiAuthKey; }
  _apiAuthKey = crypto.randomBytes(32).toString('hex');
  const n = localNow();
  db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES (?,?,?)`).run('api_auth_key', _apiAuthKey, n);
  console.log('[Auth] Generated new API key');
  return _apiAuthKey;
}
app.get('/api/auth/status', (req, res) => {
  res.json({ authenticated: true, key: getApiAuthKey() });
});
app.use('/api', (req, res, next) => {
  // Exempt auth status and whitepaper data (non-sensitive, needed before auth bootstrap)
  if (req.path === '/auth/status' || req.path.startsWith('/whitepaper/')) return next();
  const key = getApiAuthKey();
  const headerKey = req.headers['x-api-key'];
  const cookieMatch = (req.headers.cookie || '').match(/cb_auth=([^;]+)/);
  const cookieKey = cookieMatch ? cookieMatch[1] : null;
  if (headerKey === key || cookieKey === key) return next();
  res.status(401).json({ error: 'Unauthorized — missing or invalid API key' });
});

// ── In-memory rate limiter ─────────────────────────────────────
// Fixed-window per IP. Read endpoints: 300 req/min. Write endpoints: 60 req/min.
// Keyed by `${ip}:${tier}` so read and write windows are tracked independently.
const RATE_LIMIT_WINDOW_MS = parseInt(process.env.RATE_LIMIT_WINDOW_MS || '60000',  10); // default 60 s
const RATE_LIMIT_READ      = parseInt(process.env.RATE_LIMIT_READ      || '300',    10); // default 300 req/window
const RATE_LIMIT_WRITE     = parseInt(process.env.RATE_LIMIT_WRITE     || '60',     10); // default  60 req/window

/** @type {Map<string, {count: number, windowStart: number}>} */
const rateLimitStore = new Map();

// Periodically evict expired windows to prevent unbounded memory growth
setInterval(() => {
  const now = Date.now();
  for (const [key, entry] of rateLimitStore) {
    if (now - entry.windowStart >= RATE_LIMIT_WINDOW_MS) {
      rateLimitStore.delete(key);
    }
  }
}, RATE_LIMIT_WINDOW_MS);

function apiRateLimiter(req, res, next) {
  // Normalize IPv4-mapped IPv6 addresses (::ffff:1.2.3.4 → 1.2.3.4) so that
  // IPv4 clients behind dual-stack listeners share a single rate-limit bucket.
  const rawIp = req.ip || req.socket.remoteAddress || 'unknown';
  const ip = rawIp.startsWith('::ffff:') ? rawIp.slice(7) : rawIp;
  const isWrite = ['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method);
  const tier = isWrite ? 'write' : 'read';
  const limit = isWrite ? RATE_LIMIT_WRITE : RATE_LIMIT_READ;
  const key = `${ip}:${tier}`;
  const now = Date.now();

  let entry = rateLimitStore.get(key);
  if (!entry || now - entry.windowStart >= RATE_LIMIT_WINDOW_MS) {
    entry = { count: 0, windowStart: now };
    rateLimitStore.set(key, entry);
  }

  entry.count += 1;
  const remaining = Math.max(0, limit - entry.count);
  const resetSec = Math.ceil((entry.windowStart + RATE_LIMIT_WINDOW_MS - now) / 1000);

  res.set('X-RateLimit-Limit', String(limit));
  res.set('X-RateLimit-Remaining', String(remaining));
  res.set('X-RateLimit-Reset', String(resetSec));

  if (entry.count > limit) {
    logger.warn(`[rate-limit] Blocked ${ip} — ${entry.count} ${tier} requests in window (limit ${limit})`);
    res.set('Retry-After', String(resetSec));
    return res.status(429).json({
      error: 'Too Many Requests',
      message: `Rate limit exceeded. Try again in ${resetSec}s.`,
      retryAfter: resetSec
    });
  }

  next();
}

// ── Auth endpoint rate limiter ────────────────────────────────
// Strict per-IP fixed-window limiter applied only to login/token routes.
// 10 requests per 15 minutes — significantly tighter than the general API
// limiter to slow brute-force and token-stuffing attempts.
const AUTH_RATE_LIMIT_WINDOW_MS = parseInt(process.env.AUTH_RATE_LIMIT_WINDOW_MS || '900000', 10); // default 15 min
const AUTH_RATE_LIMIT_MAX       = parseInt(process.env.AUTH_RATE_LIMIT_MAX       || '10',     10); // default 10 req/window

/** @type {Map<string, {count: number, windowStart: number}>} */
const authRateLimitStore = new Map();

// Evict expired auth windows on the same cadence as the general limiter
setInterval(() => {
  const now = Date.now();
  for (const [key, entry] of authRateLimitStore) {
    if (now - entry.windowStart >= AUTH_RATE_LIMIT_WINDOW_MS) {
      authRateLimitStore.delete(key);
    }
  }
}, AUTH_RATE_LIMIT_WINDOW_MS);

function authRateLimiter(req, res, next) {
  const rawIp = req.ip || req.socket.remoteAddress || 'unknown';
  const ip = rawIp.startsWith('::ffff:') ? rawIp.slice(7) : rawIp;
  const key = `auth:${ip}`;
  const now = Date.now();

  let entry = authRateLimitStore.get(key);
  if (!entry || now - entry.windowStart >= AUTH_RATE_LIMIT_WINDOW_MS) {
    entry = { count: 0, windowStart: now };
    authRateLimitStore.set(key, entry);
  }

  entry.count += 1;
  const remaining = Math.max(0, AUTH_RATE_LIMIT_MAX - entry.count);
  const resetSec = Math.ceil((entry.windowStart + AUTH_RATE_LIMIT_WINDOW_MS - now) / 1000);

  res.set('X-RateLimit-Limit', String(AUTH_RATE_LIMIT_MAX));
  res.set('X-RateLimit-Remaining', String(remaining));
  res.set('X-RateLimit-Reset', String(resetSec));

  if (entry.count > AUTH_RATE_LIMIT_MAX) {
    logger.warn(`[auth-rate-limit] Blocked ${ip} — ${entry.count} auth requests in window`);
    res.set('Retry-After', String(resetSec));
    return res.status(429).json({
      error: 'Too Many Requests',
      message: `Auth rate limit exceeded. Try again in ${resetSec}s.`,
      retryAfter: resetSec
    });
  }

  next();
}

// Prevent browsers from caching API responses
app.use('/api', (req, res, next) => {
  res.set('Cache-Control', 'no-cache');
  next();
});

// Apply rate limiting to all /api routes
app.use('/api', apiRateLimiter);

// ── API Versioning ────────────────────────────────────────────────
// /api/v1/* is an alias for /api/* — rewrites the URL before route matching
// so all 471 existing routes are available under both prefixes without duplication.
// Future breaking changes can be introduced under /api/v2/* while v1 remains stable.
app.use('/api/v1', (req, res, next) => {
  req.url = req.url === '/' ? '/' : req.url; // preserve root if needed
  // Rewrite the original URL so downstream route handlers see /api/<rest>
  const rest = req.url; // e.g. "/tasks" or "/tasks/42"
  req.url = rest;
  // Change the path so Express re-dispatches to the /api/* handler tree
  req._parsedUrl = undefined;
  // Forward to the same /api middleware stack by prefixing path back
  req.url = rest;
  next('route');
});

// Mount /api/v1/* → dispatch to existing /api/* routes
app.use('/api/v1', (req, res, next) => {
  // Remap this request to /api/<path> by re-entering the router
  const originalUrl = req.originalUrl;
  req.originalUrl = originalUrl.replace('/api/v1', '/api');
  req.baseUrl = '/api';
  next();
});

// Catch-all that actually re-dispatches /api/v1/* through the /api/* route table
// by temporarily rewriting req.url to strip the /v1 prefix, then delegating.
// Using a sub-app approach: create a thin proxy router.
const apiV1Router = express.Router();
app.use('/api/v1', apiV1Router);

// The router itself just strips /v1 from the path and forwards to next /api handler.
// We achieve this cleanly by mounting a forwarding middleware BEFORE route definitions
// using app.use at the router level — but since all routes are registered directly on
// `app`, the simplest approach is a URL rewrite at the top of the /api/v1 mount.
// Remove the stub router above and use a single clean middleware instead:

// ── Clean implementation: rewrite /api/v1/* → /api/* via sub-router ──
// (Replacing the stubs above — they are inert, but kept for documentation clarity)
// The actual working rewrite is below:
app.use('/api/v1', (req, res, next) => {
  // Reconstruct the URL as if the request came in under /api
  const suffix = req.url; // e.g. "/tasks" or "/tasks/42?foo=bar"
  req.url = suffix;
  // Re-dispatch through the full app router under /api
  app.handle(Object.assign(Object.create(req), {
    url: '/api' + suffix,
    originalUrl: req.originalUrl.replace(/^\/api\/v1/, '/api'),
    baseUrl: ''
  }), res, next);
});

// Static assets: type-specific Cache-Control durations via setHeaders so that
// express.static's own header logic cannot overwrite them with max-age=0.
// HTML: no-cache (always revalidate — entry point must never go stale).
// JS/CSS: 1 hour + stale-while-revalidate (serve stale while fetching update).
// Images: 7 days. Fonts: 30 days + immutable (never change once deployed).
app.use(express.static(path.join(__dirname, 'public'), {
  etag: true,
  lastModified: true,
  setHeaders: (res, filePath) => {
    const ext = path.extname(filePath).toLowerCase().slice(1);
    if (ext === 'html') {
      res.setHeader('Cache-Control', 'no-cache');
    } else if (['js', 'css'].includes(ext)) {
      // Short cache + must-revalidate — browser checks ETag on every load but uses cache if unchanged
      res.setHeader('Cache-Control', 'public, max-age=0, must-revalidate');
    } else if (['png', 'jpg', 'jpeg', 'gif', 'svg', 'ico', 'webp'].includes(ext)) {
      res.setHeader('Cache-Control', 'public, max-age=604800');
    } else if (['woff', 'woff2', 'ttf', 'eot'].includes(ext)) {
      res.setHeader('Cache-Control', 'public, max-age=2592000, immutable');
    }
  }
}));

// ── File upload config ─────────────────────────────────────────
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    // Ensure inbox folder exists
    if (!fs.existsSync(INBOX_PATH)) {
      fs.mkdirSync(INBOX_PATH, { recursive: true });
    }
    cb(null, INBOX_PATH);
  },
  filename: (req, file, cb) => {
    // Preserve original filename, prefix with timestamp to avoid collisions
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    cb(null, `${timestamp}_${file.originalname}`);
  }
});
const upload = multer({ storage, limits: { fileSize: 200 * 1024 * 1024 } }); // 200MB limit for project imports

// ── Context Management System Functions ──────────────────────

/**
 * Load the right context for a member based on their tier.
 * CEO gets everything summarized, ICs get focused context only.
 */
function loadContextForMember(memberId) {
  const member = db.prepare('SELECT * FROM team_members WHERE id = ?').get(memberId);
  if (!member) return '';

  const tier = member.tier;
  const dept = member.department;
  const now = localNow();

  let budget, scopes;

  switch (tier) {
    case 'board':
      budget = 50;
      scopes = ['company', 'department', 'team', 'escalated'];
      break;
    case 'c-suite':
      budget = 40;
      scopes = ['company', 'department', 'escalated'];
      break;
    case 'specialist':
      budget = 5;  // Token audit v2: reduced from 10 — context store is heavily polluted with
                   // auto-extracted garbage (6000+ items). 5 critical/high items is sufficient.
      scopes = ['department', 'team', 'personal'];
      break;
    default: // orchestrator, leader, co-leader, subagent
      budget = 3;   // Token audit v2: reduced from 8 — subagents need minimal context
      scopes = ['team', 'personal'];
      break;
  }

  // Build scope placeholders
  const scopePlaceholders = scopes.map(() => '?').join(',');

  let items = [];
  try {
    items = db.prepare(`
      SELECT * FROM context_store
      WHERE status = 'active'
      AND (
        (author_member_id = ?)
        OR (scope IN (${scopePlaceholders}) AND (department = ? OR department IS NULL OR scope = 'company'))
      )
      AND (expires_at IS NULL OR expires_at > ?)
      ORDER BY
        CASE importance WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 WHEN 'low' THEN 3 END,
        relevance_score DESC,
        updated_at DESC
      LIMIT ?
    `).all(memberId, ...scopes, dept, now, budget);
  } catch (e) {
    console.error(`[Context] Load error for member #${memberId}: ${e.message}`);
    return '';
  }

  // Also load propagated context targeted at this member
  try {
    const propagated = db.prepare(`
      SELECT cs.* FROM context_store cs
      JOIN context_propagation cp ON cp.context_id = cs.id
      WHERE cp.to_member_id = ? AND cs.status = 'active' AND cp.acknowledged = 0
      ORDER BY cs.importance DESC, cs.created_at DESC
      LIMIT 10
    `).all(memberId);
    // Merge without duplicates
    const existingIds = new Set(items.map(i => i.id));
    for (const p of propagated) {
      if (!existingIds.has(p.id)) {
        items.push(p);
        existingIds.add(p.id);
      }
    }
  } catch (_) {}

  // Token audit v4: Removed per-item access tracking writes.
  // Writing last_accessed_at + access_count for every loaded item caused write contention
  // during concurrent spawns (each spawn loads context → each triggers N updates).
  // The decay function already handles staleness via created_at age — access tracking added
  // no operational value while creating unnecessary DB pressure.

  // Load department summaries for leadership
  let deptSummary = '';
  if (tier === 'c-suite' || tier === 'board') {
    try {
      const summaries = db.prepare(`
        SELECT * FROM department_summaries
        WHERE department = ? OR ? = 'board'
        ORDER BY period_end DESC LIMIT 3
      `).all(dept, tier);

      if (summaries.length > 0) {
        deptSummary = '\n\n## Department Summaries\n';
        for (const s of summaries) {
          deptSummary += `### ${s.department} (${s.summary_type}: ${s.period_start} to ${s.period_end})\n${s.content}\n\n`;
        }
      }
    } catch (_) {}
  }

  if (items.length === 0 && !deptSummary) return '';

  // Format context grouped by type
  let contextText = '\n\n## Your Context (what you need to know)\n';

  const grouped = {};
  for (const item of items) {
    if (!grouped[item.context_type]) grouped[item.context_type] = [];
    grouped[item.context_type].push(item);
  }

  for (const [type, typeItems] of Object.entries(grouped)) {
    const label = type.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
    contextText += `\n### ${label}\n`;
    for (const item of typeItems) {
      // Token audit v4: Skip entries that are raw JSON init blobs — they contain no useful context.
      // Also truncate content to 200 chars to prevent bloat.
      const content = (item.content || '');
      if (content.startsWith('{"type":"system"') || content.startsWith('Auto-extracted') && content.includes('"type":"system"')) {
        continue; // Skip garbage JSON init metadata
      }
      const truncated = content.length > 200 ? content.slice(0, 200) + '...' : content;
      contextText += `- **${item.title}** [${item.importance}]: ${truncated}\n`;
    }
  }

  contextText += deptSummary;

  return contextText;
}

/**
 * Auto-extract context from completed task output.
 * Creates context_store entries and escalates important findings.
 */
function autoExtractContext(taskId, memberId, output) {
  const task = db.prepare('SELECT * FROM tasks WHERE id = ?').get(taskId);
  const member = db.prepare('SELECT * FROM team_members WHERE id = ?').get(memberId);
  if (!task || !member) return;

  const now = localNow();
  // Token audit v4: Aggressive garbage rejection.
  // The sanitizer doesn't fully strip raw JSON from CLI stdout (session_id, tools arrays, etc.).
  // These fragments contain words like "Tool" (triggers "unable to"), "session" (triggers "decision"),
  // "schema" (triggers "architecture") — causing 6500+ false-positive context entries.
  const sanitized = sanitizeOutputForDelivery(output || '');

  // Gate: reject output that's still raw JSON or too short to be meaningful.
  // Real agent output has sentences; garbage has JSON fragments with curly braces and colons.
  const isGarbage = !sanitized
    || sanitized.length < 50
    || sanitized.startsWith('{')
    || sanitized.startsWith('[')
    || /^\s*\{"type"/.test(sanitized)
    || (sanitized.match(/[{}[\]"]/g) || []).length > sanitized.length * 0.15;  // >15% JSON chars = garbage

  if (isGarbage) return;  // No context worth extracting

  const outputSlice = sanitized.slice(0, 200);
  // Token audit v4: Truncate titles — task titles can be 200+ chars, bloating every context entry
  const titleSlice = (task.title || '').slice(0, 80);

  // Token audit v4: Removed "discovery" entries entirely.
  // Every completed task was creating a discovery entry, resulting in 1000+ noise items in context_store.
  // The activity_log already records task completions — discovery entries add zero value.

  const lowerOutput = sanitized.toLowerCase();

  // Token audit v4: Require word-boundary matches to prevent substring false positives.
  // "session" no longer triggers "decision", "Tool" no longer triggers "unable to".
  const wordMatch = (text, word) => new RegExp(`\\b${word}\\b`).test(text);

  // Extract decisions — require explicit decision language, not substrings
  if (wordMatch(lowerOutput, 'decided') || wordMatch(lowerOutput, 'decision') || (wordMatch(lowerOutput, 'chose') && wordMatch(lowerOutput, 'over'))) {
    try {
      const result = db.prepare(`INSERT INTO context_store (author_member_id, scope, department, context_type, title, content, importance, source_task_id, source_type, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?)`)
        .run(memberId, 'department', member.department || null, 'decision',
          `Decision during: ${titleSlice}`,
          `Auto-extracted decision from task #${taskId}: ${outputSlice}`,
          'high', taskId, 'auto_extract', now, now);
      escalateContext(Number(result.lastInsertRowid));
    } catch (_) {}
  }

  // Extract blockers — require explicit blocker language
  if (wordMatch(lowerOutput, 'blocked') || wordMatch(lowerOutput, 'blocker') || lowerOutput.includes('cannot proceed')) {
    try {
      const result = db.prepare(`INSERT INTO context_store (author_member_id, scope, department, context_type, title, content, importance, source_task_id, source_type, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?)`)
        .run(memberId, 'escalated', member.department || null, 'blocker',
          `Blocker found during: ${titleSlice}`,
          `Auto-extracted blocker from task #${taskId}: ${outputSlice}`,
          'high', taskId, 'auto_extract', now, now);
      escalateContext(Number(result.lastInsertRowid));
    } catch (_) {}
  }

  // Extract patterns — require explicit pattern language (removed "convention" — too generic)
  if (lowerOutput.includes('best practice') || lowerOutput.includes('should always')) {
    try {
      db.prepare(`INSERT INTO context_store (author_member_id, scope, department, context_type, title, content, importance, source_task_id, source_type, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?)`)
        .run(memberId, 'department', member.department || null, 'pattern',
          `Pattern from: ${titleSlice}`,
          `Auto-extracted pattern from task #${taskId}: ${outputSlice}`,
          'normal', taskId, 'auto_extract', now, now);
    } catch (_) {}
  }

  // Extract architecture decisions — require explicit architecture language
  // Removed "schema" (too generic — appears in any DB task) and "migration" (too common)
  if (lowerOutput.includes('architecture change') || lowerOutput.includes('database change') || lowerOutput.includes('breaking change')) {
    try {
      const result = db.prepare(`INSERT INTO context_store (author_member_id, scope, department, context_type, title, content, importance, source_task_id, source_type, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?)`)
        .run(memberId, 'department', member.department || null, 'architecture',
          `Architecture change: ${task.title}`,
          `Auto-extracted architecture context from task #${taskId}: ${outputSlice}`,
          'high', taskId, 'auto_extract', now, now);
      escalateContext(Number(result.lastInsertRowid));
    } catch (_) {}
  }
}

/**
 * Escalate context up the management chain.
 * High/critical items propagate up two levels.
 */
function escalateContext(contextId) {
  try {
    const ctx = db.prepare('SELECT * FROM context_store WHERE id = ?').get(contextId);
    if (!ctx) return;

    const author = db.prepare('SELECT * FROM team_members WHERE id = ?').get(ctx.author_member_id);
    if (!author || !author.reports_to) return;

    const now = localNow();

    // Propagate to direct manager
    db.prepare(`INSERT INTO context_propagation (context_id, from_member_id, to_member_id, propagation_type, created_at) VALUES (?,?,?,?,?)`)
      .run(contextId, ctx.author_member_id, author.reports_to, 'escalation', now);

    // If critical or high importance, continue up the chain
    if (ctx.importance === 'critical' || ctx.importance === 'high') {
      const manager = db.prepare('SELECT * FROM team_members WHERE id = ?').get(author.reports_to);
      if (manager && manager.reports_to) {
        db.prepare(`INSERT INTO context_propagation (context_id, from_member_id, to_member_id, propagation_type, created_at) VALUES (?,?,?,?,?)`)
          .run(contextId, author.reports_to, manager.reports_to, 'escalation', now);

        // Critical goes up three levels
        if (ctx.importance === 'critical') {
          const vp = db.prepare('SELECT * FROM team_members WHERE id = ?').get(manager.reports_to);
          if (vp && vp.reports_to) {
            db.prepare(`INSERT INTO context_propagation (context_id, from_member_id, to_member_id, propagation_type, created_at) VALUES (?,?,?,?,?)`)
              .run(contextId, manager.reports_to, vp.reports_to, 'escalation', now);
          }
        }
      }
    }
  } catch (e) {
    console.error(`[Context] Escalation error: ${e.message}`);
  }
}

/**
 * Decay context relevance scores. Run hourly.
 * Items not accessed in 7+ days slowly lose relevance.
 * Very low relevance items get auto-archived after 30 days.
 */
function decayContextRelevance() {
  const now = localNow();
  try {
    // Decay items not accessed in 7+ days
    db.prepare(`
      UPDATE context_store
      SET relevance_score = MAX(0.1, relevance_score * 0.95),
          updated_at = ?
      WHERE status = 'active'
      AND (last_accessed_at IS NULL OR last_accessed_at < datetime(?, '-7 days'))
      AND importance != 'critical'
    `).run(now, now);

    // Auto-archive items with very low relevance older than 30 days
    db.prepare(`
      UPDATE context_store
      SET status = 'archived', updated_at = ?
      WHERE status = 'active'
      AND relevance_score < 0.2
      AND importance NOT IN ('critical', 'high')
      AND created_at < datetime(?, '-30 days')
    `).run(now, now);

  } catch (e) {
    console.error(`[Context] Decay error: ${e.message}`);
  }
}

// Run context decay every hour
setInterval(decayContextRelevance, 3600000);

/**
 * Generate daily department summaries.
 * Rolls up discoveries, decisions, blockers per department for executive visibility.
 */
function generateDepartmentSummaries() {
  const now = localNow();
  const today = now.split(' ')[0];

  try {
    const departments = db.prepare("SELECT DISTINCT department FROM team_members WHERE status='active' AND department IS NOT NULL").all();

    for (const { department } of departments) {
      // Check if we already generated today's summary
      const existing = db.prepare(`SELECT id FROM department_summaries WHERE department = ? AND summary_type = 'daily' AND period_start = ?`).get(department, today);
      if (existing) continue;

      // Count work done today
      let tasksCompleted = 0;
      try {
        tasksCompleted = db.prepare(`
          SELECT COUNT(*) as c FROM tasks t
          JOIN team_members tm ON t.assigned_to = tm.id
          WHERE tm.department = ? AND t.status IN ('completed','delivered')
          AND date(t.completed_at) = date(?)
        `).get(department, now).c;
      } catch (_) {}

      let tasksInProgress = 0;
      try {
        tasksInProgress = db.prepare(`
          SELECT COUNT(*) as c FROM tasks t
          JOIN team_members tm ON t.assigned_to = tm.id
          WHERE tm.department = ? AND t.status = 'in_progress'
        `).get(department).c;
      } catch (_) {}

      // Get today's context items
      let discoveries = [];
      try {
        discoveries = db.prepare(`
          SELECT title, content FROM context_store
          WHERE department = ? AND context_type = 'discovery'
          AND date(created_at) = date(?)
          ORDER BY importance DESC LIMIT 5
        `).all(department, now);
      } catch (_) {}

      let decisions = [];
      try {
        decisions = db.prepare(`
          SELECT title, content FROM context_store
          WHERE department = ? AND context_type = 'decision'
          AND date(created_at) = date(?)
        `).all(department, now);
      } catch (_) {}

      let blockers = [];
      try {
        blockers = db.prepare(`
          SELECT title, content FROM context_store
          WHERE department = ? AND context_type = 'blocker' AND status = 'active'
        `).all(department);
      } catch (_) {}

      const summary = `Tasks completed today: ${tasksCompleted}. In progress: ${tasksInProgress}.\n\n` +
        (discoveries.length > 0 ? `Key discoveries:\n${discoveries.map(d => `- ${d.title}`).join('\n')}\n\n` : '') +
        (decisions.length > 0 ? `Decisions made:\n${decisions.map(d => `- ${d.title}`).join('\n')}\n\n` : '') +
        (blockers.length > 0 ? `Active blockers:\n${blockers.map(b => `- ${b.title}`).join('\n')}` : 'No active blockers.');

      db.prepare(`INSERT INTO department_summaries (department, summary_type, period_start, period_end, content, key_decisions, key_blockers, key_discoveries, tasks_completed, tasks_in_progress, created_at) VALUES (?,?,?,?,?,?,?,?,?,?,?)`)
        .run(department, 'daily', today, today, summary,
          JSON.stringify(decisions.map(d => d.title)),
          JSON.stringify(blockers.map(b => b.title)),
          JSON.stringify(discoveries.map(d => d.title)),
          tasksCompleted, tasksInProgress, now);
    }

  } catch (e) {
    console.error(`[Context] Summary generation error: ${e.message}`);
  }
}

// Generate department summaries daily (every 24 hours)
setInterval(generateDepartmentSummaries, 86400000);
// Also run on startup after 10 seconds
setTimeout(generateDepartmentSummaries, 10000);

// ── Helpers ──────────────────────────────────────────────────

function getTagsForEntity(entityType, entityId) {
  return stmt(`
    SELECT t.id, t.name
    FROM tags t
    JOIN taggables tg ON tg.tag_id = t.id
    WHERE tg.entity_type = ? AND tg.entity_id = ?
  `).all(entityType, entityId);
}

function attachTags(rows, entityType) {
  if (rows.length === 0) return rows;
  // Batch-fetch all tags for these entity IDs in a single query to avoid N+1
  const ids = rows.map(r => r.id);
  const placeholders = ids.map(() => '?').join(',');
  const allTags = db.prepare(`
    SELECT tg.entity_id, t.id, t.name
    FROM tags t
    JOIN taggables tg ON tg.tag_id = t.id
    WHERE tg.entity_type = ? AND tg.entity_id IN (${placeholders})
  `).all(entityType, ...ids);
  const tagMap = new Map();
  for (const tag of allTags) {
    if (!tagMap.has(tag.entity_id)) tagMap.set(tag.entity_id, []);
    tagMap.get(tag.entity_id).push({ id: tag.id, name: tag.name });
  }
  return rows.map(row => ({
    ...row,
    tags: tagMap.get(row.id) || []
  }));
}

// localNow imported from lib/helpers.js
const { localNow, escHtml } = require('./lib/helpers');
