// ── Deduplicated Notification Creator ────────────────────────────
// Before creating any notification, check if an identical one exists within the last 5 minutes.
// Notification types that are silent (auto-read) — only logged, don't bother Max
var SILENT_NOTIFICATION_TYPES = ['task_status', 'task_delivered'];

function createNotification(type, title, message, taskId) {
  try {
    const recent = stmt(`SELECT id FROM notifications WHERE type = ? AND title = ? AND message = ? AND created_at > datetime('now','localtime','-5 minutes')`).get(type, title, message);
    if (recent) return null; // Skip duplicate
    // For task_delivered, mark recent task_status notifications for the same task as read
    if (type === 'task_delivered' && taskId) {
      stmt(`UPDATE notifications SET read = 1 WHERE type = 'task_status' AND task_id = ? AND created_at > datetime('now','localtime','-1 minutes')`).run(taskId);
    }
    // Silent types are auto-read — they exist in the log but don't create unread badges
    var autoRead = SILENT_NOTIFICATION_TYPES.indexOf(type) !== -1 ? 1 : 0;
    const result = stmt(`INSERT INTO notifications (type, title, message, task_id, read, created_at) VALUES (?,?,?,?,?,?)`).run(type, title, message, taskId || null, autoRead, localNow());
    return result.lastInsertRowid;
  } catch (err) {
    console.error('[Notification] Failed to create:', err.message);
    return null;
  }
}

// ── Task Dependency: Notify newly unblocked tasks ───────────────
// Called after a task reaches completed/delivered status.
// Finds tasks that depended on it and fires a notification for each
// that is now fully unblocked (all its blockers are done).
function notifyUnblockedTasks(completedTaskId, now) {
  try {
    const dependentTasks = stmt(`
      SELECT td.task_id, t.title
      FROM task_dependencies td
      JOIN tasks t ON t.id = td.task_id
      WHERE td.depends_on = ?
        AND t.status NOT IN ('completed', 'delivered')
    `).all(completedTaskId);

    for (const depTask of dependentTasks) {
      const stillBlocking = stmt(`
        SELECT COUNT(*) as cnt
        FROM task_dependencies td2
        JOIN tasks bt ON bt.id = td2.depends_on
        WHERE td2.task_id = ?
          AND bt.status NOT IN ('completed', 'delivered')
      `).get(depTask.task_id);

      if (stillBlocking.cnt === 0) {
        createNotification('task_status',
          `Task unblocked: ${depTask.title.slice(0, 80)}`,
          `All dependencies completed — "${depTask.title}" is ready to start`,
          depTask.task_id
        );
      }
    }
  } catch (e) {
    console.error('[Dependencies] Unblock notification error:', e.message);
  }
}

// ═══════════════════════════════════════════════════════════════
// ── Thrift & Forge Optimization Triggers ──────────────────────
// ═══════════════════════════════════════════════════════════════

// THRIFT_ID = 176, FORGE_ID = 16 (from team_members table)
const THRIFT_MEMBER_ID = 176;
const FORGE_MEMBER_ID = 16;

/**
 * Trigger 1: Project completion trigger.
 * When a task that belongs to a project reaches 'delivered' status,
 * queue audit tasks for both Thrift (token optimization) and Forge (skill pattern analysis).
 */
function triggerOptimizationAuditForProject(taskId, now) {
  try {
    // Check if task belongs to a project
    const projectLink = stmt(`SELECT pt.project_id, p.name as project_name
      FROM project_tasks pt JOIN projects p ON p.id = pt.project_id
      WHERE pt.task_id = ?`).get(taskId);
    if (!projectLink) return; // Task not linked to a project — skip

    const projectId = projectLink.project_id;
    const projectName = projectLink.project_name;

    // Avoid duplicate audits: skip if a Thrift/Forge audit task for this project
    // was already created in the last hour
    const recentAudit = stmt(`SELECT id FROM tasks
      WHERE title LIKE '%[Optimization Audit]%' AND title LIKE ?
      AND created_at > datetime(?, '-1 hour')
      AND status NOT IN ('completed', 'delivered')
      LIMIT 1`).get(`%project: ${projectName}%`, now);
    if (recentAudit) return; // Already queued

    // Queue Thrift audit task (token spend analysis)
    const thriftResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, created_at, updated_at)
      VALUES (?,?,?,?,?,?,?,?)`).run(
      `[Optimization Audit] Thrift: Token spend review — project: ${projectName}`,
      `Auto-triggered on project task delivery (task #${taskId}).\n\nReview the token spend for project "${projectName}" (ID: ${projectId}). Analyze cost efficiency, identify wasteful patterns, and report findings. Check active_processes and agent_activity_stream for token usage data related to this project's tasks.`,
      'routing', 'normal', THRIFT_MEMBER_ID, `project:${projectId}`, now, now
    );
    const thriftTaskId = Number(thriftResult.lastInsertRowid);
    db.prepare('INSERT OR IGNORE INTO project_tasks (project_id, task_id, created_at) VALUES (?,?,?)').run(projectId, thriftTaskId, now);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'optimization_audit_queued', ?, ?)`)
      .run(thriftTaskId, `Thrift token audit auto-triggered for project "${projectName}" after task #${taskId} delivered`, now);

    // Queue Forge audit task (skill pattern analysis)
    const forgeResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, created_at, updated_at)
      VALUES (?,?,?,?,?,?,?,?)`).run(
      `[Optimization Audit] Forge: Skill optimization & pattern analysis — project: ${projectName}`,
      `Auto-triggered on project task delivery (task #${taskId}).\n\nAnalyze completed work in project "${projectName}" (ID: ${projectId}).\n\n## STEP 1: Check existing skills\nRun: sqlite3 "../the_team.db" "SELECT id, name, category FROM skills WHERE status=\'active\' ORDER BY name;"\n\n## STEP 2: Check recent task patterns\nRun: sqlite3 "../the_team.db" "SELECT title, assigned_to FROM tasks WHERE status=\'delivered\' ORDER BY id DESC LIMIT 10;"\n\n## STEP 3: For each proposal, INSERT directly into skills_proposals\nRun: sqlite3 "../the_team.db" "INSERT INTO skills_proposals (skill_name, display_name, description, category, rationale, skill_content, target_members, proposed_by, proposal_type, parent_skill_id, status, created_at, updated_at) VALUES (\'skill-name\', \'Display Name\', \'What it does\', \'category\', \'Why this is needed — evidence from recent tasks\', \'The skill prompt content\', \'[]\', 16, \'new\', NULL, \'pending\', datetime(\'now\',\'localtime\'), datetime(\'now\',\'localtime\'));"\n\nPRIORITY ORDER: upgrade > merge > deprecate > new. Always check existing skills first.\nFor upgrades, set proposal_type=\'upgrade\' and parent_skill_id to the existing skill ID.`,
      'routing', 'normal', FORGE_MEMBER_ID, `project:${projectId}`, now, now
    );
    const forgeTaskId = Number(forgeResult.lastInsertRowid);
    db.prepare('INSERT OR IGNORE INTO project_tasks (project_id, task_id, created_at) VALUES (?,?,?)').run(projectId, forgeTaskId, now);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'optimization_audit_queued', ?, ?)`)
      .run(forgeTaskId, `Forge skill optimization audit auto-triggered for project "${projectName}" after task #${taskId} delivered`, now);

    // Notify
    createNotification('system', 'Optimization audit queued',
      `Thrift & Forge auto-triggered for project "${projectName}" after task #${taskId} was delivered`,
      thriftTaskId);

    console.log(`[OptTrigger] Project completion: queued Thrift (#${thriftTaskId}) and Forge (#${forgeTaskId}) for project "${projectName}"`);

    broadcast('task.created', { id: thriftTaskId });
    broadcast('task.created', { id: forgeTaskId });

    // Auto-spawn terminals so audit tasks actually execute
    setImmediate(() => {
      spawnMemberTerminal(thriftTaskId, THRIFT_MEMBER_ID).catch(err => {
        console.error(`[OptTrigger] Failed to spawn Thrift terminal for task #${thriftTaskId}:`, err.message);
      });
      spawnMemberTerminal(forgeTaskId, FORGE_MEMBER_ID).catch(err => {
        console.error(`[OptTrigger] Failed to spawn Forge terminal for task #${forgeTaskId}:`, err.message);
      });
    });
  } catch (err) {
    console.error('[OptTrigger] Project completion trigger error:', err.message);
  }
}

/**
 * Trigger 2: Periodic optimization audit.
 * Every 24 hours, if 5+ tasks have been delivered since the last audit,
 * auto-trigger Thrift and Forge for a global review.
 */
function periodicOptimizationAuditCheck() {
  try {
    const now = localNow();
    const lastAuditRow = stmt(`SELECT value FROM system_settings WHERE key = 'last_optimization_audit_at'`).get();
    const lastAuditAt = (lastAuditRow && lastAuditRow.value) ? lastAuditRow.value : '2000-01-01 00:00:00';

    // Run every 4 hours (was 24h — too infrequent for 1M token/day budget)
    const hoursSince = stmt(`SELECT (julianday(?) - julianday(?)) * 24 as hours`).get(now, lastAuditAt);
    if (!hoursSince || hoursSince.hours < 4) return;

    // Count delivered tasks since last audit — lowered threshold from 5 to 1
    const delivered = stmt(`SELECT COUNT(*) as c FROM tasks WHERE status = 'delivered' AND delivered_at > ?`).get(lastAuditAt);
    if (!delivered || delivered.c < 1) return; // At least 1 delivered task needed

    // Avoid duplicate: check if a periodic audit is already queued/in-progress
    const existing = stmt(`SELECT id FROM tasks
      WHERE title LIKE '%[Periodic Optimization Audit]%'
      AND status NOT IN ('completed', 'delivered')
      LIMIT 1`).get();
    if (existing) return;

    // Queue Thrift periodic audit
    const thriftResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, created_at, updated_at)
      VALUES (?,?,?,?,?,?,?,?)`).run(
      `[Periodic Optimization Audit] Thrift: 24h token spend review`,
      `Auto-triggered periodic audit. ${delivered.c} tasks delivered since last audit (${lastAuditAt}).\n\nReview overall token spend across all projects for the past 24 hours. Identify top token consumers, wasteful retry loops, and cost optimization opportunities. Report findings and recommendations.`,
      'routing', 'normal', THRIFT_MEMBER_ID, 'periodic_audit', now, now
    );
    const thriftTaskId = Number(thriftResult.lastInsertRowid);

    // Queue Forge periodic audit
    const forgeResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, created_at, updated_at)
      VALUES (?,?,?,?,?,?,?,?)`).run(
      `[Periodic Optimization Audit] Forge: 24h skill optimization & pattern analysis`,
      `Auto-triggered periodic audit. ${delivered.c} tasks delivered since last audit (${lastAuditAt}).\n\nAnalyze all recently delivered work. PRIORITY ORDER:\n1. UPGRADE — Check if existing skills underperformed on recently delivered tasks. Propose upgrades (proposal_type: 'upgrade', set parent_skill_id) for better prompts, broader coverage, or more efficient execution.\n2. MERGE — Identify overlapping skills that should be consolidated (proposal_type: 'merge', set parent_skill_id to the primary skill).\n3. DEPRECATE — Flag skills that are no longer useful (proposal_type: 'deprecate', set parent_skill_id).\n4. NEW — Only if NO existing skill covers a detected pattern, propose a new skill (proposal_type: 'new').\n\nInsert into skills_proposals (NOT directly into agent_skills). Upgrades are almost always higher value than new skills.`,
      'routing', 'normal', FORGE_MEMBER_ID, 'periodic_audit', now, now
    );
    const forgeTaskId = Number(forgeResult.lastInsertRowid);

    // Update last audit timestamp
    db.prepare(`UPDATE system_settings SET value = ?, updated_at = ? WHERE key = 'last_optimization_audit_at'`).run(now, now);

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'periodic_audit_queued', ?, ?)`)
      .run(thriftTaskId, `Periodic optimization audit: ${delivered.c} tasks delivered since ${lastAuditAt}`, now);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'periodic_audit_queued', ?, ?)`)
      .run(forgeTaskId, `Periodic optimization audit: Forge skill analysis`, now);

    createNotification('system', 'Periodic optimization audit',
      `Thrift & Forge auto-triggered: ${delivered.c} tasks delivered in the past 24h`,
      thriftTaskId);

    console.log(`[OptTrigger] Periodic: queued Thrift (#${thriftTaskId}) and Forge (#${forgeTaskId}) — ${delivered.c} tasks delivered since ${lastAuditAt}`);

    // Post to the relevant company's Board Room (use project's company, fallback to Command Base)
    const auditCompanyId = projectId ? (db.prepare(`SELECT company_id FROM projects WHERE id = ?`).get(projectId) || {}).company_id || 1 : 1;
    try {
      db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
        VALUES (?, 'Thrift', 'Token Optimization Specialist', ?, 'response', ?, ?)`)
        .run(auditCompanyId, `Starting periodic token spend analysis. ${delivered.c} tasks delivered since last audit. I'll report findings here.`, thriftTaskId, now);
      db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
        VALUES (?, 'Forge', 'Skills Architect', ?, 'response', ?, ?)`)
        .run(auditCompanyId, `Starting periodic skill gap analysis. Reviewing ${delivered.c} recently delivered tasks for patterns. Proposals will be submitted for Council approval.`, forgeTaskId, now);
      broadcast('boardroom.message', { company_id: auditCompanyId, message_type: 'response' });
    } catch (_) {}

    broadcast('task.created', { id: thriftTaskId });
    broadcast('task.created', { id: forgeTaskId });

    // Auto-spawn terminals so periodic audit tasks actually execute
    setImmediate(() => {
      spawnMemberTerminal(thriftTaskId, THRIFT_MEMBER_ID).catch(err => {
        console.error(`[OptTrigger] Failed to spawn Thrift periodic terminal for task #${thriftTaskId}:`, err.message);
      });
      spawnMemberTerminal(forgeTaskId, FORGE_MEMBER_ID).catch(err => {
        console.error(`[OptTrigger] Failed to spawn Forge periodic terminal for task #${forgeTaskId}:`, err.message);
      });
    });
  } catch (err) {
    console.error('[OptTrigger] Periodic audit check error:', err.message);
  }
}

// ── Phase 5: Generate 3-File Identity from Existing Profiles ────
function generateIdentityFiles(memberId) {
  const member = db.prepare('SELECT * FROM team_members WHERE id = ?').get(memberId);
  if (!member) return;

  const profilePath = path.join(__dirname, '..', 'Team', `${member.name.toLowerCase()}.md`);
  let profileContent = '';
  try { profileContent = fs.readFileSync(profilePath, 'utf-8'); } catch { return; }

  const now = localNow();

  // Split by ## headers
  const sections = profileContent.split(/^## /m).map(s => s.trim()).filter(Boolean);

  let soulContent = `# ${member.name} — SOUL\n\n`;
  let heartbeatContent = `# ${member.name} — HEARTBEAT\n\n`;
  let agentsContent = `# ${member.name} — AGENTS\n\n`;

  for (const section of sections) {
    const lowerSection = section.toLowerCase();
    if (lowerSection.includes('persona') || lowerSection.includes('identity') || lowerSection.includes('core skills') || lowerSection.includes('secondary skills') || lowerSection.includes('principles') || lowerSection.includes('quality bar') || lowerSection.includes('decision')) {
      soulContent += `## ${section}\n\n`;
    } else if (lowerSection.includes('methodology') || lowerSection.includes('how') || lowerSection.includes('process') || lowerSection.includes('workflow') || lowerSection.includes('steps')) {
      heartbeatContent += `## ${section}\n\n`;
    } else if (lowerSection.includes('purview') || lowerSection.includes('restriction') || lowerSection.includes('interaction') || lowerSection.includes('route') || lowerSection.includes('anti-pattern') || lowerSection.includes('when to') || lowerSection.includes('when not')) {
      agentsContent += `## ${section}\n\n`;
    } else {
      soulContent += `## ${section}\n\n`; // Default to SOUL
    }
  }

  // Save to DB (upsert)
  for (const [fileType, content] of [['soul', soulContent], ['heartbeat', heartbeatContent], ['agents', agentsContent]]) {
    const existing = db.prepare('SELECT id, version FROM agent_identity_files WHERE member_id = ? AND file_type = ?').get(memberId, fileType);
    if (existing) {
      db.prepare('UPDATE agent_identity_files SET content = ?, version = version + 1, updated_at = ? WHERE id = ?')
        .run(content, now, existing.id);
    } else {
      db.prepare('INSERT INTO agent_identity_files (member_id, file_type, file_name, content, created_at, updated_at) VALUES (?,?,?,?,?,?)')
        .run(memberId, fileType, `${fileType.toUpperCase()}.md`, content, now, now);
    }
  }
}

// Generate identity files for all active members on startup
try {
  const activeMembers = db.prepare("SELECT id FROM team_members WHERE status = 'active'").all();
  let generated = 0;
  for (const m of activeMembers) {
    try {
      // Only generate if not already present
      const existing = db.prepare('SELECT COUNT(*) as c FROM agent_identity_files WHERE member_id = ?').get(m.id);
      if (existing.c === 0) {
        generateIdentityFiles(m.id);
        generated++;
      }
    } catch (e) { /* skip individual failures */ }
  }
} catch (e) {
}

// ── Goal Progress Recalculation ────────────────────────────────
function recalcGoalProgress(goalId) {
  try {
    const total = db.prepare('SELECT COUNT(*) as c FROM task_goals WHERE goal_id = ?').get(goalId).c;
    const completed = db.prepare(`
      SELECT COUNT(*) as c FROM task_goals tg
      JOIN tasks t ON tg.task_id = t.id
      WHERE tg.goal_id = ? AND t.status IN ('completed','delivered')
    `).get(goalId).c;
    const progress = total > 0 ? Math.round((completed / total) * 100) : 0;
    db.prepare('UPDATE goals SET progress = ?, updated_at = ? WHERE id = ?').run(progress, localNow(), goalId);

    // Recurse to parent
    const goal = db.prepare('SELECT parent_goal_id FROM goals WHERE id = ?').get(goalId);
    if (goal && goal.parent_goal_id) recalcGoalProgress(goal.parent_goal_id);
  } catch (err) {
    console.error(`[GoalProgress] Error recalculating goal ${goalId}: ${err.message}`);
  }
}

// After a task status changes, recalc all linked goals
function recalcGoalsForTask(taskId) {
  try {
    const links = db.prepare('SELECT goal_id FROM task_goals WHERE task_id = ?').all(taskId);
    for (const link of links) {
      recalcGoalProgress(link.goal_id);
    }
  } catch (_) {}
}

// ── Save Activity Event Helper ──────────────────────────────────
function saveActivityEvent(processId, taskId, memberId, sessionId, eventType, filePath, detail) {
  try {
    const fileName = filePath ? path.basename(filePath) : null;
    stmt(`INSERT INTO agent_activity_stream (process_id, task_id, member_id, session_id, event_type, file_path, file_name, detail, created_at) VALUES (?,?,?,?,?,?,?,?,?)`)
      .run(processId, taskId || null, memberId, sessionId || null, eventType, filePath || null, fileName, detail || null, localNow());
    // FIX: Sanitize detail before broadcasting to prevent credential/path leaks to all clients
    const safeDet = (detail || '').replace(/[a-zA-Z0-9+/=_-]+@[^\s]+/g, '[REDACTED]').replace(/api[_-]?key['":\s]*[a-zA-Z0-9_-]{10,}/gi, '[API_KEY_REDACTED]').slice(0, 500);
    broadcast('agent.activity', { process_id: processId, task_id: taskId, member_id: memberId, event_type: eventType, file_name: fileName, detail: safeDet });
  } catch (err) {
    console.error(`[ActivityStream] Failed to save event: ${err.message}`);
  }
}

// ── Phase 4: Budget Enforcement Functions ──────────────────────────

function checkBudget(memberId, estimatedCostCents) {
  const now = localNow();
  // Check member-specific policies
  const memberPolicy = stmt(`SELECT * FROM budget_policies WHERE member_id = ? AND status = 'active'`).get(memberId);
  // Check global policy
  const globalPolicy = stmt(`SELECT * FROM budget_policies WHERE scope = 'global' AND status = 'active' AND member_id IS NULL`).get();

  const policy = memberPolicy || globalPolicy;
  if (!policy) return { allowed: true }; // No policy = no limit

  if (policy.spent_cents + estimatedCostCents > policy.limit_cents) {
    // Budget exceeded
    if (policy.action_at_limit === 'block') {
      return { allowed: false, reason: 'Budget limit reached', policy };
    }
    if (policy.action_at_limit === 'pause') {
      // Atomic: update policy + log incident + create notification in one transaction
      db.transaction(() => {
        stmt(`UPDATE budget_policies SET status = 'exhausted', updated_at = ? WHERE id = ?`).run(now, policy.id);
        stmt(`INSERT INTO budget_incidents (policy_id, member_id, incident_type, spent_cents, limit_cents, message, created_at) VALUES (?,?,?,?,?,?,?)`)
          .run(policy.id, memberId, 'limit_reached', policy.spent_cents, policy.limit_cents, 'Auto-paused: budget limit reached', now);
        createNotification('system', 'Budget Limit', `Agent budget exhausted ($${(policy.spent_cents / 100).toFixed(2)} of $${(policy.limit_cents / 100).toFixed(2)})`);
      })();
      broadcast('budget.exhausted', { policy_id: policy.id, member_id: memberId });
      return { allowed: false, reason: 'Budget exhausted and auto-paused', policy };
    }
    // warn or notify — allow but log
    db.transaction(() => {
      stmt(`INSERT INTO budget_incidents (policy_id, member_id, incident_type, spent_cents, limit_cents, message, created_at) VALUES (?,?,?,?,?,?,?)`)
        .run(policy.id, memberId, 'threshold_warning', policy.spent_cents, policy.limit_cents, 'Budget threshold exceeded', now);
      createNotification('system', 'Budget Warning', `Spending exceeded budget limit ($${(policy.spent_cents / 100).toFixed(2)} of $${(policy.limit_cents / 100).toFixed(2)})`);
    })();
    broadcast('budget.warning', { policy_id: policy.id, member_id: memberId });
  }

  // Check threshold warning
  const thresholdCents = Math.floor(policy.limit_cents * (policy.threshold_percent / 100));
  if (policy.spent_cents >= thresholdCents && policy.spent_cents - estimatedCostCents < thresholdCents) {
    db.transaction(() => {
      stmt(`INSERT INTO budget_incidents (policy_id, member_id, incident_type, spent_cents, limit_cents, message, created_at) VALUES (?,?,?,?,?,?,?)`)
        .run(policy.id, memberId, 'threshold_warning', policy.spent_cents, policy.limit_cents, `Spending at ${policy.threshold_percent}% of limit`, now);
      createNotification('system', 'Budget Warning', `Agent spending at ${policy.threshold_percent}% of budget limit`);
    })();
  }

  return { allowed: true, policy };
}

function recordCostEvent(memberId, taskId, processId, heartbeatRunId, adapterType, model, inputTokens, outputTokens, costCents) {
  const now = localNow();
  // Single transaction: insert cost event + update all matching budget policies atomically
  db.transaction(() => {
    stmt(`INSERT INTO cost_events (member_id, task_id, process_id, heartbeat_run_id, adapter_type, model, input_tokens, output_tokens, total_tokens, cost_cents, created_at) VALUES (?,?,?,?,?,?,?,?,?,?,?)`)
      .run(memberId, taskId || null, processId || null, heartbeatRunId || null, adapterType || null, model || null, inputTokens || 0, outputTokens || 0, (inputTokens || 0) + (outputTokens || 0), costCents || 0, now);

    // Update policy spent
    const policies = stmt(`SELECT * FROM budget_policies WHERE (member_id = ? OR (scope = 'global' AND member_id IS NULL)) AND status = 'active'`).all(memberId);
    for (const policy of policies) {
      stmt(`UPDATE budget_policies SET spent_cents = spent_cents + ?, updated_at = ? WHERE id = ?`).run(costCents || 0, now, policy.id);
    }
  })();
}

// ── Dashboard ────────────────────────────────────────────────────

app.get('/api/dashboard', (req, res) => {
  try {
    // Wrap all reads in a single transaction for consistent snapshot + fewer locks
    const getDashboard = db.transaction(() => {
      const taskCounts = stmt(`
        SELECT status, COUNT(*) as count FROM tasks GROUP BY status
      `).all();

      const openTasks = stmt(`
        SELECT t.id, t.title, t.status, t.priority, t.current_step, tm.name as assignee_name,
          p.name as project_name, p.id as project_id, p.color as project_color
        FROM tasks t
        LEFT JOIN team_members tm ON t.assigned_to = tm.id
        LEFT JOIN project_tasks pt ON pt.task_id = t.id
        LEFT JOIN projects p ON pt.project_id = p.id
        WHERE t.status NOT IN ('completed', 'delivered')
        ORDER BY
          CASE t.priority WHEN 'urgent' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 WHEN 'low' THEN 3 END,
          t.created_at DESC
      `).all();

      const recentActivity = stmt(`
        SELECT a.*, t.title as task_title
        FROM activity_log a
        LEFT JOIN tasks t ON a.task_id = t.id
        ORDER BY a.created_at DESC
        LIMIT 10
      `).all();

      // action_items table does not exist yet — guard against crash
      let actionItems = [];
      try {
        actionItems = stmt(`
          SELECT ai.*, n.title as note_title, t.title as task_title
          FROM action_items ai
          LEFT JOIN notes n ON ai.note_id = n.id
          LEFT JOIN tasks t ON ai.task_id = t.id
          WHERE ai.status IN ('pending', 'needs_max')
          ORDER BY
            CASE ai.priority WHEN 'urgent' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 WHEN 'low' THEN 3 END,
            ai.created_at DESC
        `).all();
      } catch (_) {}

      const pendingDecisions = stmt(`
        SELECT d.*, t.title as task_title
        FROM decisions d
        LEFT JOIN tasks t ON d.task_id = t.id
        WHERE d.status = 'pending'
        ORDER BY d.asked_at DESC
      `).all();

      const teamCount = stmt(`SELECT COUNT(*) as count FROM team_members WHERE status = 'active'`).get();
      const noteCount = stmt(`SELECT COUNT(*) as count FROM notes`).get();
      const contactCount = stmt(`SELECT COUNT(*) as count FROM contacts`).get();

      const completedToday = stmt(`
        SELECT t.id, t.title, t.status, t.updated_at, tm.name as assignee_name
        FROM tasks t
        LEFT JOIN team_members tm ON t.assigned_to = tm.id
        WHERE t.status IN ('completed', 'delivered')
          AND date(t.updated_at) = date('now', 'localtime')
        ORDER BY t.updated_at DESC
        LIMIT 20
      `).all();

      // Work distribution data
      let distribution = { score: 0, members_with_work: 0, total_eligible: 0, top_5: [], bottom_5: [] };
      try {
        const distRows = stmt(`
          SELECT tm.name,
            (SELECT COUNT(*) FROM active_processes WHERE member_id = tm.id AND status = 'completed') as tasks
          FROM team_members tm
          WHERE tm.status = 'active' AND tm.tier = 'specialist'
          ORDER BY tasks DESC
        `).all();
        const withWork = distRows.filter(d => d.tasks > 0).length;
        distribution = {
          score: distRows.length > 0 ? Math.round((withWork / distRows.length) * 100) : 0,
          members_with_work: withWork,
          total_eligible: distRows.length,
          top_5: distRows.slice(0, 5).map(d => ({ name: d.name, tasks: d.tasks })),
          bottom_5: distRows.slice(-5).map(d => ({ name: d.name, tasks: d.tasks }))
        };
      } catch (_) {}

      return {
        taskCounts,
        openTasks,
        recentActivity,
        actionItems,
        pendingDecisions,
        completedToday,
        distribution,
        stats: {
          activeTeam: teamCount.count,
          totalNotes: noteCount.count,
          totalContacts: contactCount.count
        }
      };
    });

    res.json(getDashboard());
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── Command Base (unified dashboard endpoint) ──────────────────

app.get('/api/command-center', (req, res) => {
  try {
    const now = localNow();

    // Single transaction: consistent snapshot + eliminates N+1 queries
    const getCommandCenter = db.transaction(() => {
    // Projects with executives
    const projects = stmt(`
      SELECT p.*, pe.member_id as exec_id, tm.name as exec_name
      FROM projects p
      LEFT JOIN project_executives pe ON pe.project_id = p.id
      LEFT JOIN team_members tm ON pe.member_id = tm.id
      WHERE p.status != 'archived'
    `).all();

    // Batch-fetch running agent counts per project (eliminates N+1)
    const runningByProject = stmt(`
      SELECT pt.project_id, COUNT(*) as c FROM active_processes ap
      JOIN tasks t ON ap.task_id = t.id
      JOIN project_tasks pt ON pt.task_id = t.id
      WHERE ap.status = 'running'
      GROUP BY pt.project_id
    `).all();
    const runningMap = new Map(runningByProject.map(r => [r.project_id, r.c]));

    // Batch-fetch completed-today counts per project (eliminates N+1)
    const completedByProject = stmt(`
      SELECT project_id, COUNT(*) as c FROM project_improvements
      WHERE status = 'completed' AND date(completed_at) = date(?)
      GROUP BY project_id
    `).all(now);
    const completedMap = new Map(completedByProject.map(r => [r.project_id, r.c]));

    // Batch-fetch current work per project (eliminates N+1)
    const currentWorkRows = stmt(`
      SELECT pt.project_id, t.title as task_title FROM active_processes ap
      JOIN tasks t ON ap.task_id = t.id
      JOIN project_tasks pt ON pt.task_id = t.id
      WHERE ap.status = 'running'
      ORDER BY ap.id DESC
    `).all();
    const workMap = new Map();
    for (const w of currentWorkRows) {
      if (!workMap.has(w.project_id)) workMap.set(w.project_id, w.task_title);
    }

    // Enrich projects from pre-fetched maps (O(1) per project)
    for (const p of projects) {
      p.running_agents = runningMap.get(p.id) || 0;
      p.completed_today = completedMap.get(p.id) || 0;
      p.current_activity = workMap.get(p.id) || null;
    }

    // Agent stats
    const totalActive = stmt(`SELECT COUNT(*) as c FROM team_members WHERE status = 'active'`).get().c;
    const runningAgents = stmt(`SELECT COUNT(*) as c FROM active_processes WHERE status = 'running'`).get().c;

    // Today's stats
    const completedToday = stmt(`SELECT COUNT(*) as c FROM tasks WHERE status IN ('completed','delivered') AND date(COALESCE(completed_at, updated_at)) = date(?)`).get(now).c;
    const failedToday = stmt(`SELECT COUNT(*) as c FROM active_processes WHERE status = 'failed' AND date(COALESCE(completed_at, started_at)) = date(?)`).get(now).c;

    // Live activity feed (last 20 events)
    const feed = stmt(`
      SELECT al.*, tm.name as actor_name FROM activity_log al
      LEFT JOIN team_members tm ON al.actor = tm.name
      ORDER BY al.id DESC LIMIT 20
    `).all();

    // Blockers and escalations
    const blockers = stmt(`
      SELECT cs.*, tm.name as author_name FROM context_store cs
      LEFT JOIN team_members tm ON cs.author_member_id = tm.id
      WHERE cs.context_type IN ('blocker','escalation') AND cs.status = 'active'
      ORDER BY cs.created_at DESC LIMIT 10
    `).all();

    // Budget — FIX: null-check .get() results to prevent crash when no data exists
    const budgetPolicy = stmt(`SELECT * FROM budget_policies WHERE scope = 'global' AND status = 'active' LIMIT 1`).get() || null;
    const todayCost = (stmt(`SELECT COALESCE(SUM(cost_cents),0) as c FROM cost_events WHERE date(created_at) = date(?)`).get(now) || {}).c || 0;
    const monthCost = (stmt(`SELECT COALESCE(SUM(cost_cents),0) as c FROM cost_events WHERE strftime('%Y-%m', created_at) = strftime('%Y-%m', ?)`).get(now) || {}).c || 0;

    // Autonomous status
    const autoEnabled = stmt(`SELECT value FROM system_settings WHERE key = 'auto_execute_improvements'`).get();
    const autoStatus = {
      enabled: autoEnabled && autoEnabled.value === '1',
      queued: stmt(`SELECT COUNT(*) as c FROM improvement_proposals WHERE status = 'queued'`).get().c,
      completed_today: stmt(`SELECT COUNT(*) as c FROM improvement_proposals WHERE status = 'completed' AND date(completed_at) = date(?)`).get(now).c,
      in_progress: stmt(`SELECT COUNT(*) as c FROM improvement_proposals WHERE status = 'in_progress'`).get().c
    };

    // Get previous last_visit BEFORE updating
    const prevVisit = stmt(`SELECT value FROM system_settings WHERE key = 'max_last_visit'`).get();
    const lastVisit = prevVisit ? prevVisit.value : null;

    // Only update last_visit once per session (>5 min gap) to prevent
    // "Since You Left" data from disappearing on re-renders
    const shouldUpdate = !lastVisit || (new Date(now).getTime() - new Date(lastVisit).getTime() > 5 * 60 * 1000);
    if (shouldUpdate) {
      stmt(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('max_last_visit', ?, ?)`).run(now, now);
    }

    // Work distribution score
    let distribution = { score: 0, members_with_work: 0, total_eligible: 0 };
    try {
      const distRows = stmt(`
        SELECT tm.name,
          (SELECT COUNT(*) FROM active_processes WHERE member_id = tm.id AND status = 'completed') as tasks
        FROM team_members tm
        WHERE tm.status = 'active' AND tm.tier = 'specialist'
      `).all();
      const withWork = distRows.filter(d => d.tasks > 0).length;
      distribution = {
        score: distRows.length > 0 ? Math.round((withWork / distRows.length) * 100) : 0,
        members_with_work: withWork,
        total_eligible: distRows.length
      };
    } catch (_) {}

    return {
      projects,
      agents: { total: totalActive, running: runningAgents, idle: totalActive - runningAgents },
      today: { completed: completedToday, failed: failedToday },
      feed,
      blockers,
      budget: {
        policy: budgetPolicy,
        today_cents: todayCost,
        month_cents: monthCost
      },
      autonomous: autoStatus,
      distribution,
      local_mode: isLocalMode(),
      last_visit: lastVisit,
      timestamp: now
    };
    }); // end getCommandCenter transaction

    res.json(getCommandCenter());
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── Session Replay ───────────────────────────────────────────────

app.get('/api/session-replay', (req, res) => {
  try {
    const since = req.query.since || new Date(Date.now() - 24*60*60*1000).toLocaleString('sv-SE', { timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone }).slice(0, 19);

    // Gather ALL events since the timestamp
    const events = [];

    // Activity log entries
    const activities = db.prepare(`SELECT * FROM activity_log WHERE created_at > ? ORDER BY created_at ASC`).all(since);
    events.push(...activities.map(a => ({
      time: a.created_at,
      type: a.action,
      actor: a.actor,
      detail: a.notes,
      task_id: a.task_id,
      source: 'activity'
    })));

    // Completed improvements
    const improvements = db.prepare(`SELECT * FROM improvement_proposals WHERE status = 'completed' AND completed_at > ? ORDER BY completed_at ASC`).all(since);
    events.push(...improvements.map(i => ({
      time: i.completed_at,
      type: 'improvement_completed',
      actor: i.proposed_by,
      detail: 'Improvement completed: ' + i.title,
      source: 'improvement'
    })));

    // Escalations
    const escalations = db.prepare(`
      SELECT cs.*, tm.name as author_name FROM context_store cs
      LEFT JOIN team_members tm ON cs.author_member_id = tm.id
      WHERE cs.context_type IN ('blocker','escalation') AND cs.created_at > ?
      ORDER BY cs.created_at ASC
    `).all(since);
    events.push(...escalations.map(e => ({
      time: e.created_at,
      type: 'escalation',
      actor: e.author_name,
      detail: (e.title || '') + ': ' + (e.content || ''),
      source: 'escalation'
    })));

    // Process spawns and completions
    const processes = db.prepare(`
      SELECT ap.*, tm.name as member_name, t.title as task_title
      FROM active_processes ap
      JOIN team_members tm ON ap.member_id = tm.id
      LEFT JOIN tasks t ON ap.task_id = t.id
      WHERE ap.started_at > ? OR ap.completed_at > ?
      ORDER BY COALESCE(ap.completed_at, ap.started_at) ASC
    `).all(since, since);
    events.push(...processes.map(p => ({
      time: p.completed_at || p.started_at,
      type: p.status === 'completed' ? 'agent_completed' : p.status === 'failed' ? 'agent_failed' : 'agent_spawned',
      actor: p.member_name,
      detail: p.member_name + ' ' + p.status + ' on "' + (p.task_title || 'unknown task') + '"',
      source: 'process'
    })));

    // Sort by time
    events.sort((a, b) => (a.time || '').localeCompare(b.time || ''));

    // Group into time buckets (every hour for readability)
    const buckets = {};
    for (const event of events) {
      if (!event.time) continue;
      const bucket = event.time.slice(0, 13) + ':00'; // Round to hour
      if (!buckets[bucket]) buckets[bucket] = [];
      buckets[bucket].push(event);
    }

    // Summary stats
    const summary = {
      since,
      total_events: events.length,
      tasks_completed: events.filter(e => e.type === 'agent_completed' || e.type === 'improvement_completed').length,
      tasks_failed: events.filter(e => e.type === 'agent_failed').length,
      escalations: events.filter(e => e.type === 'escalation').length,
      hours_covered: ((Date.now() - new Date(since.replace(' ','T')).getTime()) / 3600000).toFixed(1)
    };

    res.json({ summary, events, buckets });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── Tasks ────────────────────────────────────────────────────────

app.get('/api/tasks', (req, res) => {
  try {
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 100;
    const offset = (page - 1) * limit;

    const total = stmt(`SELECT COUNT(*) as count FROM tasks`).get().count;

    // FIX: Use SUBSTR on description to prevent 300KB+ responses from bloated retry descriptions.
    // Full description is available via GET /api/tasks/:id for individual task view.
    const rows = db.prepare(`
      SELECT t.id, t.title, SUBSTR(t.description, 1, 300) as description, t.source_file,
        t.assigned_to, t.status, t.priority, t.created_at, t.updated_at, t.completed_at,
        t.delivered_at, t.revision_count, t.subagent_count, t.progress, t.current_step,
        t.started_at, t.origin, t.workflow, t.is_pinned, t.original_priority,
        tm.name as assignee_name,
        p.name as project_name, p.id as project_id, p.color as project_color,
        (SELECT COUNT(*) FROM task_dependencies td
          JOIN tasks bt ON bt.id = td.depends_on
          WHERE td.task_id = t.id AND bt.status NOT IN ('completed','delivered')
        ) as blocking_count
      FROM tasks t
      LEFT JOIN team_members tm ON t.assigned_to = tm.id
      LEFT JOIN project_tasks pt ON pt.task_id = t.id
      LEFT JOIN projects p ON pt.project_id = p.id
      ORDER BY
        CASE t.status
          WHEN 'new' THEN 0 WHEN 'routing' THEN 1 WHEN 'in_progress' THEN 2
          WHEN 'review' THEN 3 WHEN 'completed' THEN 4 WHEN 'delivered' THEN 5
        END,
        CASE t.priority WHEN 'urgent' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 WHEN 'low' THEN 3 END,
        t.created_at DESC
      LIMIT ? OFFSET ?
    `).all(limit, offset);

    const tasks = attachTags(rows, 'task');

    // Also grab files for each task — use stmt() cache to avoid re-parsing SQL
    const filesS = stmt(`SELECT * FROM task_files WHERE task_id = ?`);
    const activityS = stmt(`SELECT * FROM activity_log WHERE task_id = ? ORDER BY created_at DESC`);
    const checkoutS = stmt(`SELECT tc.*, tm.name as member_name FROM task_checkouts tc JOIN team_members tm ON tc.member_id = tm.id WHERE tc.task_id = ? AND tc.status = 'active'`);

    const enriched = tasks.map(task => {
      const checkout = checkoutS.get(task.id);
      return {
        ...task,
        files: filesS.all(task.id),
        activity: activityS.all(task.id),
        checkout: checkout || null
      };
    });

    res.json({ tasks: enriched, total, page, limit });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/tasks — create a task directly ──

app.post('/api/tasks', (req, res) => {
  try {
    const { title, description, priority, assigned_to, status } = req.body;
    if (!title || !title.trim()) {
      return res.status(400).json({ error: 'title is required' });
    }

    // Max-length validation: cap description at 10KB
    const MAX_DESCRIPTION_BYTES = 10 * 1024; // 10KB
    if (description && Buffer.byteLength(String(description), 'utf8') > MAX_DESCRIPTION_BYTES) {
      return res.status(413).json({ error: `Description exceeds maximum size of 10KB` });
    }

    const taskStatus = ['new', 'routing', 'in_progress', 'review', 'completed', 'delivered'].includes(status) ? status : 'new';
    const taskPriority = ['low', 'normal', 'high', 'urgent'].includes(priority) ? priority : 'normal';
    const now = localNow();

    const task = db.transaction(() => {
      const result = stmt(`
        INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
      `).run(
        title.trim(),
        (description || '').trim() || null,
        taskStatus,
        taskPriority,
        assigned_to || null,
        'api',
        now,
        now
      );

      const taskId = Number(result.lastInsertRowid);

      // ExoForge Swap 3: Auto-detect workflow type
      try {
        const detectedWorkflow = detectWorkflowType(title, description);
        stmt(`UPDATE tasks SET workflow = ? WHERE id = ?`).run(detectedWorkflow, taskId);
      } catch (_) {}

      // Log activity
      stmt(`
        INSERT INTO activity_log (task_id, actor, action, notes, created_at)
        VALUES (?, 'System', 'created_task', ?, ?)
      `).run(taskId, `Task created via API: ${title.trim().slice(0, 200)}`, now);

      // Create notification
      createNotification('task_status', `New task: ${title.trim().slice(0, 100)}`, `Task #${taskId} created via API`, taskId);

      return stmt(`SELECT * FROM tasks WHERE id = ?`).get(taskId);
    })();

    res.json(task);
    broadcast('task.updated', { id: task.id });
  } catch (err) {
    console.error('POST /api/tasks error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/tasks/bulk — bulk update status, priority, or assignee ──

app.post('/api/tasks/bulk', (req, res) => {
  try {
    const { ids, action, value } = req.body;
    if (!Array.isArray(ids) || ids.length === 0) {
      return res.status(400).json({ error: 'ids must be a non-empty array' });
    }
    const validActions = ['status', 'priority', 'assign', 'delete'];
    if (!validActions.includes(action)) {
      return res.status(400).json({ error: 'action must be one of: status, priority, assign, delete' });
    }
    if (action !== 'delete' && (value === undefined || value === null || value === '')) {
      return res.status(400).json({ error: 'value is required' });
    }

    const validStatuses = ['new', 'routing', 'in_progress', 'review', 'completed', 'delivered'];
    const validPriorities = ['low', 'normal', 'high', 'urgent'];

    if (action === 'status' && !validStatuses.includes(value)) {
      return res.status(400).json({ error: 'Invalid status. Must be one of: ' + validStatuses.join(', ') });
    }
    if (action === 'priority' && !validPriorities.includes(value)) {
      return res.status(400).json({ error: 'Invalid priority. Must be one of: ' + validPriorities.join(', ') });
    }
    if (action === 'assign') {
      const member = stmt(`SELECT id FROM team_members WHERE id = ?`).get(Number(value));
      if (!member) return res.status(400).json({ error: 'Team member not found' });
    }

    const now = localNow();
    let updated = 0;

    const bulkUpdate = db.transaction(() => {
      for (const rawId of ids) {
        const id = Number(rawId);
        if (!Number.isInteger(id) || id <= 0) continue;
        const task = stmt(`SELECT * FROM tasks WHERE id = ?`).get(id);
        if (!task) continue;

        if (action === 'status') {
          const updates = ['status = ?', 'updated_at = ?'];
          const vals = [value, now];
          if (value === 'in_progress' && !task.started_at) { updates.push('started_at = ?'); vals.push(now); }
          if (value === 'completed') { updates.push('completed_at = ?'); vals.push(now); }
          if (value === 'delivered') {
            if (!task.completed_at) { updates.push('completed_at = ?'); vals.push(now); }
            updates.push('delivered_at = ?'); vals.push(now);
          }
          vals.push(id);
          db.prepare(`UPDATE tasks SET ${updates.join(', ')} WHERE id = ?`).run(...vals);
          db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'bulk_update', ?, ?)`)
            .run(id, `Bulk status change to ${value}`, now);
        } else if (action === 'priority') {
          const vals = [value, now, id];
          const extra = task.original_priority ? '' : ', original_priority = ?';
          if (!task.original_priority) vals.splice(2, 0, task.priority);
          db.prepare(`UPDATE tasks SET priority = ?, updated_at = ?${extra} WHERE id = ?`).run(...vals);
          db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'bulk_update', ?, ?)`)
            .run(id, `Bulk priority change to ${value}`, now);
        } else if (action === 'assign') {
          db.prepare(`UPDATE tasks SET assigned_to = ?, updated_at = ? WHERE id = ?`).run(Number(value), now, id);
          db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'bulk_update', ?, ?)`)
            .run(id, `Bulk reassign to member #${value}`, now);
        } else if (action === 'delete') {
          stmt(`DELETE FROM task_files WHERE task_id = ?`).run(id);
          stmt(`DELETE FROM task_assignments WHERE task_id = ?`).run(id);
          stmt(`DELETE FROM activity_log WHERE task_id = ?`).run(id);
          stmt(`DELETE FROM project_tasks WHERE task_id = ?`).run(id);
          stmt(`DELETE FROM notifications WHERE task_id = ?`).run(id);
          stmt(`DELETE FROM task_dependencies WHERE task_id = ? OR depends_on = ?`).run(id, id);
          stmt(`DELETE FROM taggables WHERE entity_type = 'task' AND entity_id = ?`).run(id);
          stmt(`DELETE FROM mission_tasks WHERE task_id = ?`).run(id);
          try { stmt(`DELETE FROM task_goals WHERE task_id = ?`).run(id); } catch (_) {}
          try { stmt(`DELETE FROM task_comments WHERE task_id = ?`).run(id); } catch (_) {}
          try { stmt(`DELETE FROM task_custom_field_values WHERE task_id = ?`).run(id); } catch (_) {}
          stmt(`DELETE FROM tasks WHERE id = ?`).run(id);
        }
        updated++;
      }
    });

    bulkUpdate();

    // Thrift & Forge optimization trigger for bulk deliveries
    if (action === 'status' && value === 'delivered') {
      for (const rawId of ids) {
        const id = Number(rawId);
        if (Number.isInteger(id) && id > 0) {
          setImmediate(() => triggerOptimizationAuditForProject(id, now));
        }
      }
    }

    broadcast('tasks.bulk_updated', { count: updated });
    res.json({ updated, action, value });
  } catch (err) {
    console.error('POST /api/tasks/bulk error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── GET /api/tasks/:id — single task by ID ──

app.get('/api/tasks/:id', (req, res) => {
  try {
    const task = stmt(`
      SELECT t.*, tm.name as assignee_name,
        p.name as project_name, p.id as project_id, p.color as project_color
      FROM tasks t
      LEFT JOIN team_members tm ON t.assigned_to = tm.id
      LEFT JOIN project_tasks pt ON pt.task_id = t.id
      LEFT JOIN projects p ON pt.project_id = p.id
      WHERE t.id = ?
    `).get(req.params.id);

    if (!task) return res.status(404).json({ error: 'Task not found' });

    // Enrich with tags, files, activity, action items, and assignments
    task.tags = getTagsForEntity('task', task.id);
    task.files = stmt(`SELECT * FROM task_files WHERE task_id = ?`).all(task.id);
    task.activity = stmt(`SELECT * FROM activity_log WHERE task_id = ? ORDER BY created_at DESC`).all(task.id);
    task.assignments = stmt(`
      SELECT ta.*, tm.name as member_name, tm.role as member_role
      FROM task_assignments ta
      LEFT JOIN team_members tm ON ta.member_id = tm.id
      WHERE ta.task_id = ?
    `).all(task.id);
    task.custom_fields = stmt(`
      SELECT d.id as field_id, d.name, d.label, d.field_type, d.options, d.position, v.value
      FROM task_custom_field_definitions d
      LEFT JOIN task_custom_field_values v ON v.field_id = d.id AND v.task_id = ?
      ORDER BY d.position, d.id
    `).all(task.id);

    res.json(task);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── PUT /api/tasks/:id — update task fields ──

app.put('/api/tasks/:id', (req, res) => {
  try {
    // Validate status if provided
    if (req.body.status !== undefined) {
      const validStatuses = ['new', 'routing', 'in_progress', 'review', 'completed', 'delivered'];
      if (!validStatuses.includes(req.body.status)) {
        return res.status(400).json({ error: 'Invalid status. Must be one of: new, routing, in_progress, review, completed, delivered' });
      }
    }

    // Validate priority if provided
    if (req.body.priority !== undefined) {
      const validPriorities = ['low', 'normal', 'high', 'urgent'];
      if (!validPriorities.includes(req.body.priority)) {
        return res.status(400).json({ error: 'Invalid priority. Must be one of: low, normal, high, urgent' });
      }
    }

    const task = stmt(`SELECT * FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    // Max-length validation: cap description at 10KB
    const MAX_DESCRIPTION_BYTES = 10 * 1024; // 10KB
    if (req.body.description !== undefined && Buffer.byteLength(String(req.body.description), 'utf8') > MAX_DESCRIPTION_BYTES) {
      return res.status(413).json({ error: `Description exceeds maximum size of 10KB` });
    }

    const allowedFields = ['title', 'description', 'status', 'priority', 'assigned_to'];
    const updates = [];
    const values = [];
    const now = localNow();

    for (const f of allowedFields) {
      if (req.body[f] !== undefined) {
        updates.push(`${f} = ?`);
        values.push(req.body[f]);
      }
    }

    if (updates.length === 0) return res.status(400).json({ error: 'No fields to update' });

    // Backfill original_priority if not already set and priority is being changed
    if (req.body.priority !== undefined && !task.original_priority) {
      updates.push('original_priority = ?');
      values.push(task.priority);
    }

    // Set timestamps on status transitions
    if (req.body.status === 'in_progress' && !task.started_at) {
      updates.push('started_at = ?');
      values.push(now);
    }
    if (req.body.status === 'completed') {
      updates.push('completed_at = ?');
      values.push(now);
    }
    if (req.body.status === 'delivered') {
      if (!task.completed_at) {
        updates.push('completed_at = ?');
        values.push(now);
      }
      updates.push('delivered_at = ?');
      values.push(now);
    }

    updates.push('updated_at = ?');
    values.push(now);
    values.push(req.params.id);

    // Wrap all writes in a single transaction — reduces N implicit WAL syncs
    // to one, improving throughput and guaranteeing atomicity across the
    // task update, activity log, wakeup request, comment, and goal recalc.
    const newStatus = req.body.status;
    const newAssignee = req.body.assigned_to;
    const changed = allowedFields.filter(f => req.body[f] !== undefined).join(', ');

    db.transaction(() => {
      db.prepare(`UPDATE tasks SET ${updates.join(', ')} WHERE id = ?`).run(...values);

      // Log the update
      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'task_updated', ?, ?)`)
        .run(req.params.id, `Updated fields: ${changed}`, now);

      // Paperclip: Create wakeup request when task is assigned
      if (newAssignee && Number(newAssignee) !== task.assigned_to) {
        stmt(`INSERT INTO agent_wakeup_requests (member_id, reason, source_type, source_id) VALUES (?,?,?,?)`)
          .run(Number(newAssignee), `Task assigned: ${task.title}`, 'task_assigned', Number(req.params.id));
      }

      // Paperclip Phase 2: Auto-comment on status change
      if (req.body.status && req.body.status !== task.status) {
        stmt(`INSERT INTO task_comments (task_id, author_name, content, comment_type, created_at, updated_at) VALUES (?,?,?,?,?,?)`)
          .run(Number(req.params.id), req.body.actor || 'System', `Status changed from ${task.status} to ${req.body.status}`, 'status_change', now, now);
        // Recalculate goal progress
        recalcGoalsForTask(Number(req.params.id));
        // Notify tasks that were waiting on this one and are now unblocked
        if (req.body.status === 'completed' || req.body.status === 'delivered') {
          notifyUnblockedTasks(Number(req.params.id), now);
        }
      }
    })();

    // Auto-spawn AFTER transaction commits (async, non-transactional)
    if (newAssignee && (newStatus === 'routing' || newStatus === 'in_progress' || (!newStatus && ['new', 'routing'].includes(task.status)))) {
      const tId = Number(req.params.id);
      setImmediate(() => {
        spawnMemberTerminal(tId, Number(newAssignee)).catch(err => {
          console.error(`[AutoSpawn] Task update spawn error: ${err.message}`);
        });
      });
    }

    // Thrift & Forge optimization trigger on delivery
    if (newStatus === 'delivered') {
      setImmediate(() => triggerOptimizationAuditForProject(Number(req.params.id), now));
    }

    res.json({ message: 'Task updated' });
    broadcast('task.updated', { id: Number(req.params.id) });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── DELETE /api/tasks/:id — delete task + cascade ──

app.delete('/api/tasks/:id', (req, res) => {
  try {
    const task = stmt(`SELECT id FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    // Cascade: clean up all related records (transactional)
    // FIX: Added missing cascade targets — active_processes, task_checkouts, governance_receipts, provenance_chain
    db.transaction(() => {
      stmt(`DELETE FROM task_files WHERE task_id = ?`).run(req.params.id);
      stmt(`DELETE FROM task_assignments WHERE task_id = ?`).run(req.params.id);
      stmt(`DELETE FROM activity_log WHERE task_id = ?`).run(req.params.id);
      stmt(`DELETE FROM project_tasks WHERE task_id = ?`).run(req.params.id);
      stmt(`DELETE FROM notifications WHERE task_id = ?`).run(req.params.id);
      stmt(`DELETE FROM task_dependencies WHERE task_id = ? OR depends_on = ?`).run(req.params.id, req.params.id);
      stmt(`DELETE FROM taggables WHERE entity_type = 'task' AND entity_id = ?`).run(req.params.id);
      stmt(`DELETE FROM mission_tasks WHERE task_id = ?`).run(req.params.id);
      try { stmt(`DELETE FROM task_goals WHERE task_id = ?`).run(req.params.id); } catch (_) {}
      try { stmt(`DELETE FROM task_comments WHERE task_id = ?`).run(req.params.id); } catch (_) {}
      try { stmt(`DELETE FROM active_processes WHERE task_id = ?`).run(req.params.id); } catch (_) {}
      try { stmt(`DELETE FROM task_checkouts WHERE task_id = ?`).run(req.params.id); } catch (_) {}
      try { stmt(`DELETE FROM provenance_chain WHERE subject_id = ? AND subject_type = 'task'`).run(req.params.id); } catch (_) {}
      try { stmt(`DELETE FROM agent_activity_stream WHERE task_id = ?`).run(req.params.id); } catch (_) {}

      stmt(`DELETE FROM tasks WHERE id = ?`).run(req.params.id);
    })();

    res.json({ message: 'Task deleted' });
    broadcast('task.updated', { id: Number(req.params.id) });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

