// POST /api/task-fields — create a new custom field definition
app.post('/api/task-fields', (req, res) => {
  try {
    const { name, label, field_type, options } = req.body;
    if (!name || !name.trim()) return res.status(400).json({ error: 'name is required' });
    if (!label || !label.trim()) return res.status(400).json({ error: 'label is required' });
    const validTypes = ['text', 'number', 'date', 'dropdown'];
    if (!field_type || !validTypes.includes(field_type)) {
      return res.status(400).json({ error: 'field_type must be one of: text, number, date, dropdown' });
    }
    if (field_type === 'dropdown') {
      if (!Array.isArray(options) || options.length === 0) {
        return res.status(400).json({ error: 'options array is required for dropdown fields' });
      }
    }
    const cleanName = name.trim().toLowerCase().replace(/[^a-z0-9_]/g, '_');
    const existing = db.prepare(`SELECT id FROM task_custom_field_definitions WHERE name = ?`).get(cleanName);
    if (existing) return res.status(409).json({ error: 'A field with that name already exists' });

    const maxPos = db.prepare(`SELECT COALESCE(MAX(position),0) as m FROM task_custom_field_definitions`).get().m;
    const result = db.prepare(`
      INSERT INTO task_custom_field_definitions (name, label, field_type, options, position)
      VALUES (?, ?, ?, ?, ?)
    `).run(cleanName, label.trim(), field_type, JSON.stringify(options || []), maxPos + 1);

    const field = db.prepare(`SELECT * FROM task_custom_field_definitions WHERE id = ?`).get(result.lastInsertRowid);
    res.json(field);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// PUT /api/task-fields/:id — update a field definition's label or options
app.put('/api/task-fields/:id', (req, res) => {
  try {
    const field = db.prepare(`SELECT * FROM task_custom_field_definitions WHERE id = ?`).get(req.params.id);
    if (!field) return res.status(404).json({ error: 'Field not found' });

    const { label, options } = req.body;
    const updates = [];
    const values = [];

    if (label !== undefined) {
      if (!label.trim()) return res.status(400).json({ error: 'label cannot be empty' });
      updates.push('label = ?'); values.push(label.trim());
    }
    if (options !== undefined) {
      if (!Array.isArray(options)) return res.status(400).json({ error: 'options must be an array' });
      updates.push('options = ?'); values.push(JSON.stringify(options));
    }
    if (updates.length === 0) return res.status(400).json({ error: 'No fields to update' });

    values.push(req.params.id);
    db.prepare(`UPDATE task_custom_field_definitions SET ${updates.join(', ')} WHERE id = ?`).run(...values);
    res.json(db.prepare(`SELECT * FROM task_custom_field_definitions WHERE id = ?`).get(req.params.id));
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// DELETE /api/task-fields/:id — remove field definition and all its values
app.delete('/api/task-fields/:id', (req, res) => {
  try {
    const field = db.prepare(`SELECT id FROM task_custom_field_definitions WHERE id = ?`).get(req.params.id);
    if (!field) return res.status(404).json({ error: 'Field not found' });
    db.transaction(() => {
      db.prepare(`DELETE FROM task_custom_field_values WHERE field_id = ?`).run(req.params.id);
      db.prepare(`DELETE FROM task_custom_field_definitions WHERE id = ?`).run(req.params.id);
    })();
    res.json({ message: 'Field deleted' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/tasks/:id/custom-fields — get field values for a specific task
app.get('/api/tasks/:id/custom-fields', (req, res) => {
  try {
    const task = db.prepare(`SELECT id FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });
    const fields = db.prepare(`
      SELECT d.id as field_id, d.name, d.label, d.field_type, d.options, d.position, v.value
      FROM task_custom_field_definitions d
      LEFT JOIN task_custom_field_values v ON v.field_id = d.id AND v.task_id = ?
      ORDER BY d.position, d.id
    `).all(req.params.id);
    res.json(fields);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// PUT /api/tasks/:id/custom-fields — upsert custom field values for a task
app.put('/api/tasks/:id/custom-fields', (req, res) => {
  try {
    const task = db.prepare(`SELECT id FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    const { fields } = req.body; // [{ field_id, value }]
    if (!Array.isArray(fields)) return res.status(400).json({ error: 'fields must be an array' });

    const now = localNow();
    db.transaction(() => {
      for (const f of fields) {
        const fieldId = Number(f.field_id);
        if (!Number.isInteger(fieldId) || fieldId <= 0) continue;
        const def = db.prepare(`SELECT id, field_type FROM task_custom_field_definitions WHERE id = ?`).get(fieldId);
        if (!def) continue;
        const value = f.value === undefined ? null : String(f.value === null ? '' : f.value);
        db.prepare(`
          INSERT INTO task_custom_field_values (task_id, field_id, value, updated_at)
          VALUES (?, ?, ?, ?)
          ON CONFLICT(task_id, field_id) DO UPDATE SET value = excluded.value, updated_at = excluded.updated_at
        `).run(Number(req.params.id), fieldId, value, now);
      }
    })();

    const updated = db.prepare(`
      SELECT d.id as field_id, d.name, d.label, d.field_type, d.options, d.position, v.value
      FROM task_custom_field_definitions d
      LEFT JOIN task_custom_field_values v ON v.field_id = d.id AND v.task_id = ?
      ORDER BY d.position, d.id
    `).all(req.params.id);
    res.json(updated);
    broadcast('task.updated', { id: Number(req.params.id) });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── PATCH /api/tasks/:id/status — quick status change ──

app.patch('/api/tasks/:id/status', (req, res) => {
  try {
    const { status } = req.body;
    const validStatuses = ['new', 'routing', 'in_progress', 'review', 'completed', 'delivered'];
    if (!status || !validStatuses.includes(status)) {
      return res.status(400).json({ error: 'Invalid status. Must be one of: ' + validStatuses.join(', ') });
    }

    const task = stmt(`SELECT id, status, started_at, completed_at FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    // Enforce forward-only status transitions (allow back one step for review failures)
    const STATUS_ORDER = ['new', 'routing', 'in_progress', 'review', 'completed', 'delivered'];
    const currentIdx = STATUS_ORDER.indexOf(task.status);
    const newIdx = STATUS_ORDER.indexOf(status);
    if (newIdx < currentIdx - 1) {
      return res.status(400).json({ error: `Cannot move status from ${task.status} to ${status}. Status can only move forward or back one step.` });
    }

    const now = localNow();
    const updates = ['status = ?', 'updated_at = ?'];
    const values = [status, now];

    // Set started_at when transitioning to in_progress
    if (status === 'in_progress' && !task.started_at) {
      updates.push('started_at = ?');
      values.push(now);
    }

    // Set completed_at when transitioning to completed
    if (status === 'completed') {
      updates.push('completed_at = ?');
      values.push(now);
    }

    // Set completed_at (if missing) and delivered_at when transitioning to delivered
    if (status === 'delivered') {
      if (!task.completed_at) {
        updates.push('completed_at = ?');
        values.push(now);
      }
      updates.push('delivered_at = ?');
      values.push(now);
    }

    values.push(req.params.id);

    // Wrap all writes in a single transaction — one WAL sync instead of 4-5
    // separate implicit transactions, plus atomic rollback on failure.
    db.transaction(() => {
      db.prepare(`UPDATE tasks SET ${updates.join(', ')} WHERE id = ?`).run(...values);

      stmt(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'status_changed', ?, ?)`)
        .run(req.params.id, `Status: ${task.status} → ${status}`, now);

      // Paperclip Phase 2: Auto-comment on status change
      stmt(`INSERT INTO task_comments (task_id, author_name, content, comment_type, created_at, updated_at) VALUES (?,?,?,?,?,?)`)
        .run(Number(req.params.id), req.body.actor || 'System', `Status changed from ${task.status} to ${status}`, 'status_change', now, now);

      // Paperclip Phase 2: Recalculate goal progress
      recalcGoalsForTask(Number(req.params.id));

      // Notify tasks that were waiting on this one and are now unblocked
      if (status === 'completed' || status === 'delivered') {
        notifyUnblockedTasks(Number(req.params.id), now);
      }
    })();

    // Thrift & Forge optimization trigger on delivery
    if (status === 'delivered') {
      setImmediate(() => triggerOptimizationAuditForProject(Number(req.params.id), now));
    }

    res.json({ id: Number(req.params.id), old_status: task.status, new_status: status });
    broadcast('task.updated', { id: Number(req.params.id) });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

