const TASK_UPLOADS_DIR = path.join(__dirname, 'uploads', 'tasks');
if (!fs.existsSync(TASK_UPLOADS_DIR)) fs.mkdirSync(TASK_UPLOADS_DIR, { recursive: true });

const taskAttachmentStorage = multer.diskStorage({
  destination: (req, file, cb) => {
    const taskDir = path.join(TASK_UPLOADS_DIR, String(req.params.id));
    if (!fs.existsSync(taskDir)) fs.mkdirSync(taskDir, { recursive: true });
    cb(null, taskDir);
  },
  filename: (req, file, cb) => {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    cb(null, `${timestamp}_${file.originalname}`);
  }
});
const uploadTaskAttachment = multer({
  storage: taskAttachmentStorage,
  limits: { fileSize: 50 * 1024 * 1024 }
});

// GET /api/tasks/:id/attachments — list attachment files for a task
app.get('/api/tasks/:id/attachments', (req, res) => {
  try {
    const task = db.prepare(`SELECT id FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    const files = db.prepare(
      `SELECT * FROM task_files WHERE task_id = ? AND direction = 'attachment' ORDER BY created_at DESC`
    ).all(req.params.id);
    res.json(files);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// POST /api/tasks/:id/attachments — upload one or more files to a task
app.post('/api/tasks/:id/attachments', uploadTaskAttachment.array('files', 20), (req, res) => {
  try {
    const task = db.prepare(`SELECT id FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });
    if (!req.files || req.files.length === 0) return res.status(400).json({ error: 'No files uploaded' });

    const now = localNow();
    const insertFile = db.prepare(
      `INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at)
       VALUES (?, ?, ?, ?, 'attachment', ?)`
    );

    const inserted = [];
    for (const f of req.files) {
      const result = insertFile.run(req.params.id, f.originalname, f.path, f.mimetype, now);
      inserted.push({ id: result.lastInsertRowid, file_name: f.originalname, file_type: f.mimetype, created_at: now });
    }

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Max', 'file_attached', ?, ?)`)
      .run(req.params.id, `Attached ${inserted.length} file(s): ${inserted.map(f => f.file_name).join(', ')}`, now);

    res.json({ files: inserted });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/tasks/:id/attachments/:fileId/download — download an attachment
app.get('/api/tasks/:id/attachments/:fileId/download', (req, res) => {
  try {
    const file = db.prepare(
      `SELECT * FROM task_files WHERE id = ? AND task_id = ? AND direction = 'attachment'`
    ).get(req.params.fileId, req.params.id);
    if (!file) return res.status(404).json({ error: 'File not found' });
    if (!fs.existsSync(file.file_path)) return res.status(404).json({ error: 'File missing from disk' });

    res.setHeader('Content-Disposition', `attachment; filename="${encodeURIComponent(file.file_name)}"`);
    res.setHeader('Content-Type', file.file_type || 'application/octet-stream');
    res.sendFile(path.resolve(file.file_path));
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// DELETE /api/tasks/:id/attachments/:fileId — delete an attachment
app.delete('/api/tasks/:id/attachments/:fileId', (req, res) => {
  try {
    const file = db.prepare(
      `SELECT * FROM task_files WHERE id = ? AND task_id = ? AND direction = 'attachment'`
    ).get(req.params.fileId, req.params.id);
    if (!file) return res.status(404).json({ error: 'File not found' });

    // Remove physical file
    if (fs.existsSync(file.file_path)) {
      fs.unlinkSync(file.file_path);
    }

    db.prepare(`DELETE FROM task_files WHERE id = ?`).run(req.params.fileId);

    const now = localNow();
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Max', 'file_removed', ?, ?)`)
      .run(req.params.id, `Removed attachment: ${file.file_name}`, now);

    res.json({ message: 'Attachment deleted' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

