// ── Team ─────────────────────────────────────────────────────────

app.get('/api/team', (req, res) => {
  try {
    const statusFilter = req.query.status; // 'active', 'retired', 'all', or undefined (defaults to active)
    let whereClause = "WHERE m.status = 'active'";
    if (statusFilter === 'retired') whereClause = "WHERE m.status = 'retired'";
    else if (statusFilter === 'all') whereClause = '';

    const members = db.prepare(`
      SELECT m.*, boss.name as reports_to_name
      FROM team_members m
      LEFT JOIN team_members boss ON m.reports_to = boss.id
      ${whereClause}
      ORDER BY
        CASE m.tier WHEN 'board' THEN 0 WHEN 'c-suite' THEN 1 WHEN 'specialist' THEN 2 WHEN 'orchestrator' THEN 3 WHEN 'leader' THEN 4 WHEN 'co-leader' THEN 5 WHEN 'subagent' THEN 6 END,
        m.created_at ASC
    `).all();

    // Attach task counts per member
    const taskCountStmt = stmt(`
      SELECT status, COUNT(*) as count
      FROM tasks WHERE assigned_to = ?
      GROUP BY status
    `);

    const enriched = members.map(m => ({
      ...m,
      task_counts: taskCountStmt.all(m.id)
    }));

    const body = JSON.stringify(enriched);
    const etag = `"${crypto.createHash('md5').update(body).digest('hex')}"`;
    res.setHeader('ETag', etag);
    res.setHeader('Cache-Control', 'no-cache');
    if (req.headers['if-none-match'] === etag) return res.status(304).end();
    res.json(enriched);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── GET /api/search — global search across all entities ──

app.get('/api/search', (req, res) => {
  try {
    const { q } = req.query;
    if (!q || q.trim().length < 2) return res.json({ tasks: [], notes: [], projects: [], contacts: [], decisions: [], ideas: [], total: 0 });
    const term = `%${q.trim()}%`;
    // Title matches rank higher (2) than body/content matches (1)
    const tasks = stmt(`
      SELECT id, title, status, priority, 'task' as type,
        CASE WHEN title LIKE ? THEN 2 ELSE 1 END as relevance
      FROM tasks WHERE title LIKE ? OR description LIKE ?
      ORDER BY relevance DESC LIMIT 10
    `).all(term, term, term);
    const notes = stmt(`
      SELECT id, title, content, 'note' as type,
        CASE WHEN title LIKE ? THEN 2 ELSE 1 END as relevance
      FROM notes WHERE title LIKE ? OR content LIKE ?
      ORDER BY relevance DESC LIMIT 10
    `).all(term, term, term);
    const projects = stmt(`
      SELECT id, name as title, status, 'project' as type,
        CASE WHEN name LIKE ? THEN 2 ELSE 1 END as relevance
      FROM projects WHERE name LIKE ? OR summary LIKE ?
      ORDER BY relevance DESC LIMIT 10
    `).all(term, term, term);
    const contacts = stmt(`
      SELECT id, name as title, role, company, 'contact' as type,
        CASE WHEN name LIKE ? THEN 2 ELSE 1 END as relevance
      FROM contacts WHERE name LIKE ? OR role LIKE ? OR company LIKE ?
      ORDER BY relevance DESC LIMIT 10
    `).all(term, term, term, term);
    const decisions = stmt(`
      SELECT id, question as title, answer, status, 'decision' as type,
        CASE WHEN question LIKE ? THEN 2 ELSE 1 END as relevance
      FROM decisions WHERE question LIKE ? OR answer LIKE ?
      ORDER BY relevance DESC LIMIT 10
    `).all(term, term, term);
    const ideas = stmt(`
      SELECT id, title, tagline, description, category, status, 'idea' as type,
        CASE WHEN title LIKE ? THEN 2 ELSE 1 END as relevance
      FROM idea_board WHERE title LIKE ? OR description LIKE ? OR tagline LIKE ?
      ORDER BY relevance DESC LIMIT 10
    `).all(term, term, term, term);

    const total = tasks.length + notes.length + projects.length + contacts.length + decisions.length + ideas.length;
    res.json({ tasks, notes, projects, contacts, decisions, ideas, total });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

