// ── Activity ─────────────────────────────────────────────────────

app.get('/api/activity', (req, res) => {
  try {
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 50;
    const offset = (page - 1) * limit;
    const categoryFilter = req.query.category || null;

    // Build category WHERE clause in SQL for efficiency
    // Categories are derived from the action column using LIKE patterns
    let categoryWhere = '';
    const categoryParams = [];
    if (categoryFilter) {
      if (categoryFilter === 'task') {
        categoryWhere = ` WHERE (a.category = 'task' OR a.action LIKE '%task%' OR a.action LIKE '%mission%' OR a.action LIKE '%assigned%' OR a.action LIKE '%delivered%')`;
      } else if (categoryFilter === 'note') {
        categoryWhere = ` WHERE (a.category = 'note' OR a.action LIKE '%note%')`;
      } else if (categoryFilter === 'team') {
        categoryWhere = ` WHERE (a.category = 'team' OR a.action LIKE '%hire%' OR a.action LIKE '%team%')`;
      } else if (categoryFilter === 'decision') {
        categoryWhere = ` WHERE (a.category = 'decision' OR a.action LIKE '%decision%')`;
      } else if (categoryFilter === 'improvement') {
        categoryWhere = ` WHERE (a.category = 'improvement' OR a.action LIKE '%improvement%' OR a.action LIKE '%audit%')`;
      } else if (categoryFilter === 'system') {
        categoryWhere = ` WHERE (a.category = 'system' OR (a.action NOT LIKE '%task%' AND a.action NOT LIKE '%mission%' AND a.action NOT LIKE '%assigned%' AND a.action NOT LIKE '%delivered%' AND a.action NOT LIKE '%note%' AND a.action NOT LIKE '%hire%' AND a.action NOT LIKE '%team%' AND a.action NOT LIKE '%decision%' AND a.action NOT LIKE '%improvement%' AND a.action NOT LIKE '%audit%'))`;
      }
    }

    function categorizeAction(action) {
      if (!action) return 'system';
      const a = action.toLowerCase();
      if (a.includes('task') || a.includes('mission') || a.includes('assigned') || a.includes('delivered')) return 'task';
      if (a.includes('note')) return 'note';
      if (a.includes('hire') || a.includes('team')) return 'team';
      if (a.includes('decision')) return 'decision';
      if (a.includes('improvement') || a.includes('audit')) return 'improvement';
      return 'system';
    }

    let countSql = `SELECT COUNT(*) as count FROM activity_log a` + categoryWhere;
    let sql = `SELECT a.*, t.title as task_title
      FROM activity_log a
      LEFT JOIN tasks t ON a.task_id = t.id` + categoryWhere + `
      ORDER BY a.created_at DESC
      LIMIT ? OFFSET ?`;

    const total = db.prepare(countSql).get().count;
    const rawEntries = db.prepare(sql).all(limit, offset);

    const entries = rawEntries.map(entry => ({ ...entry, category: categorizeAction(entry.action) }));

    // Grouped mode: collapse consecutive entries with the same actor+action+notes
    if (req.query.grouped === '1') {
      const grouped = [];
      for (let i = 0; i < entries.length; i++) {
        const e = entries[i];
        const prev = grouped.length > 0 ? grouped[grouped.length - 1] : null;
        if (prev && prev.actor === e.actor && prev.action === e.action && prev.notes === e.notes) {
          prev.group_count = (prev.group_count || 1) + 1;
          prev.group_last_at = prev.group_last_at || prev.created_at;
          // Keep the most recent created_at as the group timestamp
        } else {
          grouped.push({ ...e, group_count: 1 });
        }
      }
      return res.json({ entries: grouped, total, page, limit });
    }

    res.json({ entries, total, page, limit });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

