// ── POST /api/command — Natural language command bar ────────

app.post('/api/command', authRateLimiter, (req, res) => {
  try {
    const { message, priority: rawPriority } = req.body;
    if (!message) return res.status(400).json({ error: 'Message required' });

    const lower = message.toLowerCase().trim();
    const now = localNow();
    const priority = ['low', 'normal', 'high', 'urgent'].includes(rawPriority) ? rawPriority : 'normal';
    let result = { action: 'mission', message: 'Forwarded to the Board' };

    // ── STATUS QUERIES ──
    if (/^(how('?s| is)|what('?s| is|.*status)|status of|update on).*/.test(lower)) {
        const projectMatch = lower.match(/clipper|animation|the team/i);
        if (projectMatch) {
            const pName = projectMatch[0];
            const project = db.prepare(`SELECT * FROM projects WHERE LOWER(name) LIKE ?`).get('%' + pName + '%');
            if (project) {
                const exec = db.prepare(`SELECT tm.name FROM project_executives pe JOIN team_members tm ON pe.member_id = tm.id WHERE pe.project_id = ?`).get(project.id);
                const running = db.prepare(`SELECT COUNT(*) as c FROM active_processes ap JOIN tasks t ON ap.task_id = t.id JOIN project_tasks pt ON pt.task_id = t.id WHERE pt.project_id = ? AND ap.status = 'running'`).get(project.id)?.c || 0;
                const completedToday = db.prepare(`SELECT COUNT(*) as c FROM project_improvements WHERE project_id = ? AND status = 'completed' AND date(completed_at) = date(?)`).get(project.id, now)?.c || 0;
                const queued = db.prepare(`SELECT COUNT(*) as c FROM project_improvements WHERE project_id = ? AND status = 'queued'`).get(project.id)?.c || 0;
                result = {
                    action: 'status',
                    project: project.name,
                    executive: exec ? exec.name : 'None',
                    running_agents: running,
                    completed_today: completedToday,
                    queued: queued,
                    message: `${project.name}: Led by ${exec ? exec.name : 'no executive'}. ${running} agents active, ${completedToday} completed today, ${queued} in queue.`
                };
                return res.json(result);
            }
        }
        // General status
        const totalRunning = db.prepare(`SELECT COUNT(*) as c FROM active_processes WHERE status = 'running'`).get().c;
        const totalCompleted = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status IN ('completed','delivered') AND date(completed_at) = date(?)`).get(now).c;
        result = { action: 'status', message: `${totalRunning} agents running, ${totalCompleted} tasks completed today.` };
        return res.json(result);
    }

    // ── AUTONOMOUS CONTROL ──
    if (/^(start|begin|enable|turn on|activate)\s+(autonomous|auto|pipeline|improvements?)/i.test(lower)) {
        const timerMatch = lower.match(/(\d+)\s*(min|hour|hr|h|m)/i);
        let timerMinutes = 0;
        if (timerMatch) {
            timerMinutes = parseInt(timerMatch[1]);
            if (/hour|hr|h/i.test(timerMatch[2])) timerMinutes *= 60;
        }
        db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('autonomous_improvements', '1', ?)`).run(now);
        if (timerMinutes > 0) {
            db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('autonomous_improvement_timer', ?, ?)`).run(String(timerMinutes), now);
            db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('autonomous_improvement_timer_start', ?, ?)`).run(now, now);
        } else {
            db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('autonomous_improvement_timer', '0', ?)`).run(now);
        }
        result = { action: 'autonomous_start', timer_minutes: timerMinutes || 'unlimited', message: `Autonomous improvements started${timerMinutes ? ' for ' + timerMinutes + ' minutes' : ''}.` };
        return res.json(result);
    }

    // ── PAUSE/CANCEL/RESUME (check before stop handler so "pause everything" routes correctly) ──
    if (/^pause\s+(everything|all|pipeline)/i.test(lower)) {
        db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('autonomous_improvements', '0', ?)`).run(now);
        db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('auto_execute_improvements', '0', ?)`).run(now);
        result = { action: 'pause_all', message: 'All autonomous processing paused.' };
        return res.json(result);
    }

    if (/^resume\s+(everything|all|pipeline)/i.test(lower)) {
        db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('autonomous_improvements', '1', ?)`).run(now);
        db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('auto_execute_improvements', '1', ?)`).run(now);
        result = { action: 'resume_all', message: 'All autonomous processing resumed.' };
        return res.json(result);
    }

    if (/^(stop|halt|disable|turn off|pause)\s+(autonomous|auto|pipeline|improvements?|everything|all)/i.test(lower)) {
        db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('autonomous_improvements', '0', ?)`).run(now);
        db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('autonomous_improvement_timer', '0', ?)`).run(now);
        result = { action: 'autonomous_stop', message: 'Autonomous improvements stopped.' };
        return res.json(result);
    }

    // ── TEAM QUERIES ──
    if (/^(who'?s|who\s+is|list|show)\s+(running|working|active|busy)/i.test(lower)) {
        const running = db.prepare(`SELECT tm.name, tm.role, t.title FROM active_processes ap JOIN team_members tm ON ap.member_id = tm.id JOIN tasks t ON ap.task_id = t.id WHERE ap.status = 'running'`).all();
        result = {
            action: 'team_status',
            agents: running,
            message: running.length === 0 ? 'No agents currently working.' : running.map(r => `${r.name} (${r.role}): ${r.title}`).join('\n')
        };
        return res.json(result);
    }

    // ── NAVIGATION ──
    if (/^(go to|open|show|navigate)\s+(workspace|projects?|tasks?|calendar|notes?|settings?|site.?builder|analytics|team|goals|context|routines?|plugins?|evals?|approvals?)/i.test(lower)) {
        const pageMatch = lower.match(/(workspace|projects?|tasks?|calendar|notes?|settings?|site.?builder|analytics|team|goals|context|routines?|plugins?|evals?|approvals?)/i);
        const pageMap = { workspace: 'workspace', project: 'projects', projects: 'projects', task: 'tasks', tasks: 'tasks', calendar: 'calendar', note: 'notes', notes: 'notes', settings: 'settings', 'site-builder': 'site-builder', sitebuilder: 'site-builder', analytics: 'analytics', team: 'team', goals: 'goals', context: 'context', routine: 'routines', routines: 'routines', plugin: 'plugins', plugins: 'plugins', eval: 'evals', evals: 'evals', approval: 'approvals', approvals: 'approvals' };
        const page = pageMap[pageMatch[1].toLowerCase()] || 'dashboard';
        result = { action: 'navigate', page: page, message: `Navigating to ${page}.` };
        return res.json(result);
    }

    // ── QUICK STATS ──
    if (/^(stats|numbers|metrics|how many|count)/i.test(lower)) {
        const totalMembers = db.prepare(`SELECT COUNT(*) as c FROM team_members WHERE status = 'active'`).get().c;
        const totalTasks = db.prepare(`SELECT COUNT(*) as c FROM tasks`).get().c;
        const totalProjects = db.prepare(`SELECT COUNT(*) as c FROM projects WHERE status = 'active'`).get().c;
        const completedToday = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status IN ('completed','delivered') AND date(completed_at) = date(?)`).get(now).c;
        result = { action: 'stats', message: `${totalMembers} team members, ${totalProjects} projects, ${totalTasks} total tasks, ${completedToday} completed today.` };
        return res.json(result);
    }

    // ── RESEARCH PROGRAM (from command bar) ──
    if (/^research\s+(.+)/i.test(lower)) {
        const topic = message.replace(/^research\s+/i, '').trim();
        try {
            const programRes = db.prepare(`
              INSERT INTO research_sessions (title, goal, success_criteria, max_cycles, model, created_at)
              VALUES (?, ?, ?, 50, 'sonnet', ?)
            `).run(`Research: ${topic}`, `Investigate and document findings on: ${topic}`, `Comprehensive understanding of: ${topic}`, now);
            const sessionId = Number(programRes.lastInsertRowid);

            const progResult = db.prepare(`
              INSERT INTO research_programs (session_id, title, goal, methodology, max_experiments, time_budget_minutes, loop_interval_seconds, assigned_to, created_at)
              VALUES (?, ?, ?, ?, 50, 60, 60, 'Briar', ?)
            `).run(sessionId, `Research: ${topic}`, `Investigate and document findings on: ${topic}`,
                   `Open investigation — explore multiple angles, gather evidence, synthesize findings.`, now);
            const programId = Number(progResult.lastInsertRowid);

            db.prepare(`UPDATE research_sessions SET program_id = ? WHERE id = ?`).run(programId, sessionId);

            // Auto-spawn Briar
            setImmediate(() => {
              try {
                const researcher = db.prepare(`SELECT id FROM team_members WHERE name = 'Briar' AND status = 'active'`).get();
                if (!researcher) return;
                const spawnNow = localNow();
                const taskResult = db.prepare(`
                  INSERT INTO tasks (title, description, status, priority, source_file, assigned_to, started_at, progress, current_step, created_at, updated_at)
                  VALUES (?, ?, 'in_progress', 'high', 'research_program', ?, ?, 10, 'Research program started', ?, ?)
                `).run(`Research: ${topic}`, `Investigate and document findings on: ${topic}`, researcher.id, spawnNow, spawnNow, spawnNow);
                const tId = Number(taskResult.lastInsertRowid);
                broadcast('task.created', { id: tId });
                spawnMemberTerminal(tId, researcher.id).catch(err => {
                  console.error(`[Command] Research spawn error: ${err.message}`);
                });
              } catch (err) {
                console.error(`[Command] Research spawn setup error: ${err.message}`);
              }
            });

            result = { action: 'research_program', program_id: programId, session_id: sessionId, navigate: 'research', message: `Research program created: "${topic}". Briar is on it.` };
        } catch (rpErr) {
            result = { action: 'research_program', message: `Failed to create research program: ${rpErr.message}` };
        }
        return res.json(result);
    }

    // ── DEFAULT: Forward as mission to the Board via chain of command ──
    result = { action: 'mission', message: 'Board is routing your mission...' };

    const taskResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, source_file, created_at, updated_at) VALUES (?,?,?,?,?,?,?)`)
        .run(message.slice(0, 100), message, 'routing', priority, 'command_bar', now, now);
    const taskId = Number(taskResult.lastInsertRowid);

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Max', 'command', ?, ?)`)
        .run(taskId, `Command bar: ${message.slice(0, 200)}`, now);

    createNotification('task_status', 'New mission from Max', message.slice(0, 100), taskId);

    broadcast('task.created', { id: taskId });

    // Route through chain of command (same logic as POST /api/mission with auto_assign)
    setImmediate(() => {
      const title = message.slice(0, 100);
      db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
        .run('Board analyzing mission...', localNow(), taskId);
      broadcast('task.updated', { id: taskId });

      routeViaChainOfCommand(taskId).then(routing => {
        if (routing) {
          executeRoutingDecision(taskId, routing);
        } else {
          // Chain routing returned null — use robust fallback (keyword → Strut default)
          fallbackAssignAndSpawn(taskId, message, 'CommandBar fallback').catch(err => {
            console.error(`[CommandBar] Fallback error for task #${taskId}: ${err.message}`);
          });
        }
      }).catch(err => {
        console.error(`[ChainRouting] Command bar error: ${err.message}`);
        // Chain routing threw — still try to assign via fallback
        fallbackAssignAndSpawn(taskId, message, 'CommandBar error recovery').catch(fallbackErr => {
          console.error(`[CommandBar] Error recovery fallback also failed for task #${taskId}: ${fallbackErr.message}`);
        });
      });
    });

    result.task_id = taskId;
    result.message = `Mission created (task #${taskId}). Board is routing it.`;
    return res.json(result);
  } catch (err) {
    console.error('POST /api/command error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/command/upload — Command bar with file attachments ──
// Accepts multipart/form-data: message (text), priority (text), files[] (optional).
// Mirrors the default "mission" path of /api/command but also stores uploaded files.

const COMMAND_UPLOADS_DIR = path.join(__dirname, 'uploads', 'command');
if (!fs.existsSync(COMMAND_UPLOADS_DIR)) fs.mkdirSync(COMMAND_UPLOADS_DIR, { recursive: true });

const commandUploadStorage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, COMMAND_UPLOADS_DIR);
  },
  filename: (req, file, cb) => {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const safeName = file.originalname.replace(/[^a-zA-Z0-9._-]/g, '_');
    cb(null, `${timestamp}_${safeName}`);
  }
});
const uploadCommandFiles = multer({
  storage: commandUploadStorage,
  limits: { fileSize: 50 * 1024 * 1024, files: 10 }
});

app.post('/api/command/upload', uploadCommandFiles.array('files', 10), (req, res) => {
  try {
    const message = (req.body.message || '').trim();
    const rawPriority = req.body.priority || 'normal';
    const files = req.files || [];
    if (!message && files.length === 0) return res.status(400).json({ error: 'Message or files required' });

    const priority = ['low', 'normal', 'high', 'urgent'].includes(rawPriority) ? rawPriority : 'normal';
    const now = localNow();

    // Build enriched description that includes file names and smart type detection
    const fileNames = files.map(f => f.originalname).join(', ');
    const autoDesc = files.length > 0 && !message ? generateFileDescription(files) : null;
    const title = message ? message.slice(0, 100) : (autoDesc || `File upload: ${fileNames}`).slice(0, 100);
    const description = files.length > 0
      ? `${message || autoDesc || 'File upload'}\n\nAttached files: ${fileNames}`
      : message;

    // Create task (same as /api/command default mission path)
    const taskResult = db.prepare(
      `INSERT INTO tasks (title, description, status, priority, source_file, created_at, updated_at)
       VALUES (?,?,?,?,?,?,?)`
    ).run(title, description, 'routing', priority, 'command_bar', now, now);
    const taskId = Number(taskResult.lastInsertRowid);

    // Record uploaded files in task_files
    if (files.length > 0) {
      const insertFile = db.prepare(
        `INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at)
         VALUES (?, ?, ?, ?, 'input', ?)`
      );
      for (const f of files) {
        insertFile.run(taskId, f.originalname, f.path, f.mimetype || 'application/octet-stream', now);
      }
    }

    db.prepare(
      `INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Max', 'command', ?, ?)`
    ).run(taskId, `Command bar${files.length ? ' with files' : ''}: ${(message || fileNames).slice(0, 200)}${files.length ? ` [+${files.length} file(s)]` : ''}`, now);

    createNotification('task_status', 'New mission from Max', title, taskId);
    broadcast('task.created', { id: taskId });

    // Route through chain of command asynchronously
    setImmediate(() => {
      db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
        .run('Board analyzing mission...', localNow(), taskId);
      broadcast('task.updated', { id: taskId });

      routeViaChainOfCommand(taskId).then(routing => {
        if (routing) {
          executeRoutingDecision(taskId, routing);
        } else {
          fallbackAssignAndSpawn(taskId, message, 'CommandBar upload fallback').catch(err => {
            console.error(`[CommandUpload] Fallback error for task #${taskId}: ${err.message}`);
          });
        }
      }).catch(err => {
        console.error(`[ChainRouting] Command upload error: ${err.message}`);
        fallbackAssignAndSpawn(taskId, message, 'CommandBar upload error recovery').catch(fallbackErr => {
          console.error(`[CommandUpload] Recovery fallback also failed for task #${taskId}: ${fallbackErr.message}`);
        });
      });
    });

    return res.json({
      action: 'mission',
      task_id: taskId,
      files_attached: files.length,
      message: `Mission created (task #${taskId})${files.length ? ` with ${files.length} file(s)` : ''}. Board is routing it.`
    });
  } catch (err) {
    console.error('POST /api/command/upload error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/inbox — Send a text instruction to the Board ────────

app.post('/api/inbox', (req, res) => {
  try {
    const { message, priority } = req.body;
    if (!message || !message.trim()) {
      return res.status(400).json({ error: 'Message is required' });
    }
    if (message.trim().length < 3) {
      return res.status(400).json({ error: 'Message must be at least 3 characters' });
    }

    const taskPriority = ['low', 'normal', 'high', 'urgent'].includes(priority) ? priority : 'normal';
    const now = localNow();

    // Create task in DB
    const result = db.prepare(`
      INSERT INTO tasks (title, description, status, priority, source_file, created_at, updated_at)
      VALUES (?, ?, 'new', ?, ?, ?, ?)
    `).run(
      message.trim().slice(0, 120),
      message.trim(),
      taskPriority,
      'browser',
      now,
      now
    );

    const taskId = result.lastInsertRowid;

    // Log activity
    db.prepare(`
      INSERT INTO activity_log (task_id, actor, action, notes, created_at)
      VALUES (?, 'Max', 'created_task', ?, ?)
    `).run(taskId, `Task submitted via browser: ${message.trim().slice(0, 200)}`, now);

    // Write .md file to inbox for the Board to pick up
    const safeName = `browser-task-${taskId}-${Date.now()}.md`;
    const mdContent = `# Browser Task #${taskId}\n\n**Priority:** ${taskPriority}\n**Created:** ${now}\n**Source:** browser\n\n---\n\n${message.trim()}\n`;

    if (!fs.existsSync(INBOX_PATH)) {
      fs.mkdirSync(INBOX_PATH, { recursive: true });
    }
    fs.writeFileSync(path.join(INBOX_PATH, safeName), mdContent, 'utf-8');

    // Register the .md file in task_files
    db.prepare(`
      INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at)
      VALUES (?, ?, ?, 'text/markdown', 'input', ?)
    `).run(taskId, safeName, path.join(INBOX_PATH, safeName), now);

    broadcast('task.created', { id: Number(taskId) });

    // Route through chain of command (tasks must never sit at 'new' unrouted)
    const tId = Number(taskId);
    setImmediate(() => {
      db.prepare(`UPDATE tasks SET status = 'routing', current_step = ?, updated_at = ? WHERE id = ?`)
        .run('Board analyzing task...', localNow(), tId);
      broadcast('task.updated', { id: tId });

      routeViaChainOfCommand(tId).then(routing => {
        if (routing) {
          executeRoutingDecision(tId, routing);
        } else {
          fallbackAssignAndSpawn(tId, message.trim(), 'Inbox fallback').catch(err => {
            console.error(`[Inbox] Fallback error for task #${tId}: ${err.message}`);
          });
        }
      }).catch(err => {
        console.error(`[ChainRouting] Inbox error: ${err.message}`);
        fallbackAssignAndSpawn(tId, message.trim(), 'Inbox error recovery').catch(fallbackErr => {
          console.error(`[Inbox] Error recovery fallback also failed for task #${tId}: ${fallbackErr.message}`);
        });
      });
    });

    res.json({ task_id: tId, message: 'Task sent to the Board' });
  } catch (err) {
    console.error('POST /api/inbox error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/inbox/upload — Upload files for the Board ───────────

app.post('/api/inbox/upload', upload.array('files', 20), (req, res) => {
  try {
    if (!req.files || req.files.length === 0) {
      return res.status(400).json({ error: 'No files uploaded' });
    }

    const now = localNow();
    // FIX: Sanitize file names to prevent path traversal
    req.files.forEach(f => {
      f.originalname = f.originalname.replace(/[^a-zA-Z0-9._\- ]/g, '_');
    });
    const fileNames = req.files.map(f => f.originalname).join(', ');
    const autoDesc = generateFileDescription(req.files);
    const title = autoDesc.slice(0, 120);

    // Create task in DB — starts at 'routing' (will be routed immediately below)
    const result = db.prepare(`
      INSERT INTO tasks (title, description, status, priority, source_file, created_at, updated_at)
      VALUES (?, ?, 'routing', 'normal', ?, ?, ?)
    `).run(
      title,
      `${autoDesc}\n\nUploaded ${req.files.length} file(s) via browser: ${fileNames}`,
      'browser',
      now,
      now
    );

    const taskId = result.lastInsertRowid;

    // Register each file in task_files
    const insertFile = db.prepare(`
      INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at)
      VALUES (?, ?, ?, ?, 'input', ?)
    `);

    const uploadedFiles = req.files.map(f => {
      insertFile.run(taskId, f.originalname, f.path, f.mimetype, now);
      return { name: f.originalname, size: f.size, type: f.mimetype };
    });

    // Log activity
    db.prepare(`
      INSERT INTO activity_log (task_id, actor, action, notes, created_at)
      VALUES (?, 'Max', 'uploaded_files', ?, ?)
    `).run(taskId, `Uploaded ${req.files.length} file(s) via browser: ${fileNames}`, now);

    broadcast('task.created', { id: Number(taskId) });

    // Route through chain of command (tasks must never sit at 'new' unrouted)
    const tId = Number(taskId);
    const description = `${req.files.length} file(s) uploaded via browser: ${fileNames}`;
    setImmediate(() => {
      db.prepare(`UPDATE tasks SET status = 'routing', current_step = ?, updated_at = ? WHERE id = ?`)
        .run('Board analyzing uploaded files...', localNow(), tId);
      broadcast('task.updated', { id: tId });

      routeViaChainOfCommand(tId).then(routing => {
        if (routing) {
          executeRoutingDecision(tId, routing);
        } else {
          fallbackAssignAndSpawn(tId, description, 'InboxUpload fallback').catch(err => {
            console.error(`[InboxUpload] Fallback error for task #${tId}: ${err.message}`);
          });
        }
      }).catch(err => {
        console.error(`[ChainRouting] Inbox upload error: ${err.message}`);
        fallbackAssignAndSpawn(tId, description, 'InboxUpload error recovery').catch(fallbackErr => {
          console.error(`[InboxUpload] Error recovery fallback also failed for task #${tId}: ${fallbackErr.message}`);
        });
      });
    });

    res.json({ task_id: tId, files: uploadedFiles, message: 'Files uploaded for the Board' });
  } catch (err) {
    console.error('POST /api/inbox/upload error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── Action Item Extraction & Routing Helpers ──────────────────

/**
 * Extract action items from note content.
 * Matches: - [ ] ..., TODO: ..., ACTION: ..., and imperative sentences.
 */
function extractActionItems(content) {
  const items = [];
  const lines = content.split('\n');

  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;

    // Match "- [ ] ..." checkbox items
    const checkboxMatch = trimmed.match(/^-\s*\[\s*\]\s+(.+)/);
    if (checkboxMatch) {
      items.push(checkboxMatch[1].trim());
      continue;
    }

    // Match "TODO: ..." or "ACTION: ..."
    const prefixMatch = trimmed.match(/^(?:TODO|ACTION)\s*:\s*(.+)/i);
    if (prefixMatch) {
      items.push(prefixMatch[1].trim());
      continue;
    }

    // Match imperative sentences starting with action verbs
    const imperativeMatch = trimmed.match(/^(Build|Fix|Research|Add|Implement|Create|Update|Deploy|Refactor|Test|Check|Verify|Design|Optimize|Improve|Polish|Schedule|Plan|Investigate|Look into|Set up|Write|Remove|Delete|Migrate|Configure|Enable|Disable|Review|Audit|Document)\b\s+(.+)/i);
    if (imperativeMatch) {
      items.push(trimmed);
      continue;
    }
  }

  return items;
}

/**
 * Route an action item description to the best team member by keyword matching.
 * Returns { member_id, member_name } or null for unassigned.
 */
/**
 * Generate a routing-friendly description from uploaded file names and types.
 * When a file is uploaded with no message text, this creates a description
 * the keyword router can work with (e.g. "Review CSS stylesheet" instead of "File upload").
 */
function generateFileDescription(files) {
  if (!files || files.length === 0) return 'File upload';

  const typeDescriptions = [];
  for (const f of files) {
    const name = (f.originalname || f.name || '').toLowerCase();
    const mime = (f.mimetype || f.type || '').toLowerCase();
    const ext = name.split('.').pop();

    if (/\.(js|mjs|cjs|ts|tsx|jsx)$/.test(name) || mime.includes('javascript') || mime.includes('typescript')) {
      typeDescriptions.push(`Review JavaScript/TypeScript code file: ${f.originalname || f.name}`);
    } else if (/\.(css|scss|sass|less)$/.test(name) || mime.includes('css')) {
      typeDescriptions.push(`Review CSS stylesheet: ${f.originalname || f.name}`);
    } else if (/\.(html|htm)$/.test(name) || mime.includes('html')) {
      typeDescriptions.push(`Review HTML page: ${f.originalname || f.name}`);
    } else if (/\.(json|yaml|yml|toml|ini|env|config)$/.test(name) || mime.includes('json') || mime.includes('yaml')) {
      typeDescriptions.push(`Review configuration file: ${f.originalname || f.name}`);
    } else if (/\.(py|rb|go|rs|java|kt|swift|c|cpp|h)$/.test(name)) {
      typeDescriptions.push(`Review code file: ${f.originalname || f.name}`);
    } else if (/\.(sql|db|sqlite)$/.test(name) || mime.includes('sql')) {
      typeDescriptions.push(`Review database/SQL file: ${f.originalname || f.name}`);
    } else if (/\.(md|txt|doc|docx|rtf)$/.test(name) || mime.includes('text') || mime.includes('document')) {
      typeDescriptions.push(`Review document: ${f.originalname || f.name}`);
    } else if (/\.(png|jpg|jpeg|gif|svg|webp|ico|bmp)$/.test(name) || mime.includes('image')) {
      typeDescriptions.push(`Review design/image asset: ${f.originalname || f.name}`);
    } else if (/\.(pdf)$/.test(name) || mime.includes('pdf')) {
      typeDescriptions.push(`Analyze PDF document: ${f.originalname || f.name}`);
    } else if (/\.(csv|xls|xlsx)$/.test(name) || mime.includes('spreadsheet') || mime.includes('csv')) {
      typeDescriptions.push(`Analyze data/spreadsheet: ${f.originalname || f.name}`);
    } else if (/\.(sh|bash|zsh|bat|ps1)$/.test(name)) {
      typeDescriptions.push(`Review shell script: ${f.originalname || f.name}`);
    } else if (/\.(docker|dockerfile)$/i.test(name) || name === 'dockerfile') {
      typeDescriptions.push(`Review Docker configuration: ${f.originalname || f.name}`);
    } else {
      typeDescriptions.push(`Process uploaded file: ${f.originalname || f.name} (${mime || ext || 'unknown type'})`);
    }
  }

  return typeDescriptions.join('. ');
}

function routeActionItem(description) {
  const lower = description.toLowerCase();

  // Word-boundary match to avoid false positives (e.g. "ui" inside "build")
  function hasWord(keyword) {
    const re = new RegExp('\\b' + keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'i');
    return re.test(lower);
  }

  // Detect category from keywords, then use load-balanced assignment
  // FIX: Added missing categories for HR, finance, legal, coordination, strategy
  const categoryRoutes = [
    { keywords: ['hire', 'recruit', 'onboard', 'team member', 'personnel', 'org design', 'culture'], category: 'hr' },
    { keywords: ['budget', 'forecast', 'cost', 'expense', 'invoice', 'accounting', 'financial'], category: 'finance' },
    { keywords: ['compliance', 'contract', 'legal', 'license', 'patent', 'policy', 'regulatory'], category: 'legal' },
    { keywords: ['schedule', 'meeting', 'calendar', 'coordinate', 'plan', 'strategy', 'roadmap', 'business plan'], category: 'strategy' },
    { keywords: ['research', 'investigate', 'look into', 'analyze', 'evaluate', 'feasibility'], category: 'research' },
    { keywords: ['test', 'qa', 'verify', 'check', 'coverage'], category: 'qa' },
    { keywords: ['security', 'vulnerability', 'auth', 'permission', 'penetration', 'threat'], category: 'security' },
    { keywords: ['improve', 'optimize', 'polish', 'audit', 'platform'], category: 'platform' },
    { keywords: ['ui', 'design', 'css', 'layout', 'page', 'html', 'style', 'responsive'], category: 'design' },
    { keywords: ['frontend', 'dom', 'event', 'client', 'app.js', 'render', 'websocket client'], category: 'frontend' },
    { keywords: ['devops', 'docker', 'deploy', 'ci', 'infrastructure', 'monitoring'], category: 'devops' },
    { keywords: ['content', 'documentation', 'docs', 'blog', 'seo', 'editorial'], category: 'content' },
    { keywords: ['performance', 'speed', 'cache', 'latency', 'slow'], category: 'performance' },
    { keywords: ['build', 'add', 'implement', 'code', 'api', 'endpoint', 'server', 'database', 'sql', 'backend', 'route', 'middleware', 'write'], category: 'backend' },
  ];

  let category = 'general';
  for (const route of categoryRoutes) {
    if (route.keywords.some(kw => hasWord(kw))) {
      category = route.category;
      break;
    }
  }

  // Use load-balanced assignment instead of hardcoded member IDs
  const member = assignMember(category, null);
  if (member) {
    return { member_id: member.id, member_name: member.name };
  }

  return null; // Unassigned — Board decides later
}

/**
 * Get a default specialist when all routing methods fail.
 * Returns Strut (Engineering Lead) or the least-loaded active specialist.
 */
function getDefaultSpecialist() {
  // Try Strut (Engineering Lead) first
  const strut = db.prepare(`SELECT id, name FROM team_members WHERE name = 'Strut' AND status = 'active' AND tier = 'specialist'`).get();
  if (strut) return { member_id: strut.id, member_name: strut.name };

  // Fallback: any active specialist, least loaded
  const fallback = db.prepare(`
    SELECT id, name FROM team_members
    WHERE status = 'active' AND tier = 'specialist'
    ORDER BY (SELECT COUNT(*) FROM active_processes WHERE member_id = team_members.id AND status = 'running') ASC, RANDOM()
    LIMIT 1
  `).get();
  if (fallback) return { member_id: fallback.id, member_name: fallback.name };

  return null;
}

/**
 * Robust fallback assignment: keyword routing → Strut default → null.
 * Creates task_assignment, updates task status, spawns terminal.
 * Returns true if assignment succeeded, false otherwise.
 */
async function fallbackAssignAndSpawn(taskId, description, logPrefix) {
  const now = localNow();
  const routing = routeActionItem(description);
  const member = routing || getDefaultSpecialist();

  if (member) {
    const fallbackType = routing ? 'keyword' : 'default (Strut)';
    db.prepare(`INSERT OR IGNORE INTO task_assignments (task_id, member_id, subagent_count, created_at) VALUES (?, ?, 1, ?)`)
      .run(taskId, member.member_id, now);
    db.prepare(`UPDATE tasks SET assigned_to = ?, status = 'in_progress', current_step = ?, updated_at = ? WHERE id = ?`)
      .run(member.member_id, `${logPrefix}: assigned to ${member.member_name} (${fallbackType} routing)`, now, taskId);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Board', 'chain_routing_fallback', ?, ?)`)
      .run(taskId, `${logPrefix} — ${fallbackType} routing → ${member.member_name}`, now);
    broadcast('task.updated', { id: taskId });
    autoSpawnForTask(taskId).catch(err => {
      console.error(`[${logPrefix}] Spawn error after fallback for task #${taskId}: ${err.message}`);
    });
    return true;
  }

  // Absolute last resort: grab ANY active team member (specialist, executive, or otherwise)
  const anyMember = db.prepare(`
    SELECT id, name FROM team_members
    WHERE status = 'active'
    ORDER BY (SELECT COUNT(*) FROM active_processes WHERE member_id = team_members.id AND status = 'running') ASC, RANDOM()
    LIMIT 1
  `).get();

  if (anyMember) {
    db.prepare(`INSERT OR IGNORE INTO task_assignments (task_id, member_id, subagent_count, created_at) VALUES (?, ?, 1, ?)`)
      .run(taskId, anyMember.id, now);
    db.prepare(`UPDATE tasks SET assigned_to = ?, status = 'in_progress', current_step = ?, updated_at = ? WHERE id = ?`)
      .run(anyMember.id, `${logPrefix}: last-resort assignment to ${anyMember.name}`, now, taskId);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Board', 'chain_routing_last_resort', ?, ?)`)
      .run(taskId, `${logPrefix} — no specialists matched, last-resort → ${anyMember.name}`, now);
    broadcast('task.updated', { id: taskId });
    autoSpawnForTask(taskId).catch(err => {
      console.error(`[${logPrefix}] Last-resort spawn error for task #${taskId}: ${err.message}`);
    });
    return true;
  }

  // Truly no team members at all — flag for Max (should never happen)
  db.prepare(`UPDATE tasks SET status = 'routing', current_step = ?, updated_at = ? WHERE id = ?`)
    .run('No team members available — awaiting manual assignment', now, taskId);
  const task = db.prepare(`SELECT title FROM tasks WHERE id = ?`).get(taskId);
  createNotification('decision_needed', 'Task needs assignment', `"${task ? task.title : 'task #' + taskId}" could not be auto-routed. No team members available.`, taskId);
  db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Board', 'chain_routing_fallback', ?, ?)`)
    .run(taskId, `${logPrefix} — no team members available at all`, now);
  broadcast('task.updated', { id: taskId });
  return false;
}

/**
 * Auto-execute a single action item: create task, assign member, spawn terminal.
 * Returns the created task info.
 */
async function autoExecuteActionItem(actionItemId) {
  const now = localNow();

  if (!actionItem) throw new Error(`Action item #${actionItemId} not found`);
  if (actionItem.status !== 'pending') return { skipped: true, reason: 'not_pending', status: actionItem.status };

  const routing = routeActionItem(actionItem.description);
  const assignedTo = routing ? routing.member_id : null;
  const assigneeName = routing ? routing.member_name : 'Unassigned';

  // Create task from action item
  const taskResult = db.prepare(`
    INSERT INTO tasks (title, description, status, priority, source_file, assigned_to, created_at, updated_at)
    VALUES (?, ?, ?, ?, 'action_item', ?, ?, ?)
  `).run(
    actionItem.description.slice(0, 120),
    `Auto-created from action item #${actionItem.id} (note #${actionItem.note_id || 'N/A'}).\n\n${actionItem.description}`,
    assignedTo ? 'in_progress' : 'new',
    actionItem.priority || 'normal',
    assignedTo,
    now,
    now
  );
  const taskId = Number(taskResult.lastInsertRowid);

  // Create task assignment if routed
  if (assignedTo) {
    db.prepare(`
      INSERT INTO task_assignments (task_id, member_id, subagent_count, created_at)
      VALUES (?, ?, 1, ?)
    `).run(taskId, assignedTo, now);
  }

  // Update action item: link to task, mark as auto_executed
  db.prepare(`
  `).run(taskId, now, actionItemId);

  // Log to activity_log
  db.prepare(`
    INSERT INTO activity_log (task_id, actor, action, notes, created_at)
    VALUES (?, 'Board', 'auto_execute_action_item', ?, ?)
  `).run(taskId, `Auto-executed action item #${actionItemId} → task #${taskId}, assigned to ${assigneeName}`, now);

  // Auto-spawn terminal for the assigned member
  let spawnResult = null;
  if (assignedTo) {
    try {
      spawnResult = await spawnMemberTerminal(taskId, assignedTo);
    } catch (err) {
      console.error(`[ActionItem] Spawn error for task #${taskId}, member #${assignedTo}: ${err.message}`);
    }
  }

  broadcast('task.updated', { id: taskId });
  broadcast('action_item.executed', { action_item_id: actionItemId, task_id: taskId, assignee: assigneeName });

  return { action_item_id: actionItemId, task_id: taskId, assignee: assigneeName, spawn: spawnResult };
}

