// ── GET /api/queue — Combined task queue: all active tasks ────
// Mission Control queue only shows tasks Max personally submitted (browser, api, inbox)
// Automated tasks (improvement, idea_research, action_item, site-builder) stay in their own areas

app.get('/api/queue', (req, res) => {
  try {
    // source='all' param shows everything (for Live Monitor etc.)
    const showAll = req.query.source === 'all';
    const sourceFilter = showAll
      ? ''
      : `AND (t.source_file IS NULL OR t.source_file IN ('browser', 'api', ''))`;

    const rows = db.prepare(`
      SELECT t.id, t.title, t.status, t.priority, t.created_at, t.updated_at,
             t.subagent_count, t.progress, t.current_step, t.started_at,
             t.source_file,
             tm.name as assignee_name,
             p.name as project_name, p.id as project_id, p.color as project_color
      FROM tasks t
      LEFT JOIN team_members tm ON t.assigned_to = tm.id
      LEFT JOIN project_tasks pt ON pt.task_id = t.id
      LEFT JOIN projects p ON pt.project_id = p.id
      WHERE t.status IN ('new', 'routing', 'in_progress', 'review')
      ${sourceFilter}
      ORDER BY
        CASE t.priority WHEN 'urgent' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 WHEN 'low' THEN 3 END,
        t.created_at ASC
    `).all();

    // Attach assignment details from task_assignments
    const assignStmt = db.prepare(`
      SELECT ta.member_id, ta.subagent_count, tm.name as member_name
      FROM task_assignments ta
      LEFT JOIN team_members tm ON ta.member_id = tm.id
      WHERE ta.task_id = ?
    `);

    // Attach latest activity
    const actStmt = db.prepare(`
      SELECT actor, action, notes, created_at
      FROM activity_log WHERE task_id = ?
      ORDER BY created_at DESC LIMIT 1
    `);

    // Check for active Council routing process per task
    const councilStmt = db.prepare(`
      SELECT id as process_id, started_at, output_summary
      FROM active_processes
      WHERE task_id = ? AND process_type = 'council' AND status = 'running'
      ORDER BY id DESC LIMIT 1
    `);

    const enriched = rows.map(r => {
      const councilProc = councilStmt.get(r.id);
      return {
        ...r,
        assignments: assignStmt.all(r.id),
        latest_activity: actStmt.get(r.id) || null,
        council_routing_active: !!councilProc,
        council_process_id: councilProc ? councilProc.process_id : null,
        council_started_at: councilProc ? councilProc.started_at : null
      };
    });

    res.json(enriched);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── Linked Repos ─────────────────────────────────────────────────

app.post('/api/repos', (req, res) => {
  try {
    const { url, name, description } = req.body;
    if (!url || !url.trim()) {
      return res.status(400).json({ error: 'URL is required' });
    }

    // Parse owner/name from GitHub URL
    const match = url.trim().match(/github\.com\/([^\/]+)\/([^\/\?\#]+)/);
    if (!match) {
      return res.status(400).json({ error: 'Invalid GitHub URL' });
    }
    const owner = match[1];
    const repoName = name || match[2].replace(/\.git$/, '');
    const now = localNow();

    const result = db.prepare(`
      INSERT INTO linked_repos (url, name, owner, description, created_at)
      VALUES (?, ?, ?, ?, ?)
    `).run(url.trim(), repoName, owner, (description || '').trim() || null, now);

    res.json({ id: Number(result.lastInsertRowid), name: repoName, owner, message: 'Repo linked' });
  } catch (err) {
    console.error('POST /api/repos error:', err);
    res.status(500).json({ error: err.message });
  }
});

app.get('/api/repos', (req, res) => {
  try {
    const rows = db.prepare(`SELECT * FROM linked_repos ORDER BY created_at DESC`).all();
    res.json(rows);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.delete('/api/repos/:id', (req, res) => {
  try {
    const result = db.prepare(`DELETE FROM linked_repos WHERE id = ?`).run(req.params.id);
    if (result.changes === 0) return res.status(404).json({ error: 'Repo not found' });
    res.json({ message: 'Repo unlinked' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

