app.post('/api/paths', (req, res) => {
  try {
    const { path: filePath, type, name, description } = req.body;
    if (!filePath || !filePath.trim()) {
      return res.status(400).json({ error: 'Path is required' });
    }
    if (!['file', 'folder'].includes(type)) {
      return res.status(400).json({ error: 'Type must be file or folder' });
    }
    const now = localNow();
    const pathName = name || filePath.trim().split('/').filter(Boolean).pop() || filePath.trim();

    const result = db.prepare(`
      INSERT INTO linked_paths (path, name, type, description, created_at)
      VALUES (?, ?, ?, ?, ?)
    `).run(filePath.trim(), pathName, type, (description || '').trim() || null, now);

    res.json({ id: Number(result.lastInsertRowid), name: pathName, message: 'Path linked' });
  } catch (err) {
    console.error('POST /api/paths error:', err);
    res.status(500).json({ error: err.message });
  }
});

