// PUT /api/tools/:id — update a tool
app.put('/api/tools/:id', (req, res) => {
  try {
    const existing = db.prepare(`SELECT * FROM member_tools WHERE id = ?`).get(req.params.id);
    if (!existing) return res.status(404).json({ error: 'Tool not found' });

    const tool_name = req.body.tool_name !== undefined ? req.body.tool_name : existing.tool_name;
    const tool_type = req.body.tool_type !== undefined ? req.body.tool_type : existing.tool_type;
    const config = req.body.config !== undefined ? JSON.stringify(req.body.config) : existing.config;
    const enabled = req.body.enabled !== undefined ? (req.body.enabled ? 1 : 0) : existing.enabled;
    const use_cases = req.body.use_cases !== undefined ? req.body.use_cases : existing.use_cases;
    const guidelines = req.body.guidelines !== undefined ? req.body.guidelines : existing.guidelines;
    const usage_limits = req.body.usage_limits !== undefined ? req.body.usage_limits : existing.usage_limits;
    const daily_limit = req.body.daily_limit !== undefined ? req.body.daily_limit : existing.daily_limit;
    const vault_id = req.body.vault_id !== undefined ? req.body.vault_id : existing.vault_id;
    const now = localNow();

    db.prepare(`
      UPDATE member_tools SET tool_name = ?, tool_type = ?, config = ?, enabled = ?, use_cases = ?, guidelines = ?, usage_limits = ?, daily_limit = ?, vault_id = ?, updated_at = ?
      WHERE id = ?
    `).run(tool_name, tool_type, config, enabled, use_cases, guidelines, usage_limits, daily_limit, vault_id, now, req.params.id);

    res.json({
      id: Number(req.params.id),
      member_id: existing.member_id,
      tool_name,
      tool_type,
      config: maskSensitiveConfig(JSON.parse(config)),
      enabled,
      use_cases,
      guidelines,
      usage_limits,
      daily_limit,
      daily_used: existing.daily_used,
      last_reset_date: existing.last_reset_date,
      updated_at: now
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

