// GET /api/board-room/rooms — list all chat rooms (one per company) with participant info
app.get('/api/board-room/rooms', (req, res) => {
  try {
    const companies = db.prepare(`
      SELECT c.id, c.name, c.color,
        (SELECT COUNT(*) FROM board_chats bc WHERE bc.company_id = c.id) as message_count,
        (SELECT bc2.message FROM board_chats bc2 WHERE bc2.company_id = c.id ORDER BY bc2.id DESC LIMIT 1) as last_message,
        (SELECT bc3.created_at FROM board_chats bc3 WHERE bc3.company_id = c.id ORDER BY bc3.id DESC LIMIT 1) as last_activity
      FROM companies c WHERE c.status = 'active' ORDER BY c.id
    `).all();

    // For each company, get the leadership participants
    const rooms = companies.map(c => {
      // Get highest tier below Max: board members first, then c-suite
      let participants = db.prepare(`
        SELECT tm.id, tm.name, tm.role, tm.tier, tm.icon
        FROM company_members cm
        JOIN team_members tm ON cm.member_id = tm.id
        WHERE cm.company_id = ? AND cm.status = 'active' AND tm.status = 'active'
        AND tm.tier IN ('board', 'c-suite')
        ORDER BY CASE tm.tier WHEN 'board' THEN 0 WHEN 'c-suite' THEN 1 END, tm.name
      `).all(c.id);

      // If company has board members, only show board. If only c-suite, show c-suite.
      const hasBoard = participants.some(p => p.tier === 'board');
      if (hasBoard) {
        participants = participants.filter(p => p.tier === 'board');
      }

      // For Command Base (id=1), include the main board of directors
      if (c.id === 1 && participants.length === 0) {
        participants = db.prepare(`
          SELECT id, name, role, tier, icon FROM team_members
          WHERE status = 'active' AND tier = 'board' AND name != 'Max Stewart'
          ORDER BY name
        `).all();
      }

      // For other companies without board, get their CEO/CTO
      if (participants.length === 0) {
        participants = db.prepare(`
          SELECT tm.id, tm.name, tm.role, tm.tier, tm.icon FROM team_members tm
          WHERE tm.status = 'active' AND tm.id IN (
            SELECT ceo_member_id FROM companies WHERE id = ?
            UNION SELECT cto_member_id FROM companies WHERE id = ?
          )
        `).all(c.id, c.id);
      }

      return { ...c, participants };
    });

    res.json(rooms);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/board-room/:companyId/messages — get chat history
app.get('/api/board-room/:companyId/messages', (req, res) => {
  try {
    const limit = Math.min(parseInt(req.query.limit) || 50, 200);
    const before = req.query.before; // cursor-based pagination
    let sql = `SELECT * FROM board_chats WHERE company_id = ?`;
    const params = [req.params.companyId];
    if (before) { sql += ` AND id < ?`; params.push(before); }
    sql += ` ORDER BY id DESC LIMIT ?`;
    params.push(limit);
    const messages = db.prepare(sql).all(...params).reverse();
    res.json(messages);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// POST /api/board-room/:companyId/message — Max sends a directive (supports file uploads)
app.post('/api/board-room/:companyId/message', authRateLimiter, upload.array('files', 10), (req, res) => {
  try {
    const message = req.body.message;
    const priority = req.body.priority;
    if (!message || !message.trim()) return res.status(400).json({ error: 'Message is required' });
    const companyId = Number(req.params.companyId);
    const now = localNow();

    // Save Max's directive
    const result = db.prepare(`
      INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, created_at)
      VALUES (?, 49, 'Max Stewart', 'Chairman', ?, 'directive', ?)
    `).run(companyId, message.trim(), now);
    const chatId = Number(result.lastInsertRowid);

    broadcast('boardroom.message', { company_id: companyId, id: chatId, sender_name: 'Max Stewart', message_type: 'directive' });

    // Create a mission from this directive, scoped to the company
    const company = db.prepare(`SELECT * FROM companies WHERE id = ?`).get(companyId);
    const companyName = company ? company.name : 'Unknown';
    const taskPriority = priority || 'high';

    const taskResult = db.prepare(`
      INSERT INTO tasks (title, description, status, priority, source_file, origin, created_at, updated_at)
      VALUES (?, ?, 'routing', ?, 'board-room', 'browser', ?, ?)
    `).run(
      `[${companyName}] ${message.trim().slice(0, 100)}`,
      `CHAIRMAN'S DIRECTIVE via Board Room — ${companyName}\n\n${message.trim()}`,
      taskPriority, now, now
    );
    const taskId = Number(taskResult.lastInsertRowid);

    // Link task to company's project if one exists
    const companyProject = db.prepare(`SELECT id FROM projects WHERE company_id = ? LIMIT 1`).get(companyId);
    if (companyProject) {
      db.prepare(`INSERT OR IGNORE INTO project_tasks (project_id, task_id) VALUES (?, ?)`).run(companyProject.id, taskId);
    }

    // Update chat message with task reference
    db.prepare(`UPDATE board_chats SET task_id = ? WHERE id = ?`).run(taskId, chatId);

    // Save uploaded files to task
    if (req.files && req.files.length > 0) {
      for (const f of req.files) {
        db.prepare(`INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at)
          VALUES (?, ?, ?, ?, 'input', ?)`).run(taskId, f.originalname, f.path, f.mimetype, now);
      }
    }

    // Save linked repos from the message (parsed from ## Linked Repositories section)
    const repoMatches = message.match(/## Linked Repositories\n([\s\S]*?)(?=\n##|$)/);
    if (repoMatches) {
      const repos = repoMatches[1].match(/https?:\/\/[^\s]+/g) || [];
      for (const url of repos) {
        const repoName = url.split('/').slice(-2).join('/').replace('.git', '');
        db.prepare(`INSERT OR IGNORE INTO linked_repos (url, name, owner, description, created_at)
          VALUES (?, ?, ?, 'Linked via Board Room', ?)`).run(url, repoName.split('/').pop(), repoName.split('/')[0] || '', now);
      }
    }

    // Save linked folders from the message
    const pathMatches = message.match(/## Linked Folders\n([\s\S]*?)(?=\n##|$)/);
    if (pathMatches) {
      const paths = pathMatches[1].match(/- (.+)/g) || [];
      for (const p of paths) {
        const cleanPath = p.replace('- ', '').trim();
        db.prepare(`INSERT OR IGNORE INTO linked_paths (path, type, description, created_at)
          VALUES (?, 'folder', 'Linked via Board Room', ?)`).run(cleanPath, now);
      }
    }

    // Post system message about task creation
    db.prepare(`
      INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
      VALUES (?, 'System', 'System', ?, 'system', ?, ?)
    `).run(companyId, `Directive received. Task #${taskId} created (${taskPriority} priority). Routing to leadership...`, taskId, now);

    broadcast('boardroom.message', { company_id: companyId, message_type: 'system', task_id: taskId });

    // ── CHAIN OF COMMAND — smart routing based on task size ────────
    // Board Room directives ALWAYS go through Council — the Chairman is speaking to his Board.
    // For quick tasks, use the direct-assign dropdown instead.
    // Council uses Opus for urgent, Sonnet for standard. Never skipped.
    const msgLen = message.trim().length;
    {
    // FULL PATH — Intake analyzes first, then Council deliberates
    setImmediate(async () => {
      try {
        const cliPathSetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'claude_cli_path'`).get();
        const cliPath = (cliPathSetting && cliPathSetting.value) ? cliPathSetting.value : 'claude';
        const deliberationNow = localNow();

        // Save large plans as files BEFORE Analyst step (Analyst needs the file path)
        const msgText = message.trim();
        let planFilePath = null;
        const planSizeKB = Math.ceil(msgText.length / 1024);

        if (msgText.length > 30000) {
          const planFileName = `directive-${taskId}-${Date.now()}.md`;
          planFilePath = path.join(__dirname, '..', '.claude', 'plans', planFileName);
          try {
            fs.writeFileSync(planFilePath, msgText, 'utf-8');
            console.log(`[BoardRoom] Saved ${planSizeKB}KB plan to ${planFilePath}`);
          } catch (saveErr) {
            console.warn(`[BoardRoom] Failed to save plan file: ${saveErr.message}`);
            planFilePath = null;
          }
        }

        // ── STEP 1: Digest the directive ──
        // For mega-prompts (files > 100KB), use the full digestion pipeline:
        //   chunks → parallel digesters → memories → curated brief
        // For smaller directives, use the single Analyst as before.

        let intakeBrief = null;
        let digestionResult = null;

        // Check if any attached file is large enough to trigger digestion
        const largeFile = req.files && req.files.find(f => f.size > 100000); // >100KB
        const isMegaPrompt = largeFile || (planFilePath && planSizeKB > 100);

        if (isMegaPrompt) {
          // ── MEGA-PROMPT DIGESTION PIPELINE ──
          // Break the file into chunks, distribute to digesters, collect memories
          const digestFilePath = largeFile ? largeFile.path : planFilePath;
          try {
            digestionResult = await digestMegaPrompt({
              filePath: digestFilePath,
              taskId,
              companyId,
              companyName,
              cliPath,
              taskPriority,
              msgText,
              reqFiles: req.files
            });
            intakeBrief = digestionResult.masterBrief;
            console.log(`[BoardRoom] Mega-prompt digestion complete for task #${taskId}: ${digestionResult.allMemories.length} memories, ${digestionResult.chunks.length} chunks`);
          } catch (digestErr) {
            console.error(`[BoardRoom] Digestion pipeline failed: ${digestErr.message}. Falling back to single Analyst.`);
            // Fall through to single Analyst below
          }
        }

        if (!intakeBrief) {
          // ── SINGLE ANALYST PATH (small directives or digestion fallback) ──
          const analyst = db.prepare(`
            SELECT tm.id, tm.name FROM team_members tm
            JOIN company_members cm ON tm.id = cm.member_id
            WHERE cm.company_id = ? AND tm.role LIKE '%Directive Analyst%' AND tm.status = 'active'
            LIMIT 1
          `).get(companyId) || db.prepare(`SELECT id, name FROM team_members WHERE name = 'Intake' AND status = 'active'`).get();

          if (analyst) {
            // Post that Intake is analyzing
            db.prepare(`INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, task_id, created_at)
              VALUES (?, ?, ?, 'Directive Analyst', 'Analyzing your directive and any attached files. Preparing a structured brief for the Council...', 'response', ?, ?)`)
              .run(companyId, analyst.id, analyst.name, taskId, deliberationNow);
            broadcast('boardroom.message', { company_id: companyId, message_type: 'response', task_id: taskId });

            // Build the Intake prompt
            const intakePrompt = `You are ${analyst.name}, the Directive Analyst. The Chairman has sent a directive to the Board Room. Your job is to READ everything and produce a STRUCTURED BRIEF for the Council.

MESSAGE FROM CHAIRMAN:
${planFilePath ? `The Chairman sent a ${planSizeKB}KB document. Read the FULL file at: ${planFilePath}\nRead it in sections using the Read tool (2000 lines at a time with offset/limit). Do NOT skip any part.` : msgText.slice(0, 30000)}

${req.files && req.files.length > 0 ? `ATTACHED FILES:\n${req.files.map(f => '- ' + f.originalname + ' (' + Math.ceil(f.size/1024) + 'KB) at: ' + f.path).join('\n')}\nRead each attached file completely.` : ''}

After reading EVERYTHING, produce your brief in this EXACT format:

CLASSIFICATION: [founding/feature/bugfix/import/plan]
COMPLEXITY: [simple/moderate/complex/massive]
PHASES: [estimated number]

INTENT: [What Max wants, 1-3 sentences]

DELIVERABLES:
- [deliverable 1]
- [deliverable 2]

PHASE_PLAN:
1. [Phase description] — Dependencies: [none]
2. [Phase description] — Dependencies: [Phase 1]

TECHNICAL:
- [tables/APIs/UI needed]

FILES:
- [filename — what it contains]

RISKS:
- [anything that could block or cause rework]

COUNCIL_APPROACH:
- [How Council should break this down]
- [Which exec domains are involved]`;

            // Analyst model scales with file complexity — large files need Opus to properly digest
            const isLargeFile = planFilePath && planSizeKB > 100;
            const intakeModel = isLargeFile ? 'opus' : 'sonnet';
            const intakeTurns = planFilePath ? String(Math.min(20, Math.max(5, Math.ceil(planSizeKB / 80)))) : '3';
            const intakeArgs = ['--print', '--model', intakeModel, '--max-turns', intakeTurns, '--dangerously-skip-permissions', '--output-format', 'text'];
            const { spawn } = require('child_process');
            const intakeChild = spawn(cliPath, intakeArgs, {
              env: { ...process.env, DISABLE_AUTOUPDATER: '1' },
              stdio: ['pipe', 'pipe', 'pipe'],
              cwd: path.join(process.env.PROJECT_ROOT || path.join(__dirname, '..'), 'app')
            });

            intakeBrief = await new Promise((resolve) => {
              let output = '';
              intakeChild.stdout.on('data', d => { output += d.toString(); });
              intakeChild.stderr.on('data', () => {});
              try { intakeChild.stdin.write(intakePrompt); intakeChild.stdin.end(); } catch (_) {}

              const timeout = setTimeout(() => {
                try { intakeChild.kill('SIGTERM'); } catch (_) {}
                resolve(null);
              }, planFilePath ? 180000 : 60000); // 3 min for large files, 1 min for small

              intakeChild.on('close', () => {
                clearTimeout(timeout);
                // Post Intake's brief to Board Room
                const briefText = output.length > 100 ? output.slice(0, 3000) : null;
                if (briefText) {
                  try {
                    db.prepare(`INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, task_id, created_at)
                      VALUES (?, ?, ?, 'Directive Analyst', ?, 'response', ?, ?)`)
                      .run(companyId, analyst.id, analyst.name, `Brief prepared. Passing to Council for deliberation.`, taskId, localNow());
                    broadcast('boardroom.message', { company_id: companyId, message_type: 'response', task_id: taskId });
                  } catch (_) {}
                }
                resolve(output || null);
              });
            });
          }
        }

        // ── STEP 2: Council deliberates using Intake's brief ──

        // Load LEAN team roster — department leads only, not all 74 specialists
        const csuite = db.prepare(`SELECT name, role, department FROM team_members WHERE status = 'active' AND tier IN ('c-suite','executive') AND department NOT IN ('Clipper Engine','Animation Studio') ORDER BY name`).all();

        // Get department leads (senior/director specialists) — the Council only needs to know WHO leads each area
        const deptLeads = db.prepare(`
          SELECT department, name, role FROM team_members
          WHERE status = 'active' AND tier = 'specialist'
          AND (role LIKE '%Director%' OR role LIKE '%Lead%' OR role LIKE '%Senior%')
          ORDER BY department, CASE WHEN role LIKE '%Director%' THEN 0 WHEN role LIKE '%Lead%' THEN 1 ELSE 2 END
        `).all();

        const deptMap = {};
        for (const d of deptLeads) {
          const dept = d.department || 'General';
          if (!deptMap[dept]) deptMap[dept] = [];
          if (deptMap[dept].length < 2) deptMap[dept].push(`${d.name} (${d.role})`);
        }

        let rosterText = 'Key specialists by department:\n';
        for (const [dept, leads] of Object.entries(deptMap)) {
          const exec = csuite.find(c => c.department === dept);
          rosterText += `- ${dept}: ${leads.join(', ')}${exec ? ' [Exec: ' + exec.name + ']' : ''}\n`;
        }

        // For large directives (>30KB), save the full plan as a file.
        // Plan file was already saved above (before Analyst step). Build the directive for Council.
        let directiveForPrompt = msgText;
        if (planFilePath) {
          directiveForPrompt = `The Chairman has submitted a ${planSizeKB}KB plan. File: ${planFilePath}\nThe Directive Analyst has already read and briefed you. Use the brief to plan execution. Reference the file for specific details.`;
        }

        // Use the digestion result or Intake's brief — much better structured than raw message
        let councilDirective;
        if (digestionResult && digestionResult.masterBrief) {
          // Mega-prompt was digested — give Council the curated brief with memories, not raw file
          const memSummary = digestionResult.allMemories.slice(0, 30).map(m =>
            `- [${m.importance.toUpperCase()}] ${m.title}: ${m.content.slice(0, 200)}`
          ).join('\n');
          const digestedFileSize = planSizeKB || (largeFile ? Math.ceil(largeFile.size / 1024) : 0);
          // Full memories inline — Council needs the details to make informed phasing/assignment decisions.
          // The 43KB CLAUDE.md is avoided by spawning from /tmp (no project context loaded).
          councilDirective = `The Chairman's ${digestedFileSize}KB document was digested by ${digestionResult.results.length} specialists. ${digestionResult.allMemories.length} key memories extracted. ALL information you need is below — do NOT read any files.

CHAIRMAN'S MESSAGE: ${msgText.slice(0, 500)}

CRITICAL FINDINGS:
${digestionResult.allMemories.filter(m => m.importance === 'critical').slice(0, 15).map(m => `- ${m.title}: ${m.content.slice(0, 250)}`).join('\n') || '(none)'}

HIGH-PRIORITY FINDINGS:
${digestionResult.allMemories.filter(m => m.importance === 'high').slice(0, 15).map(m => `- ${m.title}: ${m.content.slice(0, 250)}`).join('\n') || '(none)'}

KEY FINDINGS:
${digestionResult.allMemories.filter(m => m.importance === 'normal').slice(0, 10).map(m => `- ${m.title}: ${m.content.slice(0, 200)}`).join('\n') || '(none)'}

The document covers ${digestionResult.chunks.length} sections across 26 implementation segments (CE-01 through CE-26). Create a phased execution plan assigning the right specialists to each phase.`;
        } else if (intakeBrief && intakeBrief.length > 200) {
          councilDirective = `The Directive Analyst has prepared the following brief from the Chairman's message:\n\n${intakeBrief.slice(0, 8000)}${planFilePath ? '\n\nFull plan file: ' + planFilePath : ''}`;
        } else {
          councilDirective = directiveForPrompt;
        }

        const councilPrompt = `You are the Board of Directors. The Chairman has given you a directive. Your Directive Analyst has already read and structured it. You MUST respond with a structured execution plan.

IMPORTANT: Do NOT use any tools. Do NOT read any files. ALL information you need is in this prompt. Just respond with text.

DIRECTIVE: ${councilDirective}

TEAM:
C-Suite: ${csuite.map(c => c.name + ' (' + c.role + ')').join(', ')}
${rosterText}
YOUR RESPONSE MUST follow this EXACT format. Do not deviate.

CONSENSUS: [What the Board decided, 1-2 sentences]

STANDARDS:
- [Specific criterion 1 — e.g. "endpoint returns JSON with id, name, status fields"]
- [Specific criterion 2 — e.g. "page renders without console errors"]
- [Specific criterion 3]

PLAN:
1. [Task description] → Executive: [name] → Specialist: [name] → Model: sonnet → Priority: high
REQUIREMENTS: [What to build]
SPECIFICATIONS: [How — mention specific files, patterns, endpoints]
TEST_PLAN: [How to verify]
DEFINITION_OF_DONE: [Conditions for completion]

2. [Next task] → Executive: [name] → Specialist: [name] → Model: sonnet → Priority: high
REQUIREMENTS: [What]
SPECIFICATIONS: [How]
TEST_PLAN: [Verify]
DEFINITION_OF_DONE: [Done when]

EXECUTIVE_OWNER: [Name]

IMPORTANT: You MUST include at least one numbered item in the PLAN section. Every item MUST have the → Executive: → Specialist: → Model: → Priority: format on the FIRST line. Do NOT skip the PLAN.`;

        // Post that Council is deliberating — and mark task as in_progress so the routing watchdog doesn't steal it
        db.prepare(`UPDATE tasks SET status = 'in_progress', current_step = 'Council deliberating...', updated_at = ? WHERE id = ? AND status = 'routing'`)
          .run(deliberationNow, taskId);
        db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
          VALUES (?, 'Council', 'Board of Directors', 'Deliberating on your directive. Setting standards and building execution plan...', 'response', ?, ?)`)
          .run(companyId, taskId, deliberationNow);
        broadcast('boardroom.message', { company_id: companyId, message_type: 'response', task_id: taskId });

        // Spawn Council deliberation (Haiku — cheap, structured output)
        const { spawn } = require('child_process');
        // Council uses highest reasoning models. Better planning = cheaper execution downstream.
        // Opus for urgent or large plans, Sonnet for standard.
        // Turns scale with plan size — needs enough to Read the full file in chunks + deliberate.
        const isLargePlan = planFilePath !== null || digestionResult !== null;
        const councilModel = (taskPriority === 'urgent' || isLargePlan) ? 'opus' : 'sonnet';
        const effectiveSizeKB = digestionResult ? Math.ceil(digestionResult.masterBrief.length / 1024) : planSizeKB;
        // Council should produce the plan in 1-2 turns (no tool calls — everything inline).
        // More turns just means more opportunities to waste time reading files.
        const councilMaxTurns = isLargePlan ? '3' : '3';
        console.log(`[Council] Task #${taskId}: model=${councilModel}, turns=${councilMaxTurns}, isLargePlan=${isLargePlan}, effectiveSizeKB=${effectiveSizeKB}, promptLen=${councilPrompt.length}, directiveLen=${councilDirective.length}`);
        // --tools "" disables all tools — Council must respond with text only, no file reading
        // cwd set to /tmp so the CLI doesn't load the 43KB CLAUDE.md from the project root
        // (the Council has all knowledge inline from digestion — project context would bloat the prompt)
        const councilArgs = ['--print', '--model', councilModel, '--max-turns', councilMaxTurns, '--dangerously-skip-permissions', '--output-format', 'text', '--tools', ''];
        const councilChild = spawn(cliPath, councilArgs, {
          env: { ...process.env, DISABLE_AUTOUPDATER: '1' },
          stdio: ['pipe', 'pipe', 'pipe'],
          cwd: '/tmp'
        });

        // Council timeout — scales with plan size. Large plans need more time to read and digest.
        // Opus with --tools "" from /tmp needs 3-4 min for a 14KB prompt. Give it 5 min base.
        const councilTimeoutMs = isLargePlan
          ? Math.min(600000, 300000 + (effectiveSizeKB * 100)) // 5 min base + 100ms per KB, max 10 min
          : 90000;
        const councilTimeout = setTimeout(() => {
          console.warn(`[Council] Deliberation timed out after ${councilTimeoutMs/1000}s for task #${taskId}. Killing and falling back.`);
          try { councilChild.kill('SIGTERM'); } catch (_) {}
          setTimeout(() => { try { councilChild.kill('SIGKILL'); } catch (_) {} }, 5000);
        }, councilTimeoutMs);

        let councilOutput = '';
        let councilStderr = '';
        councilChild.stdout.on('data', d => { councilOutput += d.toString(); });
        councilChild.stderr.on('data', d => { councilStderr += d.toString(); });

        try { councilChild.stdin.write(councilPrompt); councilChild.stdin.end(); } catch (writeErr) {
          console.error(`[Council] stdin write failed: ${writeErr.message}`);
        }

        councilChild.on('close', (code) => {
          console.log(`[Council] Process exited with code ${code}. stdout=${councilOutput.length}ch, stderr=${councilStderr.length}ch`);
          if (councilStderr) console.log(`[Council] stderr: ${councilStderr.slice(0, 500)}`);
          clearTimeout(councilTimeout);
          const doneAt = localNow();

          // Log raw Council output for debugging empty plan issues
          try {
            const councilLogPath = path.join(__dirname, '..', '.claude', 'digestion', `council-output-task-${taskId}.txt`);
            fs.writeFileSync(councilLogPath, councilOutput || '(empty)', 'utf-8');
            console.log(`[Council] Raw output saved to ${councilLogPath} (${councilOutput.length} chars)`);
          } catch (_) {}

          // Parse Council's output — multi-strategy parser
          // Strategy 1: Strict format (CONSENSUS/STANDARDS/PLAN headers)
          // Strategy 2: Markdown headers (## Consensus, ## Plan, etc.)
          // Strategy 3: Bold headers (**Consensus**, **Plan**, etc.)
          // Strategy 4: Fallback — find ANY numbered list items with specialist names

          let consensus = 'Council reviewed and approved the directive.';
          let standards = '';
          let plan = '';
          let execOwner = '';

          // Try all header formats for each section
          const sectionPatterns = {
            consensus: /(?:^|\n)(?:CONSENSUS|#{1,3}\s*Consensus|\*\*Consensus\*\*)[:\s—\-]*([\s\S]+?)(?=\n(?:STANDARDS|#{1,3}\s*Standards|\*\*Standards|PLAN|#{1,3}\s*Plan|\*\*Plan|\d+\.))/i,
            standards: /(?:^|\n)(?:STANDARDS|#{1,3}\s*Standards|\*\*Standards[:\s]*\*\*)[:\s—\-]*([\s\S]+?)(?=\n(?:PLAN|#{1,3}\s*Plan|\*\*Plan|\d+\.))/i,
            plan: /(?:^|\n)(?:PLAN|#{1,3}\s*(?:Execution\s*)?Plan|\*\*(?:Execution\s*)?Plan[:\s]*\*\*)[:\s—\-]*([\s\S]+?)(?=\n(?:EXECUTIVE_OWNER|#{1,3}\s*Executive|Owner|\*\*Executive)|\s*$)/i,
            execOwner: /(?:EXECUTIVE_OWNER|#{1,3}\s*Executive\s*Owner|\*\*Executive\s*Owner\*\*)[:\s—\-]*(\w+)/i
          };

          const consensusMatch = councilOutput.match(sectionPatterns.consensus);
          const standardsMatch = councilOutput.match(sectionPatterns.standards);
          let planMatch = councilOutput.match(sectionPatterns.plan);
          const execMatch = councilOutput.match(sectionPatterns.execOwner);

          if (consensusMatch) consensus = consensusMatch[1].trim().replace(/^\*+|\*+$/g, '');
          if (standardsMatch) standards = standardsMatch[1].trim();
          if (planMatch) plan = planMatch[1].trim();
          if (execMatch) execOwner = execMatch[1].trim();

          // Strategy 4 fallback: if no plan found, look for ANY numbered items in the full output
          if (!plan || plan.length < 20) {
            // Look for numbered items like "1. Description → Specialist: Name"
            const numberedItems = councilOutput.match(/^\d+\.\s+.+/gm);
            if (numberedItems && numberedItems.length > 0) {
              // Extract everything from first numbered item to end
              const firstItemIdx = councilOutput.indexOf(numberedItems[0]);
              if (firstItemIdx >= 0) {
                plan = councilOutput.slice(firstItemIdx).trim();
                console.log(`[Council] Fallback parser found ${numberedItems.length} numbered items`);
              }
            }
          }

          // Strategy 5 ultra-fallback: if still no plan, look for specialist/executive mentions
          if (!plan || plan.length < 20) {
            const specMentions = councilOutput.match(/(?:Specialist|assign|delegate|route).*?(?:→|->|:)\s*\w+/gi);
            if (specMentions && specMentions.length > 0) {
              // Reconstruct a minimal plan from specialist mentions
              plan = specMentions.map((m, i) => `${i + 1}. ${m}`).join('\n');
              console.log(`[Council] Ultra-fallback: reconstructed plan from ${specMentions.length} specialist mentions`);
            }
          }

          console.log(`[Council] Parsed — consensus: ${consensus.length}ch, standards: ${standards.length}ch, plan: ${plan.length}ch, exec: ${execOwner || 'none'}`);

          // Post Council's decision to Board Room
          const councilMsg = `**Council Decision:**\n${consensus}\n\n**Standards of Work:**\n${standards}\n\n**Execution Plan:**\n${plan}${execOwner ? '\n\n**Executive Owner:** ' + execOwner : ''}`;
          db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
            VALUES (?, 'Council', 'Board of Directors', ?, 'decision', ?, ?)`)
            .run(companyId, councilMsg, taskId, doneAt);
          broadcast('boardroom.message', { company_id: companyId, message_type: 'decision', task_id: taskId });

          // Update task with standards
          db.prepare(`UPDATE tasks SET description = description || ?, updated_at = ? WHERE id = ?`)
            .run(`\n\n---\n## COUNCIL STANDARDS OF WORK\n${standards}\n\n## EXECUTION PLAN\n${plan}\n`, doneAt, taskId);

          // Parse plan into sub-tasks — flexible parsing for multiple formatting styles
          const planBlocks = plan.split(/(?=^\d+\.)/m).filter(b => b.trim().match(/^\d+\./));
          console.log(`[Council] Found ${planBlocks.length} plan blocks from ${plan.length} chars of plan text`);
          if (planBlocks.length > 0) {
            for (const block of planBlocks) {
              const blockLines = block.split('\n');
              const firstLine = blockLines[0] || '';
              // Search the whole block for specialist/executive names, not just first line
              const fullBlock = block;
              const specMatch = fullBlock.match(/Specialist[:\s]+(\w+)/i);
              const execTaskMatch = fullBlock.match(/Executive[:\s]+(\w+)/i);
              // Description: everything after the number, before → or specialist/executive markers
              const descMatch = firstLine.match(/^\d+\.\s*(.+?)(?=→|->|\s*Specialist|\s*Executive|$)/i);
              const prioMatch = fullBlock.match(/Priority[:\s]+(\w+)/i);
              const modelMatch = fullBlock.match(/Model[:\s]+(\w+)/i);

              // Also check for "Assign to: Name" or "→ Name" patterns
              const assignMatch = !specMatch ? fullBlock.match(/(?:assign(?:ed)?\s+to|→|->)[:\s]*(\w+)/i) : null;

              // Extract the four deliverable elements — search with flexible header formats
              // Support both "REQUIREMENTS:" and "**Requirements:**" and "## Requirements"
              const reqMatch = block.match(/(?:REQUIREMENTS|#{1,3}\s*Requirements|\*\*Requirements\*\*)[:\s]*([\s\S]+?)(?=\n(?:SPECIFICATIONS|#{1,3}\s*Specifications|\*\*Specifications|TEST_PLAN|#{1,3}\s*Test|DEFINITION_OF_DONE)|\n\d+\.|\s*$)/is);
              const specBlockMatch = block.match(/(?:SPECIFICATIONS|#{1,3}\s*Specifications|\*\*Specifications\*\*)[:\s]*([\s\S]+?)(?=\n(?:TEST_PLAN|#{1,3}\s*Test|DEFINITION_OF_DONE)|\n\d+\.|\s*$)/is);
              const testMatch = block.match(/(?:TEST_PLAN|#{1,3}\s*Test\s*Plan|\*\*Test\s*Plan\*\*)[:\s]*([\s\S]+?)(?=\n(?:DEFINITION_OF_DONE|#{1,3}\s*Definition)|\n\d+\.|\s*$)/is);
              const dodMatch = block.match(/(?:DEFINITION_OF_DONE|#{1,3}\s*Definition\s*of\s*Done|\*\*Definition\s*of\s*Done\*\*)[:\s]*([\s\S]+?)(?=\n\d+\.|\s*$)/is);

              const requirements = reqMatch ? reqMatch[1].trim() : '';
              const specifications = specBlockMatch ? specBlockMatch[1].trim() : '';
              const testPlan = testMatch ? testMatch[1].trim() : '';
              const definitionOfDone = dodMatch ? dodMatch[1].trim() : '';

              if (descMatch) {
                const subDesc = descMatch[1].trim();
                const specName = specMatch ? specMatch[1] : (assignMatch ? assignMatch[1] : null);
                const execName = execTaskMatch ? execTaskMatch[1] : execOwner;
                const prio = prioMatch ? prioMatch[1].toLowerCase() : 'normal';
                const requestedModel = modelMatch ? modelMatch[1].toLowerCase() : 'sonnet';
                const useHighPriority = (requestedModel === 'sonnet' || requestedModel === 'opus') ? 'high' : prio;

                // Find specialist — avoid assigning to a digester who read the source material
                // (they'll have bias from their interpretation of the raw content)
                const spec = specName ? db.prepare(`SELECT id, name, department FROM team_members WHERE name = ? AND status = 'active'`).get(specName) : null;
                const exec = execName ? db.prepare(`SELECT id, name, department FROM team_members WHERE name = ? AND status = 'active'`).get(execName) : null;

                let assignTo = spec ? spec.id : (exec ? exec.id : null);
                let assignName = spec ? spec.name : (exec ? exec.name : 'TBD');

                // Digester bias avoidance: if the assigned member was a digester, swap to a peer
                if (digestionResult && assignTo) {
                  const digesterIds = new Set(digestionResult.results.map(r => r.digesterId).filter(Boolean));
                  if (digesterIds.has(assignTo)) {
                    // Find an alternative in the same department who was NOT a digester
                    const assignedMember = spec || exec;
                    const dept = assignedMember ? assignedMember.department : null;
                    const alternative = dept ? db.prepare(`
                      SELECT id, name FROM team_members
                      WHERE status = 'active' AND department = ? AND id != ? AND tier = 'specialist'
                        AND id NOT IN (${Array.from(digesterIds).map(() => '?').join(',')})
                      ORDER BY RANDOM() LIMIT 1
                    `).get(dept, assignTo, ...Array.from(digesterIds)) : null;

                    if (alternative) {
                      console.log(`[BoardRoom] Bias avoidance: swapped ${assignName} (digester) → ${alternative.name} for sub-task "${subDesc.slice(0, 50)}"`);
                      assignTo = alternative.id;
                      assignName = alternative.name;
                    } else {
                      // No alternative in same department — acceptable bias, log it
                      console.log(`[BoardRoom] No alternative for ${assignName} in ${dept || 'unknown dept'} — accepting digester bias`);
                    }
                  }
                }

                // Build a comprehensive task description with all four deliverable elements
                let subTaskDesc = `SUB-TASK from Council Plan (Parent: Task #${taskId})\n\n${subDesc}\n`;
                if (requirements) subTaskDesc += `\n## REQUIREMENTS\n${requirements}\n`;
                if (specifications) subTaskDesc += `\n## SPECIFICATIONS\n${specifications}\n`;
                if (testPlan) subTaskDesc += `\n## TEST PLAN\n${testPlan}\n`;
                if (definitionOfDone) subTaskDesc += `\n## DEFINITION OF DONE\n${definitionOfDone}\n`;
                subTaskDesc += `\n## STANDARDS OF WORK\n${standards}\n`;
                if (digestionResult) {
                  // Mega-prompt was digested — find chunks RELEVANT to this specific sub-task
                  const chunkDir = path.join(__dirname, '..', '.claude', 'digestion', `task-${taskId}`);
                  const taskText = (subDesc + ' ' + requirements + ' ' + specifications + ' ' + definitionOfDone).toLowerCase();

                  // Semantic aliases — map common terms to related concepts that might appear in chunk titles/content
                  // This catches "clip ranking" → "composite scoring", "auth" → "BYOK key management", etc.
                  const semanticAliases = {
                    'database': ['schema', 'migration', 'table', 'column', 'fk', 'foreign key', 'orm', 'model', 'query', 'sql', 'init order'],
                    'transcript': ['transcription', 'asr', 'whisper', 'speech', 'wordtoken', 'speakerturn', 'semantic moment', 'ce-04', 'ce-04.5'],
                    'clip': ['ranking', 'scoring', 'composite', 'candidate', 'cis', 'context integrity', 'ce-06', 'ce-07', 'clipcandidate'],
                    'edit': ['editing', 'editor', 'descript', 'event sourcing', 'timeline', 'ce-05', 'ce-13'],
                    'caption': ['subtitle', 'srt', 'vtt', 'brandkit', 'ce-08'],
                    'content': ['atomization', 'thread', 'carousel', 'blog', 'newsletter', 'text atom', 'ce-09', 'ce-10'],
                    'publish': ['publishing', 'schedule', 'calendar', 'oauth', 'social', 'platform', 'ce-15', 'ce-16'],
                    'analytics': ['post-publish', 'closed-loop', 'learning', 'engagement', 'ce-18'],
                    'billing': ['subscription', 'payment', 'stripe', 'pricing', 'tier', 'plan', 'gate', 'ce-20'],
                    'safety': ['moderation', 'content policy', 'nli', 'misleading', 'guardrail', 'ce-19'],
                    'auth': ['authentication', 'user', 'byok', 'key management', 'workspace', 'ce-02'],
                    'upload': ['ingestion', 'ingest', 'tusd', 's3', 'storage', 'ce-03'],
                    'copilot': ['ai', 'natural language', 'assistant', 'agent', 'byoa', 'ce-14', 'ce-17'],
                    'doctrine': ['authority', 'packaging', 'ratification', 'bob', 'ce-21'],
                    'audience': ['register', 'translation', 'ladder', 'mode', 'ce-22'],
                    'routing': ['venture', 'multi-venture', 'ce-23'],
                    'library': ['ip', 'asset', 'digital asset', 'provenance', 'ce-24'],
                    'narrative': ['theme', 'serialized', 'continuity', 'bible', 'ce-25'],
                    'multilingual': ['language', 'translation', 'localization', 'i18n', 'ce-26'],
                    'redis': ['cache', 'queue', 'pubsub', 'session', 'hot config'],
                    'deploy': ['docker', 'container', 'kubernetes', 'gpu', 'worker', 'infrastructure', 'devops'],
                    'pipeline': ['ci/cd', 'workflow', 'processing', 'ffmpeg', 'video'],
                    'metadata': ['title', 'description', 'tag', 'hashtag', 'seo', 'ce-11'],
                    'skill': ['preset', 'template', 'recipe', 'workflow recipe', 'ce-12']
                  };

                  // Expand task keywords with semantic aliases
                  let expandedKeywords = taskText;
                  for (const [term, aliases] of Object.entries(semanticAliases)) {
                    if (taskText.includes(term)) {
                      expandedKeywords += ' ' + aliases.join(' ');
                    }
                    // Also check if any alias appears in the task
                    for (const alias of aliases) {
                      if (alias.length > 3 && taskText.includes(alias)) {
                        expandedKeywords += ' ' + term + ' ' + aliases.join(' ');
                        break;
                      }
                    }
                  }

                  // Score each chunk — search title, sections, AND actual file content
                  const scoredChunks = digestionResult.chunks.map(c => {
                    // Read first 2000 chars of chunk file for content matching
                    let chunkContent = '';
                    try {
                      const chunkPath = path.join(chunkDir, `chunk-${String(c.index).padStart(2, '0')}-of-${c.total}.md`);
                      chunkContent = fs.readFileSync(chunkPath, 'utf-8').slice(0, 2000).toLowerCase();
                    } catch (_) {}

                    const chunkText = (c.title + ' ' + (c.sections || []).join(' ') + ' ' + chunkContent).toLowerCase();
                    let score = 0;

                    // Expanded keyword matching
                    const searchWords = expandedKeywords.split(/\s+/).filter(w => w.length > 3);
                    const uniqueWords = [...new Set(searchWords)];
                    for (const word of uniqueWords) {
                      if (chunkText.includes(word)) score += 2;
                    }

                    // CE segment number matching (e.g., task mentions "CE-04" and chunk title has it)
                    const ceRefs = expandedKeywords.match(/ce-\d+\.?\d*/gi) || [];
                    for (const ce of ceRefs) {
                      if (chunkText.includes(ce.toLowerCase())) score += 20; // strong signal
                    }

                    // Title word overlap — strong signal
                    const titleWords = c.title.toLowerCase().split(/[\s\-—:,()]+/);
                    for (const tw of titleWords) {
                      if (tw.length > 3 && expandedKeywords.includes(tw)) score += 5;
                    }

                    return { chunk: c, score };
                  }).filter(sc => sc.score > 0).sort((a, b) => b.score - a.score);

                  // Take top 8 most relevant chunks (more context is better)
                  const relevantChunks = scoredChunks.slice(0, 8);
                  if (relevantChunks.length > 0) {
                    subTaskDesc += `\n## RELEVANT REFERENCE FILES (most related to your task)\n`;
                    subTaskDesc += relevantChunks.map(rc =>
                      `- Chunk ${rc.chunk.index}/${rc.chunk.total}: ${rc.chunk.title} (relevance: ${rc.score}) — ${path.join(chunkDir, `chunk-${String(rc.chunk.index).padStart(2, '0')}-of-${rc.chunk.total}.md`)}`
                    ).join('\n') + '\n';
                    subTaskDesc += `\nRead these chunk files for detailed specs. Start with the highest relevance score.\n`;
                  } else {
                    // No keyword match — give them the master brief as fallback
                    subTaskDesc += `\n## REFERENCE FILES\nNo specific chunks matched your task keywords. Read the master brief for an overview.\n`;
                  }
                  subTaskDesc += `\nAll ${digestionResult.chunks.length} chunks at: ${chunkDir}/\nMaster brief: ${digestionResult.briefPath}\n`;

                  // Include ALL critical memories + domain-relevant high/normal memories
                  const criticalMems = digestionResult.allMemories.filter(m => m.importance === 'critical');
                  const taskRelevantMems = digestionResult.allMemories.filter(m => {
                    if (m.importance === 'critical') return false; // already included above
                    const memText = (m.title + ' ' + m.content).toLowerCase();
                    // Check against expanded keywords for better matching
                    return expandedKeywords.split(/\s+/).filter(w => w.length > 4).some(w => memText.includes(w));
                  }).slice(0, 15);
                  const allRelevantMems = [...criticalMems, ...taskRelevantMems];
                  if (allRelevantMems.length > 0) {
                    subTaskDesc += `\n## KEY KNOWLEDGE FROM DIGESTION\n${allRelevantMems.map(m => `- [${m.importance.toUpperCase()}] ${m.title}: ${m.content.slice(0, 400)}`).join('\n')}\n`;
                  }
                } else if (planFilePath) {
                  subTaskDesc += `\n## FULL PLAN REFERENCE\nThe complete plan from the Chairman is at: ${planFilePath}\nRead specific sections as needed for context.\n`;
                }
                subTaskDesc += `\nExecutive: ${execName || 'TBD'}\nModel: ${requestedModel || 'sonnet'}`;
                subTaskDesc += `\n\nYour work will be reviewed against the requirements, test plan, and definition of done above. Do not consider this task complete until ALL conditions in the Definition of Done are met.`;
                subTaskDesc += `\n\nReflection: When you finish, write what you learned and what you'd do differently.`;

                const subResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, origin, created_at, updated_at)
                  VALUES (?, ?, 'in_progress', ?, ?, 'board-room-subtask', 'system', ?, ?)`)
                  .run(
                    `[${companyName}] ${subDesc.slice(0, 100)}`,
                    subTaskDesc,
                    useHighPriority, assignTo, doneAt, doneAt
                  );
                const subTaskId = Number(subResult.lastInsertRowid);

                if (assignTo) {
                  db.prepare(`INSERT OR IGNORE INTO task_assignments (task_id, member_id, subagent_count, created_at) VALUES (?,?,1,?)`).run(subTaskId, assignTo, doneAt);

                  // Auto-spawn
                  spawnMemberTerminal(subTaskId, assignTo).catch(err => {
                    console.error(`[BoardRoom] Sub-task spawn failed for ${assignName}: ${err.message}`);
                  });
                }

                // Post to Board Room
                db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
                  VALUES (?, ?, 'Executive', ?, 'response', ?, ?)`)
                  .run(companyId, execName || 'System', `Dispatched: "${subDesc.slice(0, 60)}" → ${assignName}`, subTaskId, doneAt);
              }
            }
            broadcast('boardroom.message', { company_id: companyId, message_type: 'response' });
          } else {
            // No structured plan from Council — assign to executive owner or best-fit C-Suite
            // Do NOT fall back to keyword routing (that bypasses the chain of command)
            const fallbackExec = execOwner
              ? db.prepare(`SELECT id, name, role FROM team_members WHERE name = ? AND status = 'active'`).get(execOwner)
              : db.prepare(`SELECT id, name, role FROM team_members WHERE status = 'active' AND tier = 'c-suite' ORDER BY RANDOM() LIMIT 1`).get();

            if (fallbackExec) {
              const fbNow = localNow();
              // If digestion happened, append the brief to the task so the fallback exec doesn't need to re-read the mega-file
              let fallbackNote = `Council plan parsing failed — assigned to ${fallbackExec.name} (${fallbackExec.role}) to break down and delegate`;
              if (digestionResult) {
                const digestRef = `\n\n## DIGESTED REFERENCE\nThe original document was pre-digested into ${digestionResult.chunks.length} chunks with ${digestionResult.allMemories.length} key memories extracted.\nMaster brief: ${digestionResult.briefPath}\nChunk files at: ${path.join(__dirname, '..', '.claude', 'digestion', `task-${taskId}`)}/\n\nRead the master-brief.md file first — it has all the knowledge you need to plan without re-reading the full document.`;
                db.prepare(`UPDATE tasks SET description = description || ? WHERE id = ?`).run(digestRef, taskId);
                fallbackNote += `. Digested brief available — read master-brief.md first.`;
              }
              db.prepare(`UPDATE tasks SET status = 'in_progress', assigned_to = ?, priority = 'high', current_step = ?, updated_at = ? WHERE id = ?`)
                .run(fallbackExec.id, fallbackNote, fbNow, taskId);
              db.prepare(`INSERT OR IGNORE INTO task_assignments (task_id, member_id, subagent_count, created_at) VALUES (?,?,1,?)`).run(taskId, fallbackExec.id, fbNow);
              db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
                VALUES (?, ?, ?, ?, 'decision', ?, ?)`)
                .run(companyId, fallbackExec.name, fallbackExec.role,
                  digestionResult
                    ? `Digested brief ready (${digestionResult.allMemories.length} memories, ${digestionResult.chunks.length} chunks). ${fallbackExec.name} will create the execution plan from the curated knowledge.`
                    : `Council approved but plan needs breakdown. ${fallbackExec.name} will decompose this into specialist tasks.`,
                  taskId, fbNow);
              broadcast('boardroom.message', { company_id: companyId, message_type: 'decision', task_id: taskId });
              spawnMemberTerminal(taskId, fallbackExec.id).catch(err => {
                console.error(`[BoardRoom] Fallback exec spawn failed: ${err.message}`);
              });
            }
          }

          db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Council', 'council_deliberation', ?, ?)`)
            .run(taskId, `Consensus: ${consensus.slice(0, 200)}. ${planBlocks.length} sub-tasks created.`, doneAt);
        });

      } catch (err) {
        db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
          VALUES (?, 'System', 'System', ?, 'system', ?, ?)`).run(companyId, `Deliberation error: ${err.message}`, taskId, localNow());
        broadcast('boardroom.message', { company_id: companyId, message_type: 'system' });
      }
    });
    } // end else (full Council path)

    res.json({ chat_id: chatId, task_id: taskId, message: 'Directive sent to the board' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

