// GET /api/integrity — Harden's latest integrity scan results (live check)
app.get('/api/integrity', (req, res) => {
  try {
    const now = localNow();
    const checks = {};

    checks.fk_violations = db.prepare(`SELECT COUNT(*) as c FROM pragma_foreign_key_check()`).get().c;
    checks.orphaned_assignments = db.prepare(`SELECT COUNT(*) as c FROM task_assignments WHERE task_id NOT IN (SELECT id FROM tasks)`).get().c;
    checks.orphaned_processes = db.prepare(`SELECT COUNT(*) as c FROM active_processes WHERE task_id NOT IN (SELECT id FROM tasks)`).get().c;
    checks.stuck_tasks = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status IN ('routing', 'new') AND updated_at < datetime(?, '-1 hour')`).get(now).c;
    checks.looping_tasks = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE revision_count > 3 AND status IN ('in_progress', 'review')`).get().c;
    checks.bloated_descriptions = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE length(description) > 10000 AND status IN ('in_progress', 'review')`).get().c;
    checks.stuck_processes = db.prepare(`SELECT COUNT(*) as c FROM active_processes WHERE status = 'running' AND started_at < datetime(?, '-2 hours')`).get(now).c;

    const lastScan = db.prepare(`SELECT notes, created_at FROM activity_log WHERE actor = 'Harden' AND action = 'integrity_scan' ORDER BY id DESC LIMIT 1`).get();

    const totalIssues = Object.values(checks).reduce((a, b) => a + b, 0);
    res.json({
      status: totalIssues === 0 ? 'healthy' : 'issues_detected',
      total_issues: totalIssues,
      checks,
      last_scan: lastScan ? { result: lastScan.notes, at: lastScan.created_at } : null,
      checked_at: now
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/endpoints — Full API endpoint registry with usage stats
app.get('/api/endpoints', (req, res) => {
  try {
    const endpoints = [];
    const stack = app._router.stack;

    for (const layer of stack) {
      if (layer.route) {
        const path = layer.route.path;
        const methods = Object.keys(layer.route.methods).map(m => m.toUpperCase());
        for (const method of methods) {
          // Categorize by path prefix
          const parts = path.split('/').filter(Boolean);
          const category = parts[1] || 'root'; // /api/tasks → tasks
          const hasAuth = layer.route.stack.some(s => s.name === 'authRateLimiter');
          const hasParams = path.includes(':');
          endpoints.push({ method, path, category, has_auth: hasAuth, has_params: hasParams });
        }
      }
    }

    // Sort by category then path
    endpoints.sort((a, b) => a.category.localeCompare(b.category) || a.path.localeCompare(b.path));

    // Group by category
    const categories = {};
    for (const ep of endpoints) {
      if (!categories[ep.category]) categories[ep.category] = { count: 0, endpoints: [] };
      categories[ep.category].count++;
      categories[ep.category].endpoints.push(ep);
    }

    // Get request stats from the health endpoint data
    const now = localNow();

    // Check which endpoints are called from the frontend
    let frontendCalls = [];
    try {
      const appJsPath = path.join(__dirname, 'public', 'app.js');
      const appJs = fs.readFileSync(appJsPath, 'utf-8');
      const apiCalls = appJs.match(/(?:api|fetch|fetchJson)\(['"\/]([^'")\s]+)/g) || [];
      frontendCalls = [...new Set(apiCalls.map(c => {
        const m = c.match(/['"\/]([^'")\s]+)/);
        return m ? '/api/' + m[1].replace(/^\/?(api\/)?/, '') : null;
      }).filter(Boolean))];
    } catch (_) {}

    // Mark which endpoints are used by frontend
    for (const ep of endpoints) {
      ep.used_by_frontend = frontendCalls.some(fc => {
        const pattern = ep.path.replace(/:[^/]+/g, '[^/]+');
        return new RegExp('^' + pattern + '$').test(fc) || fc.startsWith(ep.path.split(':')[0]);
      });
    }

    res.json({
      total: endpoints.length,
      by_method: {
        GET: endpoints.filter(e => e.method === 'GET').length,
        POST: endpoints.filter(e => e.method === 'POST').length,
        PUT: endpoints.filter(e => e.method === 'PUT').length,
        PATCH: endpoints.filter(e => e.method === 'PATCH').length,
        DELETE: endpoints.filter(e => e.method === 'DELETE').length
      },
      categories,
      all_endpoints: endpoints,
      frontend_calls: frontendCalls.length,
      checked_at: now
    });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// GET /api/inbox — Chairman's inbox: organized deliverables from the team
app.get('/api/inbox', (req, res) => {
  try {
    const page = Math.max(1, parseInt(req.query.page) || 1);
    const limit = Math.min(50, parseInt(req.query.limit) || 20);
    const offset = (page - 1) * limit;
    const search = req.query.search || '';

    // Only show deliverables from tasks Max explicitly asked for (Board Room directives)
    // Not auto-spawn outputs, peer reviews, optimization audits, etc.
    let where = `WHERE tf.direction = 'output' AND t.source_file IN ('board-room', 'board-room-direct', 'board-room-subtask')`;
    const params = [];
    if (search) { where += ` AND (tf.file_name LIKE ? OR t.title LIKE ?)`; params.push(`%${search}%`, `%${search}%`); }

    const total = db.prepare(`SELECT COUNT(*) as c FROM task_files tf JOIN tasks t ON tf.task_id = t.id ${where}`).get(...params).c;

    const files = db.prepare(`
      SELECT tf.id, tf.task_id, tf.file_name, tf.file_path, tf.file_type, tf.created_at,
        t.title as task_title, t.priority, tm.name as from_member,
        c.name as company_name, c.color as company_color, p.name as project_name
      FROM task_files tf
      JOIN tasks t ON tf.task_id = t.id
      LEFT JOIN team_members tm ON t.assigned_to = tm.id
      LEFT JOIN project_tasks pt ON pt.task_id = t.id
      LEFT JOIN projects p ON pt.project_id = p.id
      LEFT JOIN companies c ON p.company_id = c.id
      ${where} ORDER BY tf.created_at DESC LIMIT ? OFFSET ?
    `).all(...params, limit, offset);

    for (const f of files) {
      try { f.size_bytes = fs.statSync(f.file_path).size; } catch { f.size_bytes = 0; }
      f.size_display = f.size_bytes > 1048576 ? (f.size_bytes / 1048576).toFixed(1) + ' MB'
        : f.size_bytes > 1024 ? (f.size_bytes / 1024).toFixed(0) + ' KB' : f.size_bytes + ' B';
    }

    res.json({
      files, total, page, limit,
      today: db.prepare(`SELECT COUNT(*) as c FROM task_files WHERE direction='output' AND date(created_at)=date('now','localtime')`).get().c,
      this_week: db.prepare(`SELECT COUNT(*) as c FROM task_files WHERE direction='output' AND created_at>datetime('now','-7 days','localtime')`).get().c
    });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// GET /api/inbox/:id/preview — Preview a deliverable's content
app.get('/api/inbox/:id/preview', (req, res) => {
  try {
    const file = db.prepare(`SELECT * FROM task_files WHERE id = ? AND direction = 'output'`).get(Number(req.params.id));
    if (!file) return res.status(404).json({ error: 'File not found' });
    try {
      const content = fs.readFileSync(file.file_path, 'utf-8');
      res.json({ id: file.id, file_name: file.file_name, content: content.slice(0, 50000) });
    } catch { res.status(404).json({ error: 'File missing from disk' }); }
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// GET /api/financials/overview — Site-wide financial summary (secondary to company-specific)
app.get('/api/financials/overview', (req, res) => {
  try {
    // Per-company breakdown (PRIMARY — these are the numbers that matter)
    const perCompany = db.prepare(`
      SELECT c.id, c.name, c.color,
        COALESCE((SELECT SUM(amount) FROM company_revenue WHERE company_id = c.id), 0) as revenue,
        COALESCE((SELECT SUM(amount) FROM company_expenses WHERE company_id = c.id), 0) as expenses,
        (SELECT COUNT(*) FROM company_domains WHERE company_id = c.id) as domains,
        (SELECT COUNT(*) FROM company_campaigns WHERE company_id = c.id) as campaigns
      FROM companies c WHERE c.status = 'active' ORDER BY c.id
    `).all();

    // Cumulative totals (SECONDARY — sum of all companies)
    const totalRevenue = perCompany.reduce((s, c) => s + c.revenue, 0);
    const totalExpenses = perCompany.reduce((s, c) => s + c.expenses, 0);

    // Per-member cost breakdown (top spenders)
    const topMembers = db.prepare(`
      SELECT tm.name, tm.department, SUM(ce.cost_cents) as total_cents,
        c.name as primary_company
      FROM cost_events ce
      JOIN team_members tm ON ce.member_id = tm.id
      LEFT JOIN company_members cm ON ce.member_id = cm.member_id AND cm.status = 'active'
      LEFT JOIN companies c ON cm.company_id = c.id
      GROUP BY ce.member_id
      ORDER BY total_cents DESC LIMIT 10
    `).all();

    res.json({
      companies: perCompany,
      cumulative: {
        total_revenue: totalRevenue,
        total_expenses: totalExpenses,
        net: totalRevenue - totalExpenses,
        note: 'Cumulative across all companies — see per-company for authoritative numbers'
      },
      top_spenders: topMembers.map(m => ({
        name: m.name,
        department: m.department,
        company: m.primary_company,
        spent: (m.total_cents / 100).toFixed(2)
      }))
    });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// GET /api/database — Full database inspector: tables, sizes, health, storage
app.get('/api/database', (req, res) => {
  try {
    const tables = db.prepare(`SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%' ORDER BY name`).all().map(t => {
      const count = db.prepare(`SELECT COUNT(*) as c FROM "${t.name}"`).get().c;
      const cols = db.pragma(`table_info("${t.name}")`);
      return { name: t.name, rows: count, columns: cols.length };
    }).sort((a, b) => b.rows - a.rows);

    const dbPath = DB_PATH;
    const dbSize = fs.statSync(dbPath).size;
    const walSize = (() => { try { return fs.statSync(dbPath + '-wal').size; } catch { return 0; } })();
    const shmSize = (() => { try { return fs.statSync(dbPath + '-shm').size; } catch { return 0; } })();

    const journalMode = db.pragma('journal_mode')[0].journal_mode;
    const pageSize = db.pragma('page_size')[0].page_size;
    const pageCount = db.pragma('page_count')[0].page_count;
    const freePages = db.pragma('freelist_count')[0].freelist_count;
    const cacheSize = db.pragma('cache_size')[0].cache_size;
    const integrity = db.pragma('integrity_check')[0].integrity_check;
    const fkViolations = db.prepare(`SELECT COUNT(*) as c FROM pragma_foreign_key_check()`).get().c;

    const growth = db.prepare(`SELECT date(created_at) as day, COUNT(*) as count FROM tasks WHERE created_at > datetime('now', '-7 days', 'localtime') GROUP BY date(created_at) ORDER BY day`).all();

    const categories = {};
    for (const t of tables) {
      const n = t.name.toLowerCase();
      const cat = /^(tasks|team_members|projects|companies|company_members|task_|project_|mission)/.test(n) ? 'Core'
        : /^(governance|constitutional|provenance|review_panel)/.test(n) ? 'Governance'
        : /^(agent_|heartbeat|active_processes|scan_cycles|board_chats)/.test(n) ? 'Agents'
        : /^(activity|notification|cost_|budget)/.test(n) ? 'Activity'
        : /^(calendar|notes|contacts|tags|taggable|template|decision)/.test(n) ? 'Content'
        : 'System';
      if (!categories[cat]) categories[cat] = { tables: 0, rows: 0 };
      categories[cat].tables++;
      categories[cat].rows += t.rows;
    }

    res.json({
      health: { integrity, fk_violations: fkViolations, journal_mode: journalMode, status: integrity === 'ok' && fkViolations === 0 ? 'healthy' : 'issues' },
      storage: {
        db_mb: (dbSize / 1048576).toFixed(1), wal_mb: (walSize / 1048576).toFixed(1),
        total_mb: ((dbSize + walSize + shmSize) / 1048576).toFixed(1),
        page_size: pageSize, page_count: pageCount, free_pages: freePages,
        fragmentation_pct: pageCount > 0 ? ((freePages / pageCount) * 100).toFixed(1) : '0',
        cache_size_kb: Math.abs(cacheSize)
      },
      schema: { total_tables: tables.length, total_rows: tables.reduce((a, t) => a + t.rows, 0) },
      categories, top_tables: tables.slice(0, 15), all_tables: tables, growth, checked_at: localNow()
    });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// POST /api/board-room/:companyId/direct-task — Max assigns a task directly to a C-Suite member
// Skips Council entirely. The executive delegates to their specialists. Zero routing tokens.
app.post('/api/board-room/:companyId/direct-task', authRateLimiter, (req, res) => {
  try {
    const { message, assign_to } = req.body;
    if (!message || !message.trim()) return res.status(400).json({ error: 'Message is required' });
    if (!assign_to) return res.status(400).json({ error: 'assign_to is required' });
    const companyId = Number(req.params.companyId);
    const memberId = Number(assign_to);
    const now = localNow();

    // Verify the member exists and is C-Suite
    const member = db.prepare(`SELECT id, name, role, tier, department FROM team_members WHERE id = ? AND status = 'active'`).get(memberId);
    if (!member) return res.status(404).json({ error: 'Team member not found' });

    // Save Max's message to chat
    const chatResult = db.prepare(`
      INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, created_at)
      VALUES (?, 49, 'Max Stewart', 'Chairman', ?, 'directive', ?)
    `).run(companyId, message.trim(), now);
    const chatId = Number(chatResult.lastInsertRowid);

    // Create task assigned directly to the member — no routing needed
    const company = db.prepare(`SELECT name FROM companies WHERE id = ?`).get(companyId);
    const companyName = company ? company.name : 'Unknown';

    // For Thrift and Forge: inject last scan findings as context so they can refine/deepen
    let contextBlock = '';
    if (memberId === THRIFT_MEMBER_ID || memberId === FORGE_MEMBER_ID) {
      const lastScan = db.prepare(`
        SELECT ap.output_summary, t.title, t.completed_at
        FROM active_processes ap
        JOIN tasks t ON ap.task_id = t.id
        WHERE ap.member_id = ? AND ap.status = 'completed' AND ap.output_summary IS NOT NULL
        ORDER BY ap.id DESC LIMIT 1
      `).get(memberId);
      if (lastScan && lastScan.output_summary) {
        const summary = lastScan.output_summary.slice(0, 2000);
        contextBlock = `\n\n## Previous Findings (for refinement)\nYour last scan (${lastScan.completed_at || 'recent'}):\n${summary}\n\nMax is asking you to go deeper, search for more, or refine these results. Build on your previous findings — don't start from scratch.\n`;
      }

      // Also pull recent cost data for Thrift
      if (memberId === THRIFT_MEMBER_ID) {
        try {
          const costSummary = db.prepare(`
            SELECT COUNT(*) as events, COALESCE(SUM(cost_cents),0) as total_cents,
              COALESCE(SUM(input_tokens),0) as input_tok, COALESCE(SUM(output_tokens),0) as output_tok
            FROM cost_events WHERE created_at > datetime(?, '-24 hours')
          `).get(now);
          if (costSummary) {
            contextBlock += `\n## Live Token Data (last 24h)\n- Cost events: ${costSummary.events}\n- Total spend: ${costSummary.total_cents} cents\n- Input tokens: ${costSummary.input_tok.toLocaleString()}\n- Output tokens: ${costSummary.output_tok.toLocaleString()}\n`;
          }
        } catch (_) {}
      }
    }

    const taskResult = db.prepare(`
      INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, origin, created_at, updated_at)
      VALUES (?, ?, 'in_progress', 'normal', ?, 'board-room-direct', 'browser', ?, ?)
    `).run(
      `[${companyName}] ${message.trim().slice(0, 100)}`,
      `DIRECT TASK from Chairman to ${member.name} (${member.role})\n\n${message.trim()}${contextBlock}\n\n---\nAssigned directly — no Council routing. ${member.name} should delegate to appropriate specialists in their department.`,
      memberId, now, now
    );
    const taskId = Number(taskResult.lastInsertRowid);

    // Create task assignment
    db.prepare(`INSERT OR IGNORE INTO task_assignments (task_id, member_id, subagent_count, created_at) VALUES (?, ?, 1, ?)`)
      .run(taskId, memberId, now);

    // Link to company project
    const companyProject = db.prepare(`SELECT id FROM projects WHERE company_id = ? LIMIT 1`).get(companyId);
    if (companyProject) {
      db.prepare(`INSERT OR IGNORE INTO project_tasks (project_id, task_id) VALUES (?, ?)`).run(companyProject.id, taskId);
    }

    // Update chat with task reference
    db.prepare(`UPDATE board_chats SET task_id = ? WHERE id = ?`).run(taskId, chatId);

    // Post assignment confirmation to chat
    db.prepare(`
      INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
      VALUES (?, 'System', 'System', ?, 'system', ?, ?)
    `).run(companyId, `Direct task assigned to ${member.name} (${member.role}). Task #${taskId} — skipped routing to save tokens.`, taskId, now);

    // Log activity
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Max Stewart', 'direct_assignment', ?, ?)`)
      .run(taskId, `Chairman assigned directly to ${member.name} via Board Room. No Council routing.`, now);

    broadcast('boardroom.message', { company_id: companyId, message_type: 'system', task_id: taskId });
    broadcast('task.created', { id: taskId });

    // Auto-spawn the member's terminal
    setImmediate(() => {
      spawnMemberTerminal(taskId, memberId).catch(err => {
        console.error(`[BoardRoom] Direct spawn failed for ${member.name}: ${err.message}`);
      });
    });

    // Post the executive's acknowledgment to chat after a short delay
    setTimeout(() => {
      db.prepare(`
        INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, task_id, created_at)
        VALUES (?, ?, ?, ?, ?, 'response', ?, ?)
      `).run(companyId, memberId, member.name, member.role, `Received. I'll delegate this to the right specialist in ${member.department || 'my department'} and report back.`, taskId, localNow());
      broadcast('boardroom.message', { company_id: companyId, message_type: 'response', task_id: taskId });
    }, 2000);

    res.json({ chat_id: chatId, task_id: taskId, assigned_to: member.name, message: 'Direct task assigned' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

