// ── Notification Center (dashboard page) ─────────────────────────

app.get('/api/notifications/dashboard', (req, res) => {
  try {
    const now = localNow();
    const { type, read, since, limit } = req.query;

    let sql = 'SELECT * FROM notifications WHERE 1=1';
    const params = [];

    if (type) { sql += ' AND type = ?'; params.push(type); }
    if (read === '0' || read === '1') { sql += ' AND read = ?'; params.push(parseInt(read)); }
    if (since) { sql += ' AND created_at > ?'; params.push(since); }

    sql += ' ORDER BY created_at DESC LIMIT ?';
    params.push(parseInt(limit) || 100);

    const notifications = db.prepare(sql).all(...params);

    // Stats
    const stats = {
      total: db.prepare('SELECT COUNT(*) as c FROM notifications').get().c,
      unread: db.prepare('SELECT COUNT(*) as c FROM notifications WHERE read=0').get().c,
      by_type: db.prepare('SELECT type, COUNT(*) as total, SUM(CASE WHEN read=0 THEN 1 ELSE 0 END) as unread FROM notifications GROUP BY type').all(),
      today: db.prepare('SELECT COUNT(*) as c FROM notifications WHERE date(created_at) = date(?)').get(now).c,
      this_week: db.prepare("SELECT COUNT(*) as c FROM notifications WHERE created_at > datetime(?, '-7 days')").get(now).c
    };

    res.json({ notifications, stats });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/notifications/mark-read', (req, res) => {
  try {
    const { ids, type, all } = req.body;
    if (all) {
      db.prepare('UPDATE notifications SET read=1 WHERE read=0').run();
    } else if (type) {
      db.prepare('UPDATE notifications SET read=1 WHERE type=? AND read=0').run(type);
    } else if (ids && ids.length) {
      const placeholders = ids.map(() => '?').join(',');
      db.prepare(`UPDATE notifications SET read=1 WHERE id IN (${placeholders})`).run(...ids);
    }
    res.json({ message: 'Done' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/notifications/clear-old', (req, res) => {
  try {
    const { days } = req.body;
    const cutoff = days || 7;
    const deleted = db.prepare(`DELETE FROM notifications WHERE read=1 AND created_at < datetime('now','localtime','-' || ? || ' days')`).run(cutoff);
    res.json({ deleted: deleted.changes });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

