app.put('/api/templates/:id', (req, res) => {
  try {
    const existing = db.prepare(`SELECT * FROM templates WHERE id = ?`).get(req.params.id);
    if (!existing) return res.status(404).json({ error: 'Template not found' });

    const name = req.body.name !== undefined ? req.body.name.trim() : existing.name;
    const category = req.body.category !== undefined ? req.body.category.trim() : existing.category;
    const description = req.body.description !== undefined ? req.body.description : existing.description;
    const prompt_template = req.body.prompt_template !== undefined ? req.body.prompt_template : existing.prompt_template;
    const default_priority = req.body.default_priority !== undefined && ['low', 'normal', 'high', 'urgent'].includes(req.body.default_priority)
      ? req.body.default_priority : existing.default_priority;
    const default_assignments = req.body.default_assignments !== undefined
      ? JSON.stringify(req.body.default_assignments) : existing.default_assignments;
    const auto_assign = req.body.auto_assign !== undefined ? (req.body.auto_assign ? 1 : 0) : existing.auto_assign;
    const now = localNow();

    db.prepare(`
      UPDATE templates SET name = ?, category = ?, description = ?, prompt_template = ?, default_priority = ?, default_assignments = ?, auto_assign = ?, updated_at = ?
      WHERE id = ?
    `).run(name, category, description, prompt_template, default_priority, default_assignments, auto_assign, now, req.params.id);

    res.json({ message: 'Template updated' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

