// ── Notification Dispatch ────────────────────────────────────────

function sendTwilioSms(config, body) {
  return new Promise((resolve) => {
    try {
      const https = require('https');
      const postData = new URLSearchParams({
        From: config.twilio_number,
        To: config.phone_number,
        Body: body.slice(0, 1600)
      }).toString();

      const auth = Buffer.from(config.account_sid + ':' + config.auth_token).toString('base64');

      const options = {
        hostname: 'api.twilio.com',
        path: '/2010-04-01/Accounts/' + encodeURIComponent(config.account_sid) + '/Messages.json',
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Content-Length': Buffer.byteLength(postData),
          'Authorization': 'Basic ' + auth
        }
      };

      const request = https.request(options, (response) => {
        let data = '';
        response.on('data', chunk => { data += chunk; });
        response.on('end', () => {
          try {
            const parsed = JSON.parse(data);
            if (response.statusCode >= 200 && response.statusCode < 300) {
              resolve({ sid: parsed.sid });
            } else {
              resolve({ error: parsed.message || 'Twilio error: ' + response.statusCode });
            }
          } catch (e) {
            resolve({ error: 'Invalid Twilio response' });
          }
        });
      });

      request.on('error', (err) => {
        resolve({ error: 'Twilio request failed: ' + err.message });
      });

      request.write(postData);
      request.end();
    } catch (err) {
      resolve({ error: 'SMS send error: ' + err.message });
    }
  });
}

function sendSlackMessage(config, title, message) {
  return new Promise((resolve) => {
    try {
      const https = require('https');
      const url = new URL(config.webhook_url);
      const payload = JSON.stringify({ text: '*' + title + '*\n' + (message || '') });

      const options = {
        hostname: url.hostname,
        path: url.pathname + (url.search || ''),
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(payload)
        }
      };

      const request = https.request(options, (response) => {
        let data = '';
        response.on('data', chunk => { data += chunk; });
        response.on('end', () => {
          if (response.statusCode >= 200 && response.statusCode < 300) {
            resolve({});
          } else {
            resolve({ error: 'Slack error: ' + response.statusCode + ' — ' + data });
          }
        });
      });

      request.on('error', (err) => {
        resolve({ error: 'Slack request failed: ' + err.message });
      });

      request.write(payload);
      request.end();
    } catch (err) {
      resolve({ error: 'Slack send error: ' + err.message });
    }
  });
}

async function dispatchNotification(notification) {
  try {
    const integrations = db.prepare(`SELECT * FROM integrations WHERE enabled = 1`).all();
    for (const integration of integrations) {
      const config = JSON.parse(integration.config || '{}');
      const body = (notification.title || '') + (notification.message ? ': ' + notification.message : '');

      if (integration.type === 'sms' && config.account_sid && config.auth_token && config.twilio_number && config.phone_number) {
        sendTwilioSms(config, body).then(result => {
          if (result.error) console.error('[Dispatch SMS] Error:', result.error);
        });
      }

      if (integration.type === 'slack' && config.webhook_url) {
        sendSlackMessage(config, notification.title || 'Notification', notification.message || '').then(result => {
          if (result.error) console.error('[Dispatch Slack] Error:', result.error);
        });
      }
    }
  } catch (err) {
    console.error('[dispatchNotification] Error:', err.message);
  }
}

// ── Inbound Webhooks ─────────────────────────────────────────────

// POST /api/webhooks/sms — Twilio sends incoming SMS here
app.post('/api/webhooks/sms', (req, res) => {
  try {
    // Webhook authentication
    const webhookSecret = db.prepare(`SELECT value FROM system_settings WHERE key = 'webhook_secret'`).get();
    if (webhookSecret && webhookSecret.value) {
      const provided = req.headers['x-webhook-secret'] || req.query.secret;
      if (provided !== webhookSecret.value) {
        return res.status(401).json({ error: 'Unauthorized' });
      }
    }

    const from = req.body.From || 'unknown';
    const body = (req.body.Body || '').trim();
    const messageSid = req.body.MessageSid || '';

    if (!body) {
      res.set('Content-Type', 'text/xml');
      return res.send('<?xml version="1.0" encoding="UTF-8"?><Response><Message>Empty message received.</Message></Response>');
    }

    const now = localNow();
    const title = body.slice(0, 120);

    // Create task
    const taskResult = db.prepare(`
      INSERT INTO tasks (title, description, status, priority, source_file, created_at, updated_at)
      VALUES (?, ?, 'new', 'normal', 'sms', ?, ?)
    `).run(title, body, now, now);
    const taskId = taskResult.lastInsertRowid;

    // Write .md file to inbox
    const safeName = 'sms-mission-' + taskId + '-' + Date.now() + '.md';
    const mdContent = '# SMS Mission #' + taskId + '\n\n**From:** ' + from + '\n**MessageSid:** ' + messageSid + '\n**Created:** ' + now + '\n**Source:** sms\n\n---\n\n' + body + '\n';

    if (!fs.existsSync(INBOX_PATH)) {
      fs.mkdirSync(INBOX_PATH, { recursive: true });
    }
    fs.writeFileSync(path.join(INBOX_PATH, safeName), mdContent, 'utf-8');

    // Register file
    db.prepare(`
      INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at)
      VALUES (?, ?, ?, 'text/markdown', 'input', ?)
    `).run(taskId, safeName, path.join(INBOX_PATH, safeName), now);

    // Create notification
    createNotification('system', 'SMS mission received', body.slice(0, 200), taskId);

    // Log activity
    db.prepare(`
      INSERT INTO activity_log (task_id, actor, action, notes, created_at)
      VALUES (?, 'System', 'sms_mission_received', ?, ?)
    `).run(taskId, 'SMS from ' + from + ': ' + body.slice(0, 200), now);

    // Auto-spawn: if task has an assignee, spawn immediately; otherwise it will be spawned when assigned/processed
    const smsTaskId = Number(taskId);
    setImmediate(() => {
      autoSpawnForTask(smsTaskId).catch(err => {
        console.error(`[AutoSpawn] SMS webhook spawn error: ${err.message}`);
      });
    });

    // Respond with TwiML
    res.set('Content-Type', 'text/xml');
    res.send('<?xml version="1.0" encoding="UTF-8"?>\n<Response><Message>Mission received by the Board.</Message></Response>');
  } catch (err) {
    console.error('POST /api/webhooks/sms error:', err);
    res.set('Content-Type', 'text/xml');
    res.send('<?xml version="1.0" encoding="UTF-8"?>\n<Response><Message>Error processing message.</Message></Response>');
  }
});

// POST /api/webhooks/slack — Slack sends events/commands here
app.post('/api/webhooks/slack', (req, res) => {
  try {
    // Webhook authentication
    const webhookSecret = db.prepare(`SELECT value FROM system_settings WHERE key = 'webhook_secret'`).get();
    if (webhookSecret && webhookSecret.value) {
      const provided = req.headers['x-webhook-secret'] || req.query.secret;
      if (provided !== webhookSecret.value) {
        return res.status(401).json({ error: 'Unauthorized' });
      }
    }

    // Handle Slack URL verification challenge
    if (req.body.type === 'url_verification') {
      return res.json({ challenge: req.body.challenge });
    }

    // Parse text from slash commands or event payloads
    const text = (req.body.text || (req.body.event && req.body.event.text) || '').trim();
    const user = req.body.user_name || req.body.user_id || (req.body.event && req.body.event.user) || 'slack-user';

    if (!text) {
      return res.json({ response_type: 'ephemeral', text: 'Please provide mission instructions.' });
    }

    const now = localNow();
    const title = text.slice(0, 120);

    // Create task
    const taskResult = db.prepare(`
      INSERT INTO tasks (title, description, status, priority, source_file, created_at, updated_at)
      VALUES (?, ?, 'new', 'normal', 'slack', ?, ?)
    `).run(title, text, now, now);
    const taskId = taskResult.lastInsertRowid;

    // Write .md file to inbox
    const safeName = 'slack-mission-' + taskId + '-' + Date.now() + '.md';
    const mdContent = '# Slack Mission #' + taskId + '\n\n**From:** ' + user + '\n**Created:** ' + now + '\n**Source:** slack\n\n---\n\n' + text + '\n';

    if (!fs.existsSync(INBOX_PATH)) {
      fs.mkdirSync(INBOX_PATH, { recursive: true });
    }
    fs.writeFileSync(path.join(INBOX_PATH, safeName), mdContent, 'utf-8');

    // Register file
    db.prepare(`
      INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at)
      VALUES (?, ?, ?, 'text/markdown', 'input', ?)
    `).run(taskId, safeName, path.join(INBOX_PATH, safeName), now);

    // Create notification
    createNotification('system', 'Slack mission received', text.slice(0, 200), taskId);

    // Log activity
    db.prepare(`
      INSERT INTO activity_log (task_id, actor, action, notes, created_at)
      VALUES (?, 'System', 'slack_mission_received', ?, ?)
    `).run(taskId, 'Slack from ' + user + ': ' + text.slice(0, 200), now);

    // Auto-spawn: if task has an assignee, spawn immediately; otherwise it will be spawned when assigned/processed
    const slackTaskId = Number(taskId);
    setImmediate(() => {
      autoSpawnForTask(slackTaskId).catch(err => {
        console.error(`[AutoSpawn] Slack webhook spawn error: ${err.message}`);
      });
    });

    res.json({ response_type: 'in_channel', text: 'Mission received by the Board.' });
  } catch (err) {
    console.error('POST /api/webhooks/slack error:', err);
    res.json({ response_type: 'ephemeral', text: 'Error processing mission: ' + err.message });
  }
});

