// ── Org Chart Helper: walk reports_to chain to find c-suite executive ──

function findCsuiteExec(memberId, memberMap, maxDepth = 10) {
  let current = memberMap.get(memberId);
  let depth = 0;
  while (current && depth < maxDepth) {
    if (current.tier === 'c-suite') return current;
    if (!current.reports_to) return null;
    current = memberMap.get(current.reports_to);
    depth++;
  }
  return null;
}

function buildMemberMap(members) {
  const map = new Map();
  for (const m of members) map.set(m.id, m);
  return map;
}

function groupSpecialistsByExec(specialists, memberMap) {
  const byExec = {};
  const unassigned = [];
  for (const spec of specialists) {
    if (!spec.reports_to) { unassigned.push(spec); continue; }
    // Walk the chain from the person this specialist reports to
    const exec = findCsuiteExec(spec.reports_to, memberMap);
    if (exec) {
      if (!byExec[exec.id]) byExec[exec.id] = [];
      byExec[exec.id].push(spec);
    } else {
      unassigned.push(spec);
    }
  }
  return { byExec, unassigned };
}

