// ── PUT /api/tasks/:id/downgrade — downgrade priority with tracking ──

app.put('/api/tasks/:id/downgrade', (req, res) => {
  try {
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    const priorities = ['low', 'normal', 'high', 'urgent'];
    const currentIdx = priorities.indexOf(task.priority);
    if (currentIdx <= 0) return res.status(400).json({ error: 'Cannot downgrade further' });

    const newPriority = priorities[currentIdx - 1];
    const now = localNow();
    const actor = req.body.actor || 'Board';

    db.prepare(`UPDATE tasks SET priority = ?, downgraded_by = ?, downgraded_at = ?, updated_at = ? WHERE id = ?`)
      .run(newPriority, actor, now, now, req.params.id);

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'priority_downgraded', ?, ?)`)
      .run(req.params.id, actor, `Priority downgraded: ${task.priority} → ${newPriority} (original: ${task.original_priority || task.priority})`, now);

    res.json({ id: task.id, old_priority: task.priority, new_priority: newPriority, original_priority: task.original_priority || task.priority });
    broadcast('task.updated', { id: Number(req.params.id) });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

