/**
 * Auto-fill a project-specific improvement chamber.
 */
function autoFillProjectChamber(projectId) {
  const project = db.prepare('SELECT * FROM projects WHERE id = ?').get(projectId);
  if (!project) return;

  const now = localNow();
  const poolSize = 10;
  const currentCount = db.prepare(`SELECT COUNT(*) as c FROM project_improvements WHERE project_id = ? AND status = 'proposed'`).get(projectId).c;

  if (currentCount >= poolSize) return;

  const needed = poolSize - currentCount;
  const existingTitles = db.prepare(`SELECT title FROM project_improvements WHERE project_id = ?`).all(projectId).map(r => r.title.toLowerCase());

  // Get seeds for this project
  const seeds = PROJECT_IMPROVEMENT_SEEDS[project.name] || PROJECT_IMPROVEMENT_SEEDS['default'];
  const availableSeeds = seeds.filter(s => !existingTitles.includes(s.title.toLowerCase()));
  const shuffled = availableSeeds.sort(() => Math.random() - 0.5);
  const batch = shuffled.slice(0, needed);

  let inserted = 0;
  for (const s of batch) {
    db.prepare(`INSERT INTO project_improvements (project_id, title, description, category, impact, effort, proposed_by, status, created_at, updated_at)
      VALUES (?,?,?,?,?,?,?,?,?,?)`)
      .run(projectId, s.title, s.description, s.category, s.impact, s.effort, 'Board', 'proposed', now, now);
    inserted++;
  }

  if (inserted > 0) {
    broadcast('project_improvement.updated', { project_id: projectId, new_count: inserted });
  }
}

/**
 * Supervise a project improvement — same logic as dashboard supervisor.
 */
function superviseProjectImprovement(imp) {
  const title = (imp.title || '').toLowerCase();
  const desc = (imp.description || '').toLowerCase();

  // Reject vague
  if (['make things better', 'improve stuff', 'fix things'].some(p => (title + ' ' + desc).includes(p))) {
    return { approved: false, reason: 'Too vague' };
  }

  // Reject duplicates
  const existing = db.prepare(`
    SELECT id, status FROM project_improvements
    WHERE project_id = ? AND id != ? AND status IN ('completed','in_progress','queued')
    AND LOWER(title) = LOWER(?)
  `).get(imp.project_id, imp.id, imp.title);
  if (existing) return { approved: false, reason: `Duplicate of #${existing.id}` };

  // Require action verb
  const verbs = ['add', 'fix', 'improve', 'optimize', 'implement', 'create', 'build', 'refactor', 'update', 'enhance', 'set', 'configure'];
  if (!verbs.some(v => title.startsWith(v) || title.includes(' ' + v + ' '))) {
    return { approved: false, reason: 'No clear action verb' };
  }

  // Require substantive description
  if (!imp.description || imp.description.length < 20) {
    return { approved: false, reason: 'Description too short' };
  }

  const impactScore = imp.impact === 'high' ? 3 : imp.impact === 'medium' ? 2 : 1;
  const effortScore = imp.effort === 'small' ? 3 : imp.effort === 'medium' ? 2 : 1;
  return { approved: true, reason: `Value: ${impactScore * effortScore}`, valueScore: impactScore * effortScore };
}

/**
 * Execute a project improvement — spawn a member terminal with project context.
 */
function executeProjectImprovement(impId) {
  const now = localNow();
  const imp = db.prepare('SELECT * FROM project_improvements WHERE id = ?').get(impId);
  if (!imp) return null;

  const project = db.prepare('SELECT * FROM projects WHERE id = ?').get(imp.project_id);
  if (!project) return null;

  // Get the project executive (they orchestrate the work)
  const exec = db.prepare(`
    SELECT pe.*, tm.name as exec_name FROM project_executives pe
    JOIN team_members tm ON pe.member_id = tm.id
    WHERE pe.project_id = ?
  `).get(imp.project_id);
  const orchestrator = exec ? exec.exec_name : 'Board';

  // Find assignee with project affinity
  const assignee = findProjectImprovementAssignee(imp.category, imp.project_id);
  if (!assignee) {
    return null;
  }

  // Update improvement status
  db.prepare(`UPDATE project_improvements SET status = 'in_progress', assigned_member_id = ?, work_started_at = ?, progress_percent = 10, current_step = 'Starting...', updated_at = ? WHERE id = ?`)
    .run(assignee.id, now, now, impId);

  // Create a task for this improvement
  const taskResult = db.prepare(`
    INSERT INTO tasks (title, description, status, priority, source_file, assigned_to, started_at, progress, current_step, created_at, updated_at)
    VALUES (?, ?, 'in_progress', ?, 'project_improvement', ?, ?, 10, 'Starting project improvement', ?, ?)
  `).run(
    `[${project.name}] Execute: ${imp.title}`,
    `Project improvement #${impId} for "${project.name}": ${imp.description}\n\nOrchestrated by ${orchestrator} (Project Executive)`,
    imp.impact === 'high' ? 'high' : 'normal',
    assignee.id, now, now, now
  );
  const taskId = Number(taskResult.lastInsertRowid);

  // Link task to project
  db.prepare('INSERT OR IGNORE INTO project_tasks (project_id, task_id, created_at) VALUES (?,?,?)').run(imp.project_id, taskId, now);

  // Log — executive is the actor, not Gray
  db.prepare(`INSERT INTO activity_log (actor, action, notes, task_id, created_at) VALUES (?, 'project_improvement_start', ?, ?, ?)`)
    .run(orchestrator, `${orchestrator} started project improvement #${impId}: ${imp.title} for "${project.name}", assigned to ${assignee.name}`, taskId, now);

  broadcast('task.updated', { id: taskId });
  broadcast('project_improvement.updated', { project_id: imp.project_id, id: impId });

  // Spawn the member terminal
  spawnMemberTerminal(taskId, assignee.id).catch(err => {
    console.error(`[ProjectPipeline] Spawn error for improvement #${impId}: ${err.message}`);
  });

  return { taskId, assignee: assignee.name, improvement: imp.title, orchestrator };
}

/**
 * Project autonomous improvement cycle — runs per project.
 */
function projectAutonomousCycle(projectId) {
  if (isLocalMode()) return;
  const now = localNow();
  const project = db.prepare('SELECT * FROM projects WHERE id = ?').get(projectId);
  if (!project || project.status !== 'active') return;

  // Check if this project has autonomous mode enabled
  const setting = db.prepare(`SELECT value FROM system_settings WHERE key = ?`).get(`project_autonomous_${projectId}`);
  if (!setting || setting.value !== '1') return;

  // Get the project executive — they run the autonomous cycle
  const exec = db.prepare(`
    SELECT pe.*, tm.name as exec_name FROM project_executives pe
    JOIN team_members tm ON pe.member_id = tm.id
    WHERE pe.project_id = ?
  `).get(projectId);
  const orchestrator = exec ? exec.exec_name : 'Board';

  // Count running project improvements
  const inProgress = db.prepare(`SELECT COUNT(*) as c FROM project_improvements WHERE project_id = ? AND status = 'in_progress'`).get(projectId).c;
  if (inProgress >= 2) return; // Max 2 concurrent per project

  // Step 1: Start queued items
  const queued = db.prepare(`SELECT * FROM project_improvements WHERE project_id = ? AND status = 'queued' ORDER BY CASE impact WHEN 'high' THEN 0 WHEN 'medium' THEN 1 WHEN 'low' THEN 2 END, created_at ASC LIMIT 1`).get(projectId);
  if (queued) {
    executeProjectImprovement(queued.id);
    return;
  }

  // Step 2: Supervise proposed items — executive approves/denies
  const proposed = db.prepare(`SELECT * FROM project_improvements WHERE project_id = ? AND status = 'proposed' ORDER BY CASE impact WHEN 'high' THEN 0 WHEN 'medium' THEN 1 WHEN 'low' THEN 2 END, created_at ASC LIMIT 2`).all(projectId);

  for (const imp of proposed) {
    const verdict = superviseProjectImprovement(imp);
    if (verdict.approved) {
      db.prepare(`UPDATE project_improvements SET status = 'queued', approved_by = ?, updated_at = ?, current_step = 'Auto-approved' WHERE id = ?`).run(`${orchestrator} (auto)`, now, imp.id);
      db.prepare(`INSERT INTO activity_log (actor, action, notes, created_at) VALUES (?, 'project_auto_approve', ?, ?)`)
        .run(orchestrator, `${orchestrator} auto-approved project improvement #${imp.id}: ${imp.title} for "${project.name}"`, now);
    } else {
      db.prepare(`UPDATE project_improvements SET status = 'denied', approved_by = ?, updated_at = ?, current_step = ? WHERE id = ?`).run(`${orchestrator} (auto)`, now, `Rejected: ${verdict.reason}`, imp.id);
    }
    broadcast('project_improvement.updated', { project_id: projectId, id: imp.id });
  }

  // Refill chamber
  try { autoFillProjectChamber(projectId); } catch (e) { console.warn(`[ProjectChamber] Refill error for project #${projectId}: ${e.message}`); }

  // Start newly queued
  const newQueued = db.prepare(`SELECT * FROM project_improvements WHERE project_id = ? AND status = 'queued' ORDER BY CASE impact WHEN 'high' THEN 0 WHEN 'medium' THEN 1 WHEN 'low' THEN 2 END LIMIT 1`).get(projectId);
  if (newQueued && inProgress < 2) {
    executeProjectImprovement(newQueued.id);
  }
}

// Per-project autonomous interval timer — checks all projects
setInterval(() => {
  try {
    const projects = db.prepare(`SELECT id FROM projects WHERE status = 'active'`).all();
    for (const p of projects) {
      const setting = db.prepare(`SELECT value FROM system_settings WHERE key = ?`).get(`project_autonomous_${p.id}`);
      if (setting && setting.value === '1') {
        // Check timing
        const lastKey = `project_autonomous_last_cycle_${p.id}`;
        const lastRun = db.prepare(`SELECT value FROM system_settings WHERE key = ?`).get(lastKey);
        const lastRunTime = lastRun && lastRun.value ? new Date(lastRun.value.replace(' ', 'T')).getTime() : 0;
        const elapsed = (Date.now() - lastRunTime) / 1000;
        const interval = parseInt((db.prepare(`SELECT value FROM system_settings WHERE key = 'project_autonomous_interval'`).get() || {}).value || '120', 10);
        if (elapsed >= interval) {
          projectAutonomousCycle(p.id);
          const now = localNow();
          db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES (?, ?, ?)`).run(lastKey, now, now);
        }
      }
    }
  } catch (e) { console.warn('[ProjectAutoLoop] Error:', e.message); }
}, 30000);

// ═══════════════════════════════════════════════════════════════
//  Auto-execution queue helper
// ═══════════════════════════════════════════════════════════════

// ── Overnight Watchdog — catches stuck improvements and keeps the pipeline moving ──
// Runs every 2 minutes. If an improvement has been in_progress for over 45 minutes
// with no progress, it's stuck. Reset it and move on.
setInterval(() => {
  try {
    const now = localNow();
    const stuckTimeout = 45; // minutes

    // Find stuck improvements (in_progress but no real progress for stuckTimeout minutes)
    const stuck = db.prepare(`
      SELECT ip.id, ip.title, ip.status, ip.progress_percent, ip.work_started_at
      FROM improvement_proposals ip
      WHERE ip.status = 'in_progress'
      AND ip.work_started_at < datetime(?, '-${stuckTimeout} minutes')
    `).all(now);

    for (const imp of stuck) {

      // Check if there's a running task for this improvement
      const relatedTask = db.prepare(`SELECT id, status, progress, current_step FROM tasks WHERE title LIKE ? AND status = 'in_progress' ORDER BY id DESC LIMIT 1`)
        .get(`Execute: ${imp.title}`);

      // Check if process is actually alive
      let processAlive = false;
      if (relatedTask) {
        const proc = db.prepare(`SELECT pid FROM active_processes WHERE task_id = ? AND status = 'running' ORDER BY id DESC LIMIT 1`).get(relatedTask.id);
        if (proc && proc.pid) {
          try {
            process.kill(proc.pid, 0); // Check if alive (signal 0 = no-op check)
            processAlive = true;

            // If alive AND making progress (>30%), give it more time
            if (relatedTask.progress > 30) {
              continue;
            }
          } catch (_) {
            processAlive = false;
          }
        }
      }

      if (!processAlive) {
        // Process is dead or never started — reset improvement to queued
        db.prepare(`UPDATE improvement_proposals SET status = 'queued', progress_percent = 0, current_step = 'Re-queued by watchdog (was stuck ${stuckTimeout}m+)', updated_at = ? WHERE id = ?`)
          .run(now, imp.id);

        // Clean up the stuck task too
        if (relatedTask) {
          db.prepare(`UPDATE tasks SET status = 'delivered', progress = 100, current_step = 'Closed by watchdog — was stuck', updated_at = ? WHERE id = ?`)
            .run(now, relatedTask.id);
          // Kill any ghost processes
          db.prepare(`UPDATE active_processes SET status = 'killed' WHERE task_id = ? AND status = 'running'`).run(relatedTask.id);
        }

        db.prepare(`INSERT INTO activity_log (actor, action, notes, created_at) VALUES ('Watchdog', 'unstuck', ?, ?)`)
          .run(`Re-queued stuck improvement #${imp.id}: ${imp.title} (was stuck for ${stuckTimeout}+ minutes, process dead)`, now);

      } else {
        // Process alive but stuck at low progress — kill it and re-queue
        if (relatedTask) {
          const proc = db.prepare(`SELECT pid FROM active_processes WHERE task_id = ? AND status = 'running' ORDER BY id DESC LIMIT 1`).get(relatedTask.id);
          if (proc && proc.pid) {
            try { process.kill(proc.pid, 'SIGTERM'); } catch (_) {}
          }
        }

        db.prepare(`UPDATE improvement_proposals SET status = 'queued', progress_percent = 0, current_step = 'Re-queued by watchdog (stuck at low progress)', updated_at = ? WHERE id = ?`)
          .run(now, imp.id);

        db.prepare(`INSERT INTO activity_log (actor, action, notes, created_at) VALUES ('Watchdog', 'unstuck', ?, ?)`)
          .run(`Killed and re-queued stuck improvement #${imp.id}: ${imp.title}`, now);
      }

      try { broadcast('improvement.updated', { id: imp.id }); } catch (_) {}
    }

    // After unsticking, trigger the queue to pick up the re-queued items
    if (stuck.length > 0) {
      const autoSetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'auto_execute_improvements'`).get();
      if (autoSetting && autoSetting.value === '1') {
        autoStartNextQueued();
      }
    }
  } catch (e) {
    console.warn('[Watchdog] Error:', e.message);
  }
}, 120000); // Every 2 minutes


// ── Stale Process Detector — catches crashed/orphaned processes in active_processes ──
// Runs every 5 minutes. If a process has been in 'running' status for over 15 minutes
// and its OS process is no longer alive, mark it as 'failed' and unblock the queue.
setInterval(() => {
  try {
    const now = localNow();
    const staleMinutes = 15;

    // Find processes stuck in 'running' for longer than staleMinutes
    const staleProcesses = db.prepare(`
      SELECT ap.id, ap.task_id, ap.member_id, ap.pid, ap.started_at,
             tm.name as member_name, t.title as task_title
      FROM active_processes ap
      LEFT JOIN team_members tm ON ap.member_id = tm.id
      LEFT JOIN tasks t ON ap.task_id = t.id
      WHERE ap.status = 'running'
      AND ap.started_at < datetime(?, '-' || ? || ' minutes')
    `).all(now, staleMinutes);

    let cleaned = 0;
    for (const proc of staleProcesses) {
      let processAlive = false;

      // Check if the OS process is still alive
      if (proc.pid) {
        try {
          process.kill(proc.pid, 0); // Signal 0 = existence check
          processAlive = true;
        } catch (_) {
          processAlive = false;
        }
      }

      // Also check in-memory registry
      if (!processAlive && runningProcesses.has(proc.id)) {
        runningProcesses.delete(proc.id);
      }

      if (!processAlive) {
        // Process is dead — mark as failed
        db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = COALESCE(output_summary, '') || ' [STALE: cleaned by detector — no heartbeat for 15+ min]' WHERE id = ?`)
          .run(now, proc.id);

        db.prepare(`INSERT INTO activity_log (actor, action, notes, created_at) VALUES ('StaleDetector', 'cleanup', ?, ?)`)
          .run(`Marked stale process #${proc.id} as failed (task: ${proc.task_title || proc.task_id}, member: ${proc.member_name || proc.member_id}, pid: ${proc.pid || 'none'}, started: ${proc.started_at})`, now);

        try { broadcast('process.failed', { process_id: proc.id, task_id: proc.task_id, reason: 'stale_cleanup' }); } catch (_) {}
        cleaned++;
      }
    }

    if (cleaned > 0) {
      // Trigger the improvement queue to fill freed slots
      const autoSetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'auto_execute_improvements'`).get();
      if (autoSetting && autoSetting.value === '1') {
        autoStartNextQueued();
      }
    }
  } catch (e) {
    console.warn('[StaleDetector] Error:', e.message);
  }
}, 300000); // Every 5 minutes


// Concurrency-aware improvement queue processor
// Runs multiple improvements in parallel without overloading the system
function autoStartNextQueued() {
  if (isLocalMode()) return null;
  const now = localNow();

  // Get concurrency settings
  const maxConcurrentSetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'improvement_max_concurrent'`).get();
  const maxConcurrent = maxConcurrentSetting ? parseInt(maxConcurrentSetting.value) : 3;

  // Count currently running improvements
  const currentlyRunning = db.prepare(`SELECT COUNT(*) as c FROM improvement_proposals WHERE status = 'in_progress'`).get().c;

  // Count other running processes (workspace, missions, etc.) to avoid overload
  const otherRunning = db.prepare(`SELECT COUNT(*) as c FROM active_processes WHERE status = 'running'`).get().c;
  const totalLoad = currentlyRunning + otherRunning;

  // System-wide cap
  const systemMaxSetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'system_max_concurrent_processes'`).get();
  const systemMax = systemMaxSetting ? parseInt(systemMaxSetting.value) : 6;

  // How many slots are available
  const slots = Math.min(maxConcurrent - currentlyRunning, systemMax - totalLoad);

  if (slots <= 0) {
    return null;
  }

  // Get next batch
  const batch = db.prepare(`
    SELECT * FROM improvement_proposals WHERE status = 'queued'
    ORDER BY CASE impact WHEN 'high' THEN 0 WHEN 'medium' THEN 1 WHEN 'low' THEN 2 END,
      queue_position ASC, created_at ASC
    LIMIT ?
  `).all(slots);

  if (batch.length === 0) return null;


  const started = [];

  for (let i = 0; i < batch.length; i++) {
    const next = batch[i];

    db.prepare(`UPDATE improvement_proposals SET status = 'in_progress', work_started_at = ?, progress_percent = 10, current_step = 'Auto-starting...', updated_at = ? WHERE id = ?`)
      .run(now, now, next.id);

    createNotification('system', `Auto-started: ${next.title}`, `Improvement #${next.id} auto-started from queue`);

    db.prepare(`INSERT INTO activity_log (actor, action, notes, created_at, category) VALUES ('System', 'auto_queue_start', ?, ?, 'improvement')`)
      .run(`Auto-started improvement #${next.id}: ${next.title}`, now);

    db.prepare(`INSERT INTO improvement_log (proposal_id, action, notes, created_at) VALUES (?, 'in_progress', 'Auto-started from execution queue', ?)`)
      .run(next.id, now);

    broadcast('improvement.updated', { id: next.id });

    // Stagger spawns by 2 seconds each to avoid hammering
    setTimeout(() => {
      try {
        const assignee = findImprovementAssignee(next.category);
        if (assignee) {
          const execNow = localNow();
          const taskResult = db.prepare(`
            INSERT INTO tasks (title, description, status, priority, source_file, assigned_to, started_at, progress, current_step, created_at, updated_at)
            VALUES (?, ?, 'in_progress', ?, 'improvement', ?, ?, 10, 'Auto-queue started', ?, ?)
          `).run(`Execute: ${next.title}`, `Implement improvement #${next.id}: ${next.description}`,
            next.impact === 'high' ? 'high' : 'normal', assignee.id, execNow, execNow, execNow);
          const tId = Number(taskResult.lastInsertRowid);
          broadcast('task.updated', { id: tId });
          spawnMemberTerminal(tId, assignee.id).catch(err => {
            console.error(`[AutoSpawn] Queue spawn error #${next.id}: ${err.message}`);
          });
        }
      } catch (err) {
        console.error(`[AutoSpawn] Queue setup error #${next.id}: ${err.message}`);
      }
    }, i * 10000); // 10 second stagger between spawns to avoid rate limits

    started.push(next);
  }

  return started.length === 1
    ? db.prepare(`SELECT * FROM improvement_proposals WHERE id = ?`).get(started[0].id)
    : { count: started.length, items: started.map(s => ({ id: s.id, title: s.title })) };
}

