function autoFillBrainstorm() {
  const now = localNow();
  const currentCount = db.prepare(`SELECT COUNT(*) as c FROM idea_board WHERE status = 'fresh'`).get().c;
  if (currentCount >= 5) return;

  const needed = 5 - currentCount;

  // Get titles of all existing ideas to avoid duplicates
  const existingTitles = db.prepare(`SELECT title FROM idea_board`).all().map(r => r.title.toLowerCase());

  // Find templates not already used
  const available = BRAINSTORM_TEMPLATES.filter(t => !existingTitles.includes(t.title.toLowerCase()));

  // Shuffle and pick what we need
  const shuffled = available.sort(() => Math.random() - 0.5);
  const toInsert = shuffled.slice(0, needed);

  for (const t of toInsert) {
    db.prepare(`INSERT INTO idea_board (title, tagline, description, category, status, generated_by, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?)`)
      .run(t.title, t.tagline, t.description, t.category, 'fresh', 'Pax', now, now);
  }

  if (toInsert.length > 0) {
    broadcast('ideas.updated', { brainstorm_refilled: true });
  }
}

// Fill brainstorm on startup
try { autoFillBrainstorm(); } catch (e) { logger.warn('Brainstorm auto-fill on startup failed:', e.message); }

