// ── GET /api/monitor — all active/recent tasks with full progress detail ──

app.get('/api/monitor', (req, res) => {
  try {
    const rows = db.prepare(`
      SELECT t.*, tm.name as assignee_name, tm.role as assignee_role,
        p.name as project_name, p.color as project_color
      FROM tasks t
      LEFT JOIN team_members tm ON t.assigned_to = tm.id
      LEFT JOIN project_tasks pt ON pt.task_id = t.id
      LEFT JOIN projects p ON pt.project_id = p.id
      WHERE t.status NOT IN ('delivered', 'completed')
      ORDER BY
        CASE t.status WHEN 'in_progress' THEN 0 WHEN 'review' THEN 1 WHEN 'routing' THEN 2 WHEN 'new' THEN 3 END,
        CASE t.priority WHEN 'urgent' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 WHEN 'low' THEN 3 END,
        t.created_at DESC
      LIMIT 100
    `).all();

    // Parse execution_log JSON for each
    const enriched = rows.map(t => {
      let execLog = [];
      try { execLog = JSON.parse(t.execution_log || '[]'); } catch (parseErr) {
        console.warn(`[monitor] Malformed execution_log for task ${t.id}: ${parseErr.message}`);
      }
      return { ...t, execution_log: execLog };
    });

    // Also get active processes (includes process_type for council distinction)
    const processes = db.prepare(`
      SELECT ap.*, ap.process_type, tm.name as member_name, tm.tier as member_tier, t.title as task_title
      FROM active_processes ap
      LEFT JOIN team_members tm ON ap.member_id = tm.id
      LEFT JOIN tasks t ON ap.task_id = t.id
      WHERE ap.status = 'running'
      ORDER BY ap.started_at DESC
    `).all();

    // Recently delivered (last 10)
    const delivered = db.prepare(`
      SELECT t.*, tm.name as assignee_name
      FROM tasks t
      LEFT JOIN team_members tm ON t.assigned_to = tm.id
      WHERE t.status = 'delivered'
      ORDER BY t.delivered_at DESC LIMIT 10
    `).all();

    res.json({ active_tasks: enriched, active_processes: processes, recent_delivered: delivered });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// ── PUT /api/tasks/:id/progress — update task progress ──

app.put('/api/tasks/:id/progress', (req, res) => {
  try {
    const { progress, current_step, total_steps, step_number, log_entry } = req.body;
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    const now = localNow();
    const updates = ['updated_at = ?'];
    const values = [now];

    if (progress !== undefined) { updates.push('progress = ?'); values.push(Math.min(100, Math.max(0, progress))); }
    if (current_step) { updates.push('current_step = ?'); values.push(current_step); }
    if (total_steps) { updates.push('total_steps = ?'); values.push(total_steps); }
    if (step_number) { updates.push('step_number = ?'); values.push(step_number); }

    // Append to execution log
    if (log_entry) {
      let execLog = [];
      try { execLog = JSON.parse(task.execution_log || '[]'); } catch {}
      execLog.push({ timestamp: now, message: log_entry });
      // Keep last 50 entries
      if (execLog.length > 50) execLog = execLog.slice(-50);
      updates.push('execution_log = ?');
      values.push(JSON.stringify(execLog));
    }

    values.push(req.params.id);
    db.prepare(`UPDATE tasks SET ${updates.join(', ')} WHERE id = ?`).run(...values);

    res.json({ message: 'Progress updated' });
    broadcast('task.updated', { id: Number(req.params.id) });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// ── GET /api/monitor/stats — execution statistics ──

app.get('/api/monitor/stats', (req, res) => {
  try {
    const queued = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status = 'new'`).get().c;
    const routing = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status = 'routing'`).get().c;
    const inProgress = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status = 'in_progress'`).get().c;
    const inReview = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status = 'review'`).get().c;
    const runningProcesses = db.prepare(`SELECT COUNT(*) as c FROM active_processes WHERE status = 'running'`).get().c;
    const deliveredToday = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status = 'delivered' AND date(delivered_at) = date('now', 'localtime')`).get().c;
    const terminalHb = db.prepare(`SELECT value FROM system_settings WHERE key = 'terminal_last_heartbeat'`).get();
    const terminalOnline = terminalHb && terminalHb.value ? (Date.now() - new Date(terminalHb.value).getTime()) < 90000 : false;
    const workerStatus = db.prepare(`SELECT value FROM system_settings WHERE key = 'worker_status'`).get();

    res.json({
      queued, routing, in_progress: inProgress, in_review: inReview,
      running_processes: runningProcesses, delivered_today: deliveredToday,
      terminal_online: terminalOnline,
      worker_running: workerStatus ? workerStatus.value === 'running' : false
    });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// ── POST /api/monitor/stale-cleanup — manually trigger stale process detection ──

app.post('/api/monitor/stale-cleanup', (req, res) => {
  try {
    const now = localNow();
    const staleMinutes = 15;

    const staleProcesses = db.prepare(`
      SELECT ap.id, ap.task_id, ap.member_id, ap.pid, ap.started_at,
             tm.name as member_name, t.title as task_title
      FROM active_processes ap
      LEFT JOIN team_members tm ON ap.member_id = tm.id
      LEFT JOIN tasks t ON ap.task_id = t.id
      WHERE ap.status = 'running'
      AND ap.started_at < datetime(?, '-' || ? || ' minutes')
    `).all(now, staleMinutes);

    let cleaned = 0;
    const details = [];
    for (const proc of staleProcesses) {
      let processAlive = false;
      if (proc.pid) {
        try { process.kill(proc.pid, 0); processAlive = true; } catch (_) { processAlive = false; }
      }
      if (!processAlive && runningProcesses.has(proc.id)) {
        runningProcesses.delete(proc.id);
      }
      if (!processAlive) {
        db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = COALESCE(output_summary, '') || ' [STALE: manual cleanup]' WHERE id = ?`)
          .run(now, proc.id);
        db.prepare(`INSERT INTO activity_log (actor, action, notes, created_at) VALUES ('StaleDetector', 'manual_cleanup', ?, ?)`)
          .run(`Manual cleanup: stale process #${proc.id} (task: ${proc.task_title || proc.task_id}, member: ${proc.member_name || proc.member_id})`, now);
        try { broadcast('process.failed', { process_id: proc.id, task_id: proc.task_id, reason: 'manual_stale_cleanup' }); } catch (_) {}
        details.push({ id: proc.id, task_id: proc.task_id, member: proc.member_name, pid: proc.pid, started_at: proc.started_at });
        cleaned++;
      }
    }

    res.json({ cleaned, scanned: staleProcesses.length, stale_threshold_minutes: staleMinutes, details });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// ── GET /api/monitor/stale — list currently stale processes without cleaning ──

app.get('/api/monitor/stale', (req, res) => {
  try {
    const now = localNow();
    const staleMinutes = 15;

    const staleProcesses = db.prepare(`
      SELECT ap.id, ap.task_id, ap.member_id, ap.pid, ap.started_at, ap.status,
             tm.name as member_name, t.title as task_title,
             CAST((julianday(?) - julianday(ap.started_at)) * 24 * 60 AS INTEGER) as running_minutes
      FROM active_processes ap
      LEFT JOIN team_members tm ON ap.member_id = tm.id
      LEFT JOIN tasks t ON ap.task_id = t.id
      WHERE ap.status = 'running'
      AND ap.started_at < datetime(?, '-' || ? || ' minutes')
      ORDER BY ap.started_at ASC
    `).all(now, now, staleMinutes);

    // Check which ones have dead PIDs
    const enriched = staleProcesses.map(proc => {
      let alive = false;
      if (proc.pid) {
        try { process.kill(proc.pid, 0); alive = true; } catch (_) {}
      }
      return { ...proc, pid_alive: alive };
    });

    res.json({ stale_count: enriched.length, stale_threshold_minutes: staleMinutes, processes: enriched });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

