// ── POST /api/processor/run — Process queued improvements and new tasks ──

app.post('/api/processor/run', (req, res) => {
  try {
    const now = localNow();
    const processed = [];

    // 1) Find queued improvements
    const queuedImprovements = db.prepare(`
      SELECT * FROM improvement_proposals WHERE status = 'queued'
      ORDER BY CASE impact WHEN 'high' THEN 0 WHEN 'medium' THEN 1 WHEN 'low' THEN 2 END,
        queued_at ASC
    `).all();

    for (const imp of queuedImprovements) {
      // Set to in_progress with work_started_at
      db.prepare(`UPDATE improvement_proposals SET status = 'in_progress', work_started_at = ?, progress_percent = 5, current_step = 'Processing started', updated_at = ? WHERE id = ?`)
        .run(now, now, imp.id);

      // Log the transition
      db.prepare(`INSERT INTO improvement_log (proposal_id, action, notes, created_at) VALUES (?, 'in_progress', 'Auto-processor started work', ?)`)
        .run(imp.id, now);

      // Create notification
      createNotification('system', `Processing: ${imp.title}`, `Improvement #${imp.id} is now being processed`);

      // Auto-spawn member for this improvement (fire-and-forget)
      setImmediate(() => {
        try {
          const assigneeName = imp.category === 'architecture' ? 'Onyx' : 'Lathe';
          const assignee = db.prepare(`SELECT id FROM team_members WHERE name = ? AND status = 'active'`).get(assigneeName);
          if (assignee) {
            const pNow = localNow();
            const taskResult = db.prepare(`
              INSERT INTO tasks (title, description, status, priority, source_file, assigned_to, started_at, progress, current_step, created_at, updated_at)
              VALUES (?, ?, 'in_progress', ?, 'improvement', ?, ?, 10, 'Processor started', ?, ?)
            `).run(`Execute: ${imp.title}`, `Implement improvement #${imp.id}: ${imp.description}`, imp.impact === 'high' ? 'high' : 'normal', assignee.id, pNow, pNow, pNow);
            const tId = Number(taskResult.lastInsertRowid);
            db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'processor_spawn', ?, ?)`)
              .run(tId, assigneeName, `Processor auto-spawned ${assigneeName} for improvement #${imp.id}`, pNow);
            broadcast('task.updated', { id: tId });
            spawnMemberTerminal(tId, assignee.id).catch(err => {
              console.error(`[AutoSpawn] Processor improvement spawn error: ${err.message}`);
            });
          }
        } catch (err) {
          console.error(`[AutoSpawn] Processor improvement spawn setup error: ${err.message}`);
        }
      });

      processed.push({ type: 'improvement', id: imp.id, title: imp.title });
    }

    // 2) Find new tasks that are unassigned
    const newTasks = db.prepare(`
      SELECT * FROM tasks WHERE status = 'new'
      ORDER BY CASE priority WHEN 'urgent' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 WHEN 'low' THEN 3 END,
        created_at ASC
    `).all();

    for (const task of newTasks) {
      // Move to routing
      db.prepare(`UPDATE tasks SET status = 'routing', updated_at = ? WHERE id = ?`).run(now, task.id);

      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Processor', 'status_change', 'Auto-processor moved task to routing', ?)`)
        .run(task.id, now);

      createNotification('task_status', `Processing: ${task.title}`, `Task #${task.id} picked up by processor`, task.id);

      // Auto-spawn if task already has an assignee
      if (task.assigned_to) {
        const tId = Number(task.id);
        setImmediate(() => {
          autoSpawnForTask(tId).catch(err => {
            console.error(`[AutoSpawn] Processor task spawn error: ${err.message}`);
          });
        });
      }

      processed.push({ type: 'task', id: task.id, title: task.title });
    }

    // Broadcast updates
    if (processed.length > 0) {
      broadcast('processor.run', { processed: processed.length, items: processed });
    }

    res.json({ processed: processed.length, items: processed });
  } catch (err) {
    console.error('POST /api/processor/run error:', err);
    res.status(500).json({ error: err.message });
  }
});

