// ── POST /api/tasks/:id/start-work — Start work on a task from the browser ──

app.post('/api/tasks/:id/start-work', (req, res) => {
  try {
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    if (task.status === 'completed' || task.status === 'delivered') {
      return res.status(400).json({ error: `Cannot start work on a task in status "${task.status}"` });
    }

    const now = localNow();

    // Set task to in_progress with initial progress
    db.prepare(`UPDATE tasks SET status = 'in_progress', started_at = COALESCE(started_at, ?), progress = 10, current_step = 'Starting...', updated_at = ? WHERE id = ?`)
      .run(now, now, task.id);

    // Log activity
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Browser', 'work_started', 'Work started from browser dashboard', ?)`)
      .run(task.id, now);

    // Create notification
    createNotification('task_status', `Work started: ${task.title}`, `Task #${task.id} is now in progress`, task.id);

    // Broadcast
    broadcast('task.updated', { id: Number(req.params.id) });

    // Auto-spawn assigned member(s) CLI sessions
    const tId = Number(req.params.id);
    setImmediate(() => {
      autoSpawnForTask(tId).catch(err => {
        console.error(`[AutoSpawn] Start-work spawn error: ${err.message}`);
      });
    });

    res.json({ message: 'Work started', task_id: task.id, status: 'in_progress' });
  } catch (err) {
    console.error('POST /api/tasks/:id/start-work error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/tasks/:id/retry — Retry a failed task ──

app.post('/api/tasks/:id/retry', (req, res) => {
  try {
    const taskId = Number(req.params.id);
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(taskId);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    const now = localNow();

    // Reset task status
    db.prepare(`UPDATE tasks SET status = 'in_progress', progress = 5, current_step = 'Retrying...', updated_at = ? WHERE id = ?`)
      .run(now, taskId);

    // Mark old failed processes as retried
    db.prepare(`UPDATE active_processes SET output_summary = output_summary || ' [RETRIED]' WHERE task_id = ? AND status = 'failed'`)
      .run(taskId);

    // Log
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Max', 'task_retry', 'Manually retried failed task from dashboard', ?)`)
      .run(taskId, now);

    createNotification('task_status', `Task retrying`, `Task #${taskId} "${task.title}" is being retried`, taskId);

    broadcast('task.updated', { id: taskId });

    // Re-spawn the assigned member
    setImmediate(() => {
      autoSpawnForTask(taskId).catch(err => {
        console.error(`[AutoSpawn] Retry spawn error: ${err.message}`);
      });
    });

    res.json({ message: 'Task retrying', task_id: taskId, status: 'in_progress' });
  } catch (err) {
    console.error('POST /api/tasks/:id/retry error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/tasks/:id/pause — Pause a running task ──

app.post('/api/tasks/:id/pause', (req, res) => {
  try {
    const taskId = Number(req.params.id);
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(taskId);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    if (task.status !== 'in_progress') {
      return res.status(400).json({ error: `Can only pause in_progress tasks, current status is "${task.status}"` });
    }

    const now = localNow();

    // Kill all running processes for this task
    const procs = db.prepare(`SELECT * FROM active_processes WHERE task_id = ? AND status = 'running'`).all(taskId);
    let killed = 0;
    for (const proc of procs) {
      if (proc.pid) {
        try {
          process.kill(proc.pid, 'SIGTERM');
          setTimeout(() => { try { process.kill(proc.pid, 'SIGKILL'); } catch {} }, 3000);
        } catch {}
      }
      runningProcesses.delete(proc.id);
      db.prepare(`UPDATE active_processes SET status = 'paused', completed_at = ?, output_summary = COALESCE(output_summary, '') || ' [PAUSED]' WHERE id = ?`)
        .run(now, proc.id);
      killed++;
    }

    // Set task status to paused (we store as 'new' with a paused step indicator so it doesn't auto-restart)
    db.prepare(`UPDATE tasks SET status = 'new', current_step = ?, updated_at = ? WHERE id = ?`)
      .run('PAUSED: ' + (task.current_step || 'In progress'), now, taskId);

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Max', 'task_paused', ?, ?)`)
      .run(taskId, `Task paused by user. ${killed} process(es) stopped. Progress: ${task.progress || 0}%`, now);

    createNotification('task_status', `Task paused`, `Task #${taskId} "${task.title}" has been paused`, taskId);

    broadcast('task.updated', { id: taskId });

    res.json({ message: 'Task paused', task_id: taskId, processes_stopped: killed });
  } catch (err) {
    console.error('POST /api/tasks/:id/pause error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/tasks/:id/cancel — Cancel a task completely ──

app.post('/api/tasks/:id/cancel', (req, res) => {
  try {
    const taskId = Number(req.params.id);
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(taskId);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    if (task.status === 'delivered') {
      return res.status(400).json({ error: 'Cannot cancel a delivered task' });
    }

    const now = localNow();

    // Kill all running processes for this task
    const procs = db.prepare(`SELECT * FROM active_processes WHERE task_id = ? AND status = 'running'`).all(taskId);
    let killed = 0;
    for (const proc of procs) {
      if (proc.pid) {
        try {
          process.kill(proc.pid, 'SIGTERM');
          setTimeout(() => { try { process.kill(proc.pid, 'SIGKILL'); } catch {} }, 3000);
        } catch {}
      }
      runningProcesses.delete(proc.id);
      db.prepare(`UPDATE active_processes SET status = 'killed', completed_at = ?, output_summary = COALESCE(output_summary, '') || ' [CANCELLED]' WHERE id = ?`)
        .run(now, proc.id);
      killed++;
    }

    // Mark task as cancelled (using 'completed' status with cancelled indicator)
    db.prepare(`UPDATE tasks SET status = 'completed', current_step = 'CANCELLED', progress = 0, completed_at = ?, updated_at = ? WHERE id = ?`)
      .run(now, now, taskId);

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Max', 'task_cancelled', ?, ?)`)
      .run(taskId, `Task cancelled by user. ${killed} process(es) killed.`, now);

    createNotification('task_status', `Task cancelled`, `Task #${taskId} "${task.title}" has been cancelled`, taskId);

    broadcast('task.updated', { id: taskId });

    res.json({ message: 'Task cancelled', task_id: taskId, processes_killed: killed });
  } catch (err) {
    console.error('POST /api/tasks/:id/cancel error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/tasks/:id/resume — Resume a paused task ──

app.post('/api/tasks/:id/resume', (req, res) => {
  try {
    const taskId = Number(req.params.id);
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(taskId);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    // Check if this is actually a paused task
    const isPaused = (task.current_step || '').startsWith('PAUSED:');
    if (!isPaused && task.status !== 'new') {
      return res.status(400).json({ error: 'Task is not paused' });
    }

    const now = localNow();
    const resumedStep = isPaused ? task.current_step.replace('PAUSED: ', '') : 'Resuming...';

    // Restore task to in_progress
    db.prepare(`UPDATE tasks SET status = 'in_progress', current_step = ?, updated_at = ? WHERE id = ?`)
      .run(resumedStep, now, taskId);

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Max', 'task_resumed', ?, ?)`)
      .run(taskId, `Task resumed by user. Progress: ${task.progress || 0}%`, now);

    createNotification('task_status', `Task resumed`, `Task #${taskId} "${task.title}" has been resumed`, taskId);

    broadcast('task.updated', { id: taskId });

    // Re-spawn the assigned member(s)
    setImmediate(() => {
      autoSpawnForTask(taskId).catch(err => {
        console.error(`[AutoSpawn] Resume spawn error: ${err.message}`);
      });
    });

    res.json({ message: 'Task resumed', task_id: taskId, status: 'in_progress' });
  } catch (err) {
    console.error('POST /api/tasks/:id/resume error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/clipper-engine/submit-prompt — Receive master dossier from browser ──

app.post('/api/clipper-engine/submit-prompt', (req, res) => {
  try {
    const { prompt } = req.body;
    if (!prompt || !prompt.trim()) {
      return res.status(400).json({ error: 'prompt is required' });
    }

    const now = localNow();
    const dossierDir = path.join(__dirname, '..', 'projects', 'clipper-engine');
    const dossierPath = path.join(dossierDir, 'MASTER_DOSSIER.md');

    // Ensure directory exists
    if (!fs.existsSync(dossierDir)) {
      fs.mkdirSync(dossierDir, { recursive: true });
    }

    // Save the master dossier
    const header = `# Clipper Engine Master Dossier\n\n**Submitted:** ${now}\n**Source:** Browser Dashboard\n\n---\n\n`;
    fs.writeFileSync(dossierPath, header + prompt.trim(), 'utf-8');

    // Create a project note (as a note linked to the Clipper Engine project)
    const noteResult = db.prepare(`
      INSERT INTO notes (title, content, source, created_at, updated_at)
      VALUES ('Clipper Engine Master Dossier', ?, 'browser', ?, ?)
    `).run(prompt.trim(), now, now);
    const noteId = Number(noteResult.lastInsertRowid);

    // Tag the note with clipper-engine
    const ceTag = db.prepare(`SELECT id FROM tags WHERE name = 'clipper-engine'`).get();
    let tagId;
    if (ceTag) {
      tagId = ceTag.id;
    } else {
      const tagResult = db.prepare(`INSERT INTO tags (name) VALUES ('clipper-engine')`).run();
      tagId = Number(tagResult.lastInsertRowid);
    }
    db.prepare(`INSERT OR IGNORE INTO taggables (tag_id, entity_type, entity_id) VALUES (?, 'note', ?)`)
      .run(tagId, noteId);

    // Find or reference the Clipper Engine project
    const clipperProject = db.prepare(`SELECT id FROM projects WHERE name LIKE '%Clipper Engine%' LIMIT 1`).get();
    const projectId = clipperProject ? clipperProject.id : null;

    // Parse the dossier into execution packets (extract sections as phases)
    const lines = prompt.trim().split('\n');
    const sections = [];
    let currentSection = null;

    for (const line of lines) {
      const headingMatch = line.match(/^#{1,3}\s+(.+)/);
      if (headingMatch) {
        if (currentSection) sections.push(currentSection);
        currentSection = { title: headingMatch[1].trim(), content: '' };
      } else if (currentSection) {
        currentSection.content += line + '\n';
      }
    }
    if (currentSection) sections.push(currentSection);

    // Create execution packets from the first few meaningful sections (up to 5)
    const packetIds = [];
    const meaningfulSections = sections.filter(s => s.content.trim().length > 20).slice(0, 5);

    for (let i = 0; i < meaningfulSections.length; i++) {
      const section = meaningfulSections[i];
      const packetIdStr = `CE-DOSSIER-${Date.now()}-${i + 1}`;

      try {
        const pResult = db.prepare(`
          INSERT INTO execution_packets (packet_id, title, active_phase, objective, status, project_id, created_at, updated_at)
          VALUES (?, ?, ?, ?, 'draft', ?, ?, ?)
        `).run(
          packetIdStr,
          section.title,
          i + 1,
          section.content.trim().slice(0, 500),
          projectId,
          now,
          now
        );
        packetIds.push({ id: Number(pResult.lastInsertRowid), packet_id: packetIdStr, title: section.title });
      } catch (packetErr) {
        // Skip duplicate packet_ids silently
        console.error(`Packet creation skipped: ${packetErr.message}`);
      }
    }

    // Create notification
    createNotification('system', 'Clipper Engine Dossier Received', `Master dossier saved with ${packetIds.length} execution packets created`);

    broadcast('notification.created', { title: 'Clipper Engine Dossier Received' });
    if (packetIds.length > 0) broadcast('packet.updated', { count: packetIds.length });

    res.json({
      message: `Master dossier saved — ${packetIds.length} execution packets created`,
      file_path: dossierPath,
      note_id: noteId,
      packets: packetIds
    });
  } catch (err) {
    console.error('POST /api/clipper-engine/submit-prompt error:', err);
    res.status(500).json({ error: err.message });
  }
});

// ── GET /api/clipper-engine/dashboard — Clipper Engine dashboard summary ──

app.get('/api/clipper-engine/dashboard', (req, res) => {
  try {
    const projectId = 3;

    // Fetch all execution packets for the project
    const packets = db.prepare(`SELECT * FROM execution_packets WHERE project_id = ?`).all(projectId);

    // Fetch all project phases
    const phases = db.prepare(`SELECT * FROM project_phases WHERE project_id = ? ORDER BY phase_number`).all(projectId);

    // Fetch all founder decisions
    const decisions = db.prepare(`SELECT * FROM founder_decisions WHERE project_id = ?`).all(projectId);

    // Fetch all feature flags
    const flags = db.prepare(`SELECT * FROM feature_flags WHERE project_id = ?`).all(projectId);

    // Fetch all escalations
    const escalations = db.prepare(`SELECT * FROM escalation_log WHERE project_id = ?`).all(projectId);

    // Compute stats
    const byStatus = {};
    for (const p of packets) {
      byStatus[p.status] = (byStatus[p.status] || 0) + 1;
    }

    const activePhases = new Set(packets.filter(p => p.status === 'in_progress' || p.status === 'review' || p.status === 'verification').map(p => p.active_phase));

    const openEscalations = escalations.filter(e => e.status === 'open' || e.status === 'founder_required').length;
    const decisionsPending = decisions.filter(d => d.status === 'pending').length;

    res.json({
      packets,
      phases,
      decisions,
      flags,
      escalations,
      stats: {
        total_packets: packets.length,
        by_status: byStatus,
        active_phase_count: activePhases.size,
        open_escalations: openEscalations,
        decisions_pending: decisionsPending
      }
    });
  } catch (err) {
    console.error('GET /api/clipper-engine/dashboard error:', err);
    res.status(500).json({ error: err.message });
  }
});

