// ── GET /api/review-panel/:taskId — get review panel votes for a task ──

app.get('/api/review-panel/:taskId', (req, res) => {
  try {
    const taskId = parseInt(req.params.taskId);
    const votes = db.prepare('SELECT * FROM review_panel_votes WHERE task_id = ? ORDER BY created_at DESC').all(taskId);

    // Aggregate the most recent set of votes
    const latestTime = votes.length > 0 ? votes[0].created_at : null;
    const latestVotes = latestTime ? votes.filter(v => v.created_at === latestTime) : [];

    const blocks = latestVotes.filter(v => v.vote === 'block');
    const approves = latestVotes.filter(v => v.vote === 'approve');
    const amends = latestVotes.filter(v => v.vote === 'amend');

    let disposition = 'approve';
    if (blocks.length > 0) disposition = 'block';
    else if (amends.length >= 2) disposition = 'amend';

    res.json({
      task_id: taskId,
      total_reviews: votes.length,
      latest_review: latestTime,
      latest_votes: latestVotes,
      disposition,
      summary: `${approves.length} approve, ${blocks.length} block, ${amends.length} amend`,
      all_votes: votes
    });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// ── POST /api/review-panel/:taskId/run — trigger a review panel ──

app.post('/api/review-panel/:taskId/run', (req, res) => {
  try {
    const taskId = parseInt(req.params.taskId);
    const task = db.prepare('SELECT * FROM tasks WHERE id = ?').get(taskId);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    // Get the most recent process output for this task
    const proc = db.prepare('SELECT output_summary FROM active_processes WHERE task_id = ? ORDER BY id DESC LIMIT 1').get(taskId);
    const output = proc ? proc.output_summary || '' : task.current_step || task.description || '';

    const result = runReviewPanel(taskId, output);
    res.json({
      task_id: taskId,
      task_title: task.title,
      disposition: result.disposition,
      summary: result.summary,
      votes: result.votes
    });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

