// ── GET /api/self-improvement/status — get scan results and auto-generated tasks ──

app.get('/api/self-improvement/status', (req, res) => {
  try {
    // Get recent self-improvement scan logs
    const recentScans = db.prepare(`SELECT * FROM activity_log WHERE action = 'self_improvement_scan' ORDER BY created_at DESC LIMIT 10`).all();
    const parsedScans = recentScans.map(s => {
      try { return { ...s, notes: JSON.parse(s.notes) }; } catch { return s; }
    });

    // Get auto-generated improvement tasks
    const autoTasks = db.prepare(`SELECT * FROM tasks WHERE source_file = 'self_improvement' ORDER BY created_at DESC LIMIT 20`).all();

    // Get failing agent stats
    const now = localNow();
    const failingAgents = db.prepare(`
      SELECT ap.member_id, tm.name, COUNT(*) as failures
      FROM active_processes ap
      LEFT JOIN team_members tm ON ap.member_id = tm.id
      WHERE ap.status = 'failed' AND ap.completed_at > datetime(?, '-24 hours')
      GROUP BY ap.member_id HAVING failures >= 2
      ORDER BY failures DESC
    `).all(now);

    // Get stale task count
    const staleTasks = db.prepare(`
      SELECT COUNT(*) as c FROM tasks
      WHERE status = 'in_progress' AND updated_at < datetime(?, '-48 hours')
    `).get(now);

    res.json({
      recent_scans: parsedScans,
      auto_generated_tasks: autoTasks,
      failing_agents: failingAgents,
      stale_task_count: staleTasks ? staleTasks.c : 0,
      scan_interval_minutes: 30
    });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

