const WRITABLE_SETTINGS = ['execution_mode', 'autonomous_model', 'autonomous_model_complex', 'default_page', 'llm_auth_mode', 'openrouter_base_url', 'openrouter_model_prefix'];

// ── PUT /api/settings/execution-mode — switch global mode ──
// (Convenience wrapper with validation)

app.put('/api/execution-mode', (req, res) => {
  try {
    const { mode } = req.body;
    if (!['terminal', 'autonomous'].includes(mode)) {
      return res.status(400).json({ error: 'Mode must be terminal or autonomous' });
    }
    // If switching to autonomous, require either OAuth token or OpenRouter API key
    if (mode === 'autonomous') {
      const llmAuthMode = getCachedSetting('llm_auth_mode') || 'oauth';
      if (llmAuthMode === 'api_key') {
        const apiKey = db.prepare(`SELECT value FROM system_settings WHERE key = 'openrouter_api_key'`).get();
        if (!apiKey || !apiKey.value) {
          return res.status(400).json({ error: 'Cannot enable autonomous mode without an OpenRouter API key. Add your key in Settings.' });
        }
      } else {
        const token = db.prepare(`SELECT value FROM system_settings WHERE key = 'oauth_token'`).get();
        if (!token || !token.value) {
          return res.status(400).json({ error: 'Cannot enable autonomous mode without an OAuth token. Run claude setup-token in your terminal.' });
        }
      }
    }
    const now = localNow();
    db.prepare(`UPDATE system_settings SET value = ?, updated_at = ? WHERE key = 'execution_mode'`).run(mode, now);
    res.json({ mode, message: `Switched to ${mode} mode` });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── GET /api/execution-mode — current mode + status ──

app.get('/api/execution-mode', (req, res) => {
  try {
    const mode = db.prepare(`SELECT value FROM system_settings WHERE key = 'execution_mode'`).get();
    const workerStatus = db.prepare(`SELECT value FROM system_settings WHERE key = 'worker_status'`).get();
    const heartbeat = db.prepare(`SELECT value FROM system_settings WHERE key = 'terminal_last_heartbeat'`).get();
    const token = db.prepare(`SELECT value FROM system_settings WHERE key = 'oauth_token'`).get();

    const hbTime = heartbeat ? heartbeat.value : '';
    const terminalOnline = hbTime ? (Date.now() - new Date(hbTime).getTime()) < 90000 : false;

    res.json({
      mode: mode ? mode.value : 'terminal',
      worker_status: workerStatus ? workerStatus.value : 'stopped',
      terminal_online: terminalOnline,
      terminal_last_heartbeat: hbTime,
      has_oauth_token: !!(token && token.value)
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/terminal/heartbeat — terminal pings this ──

app.post('/api/terminal/heartbeat', (req, res) => {
  try {
    const now = localNow();
    db.prepare(`UPDATE system_settings SET value = ?, updated_at = ? WHERE key = 'terminal_last_heartbeat'`).run(now, now);

    // Return status + any pending task count so the CLI knows if there's work
    const pendingCount = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status IN ('new', 'routing')`).get().c;
    res.json({ status: 'ok', timestamp: now, pending_tasks: pendingCount });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── GET /api/terminal/next-task — CLI polls for the next task to work on ──

app.get('/api/terminal/next-task', (req, res) => {
  try {
    // Find the highest-priority task that's ready for terminal processing
    const task = db.prepare(`
      SELECT t.*, GROUP_CONCAT(ta.member_id) as assigned_member_ids
      FROM tasks t
      LEFT JOIN task_assignments ta ON ta.task_id = t.id
      WHERE t.status IN ('new', 'routing')
      GROUP BY t.id
      ORDER BY
        CASE t.priority WHEN 'urgent' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 WHEN 'low' THEN 3 END,
        t.created_at ASC
      LIMIT 1
    `).get();

    if (!task) {
      return res.json({ task: null, message: 'No tasks waiting' });
    }

    // Get assigned member details
    let members = [];
    if (task.assigned_to) {
      const member = db.prepare(`SELECT id, name, role FROM team_members WHERE id = ?`).get(task.assigned_to);
      if (member) members.push(member);
    }
    const assignments = db.prepare(`
      SELECT tm.id, tm.name, tm.role FROM task_assignments ta
      JOIN team_members tm ON ta.member_id = tm.id
      WHERE ta.task_id = ?
    `).all(task.id);
    if (assignments.length > 0) members = assignments;

    // Get input files
    const files = db.prepare(`SELECT * FROM task_files WHERE task_id = ? AND direction = 'input'`).all(task.id);

    // Get mission context if linked
    const mission = db.prepare(`
      SELECT m.* FROM missions m
      JOIN mission_tasks mt ON mt.mission_id = m.id
      WHERE mt.task_id = ?
    `).get(task.id);

    // Get project context if linked
    const project = db.prepare(`
      SELECT p.* FROM projects p
      JOIN project_tasks pt ON pt.project_id = p.id
      WHERE pt.task_id = ?
    `).get(task.id);

    res.json({
      task: {
        id: task.id,
        title: task.title,
        description: task.description,
        priority: task.priority,
        status: task.status,
        source_file: task.source_file,
        created_at: task.created_at,
        revision_count: task.revision_count || 0
      },
      members,
      files,
      mission: mission || null,
      project: project || null
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/terminal/claim-task/:id — CLI claims a task to start working on it ──

app.post('/api/terminal/claim-task/:id', (req, res) => {
  try {
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    if (!['new', 'routing'].includes(task.status)) {
      return res.status(400).json({ error: `Task is already in status "${task.status}"` });
    }

    const now = localNow();
    db.prepare(`UPDATE tasks SET status = 'in_progress', started_at = COALESCE(started_at, ?), updated_at = ? WHERE id = ?`)
      .run(now, now, task.id);

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Terminal', 'task_claimed', 'Terminal CLI claimed task for processing', ?)`)
      .run(task.id, now);

    // Update heartbeat since the terminal is active
    db.prepare(`UPDATE system_settings SET value = ?, updated_at = ? WHERE key = 'terminal_last_heartbeat'`).run(now, now);

    broadcast('task.updated', { id: task.id });

    res.json({ success: true, task_id: task.id, status: 'in_progress' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/terminal/submit-result/:id — CLI submits completed work ──

app.post('/api/terminal/submit-result/:id', (req, res) => {
  try {
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    const { output, status, actor, notes } = req.body;
    const finalStatus = status || 'review';
    const now = localNow();

    // Update task status
    const updateFields = {
      review: `UPDATE tasks SET status = 'review', progress = 90, current_step = 'Awaiting review', updated_at = ? WHERE id = ?`,
      completed: `UPDATE tasks SET status = 'completed', completed_at = ?, progress = 100, current_step = 'Completed', updated_at = ? WHERE id = ?`,
      delivered: `UPDATE tasks SET status = 'delivered', completed_at = COALESCE(completed_at, ?), delivered_at = ?, progress = 100, current_step = 'Delivered', updated_at = ? WHERE id = ?`
    };

    if (finalStatus === 'review') {
      db.prepare(updateFields.review).run(now, task.id);
    } else if (finalStatus === 'completed') {
      db.prepare(updateFields.completed).run(now, now, task.id);
    } else if (finalStatus === 'delivered') {
      db.prepare(updateFields.delivered).run(now, now, now, task.id);
    } else {
      return res.status(400).json({ error: 'Status must be review, completed, or delivered' });
    }

    // Log activity
    const actorName = actor || 'Terminal';
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'task_result_submitted', ?, ?)`)
      .run(task.id, actorName, notes || `Terminal submitted result (status: ${finalStatus})`, now);

    // If output provided, save to outbox and register as task file
    if (output) {
      const fs = require('fs');
      const path = require('path');
      const outboxPath = process.env.OUTBOX_PATH || path.join(__dirname, '..', "Stew's inbox:Owner");
      const outputFile = `task-${task.id}-output-${Date.now()}.md`;
      const outputContent = `# Task #${task.id}: ${task.title}\n\n**Completed by:** ${actorName}\n**Date:** ${now}\n\n---\n\n${output}\n`;

      if (!fs.existsSync(outboxPath)) {
        fs.mkdirSync(outboxPath, { recursive: true });
      }
      fs.writeFileSync(path.join(outboxPath, outputFile), outputContent, 'utf-8');

      db.prepare(`INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at) VALUES (?, ?, ?, 'text/markdown', 'output', ?)`)
        .run(task.id, outputFile, path.join(outboxPath, outputFile), now);
    }

    // Create notification
    createNotification('task_status', `Task ${finalStatus}: ${task.title}`, `${actorName} submitted result for "${task.title}"`, task.id);

    // Update heartbeat
    const hbNow = new Date().toISOString();
    db.prepare(`UPDATE system_settings SET value = ?, updated_at = ? WHERE key = 'terminal_last_heartbeat'`).run(hbNow, now);

    broadcast('task.updated', { id: task.id });

    res.json({ success: true, task_id: task.id, status: finalStatus });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/terminal/update-progress/:id — CLI reports progress on a task ──

app.post('/api/terminal/update-progress/:id', (req, res) => {
  try {
    const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(req.params.id);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    const { progress, current_step } = req.body;
    const now = localNow();

    const updates = [];
    const params = [];

    if (progress !== undefined) {
      updates.push('progress = ?');
      params.push(Math.min(100, Math.max(0, parseInt(progress) || 0)));
    }
    if (current_step) {
      updates.push('current_step = ?');
      params.push(current_step);
    }

    if (updates.length === 0) {
      return res.status(400).json({ error: 'Provide progress and/or current_step' });
    }

    updates.push('updated_at = ?');
    params.push(now);
    params.push(task.id);

    db.prepare(`UPDATE tasks SET ${updates.join(', ')} WHERE id = ?`).run(...params);

    // Update heartbeat
    const hbNow = new Date().toISOString();
    db.prepare(`UPDATE system_settings SET value = ?, updated_at = ? WHERE key = 'terminal_last_heartbeat'`).run(hbNow, now);

    broadcast('task.updated', { id: task.id });

    res.json({ success: true, task_id: task.id });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── GET /api/terminal/status — full terminal status summary for CLI ──

app.get('/api/terminal/status', (req, res) => {
  try {
    const mode = db.prepare(`SELECT value FROM system_settings WHERE key = 'execution_mode'`).get();
    const pending = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status IN ('new', 'routing')`).get().c;
    const inProgress = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status = 'in_progress'`).get().c;
    const inReview = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status = 'review'`).get().c;

    res.json({
      mode: mode ? mode.value : 'terminal',
      pending_tasks: pending,
      in_progress_tasks: inProgress,
      in_review_tasks: inReview,
      dashboard_url: process.env.DASHBOARD_URL || `${req.protocol}://${req.get('host')}`
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

