// ── Worker control ──

const { execSync } = require('child_process');

app.get('/api/worker/status', (req, res) => {
  try {
    const dbStatus = db.prepare(`SELECT value FROM system_settings WHERE key = 'worker_status'`).get();

    // Also check if the Docker container is actually running
    let containerRunning = false;
    try {
      const result = execSync('docker inspect -f "{{.State.Status}}" the-team-worker 2>/dev/null', { timeout: 5000 }).toString().trim();
      containerRunning = result === 'running';
    } catch { /* container doesn't exist or docker not available */ }

    res.json({
      status: dbStatus ? dbStatus.value : 'stopped',
      container_running: containerRunning
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/worker/start', (req, res) => {
  try {
    const token = db.prepare(`SELECT value FROM system_settings WHERE key = 'oauth_token'`).get();
    if (!token || !token.value) {
      return res.status(400).json({ error: 'OAuth token required. Run claude setup-token in your terminal.' });
    }

    // Update DB status
    db.prepare(`UPDATE system_settings SET value = 'running', updated_at = ? WHERE key = 'worker_status'`).run(localNow());

    // Try to start the worker Docker container
    try {
      execSync('docker compose --profile autonomous up -d worker 2>&1', {
        cwd: '/data/project',
        timeout: 30000
      });
    } catch (dockerErr) {
      // If docker commands fail (e.g., running inside Docker without socket), just set DB status
      // The worker polling loop will pick up 'running' status from the DB
    }

    res.json({ status: 'running', message: 'Worker started' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/worker/stop', (req, res) => {
  try {
    db.prepare(`UPDATE system_settings SET value = 'stopped', updated_at = ? WHERE key = 'worker_status'`).run(localNow());

    // Try to stop the worker container
    try {
      execSync('docker stop the-team-worker 2>/dev/null', { timeout: 10000 });
    } catch { /* container may not exist */ }
    res.json({ status: 'stopped', message: 'Worker stopped' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── Auto-Spawn Process Manager ─────────────────────────────────

const { spawn } = require('child_process');

// In-memory registry of running child processes (pid -> info)
const runningProcesses = new Map();

// ── Adapter Handler Functions (Phase 3) ─────────────────────────

function spawnProcessAdapter(taskId, processId, memberId, member, task, adapterConfig, prompt) {
  const cmd = adapterConfig.command || 'echo';
  const rawArgs = adapterConfig.args || [];
  const args = Array.isArray(rawArgs) ? rawArgs : [rawArgs];
  const workingDir = adapterConfig.cwd || path.join(process.env.PROJECT_ROOT || path.join(__dirname, '..'), 'app');
  const now = localNow();

  let child;
  try {
    child = spawn(cmd, args, {
      env: { ...process.env, ...(adapterConfig.env || {}) },
      stdio: ['pipe', 'pipe', 'pipe'],
      cwd: workingDir,
      detached: false
    });
  } catch (err) {
    console.error(`[ProcessAdapter] Failed to spawn '${cmd}': ${err.message}`);
    db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
      .run(now, `Process spawn failed: ${err.message}`, processId);
    return;
  }

  db.prepare(`UPDATE active_processes SET pid = ? WHERE id = ?`).run(child.pid, processId);
  runningProcesses.set(processId, { child, taskId, memberId, memberName: member.name, startedAt: now });

  try {
    child.stdin.write(prompt);
    child.stdin.end();
  } catch (e) { console.error(`[ProcessAdapter] stdin write error: ${e.message}`); }

  let stdout = '';
  let stderr = '';
  child.stdout.on('data', d => { stdout += d.toString(); });
  child.stderr.on('data', d => { stderr += d.toString(); });

  child.on('close', (code) => {
    const finishedAt = localNow();
    runningProcesses.delete(processId);
    if (code === 0) {
      handleSpawnSuccess(taskId, processId, member, task, 'process', stdout, finishedAt);
    } else {
      handleSpawnFailure(taskId, processId, member, task, code, stdout, stderr, finishedAt);
    }
  });

  child.on('error', (err) => {
    runningProcesses.delete(processId);
    const failedAt = localNow();
    db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
      .run(failedAt, `Process error: ${err.message}`, processId);
    broadcast('process.failed', { process_id: processId, task_id: taskId, error: err.message });
  });

  // Timeout
  const timeoutMs = adapterConfig.timeout_ms || 900000;
  setTimeout(() => {
    if (runningProcesses.has(processId)) {
      try { child.kill('SIGTERM'); } catch {}
      setTimeout(() => { try { child.kill('SIGKILL'); } catch {} }, 5000);
    }
  }, timeoutMs);
}

async function callHttpAdapter(taskId, processId, memberId, member, task, adapterConfig, prompt) {
  const url = adapterConfig.url;
  if (!url) {
    const now = localNow();
    db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
      .run(now, 'HTTP adapter: no URL configured', processId);
    return;
  }

  const method = (adapterConfig.method || 'POST').toUpperCase();
  const headers = adapterConfig.headers || { 'Content-Type': 'application/json' };

  try {
    const body = JSON.stringify({
      prompt,
      task_id: taskId,
      member_id: memberId,
      member_name: member.name,
      task_title: task.title,
      ...(adapterConfig.extra_body || {})
    });

    const parsedUrl = new URL(url);
    const httpModule = parsedUrl.protocol === 'https:' ? https : http;

    const result = await new Promise((resolve, reject) => {
      const req = httpModule.request(url, {
        method,
        headers: { ...headers, 'Content-Length': Buffer.byteLength(body) },
        timeout: adapterConfig.timeout_ms || 120000
      }, (res) => {
        let data = '';
        res.on('data', chunk => { data += chunk; });
        res.on('end', () => resolve({ status: res.statusCode, body: data }));
      });
      req.on('error', reject);
      req.on('timeout', () => { req.destroy(); reject(new Error('HTTP request timeout')); });
      req.write(body);
      req.end();
    });

    const finishedAt = localNow();
    if (result.status >= 200 && result.status < 300) {
      handleSpawnSuccess(taskId, processId, member, task, 'http', result.body, finishedAt);
    } else {
      db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
        .run(finishedAt, `HTTP ${result.status}: ${result.body.slice(0, 500)}`, processId);
      broadcast('process.failed', { process_id: processId, task_id: taskId, error: `HTTP ${result.status}` });
    }
  } catch (err) {
    const failedAt = localNow();
    db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
      .run(failedAt, `HTTP adapter error: ${err.message}`, processId);
    broadcast('process.failed', { process_id: processId, task_id: taskId, error: err.message });
  }
}

async function connectOpenClawAdapter(taskId, processId, memberId, member, task, adapterConfig, prompt) {
  const gatewayUrl = adapterConfig.gateway_url;
  const agentId = adapterConfig.agent_id;
  const apiKey = adapterConfig.api_key || '';

  if (!gatewayUrl) {
    const now = localNow();
    db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
      .run(now, 'OpenClaw adapter: no gateway_url configured', processId);
    return;
  }

  try {
    const body = JSON.stringify({
      agent_id: agentId,
      prompt,
      task_id: taskId,
      member_name: member.name,
      task_title: task.title
    });

    const parsedUrl = new URL(gatewayUrl);
    const httpModule = parsedUrl.protocol === 'https:' ? https : http;

    const result = await new Promise((resolve, reject) => {
      const req = httpModule.request(gatewayUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': apiKey ? `Bearer ${apiKey}` : '',
          'Content-Length': Buffer.byteLength(body)
        },
        timeout: adapterConfig.timeout_ms || 300000
      }, (res) => {
        let data = '';
        res.on('data', chunk => { data += chunk; });
        res.on('end', () => resolve({ status: res.statusCode, body: data }));
      });
      req.on('error', reject);
      req.on('timeout', () => { req.destroy(); reject(new Error('OpenClaw request timeout')); });
      req.write(body);
      req.end();
    });

    const finishedAt = localNow();
    if (result.status >= 200 && result.status < 300) {
      handleSpawnSuccess(taskId, processId, member, task, 'openclaw', result.body, finishedAt);
    } else {
      db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
        .run(finishedAt, `OpenClaw ${result.status}: ${result.body.slice(0, 500)}`, processId);
      broadcast('process.failed', { process_id: processId, task_id: taskId, error: `OpenClaw ${result.status}` });
    }
  } catch (err) {
    const failedAt = localNow();
    db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
      .run(failedAt, `OpenClaw adapter error: ${err.message}`, processId);
    broadcast('process.failed', { process_id: processId, task_id: taskId, error: err.message });
  }
}

// ──────────────────────────────────────────────────────────────────────────────
// MEGA-PROMPT DIGESTION SYSTEM
// Breaks large files into chunks, distributes to digesters, collects memories,
// and produces a curated brief for the board/leadership.
// ──────────────────────────────────────────────────────────────────────────────

/**
 * Split a markdown file into logical chunks by top-level headers.
 * Each chunk includes context about what came before/after.
 * Returns array of { index, total, title, content, contextBefore, contextAfter }
 */
function chunkMarkdownFile(filePath, maxChunkSize = 40000) {
  const content = fs.readFileSync(filePath, 'utf-8');
  const lines = content.split('\n');

  // Find section boundaries (# or ## headers)
  const sections = [];
  let currentSection = { title: 'Preamble', startLine: 0, lines: [] };

  for (let i = 0; i < lines.length; i++) {
    const headerMatch = lines[i].match(/^(#{1,2})\s+(.+)/);
    if (headerMatch && currentSection.lines.length > 0) {
      sections.push(currentSection);
      currentSection = { title: headerMatch[2].trim(), startLine: i, lines: [] };
    }
    currentSection.lines.push(lines[i]);
  }
  if (currentSection.lines.length > 0) sections.push(currentSection);

  // Merge small sections together so we don't create too many tiny chunks
  const merged = [];
  let buffer = null;
  for (const section of sections) {
    const sectionText = section.lines.join('\n');
    if (!buffer) {
      buffer = { title: section.title, content: sectionText, titles: [section.title] };
    } else if ((buffer.content.length + sectionText.length) < maxChunkSize) {
      buffer.content += '\n' + sectionText;
      buffer.titles.push(section.title);
    } else {
      merged.push(buffer);
      buffer = { title: section.title, content: sectionText, titles: [section.title] };
    }
  }
  if (buffer) merged.push(buffer);

  // If a single merged chunk is still too big, split it by character count
  const finalChunks = [];
  for (const chunk of merged) {
    if (chunk.content.length <= maxChunkSize) {
      finalChunks.push(chunk);
    } else {
      // Split by sub-sections (### headers) or by size
      const subLines = chunk.content.split('\n');
      let subChunk = '';
      let subIdx = 0;
      for (const line of subLines) {
        if (subChunk.length + line.length > maxChunkSize && subChunk.length > 5000) {
          finalChunks.push({ title: `${chunk.title} (Part ${subIdx + 1})`, content: subChunk, titles: [chunk.title] });
          subChunk = '';
          subIdx++;
        }
        subChunk += line + '\n';
      }
      if (subChunk.trim()) {
        finalChunks.push({ title: `${chunk.title} (Part ${subIdx + 1})`, content: subChunk, titles: [chunk.title] });
      }
    }
  }

  // Build context-aware chunks
  const total = finalChunks.length;
  return finalChunks.map((chunk, i) => ({
    index: i + 1,
    total,
    title: chunk.title,
    sections: chunk.titles,
    content: chunk.content,
    contextBefore: i > 0 ? `Previous chunk (${i}/${total}): "${finalChunks[i - 1].title}" — covers ${finalChunks[i - 1].titles.join(', ')}` : 'This is the first chunk.',
    contextAfter: i < total - 1 ? `Next chunk (${i + 2}/${total}): "${finalChunks[i + 1].title}" — covers ${finalChunks[i + 1].titles.join(', ')}` : 'This is the last chunk.'
  }));
}

/**
 * Mega-Prompt Digestion Pipeline
 * Breaks large files into chunks, spawns digesters in parallel, collects memories and summaries,
 * then feeds a curated brief to the Council/leadership.
 *
 * @param {Object} opts - { filePath, taskId, companyId, companyName, cliPath, taskPriority, msgText, reqFiles }
 * @returns {string} Aggregated brief for Council consumption
 */
async function digestMegaPrompt(opts) {
  const { filePath, taskId, companyId, companyName, cliPath, taskPriority, msgText, reqFiles } = opts;
  const { spawn } = require('child_process');
  const now = localNow();

  // 1. Determine company size — full board vs lean team
  const companyMembers = db.prepare(`
    SELECT tm.id, tm.name, tm.role, tm.tier, tm.department
    FROM team_members tm
    JOIN company_members cm ON tm.id = cm.member_id
    WHERE cm.company_id = ? AND tm.status = 'active'
    ORDER BY CASE tm.tier WHEN 'board' THEN 0 WHEN 'executive' THEN 1 WHEN 'c-suite' THEN 1 ELSE 2 END, tm.name
  `).all(companyId);

  const boardMembers = companyMembers.filter(m => m.tier === 'board' || m.tier === 'executive' || m.tier === 'c-suite');
  const isLargeCompany = boardMembers.length >= 5;

  // 2. Chunk the file
  const chunks = chunkMarkdownFile(filePath);
  const totalChunks = chunks.length;

  console.log(`[Digestion] Task #${taskId}: ${totalChunks} chunks from ${path.basename(filePath)} (${Math.ceil(fs.statSync(filePath).size / 1024)}KB). Company: ${companyName} (${isLargeCompany ? 'large' : 'small'} team, ${companyMembers.length} members)`);

  // Post status to Board Room
  db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
    VALUES (?, 'System', 'System', ?, 'system', ?, ?)`)
    .run(companyId, `Mega-prompt detected (${Math.ceil(fs.statSync(filePath).size / 1024)}KB). Breaking into ${totalChunks} digestible chunks. ${isLargeCompany ? 'Board members will each process sections.' : 'Spawning digestion squad.'}`, taskId, now);
  broadcast('boardroom.message', { company_id: companyId, message_type: 'system', task_id: taskId });

  // 3. Save each chunk as a numbered file
  const chunkDir = path.join(__dirname, '..', '.claude', 'digestion', `task-${taskId}`);
  try { fs.mkdirSync(chunkDir, { recursive: true }); } catch (_) {}

  for (const chunk of chunks) {
    const chunkFile = path.join(chunkDir, `chunk-${String(chunk.index).padStart(2, '0')}-of-${totalChunks}.md`);
    const chunkContent = `# Chunk ${chunk.index} of ${totalChunks}: ${chunk.title}
## Context
- ${chunk.contextBefore}
- ${chunk.contextAfter}
- **Project:** ${companyName}
- **Source:** ${path.basename(filePath)}
- **Chairman's Message:** ${msgText.slice(0, 500)}

## Content
${chunk.content}`;
    fs.writeFileSync(chunkFile, chunkContent, 'utf-8');
  }

  // 4. Classify each chunk by domain so the RIGHT expert digests it
  const domainKeywords = {
    engineering: ['api', 'endpoint', 'database', 'schema', 'migration', 'server', 'backend', 'middleware', 'route', 'query', 'sql', 'orm', 'crud', 'rest', 'graphql', 'websocket', 'authentication', 'auth', 'token', 'session', 'docker', 'deploy', 'ci/cd', 'pipeline', 'redis', 'celery', 'fastapi', 'express', 'node', 'python', 'typescript', 'javascript', 'async', 'worker', 'queue', 'cache', 'index', 'table', 'column', 'foreign key', 'constraint', 'service', 'microservice', 'monolith', 'repository', 'git', 'branch', 'merge', 'test', 'unit test', 'integration test', 'fixture', 'mock', 'assert', 'coverage', 'lint', 'format', 'build', 'compile', 'bundle', 'webpack', 'vite', 'makefile', 'dockerfile', 'env var', 'config', 'ffmpeg', 'codec', 'transcode', 'encode'],
    frontend: ['ui', 'ux', 'component', 'layout', 'responsive', 'css', 'html', 'dom', 'render', 'animation', 'transition', 'modal', 'form', 'input', 'button', 'navigation', 'sidebar', 'dashboard', 'page', 'view', 'screen', 'design system', 'accessibility', 'a11y', 'figma', 'wireframe', 'prototype', 'user interface', 'frontend', 'client-side', 'spa', 'react', 'vue', 'angular', 'canvas', 'svg', 'icon', 'theme', 'dark mode', 'color', 'font', 'typography', 'grid', 'flexbox', 'mobile', 'tablet', 'desktop', 'breakpoint'],
    product: ['roadmap', 'phase', 'milestone', 'feature', 'requirement', 'specification', 'user story', 'acceptance criteria', 'mvp', 'scope', 'priority', 'backlog', 'sprint', 'iteration', 'release', 'version', 'changelog', 'product', 'strategy', 'vision', 'mission', 'objective', 'okr', 'kpi', 'metric', 'workflow', 'process', 'lifecycle', 'stakeholder', 'persona', 'use case', 'scenario', 'evolution', 'maturity', 'stage'],
    data: ['analytics', 'data', 'machine learning', 'ml', 'ai', 'model', 'training', 'inference', 'nlp', 'embedding', 'vector', 'classification', 'clustering', 'recommendation', 'scoring', 'prediction', 'algorithm', 'neural', 'transformer', 'bert', 'gpt', 'llm', 'prompt', 'context window', 'token', 'transcription', 'transcript', 'whisper', 'semantic', 'sentiment', 'topic', 'extraction', 'entity', 'pipeline', 'etl', 'dataset', 'annotation', 'label', 'evaluation', 'accuracy', 'precision', 'recall', 'f1'],
    business: ['revenue', 'pricing', 'subscription', 'billing', 'payment', 'invoice', 'cost', 'budget', 'forecast', 'margin', 'profit', 'loss', 'market', 'competitor', 'customer', 'user', 'acquisition', 'retention', 'churn', 'growth', 'conversion', 'funnel', 'segment', 'target', 'positioning', 'differentiat', 'value prop', 'business model', 'saas', 'arr', 'mrr', 'ltv', 'cac', 'partnership', 'sales', 'enterprise', 'b2b', 'b2c', 'agency', 'creator', 'founder', 'solopreneur', 'valuation', 'funding', 'investor'],
    marketing: ['brand', 'content', 'social', 'seo', 'campaign', 'publish', 'schedule', 'post', 'tweet', 'thread', 'carousel', 'blog', 'newsletter', 'email', 'linkedin', 'twitter', 'instagram', 'tiktok', 'youtube', 'facebook', 'platform', 'channel', 'audience', 'engagement', 'impression', 'click', 'reach', 'follower', 'subscriber', 'content calendar', 'editorial', 'copywriting', 'headline', 'caption', 'hashtag', 'thumbnail', 'metadata', 'oauth', 'distribution'],
    security: ['security', 'vulnerability', 'exploit', 'injection', 'xss', 'csrf', 'encryption', 'hash', 'certificate', 'ssl', 'tls', 'firewall', 'audit', 'compliance', 'gdpr', 'privacy', 'permission', 'role', 'access control', 'rbac', 'sanitiz', 'escap', 'rate limit', 'ddos', 'penetration', 'threat', 'risk', 'safety', 'moderation', 'content filter', 'guardrail', 'integrity', 'provenance'],
    legal: ['license', 'copyright', 'trademark', 'patent', 'ip', 'intellectual property', 'terms of service', 'privacy policy', 'compliance', 'regulation', 'legal', 'contract', 'agreement', 'liability', 'indemnif', 'warranty', 'disclaimer'],
    operations: ['deploy', 'monitor', 'logging', 'alert', 'incident', 'uptime', 'sla', 'disaster recovery', 'backup', 'restore', 'scaling', 'load balancing', 'cdn', 'infrastructure', 'cloud', 'aws', 'gcp', 'azure', 'kubernetes', 'container', 'orchestrat', 'health check', 'heartbeat', 'retry', 'circuit breaker', 'queue', 'worker', 'cron', 'scheduler']
  };

  // Map domains to department patterns for member matching
  const domainToDepartment = {
    engineering: ['Engineering', 'Technology', 'Backend', 'Platform', 'DevOps', 'QA', 'CTO'],
    frontend: ['Engineering', 'Design', 'UI', 'UX', 'Frontend'],
    product: ['Product', 'Strategy', 'CPO'],
    data: ['Data', 'AI', 'Analytics', 'ML', 'CAIO'],
    business: ['Finance', 'Revenue', 'Sales', 'CFO', 'CRO', 'CEO'],
    marketing: ['Marketing', 'Content', 'CMO', 'Growth'],
    security: ['Security', 'Compliance'],
    legal: ['Legal', 'Compliance', 'CLO'],
    operations: ['Operations', 'DevOps', 'SRE', 'COO', 'Infrastructure']
  };

  // Classify each chunk
  function classifyChunk(chunk) {
    const text = (chunk.title + ' ' + chunk.content).toLowerCase();
    const scores = {};
    for (const [domain, keywords] of Object.entries(domainKeywords)) {
      scores[domain] = 0;
      for (const kw of keywords) {
        // Count occurrences (case-insensitive)
        const regex = new RegExp(kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
        const matches = text.match(regex);
        if (matches) scores[domain] += matches.length;
      }
    }
    // Sort by score descending, return top 2 domains
    const sorted = Object.entries(scores).sort((a, b) => b[1] - a[1]);
    return {
      primary: sorted[0][1] > 0 ? sorted[0][0] : 'engineering',
      secondary: sorted[1][1] > 0 ? sorted[1][0] : null,
      scores
    };
  }

  const chunkClassifications = chunks.map(c => ({ chunk: c, classification: classifyChunk(c) }));

  console.log(`[Digestion] Chunk classifications: ${chunkClassifications.map(cc => `${cc.chunk.index}:${cc.classification.primary}`).join(', ')}`);

  // 5. Match chunks to the RIGHT team members based on domain
  // For large companies: use company members matched by department
  // For small companies: pull in Command Base specialists from relevant domains

  // Build a pool of available digesters
  let memberPool;
  if (isLargeCompany) {
    memberPool = companyMembers; // all company members available
  } else {
    // Start with company members, supplement with Command Base specialists
    const cbSpecialists = db.prepare(`
      SELECT tm.id, tm.name, tm.role, tm.tier, tm.department
      FROM team_members tm
      WHERE tm.status = 'active' AND tm.tier = 'specialist'
      ORDER BY tm.name
    `).all();
    memberPool = [...companyMembers, ...cbSpecialists.filter(s => !companyMembers.find(c => c.id === s.id))];
  }

  // Find the best member for a domain
  function findMemberForDomain(domain, usedMemberIds) {
    const deptPatterns = domainToDepartment[domain] || ['Engineering'];
    // Try to find an unused member whose department/role matches
    for (const pattern of deptPatterns) {
      const match = memberPool.find(m =>
        !usedMemberIds.has(m.id) &&
        ((m.department && m.department.toLowerCase().includes(pattern.toLowerCase())) ||
         (m.role && m.role.toLowerCase().includes(pattern.toLowerCase())))
      );
      if (match) return match;
    }
    // If no unused match, allow reuse of the best match
    for (const pattern of deptPatterns) {
      const match = memberPool.find(m =>
        (m.department && m.department.toLowerCase().includes(pattern.toLowerCase())) ||
        (m.role && m.role.toLowerCase().includes(pattern.toLowerCase()))
      );
      if (match) return match;
    }
    // Last resort: any unused member, or first available
    return memberPool.find(m => !usedMemberIds.has(m.id)) || memberPool[0];
  }

  // Assign chunks to members based on classification
  // CAP: max 5 chunks per digester — more than that and they run out of turns
  // reading files before they can produce formatted memory output
  const digesterMap = new Map(); // memberId -> { member, chunkIndices[] }
  const usedMemberIds = new Set();
  const MAX_CHUNKS_PER_DIGESTER = 3;  // 3 chunks × ~40KB = ~120KB inline prompt — fits Sonnet context
  const maxDigesters = Math.min(15, memberPool.length); // more digesters since fewer chunks each

  for (const { chunk, classification } of chunkClassifications) {
    // Find a member for this domain who hasn't hit the chunk cap
    let member = null;
    const triedIds = new Set();

    while (!member) {
      const candidate = findMemberForDomain(classification.primary, triedIds);
      if (!candidate || triedIds.has(candidate.id)) {
        // No more candidates — find any member under the cap
        member = memberPool.find(m => {
          const existing = digesterMap.get(m.id);
          return !existing || existing.chunkIndices.length < MAX_CHUNKS_PER_DIGESTER;
        }) || memberPool[0]; // absolute last resort
        break;
      }

      const existing = digesterMap.get(candidate.id);
      if (!existing || existing.chunkIndices.length < MAX_CHUNKS_PER_DIGESTER) {
        member = candidate; // under the cap, use them
      } else {
        triedIds.add(candidate.id); // over cap, try another
      }
    }

    if (!digesterMap.has(member.id)) {
      digesterMap.set(member.id, {
        memberId: member.id,
        memberName: member.name,
        memberRole: member.role,
        memberDepartment: member.department || '',
        chunkIndices: [],
        domains: new Set()
      });
      usedMemberIds.add(member.id);
    }
    digesterMap.get(member.id).chunkIndices.push(chunks.indexOf(chunk));
    digesterMap.get(member.id).domains.add(classification.primary);
  }

  const digesters = Array.from(digesterMap.values());

  // Post assignment summary to Board Room
  const assignmentSummary = digesters.map(d =>
    `${d.memberName} (${d.memberRole}): chunks ${d.chunkIndices.map(i => chunks[i].index).join(', ')} [${Array.from(d.domains).join(', ')}]`
  ).join('\n');
  db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
    VALUES (?, 'System', 'System', ?, 'system', ?, ?)`)
    .run(companyId, `Chunks assigned by domain expertise:\n${assignmentSummary}`, taskId, localNow());
  broadcast('boardroom.message', { company_id: companyId, message_type: 'system', task_id: taskId });

  console.log(`[Digestion] Assignments:\n${assignmentSummary}`);

  // 5. Spawn digester agents in parallel — chunk content INLINED into prompt (no file reading)
  const digestionPromises = digesters.map(digester => {
    return new Promise((resolve) => {
      const assignedChunks = digester.chunkIndices.map(i => chunks[i]);
      const chunkFiles = assignedChunks.map(c =>
        path.join(chunkDir, `chunk-${String(c.index).padStart(2, '0')}-of-${totalChunks}.md`)
      );

      // Read chunk content and inline it directly — no tool calls needed
      const inlinedChunks = assignedChunks.map(c => {
        const filePath = path.join(chunkDir, `chunk-${String(c.index).padStart(2, '0')}-of-${totalChunks}.md`);
        try { return `\n--- CHUNK ${c.index}/${totalChunks}: ${c.title} ---\n${fs.readFileSync(filePath, 'utf-8')}\n--- END CHUNK ${c.index} ---\n`; }
        catch (_) { return `\n--- CHUNK ${c.index}: (read error) ---\n`; }
      }).join('\n');

      const chunkDomains = Array.from(digester.domains).join(', ');
      const digesterPrompt = `You are ${digester.memberName} (${digester.memberRole}${digester.memberDepartment ? ', ' + digester.memberDepartment + ' department' : ''}). A large document for project "${companyName}" has been split into ${totalChunks} chunks. You have ${assignedChunks.length} chunks in YOUR area of expertise: ${chunkDomains}.

ALL chunk content is BELOW — do NOT use any tools or read any files. Just analyze and respond.

YOUR JOB: Produce TWO things from the content below:

## 1. STRUCTURED SUMMARY
For each chunk, write a detailed summary preserving ALL important information — especially:
- Architecture decisions, data models, API contracts, technical specs
- Non-negotiable rules, constraints, thresholds
- Dependencies on other sections
- Important numbers, metrics, component names

## 2. KEY MEMORIES
Extract the most important insights. Format EACH as:

MEMORY: [title]
TYPE: [requirement/architecture/constraint/workflow/decision]
IMPORTANCE: [critical/high/normal]
CONTENT: [Precise knowledge — numbers, names, technical details. Brief a colleague who will implement this.]

Produce at least 3 memories per chunk. Be specific, not generic.

====== CHUNK CONTENT ======
${inlinedChunks}
====== END CHUNKS ======

Now produce your STRUCTURED SUMMARY and KEY MEMORIES. Do NOT use any tools.`;

      // No tools needed — content is inline. 1 turn is enough for response.
      const digesterArgs = ['--print', '--model', 'sonnet', '--max-turns', '1',
        '--dangerously-skip-permissions', '--output-format', 'text', '--tools', ''];

      const child = spawn(cliPath, digesterArgs, {
        env: { ...process.env, DISABLE_AUTOUPDATER: '1' },
        stdio: ['pipe', 'pipe', 'pipe'],
        cwd: path.join(process.env.PROJECT_ROOT || path.join(__dirname, '..'), 'app')
      });

      let output = '';
      child.stdout.on('data', d => { output += d.toString(); });
      child.stderr.on('data', () => {});
      try { child.stdin.write(digesterPrompt); child.stdin.end(); } catch (_) {}

      // Post progress update
      db.prepare(`INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, task_id, created_at)
        VALUES (?, ?, ?, ?, ?, 'response', ?, ?)`)
        .run(companyId, digester.memberId, digester.memberName, digester.memberRole,
          `Digesting chunks ${assignedChunks.map(c => c.index).join(', ')} of ${totalChunks}...`, taskId, localNow());
      broadcast('boardroom.message', { company_id: companyId, message_type: 'response', task_id: taskId });

      const timeout = setTimeout(() => {
        try { child.kill('SIGTERM'); } catch (_) {}
        resolve({ digester: digester.memberName, digesterId: digester.memberId, chunks: assignedChunks.map(c => c.index), output: output || '(timed out)', memories: [] });
      }, 180000); // 3 min per digester (no tool calls, should finish in <90s)

      child.on('close', () => {
        clearTimeout(timeout);

        // Extract memories from output — multi-strategy extraction
        const memories = [];

        // Strategy 1: Strict MEMORY:/TYPE:/IMPORTANCE:/CONTENT: format
        const memoryBlocks = output.split(/MEMORY:\s*/i).slice(1);
        for (const block of memoryBlocks) {
          const titleMatch = block.match(/^(.+?)(?:\n|$)/);
          const typeMatch = block.match(/TYPE:\s*(.+?)(?:\n|$)/i);
          const importanceMatch = block.match(/IMPORTANCE:\s*(.+?)(?:\n|$)/i);
          const contentMatch = block.match(/CONTENT:\s*([\s\S]+?)(?=\nMEMORY:|\n---|\n##|$)/i);

          if (titleMatch && contentMatch) {
            memories.push({
              title: titleMatch[1].trim(),
              type: typeMatch ? typeMatch[1].trim().toLowerCase() : 'insight',
              importance: importanceMatch ? importanceMatch[1].trim().toLowerCase() : 'normal',
              content: contentMatch[1].trim()
            });
          }
        }

        // Strategy 2: If strict format found < 2 memories, extract from bold headers and bullet points
        // Models often produce "**Key Finding**: description" or "- **Important**: detail" instead
        if (memories.length < 2 && output.length > 500) {
          // Look for bold-title patterns: **Title**: content or **Title** — content
          const boldPatterns = output.matchAll(/\*\*([^*]{5,80})\*\*[:\s—\-]+([^\n]{20,500})/g);
          for (const match of boldPatterns) {
            const title = match[1].trim();
            const content = match[2].trim();
            // Skip generic headers like "Structured Summary" or "Key Memories"
            if (/summary|chunk|section|context|note|important/i.test(title) && content.length < 50) continue;
            // Classify importance by keywords
            const isImportant = /must|critical|required|never|always|non-negotiable|mandatory|hard gate|threshold/i.test(content);
            if (!memories.find(m => m.title === title)) {
              memories.push({
                title: title.slice(0, 200),
                type: 'insight',
                importance: isImportant ? 'high' : 'normal',
                content: content.slice(0, 2000)
              });
            }
          }

          // Look for numbered items: 1. **Title**: content
          const numberedPatterns = output.matchAll(/\d+\.\s+\*\*([^*]{5,80})\*\*[:\s—\-]+([^\n]{20,500})/g);
          for (const match of numberedPatterns) {
            const title = match[1].trim();
            const content = match[2].trim();
            const isImportant = /must|critical|required|never|always|non-negotiable|mandatory/i.test(content);
            if (!memories.find(m => m.title === title)) {
              memories.push({
                title: title.slice(0, 200),
                type: 'insight',
                importance: isImportant ? 'high' : 'normal',
                content: content.slice(0, 2000)
              });
            }
          }
        }

        // Cap at 15 memories per digester to avoid noise
        const finalMemories = memories.slice(0, 15);

        // Save memories to agent_memory_entities for this digester
        for (const mem of finalMemories) {
          try {
            db.prepare(`INSERT INTO agent_memory_entities (member_id, entity_type, title, content, importance, source_task_id, created_at, updated_at)
              VALUES (?, 'insight', ?, ?, ?, ?, ?, ?)`)
              .run(digester.memberId, mem.title.slice(0, 200), mem.content.slice(0, 2000), mem.importance, taskId, localNow(), localNow());
          } catch (_) {}
        }

        // Post completion update
        try {
          db.prepare(`INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, task_id, created_at)
            VALUES (?, ?, ?, ?, ?, 'response', ?, ?)`)
            .run(companyId, digester.memberId, digester.memberName, digester.memberRole,
              `Finished digesting chunks ${assignedChunks.map(c => c.index).join(', ')}. Extracted ${finalMemories.length} key memories.`, taskId, localNow());
          broadcast('boardroom.message', { company_id: companyId, message_type: 'response', task_id: taskId });
        } catch (_) {}

        resolve({
          digester: digester.memberName,
          digesterId: digester.memberId,
          chunks: assignedChunks.map(c => c.index),
          output: output || '',
          memories: finalMemories
        });
      });
    });
  });

  // 6. Wait for all digesters to complete
  const results = await Promise.all(digestionPromises);

  // 7. Aggregate — build the master brief from all digester outputs + memories
  const allMemories = results.flatMap(r => r.memories);
  const allSummaries = results.map(r => {
    const chunkTitles = r.chunks.map(i => chunks[i - 1]?.title || `Chunk ${i}`).join(', ');
    return `### ${r.digester} — Chunks ${r.chunks.join(', ')} (${chunkTitles})\n${r.output.slice(0, 6000)}`;
  });

  // Group memories by importance
  const criticalMemories = allMemories.filter(m => m.importance === 'critical');
  const highMemories = allMemories.filter(m => m.importance === 'high');
  const normalMemories = allMemories.filter(m => m.importance === 'normal');

  // Propagate critical/high memories up the chain as team_insight for executives
  for (const mem of [...criticalMemories, ...highMemories]) {
    try {
      // Find an executive in this company to receive the insight
      const exec = db.prepare(`
        SELECT tm.id FROM team_members tm
        JOIN company_members cm ON tm.id = cm.member_id
        WHERE cm.company_id = ? AND tm.tier IN ('c-suite','executive') AND tm.status = 'active'
        LIMIT 1
      `).get(companyId);
      if (exec) {
        db.prepare(`INSERT INTO agent_memory_entities (member_id, entity_type, title, content, importance, source_task_id, created_at, updated_at)
          VALUES (?, 'team_insight', ?, ?, ?, ?, ?, ?)`)
          .run(exec.id, `[Digestion] ${mem.title}`.slice(0, 200), mem.content.slice(0, 2000), mem.importance, taskId, localNow(), localNow());
      }
    } catch (_) {}
  }

  // 8. Build the curated brief
  const masterBrief = `# MEGA-PROMPT DIGESTION COMPLETE
## Source: ${path.basename(filePath)} (${Math.ceil(fs.statSync(filePath).size / 1024)}KB)
## Chunks: ${totalChunks} | Digesters: ${results.length} | Memories extracted: ${allMemories.length}
## Chairman's message: ${msgText.slice(0, 500)}

---

## CRITICAL KNOWLEDGE (${criticalMemories.length} items)
${criticalMemories.map(m => `- **${m.title}**: ${m.content}`).join('\n') || '(none)'}

## HIGH-PRIORITY KNOWLEDGE (${highMemories.length} items)
${highMemories.map(m => `- **${m.title}**: ${m.content}`).join('\n') || '(none)'}

## KEY KNOWLEDGE (${normalMemories.length} items)
${normalMemories.map(m => `- **${m.title}**: ${m.content}`).join('\n') || '(none)'}

---

## SECTION SUMMARIES

${allSummaries.join('\n\n---\n\n')}

---

## CHUNK FILES (for detailed reference)
${chunks.map(c => `- Chunk ${c.index}/${totalChunks}: ${c.title} — ${path.join(chunkDir, `chunk-${String(c.index).padStart(2, '0')}-of-${totalChunks}.md`)}`).join('\n')}

## FULL SOURCE FILE
${filePath}`;

  // Save the master brief
  const briefPath = path.join(chunkDir, 'master-brief.md');
  fs.writeFileSync(briefPath, masterBrief, 'utf-8');

  // Post final status
  db.prepare(`INSERT INTO board_chats (company_id, sender_name, sender_role, message, message_type, task_id, created_at)
    VALUES (?, 'System', 'System', ?, 'system', ?, ?)`)
    .run(companyId, `Digestion complete. ${totalChunks} chunks processed by ${results.length} digesters. ${allMemories.length} key memories extracted (${criticalMemories.length} critical, ${highMemories.length} high). Master brief ready for Council.`, taskId, localNow());
  broadcast('boardroom.message', { company_id: companyId, message_type: 'system', task_id: taskId });

  console.log(`[Digestion] Task #${taskId}: Complete. ${allMemories.length} memories, ${totalChunks} chunks. Brief at ${briefPath}`);

  return { masterBrief, briefPath, allMemories, chunks, results };
}

/**
 * Spawn a Claude Code CLI session for a specific team member working on a task.
 * Each member gets their own parallel process with full context.
 */
async function spawnMemberTerminal(taskId, memberId) {
  if (isLocalMode()) {
    return { success: false, reason: 'local_mode' };
  }

  const now = localNow();

  // Token audit v4: Use cached settings instead of raw DB query.
  // auto_spawn_enabled is checked on every spawn — cache avoids repeated DB hits.
  const autoSpawnEnabled = getCachedSetting('auto_spawn_enabled');
  if (autoSpawnEnabled !== '1') {
    return { success: false, reason: 'auto_spawn_disabled' };
  }

  // Phase 4: Budget enforcement check before spawning
  try {
    const budgetCheck = checkBudget(memberId, 50); // estimate 50 cents per run
    if (!budgetCheck.allowed) {
      db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
        .run(`Budget limit: ${budgetCheck.reason}`, now, taskId);
      return { success: false, reason: 'budget_exceeded' };
    }
  } catch (budgetErr) {
  }

  // Check if this member already has a running process for this task
  const existing = db.prepare(`SELECT * FROM active_processes WHERE task_id = ? AND member_id = ? AND status = 'running'`).get(taskId, memberId);
  if (existing) {
    return { success: false, reason: 'already_running', process_id: existing.id };
  }

  // Load member profile
  const member = db.prepare(`SELECT * FROM team_members WHERE id = ?`).get(memberId);
  if (!member) {
    return { success: false, reason: 'member_not_found' };
  }

  // Load task details
  const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(taskId);
  if (!task) {
    return { success: false, reason: 'task_not_found' };
  }

  // Load member tools
  const tools = db.prepare(`SELECT * FROM member_tools WHERE member_id = ? AND enabled = 1`).all(memberId);

  // Load member's assigned skills (Phase 3)
  const memberSkills = db.prepare(`
    SELECT s.* FROM skills s
    JOIN agent_skills ON s.id = agent_skills.skill_id
    WHERE agent_skills.member_id = ? AND s.status = 'active'
    ORDER BY agent_skills.priority DESC
  `).all(memberId);

  // Get adapter type and config (Phase 3)
  const adapterType = member.adapter_type || 'claude_local';
  let adapterConfig = {};
  try { adapterConfig = JSON.parse(member.adapter_config || '{}'); } catch {}

  // Load member profile from file (fallback when identity files missing)
  // FIX: Increased from 1500 to 4000 chars. At 1500, profiles were truncated at the Persona
  // section, losing all competencies, methodology, purview, and restrictions. Members were
  // operating without knowing their own boundaries. 4000 chars covers Identity + Persona +
  // Core Competencies + Methodology which is the essential context.
  let profileContent = '';
  const profilePath = path.join(__dirname, '..', 'Team', `${member.name.toLowerCase()}.md`);
  try {
    if (fs.existsSync(profilePath)) {
      const raw = fs.readFileSync(profilePath, 'utf-8');
      profileContent = raw.length > 4000 ? raw.slice(0, 4000) + '\n...(truncated)' : raw;
    }
  } catch (e) {
  }

  // Load task files for context
  const taskFiles = db.prepare(`SELECT * FROM task_files WHERE task_id = ? AND direction = 'input'`).all(taskId);

  // Token audit: Only load linked repos/paths when the task is associated with a project.
  // Most tasks (peer reviews, QA, simple fixes) don't need the full repo/path listing —
  // skipping saves ~100-300 tokens per prompt on tasks without project context.
  let linkedRepos = [];
  let linkedPaths = [];

  // Load task assignments (sibling members working in parallel)
  const assignments = db.prepare(`
    SELECT ta.*, tm.name as member_name, tm.role as member_role
    FROM task_assignments ta
    JOIN team_members tm ON ta.member_id = tm.id
    WHERE ta.task_id = ?
  `).all(taskId);

  // Load project context if linked
  const project = db.prepare(`
    SELECT p.* FROM projects p
    JOIN project_tasks pt ON pt.project_id = p.id
    WHERE pt.task_id = ?
  `).get(taskId);

  // Build the comprehensive prompt
  let prompt = '';

  // Member identity
  prompt += `You are ${member.name}, ${member.role}.\n\n`;

  // Token audit v3: 3-tier prompt system — minimal/standard/full.
  // Minimal (peer review, QA, retries): persona + task only. Saves ~3000-5000 tokens.
  // Standard (most tasks): SOUL.md + 5 memories + task. Saves ~1000-2000 tokens vs full.
  // Full (urgent+complex, first attempt only): everything — identity files, 10 memories, tacit, daily notes, context store.
  const isMinimalTask = task.source_file === 'peer_review'
    || task.source_file === 'qa_verification'
    || (task.title && (task.title.startsWith('Peer Review:') || task.title.startsWith('QA Verify:')));
  // MAX'S DIRECTIVE: Retries use minimal tier — member already has context from first attempt.
  // Don't reload memories, tacit knowledge, context store on retries. Just persona + task + feedback.
  const isRetry = (task.revision_count || 0) > 0;
  const isFullTask = !isRetry && task.priority === 'urgent' && (task.description || '').length > 800;
  const promptTier = (isMinimalTask || isRetry) ? 'minimal' : (isFullTask ? 'full' : 'standard');

  if (promptTier === 'full') {
    // Full tier: Load ALL identity files + memory + tacit + daily + context
    const identityFiles = db.prepare('SELECT * FROM agent_identity_files WHERE member_id = ?').all(memberId);
    if (identityFiles.length > 0) {
      prompt += `## Your Identity Files\n`;
      for (const f of identityFiles) {
        prompt += `\n--- ${f.file_name} ---\n${f.content}\n`;
      }
      prompt += `\n`;
    } else if (profileContent) {
      prompt += `## Your Full Profile\n${profileContent}\n\n`;
    }

    // Full tier: 10 memories — the member's personal recollections and growth
    try {
      const memories = db.prepare(`
        SELECT * FROM agent_memory_entities
        WHERE member_id = ? AND (expires_at IS NULL OR expires_at > ?)
        ORDER BY CASE importance WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 WHEN 'low' THEN 3 END, updated_at DESC
        LIMIT 10
      `).all(memberId, localNow());
      if (memories.length > 0) {
        prompt += `## Your Experience & Memory\n`;
        prompt += `These are your personal recollections — lessons learned, achievements, and insights from your work:\n`;
        for (const m of memories) {
          const content = (m.content || '').length > 300 ? m.content.slice(0, 300) + '...' : m.content;
          const typeLabel = m.entity_type === 'lesson' ? 'Lesson'
            : m.entity_type === 'achievement' ? 'Achievement'
            : m.entity_type === 'insight' ? 'Insight'
            : m.entity_type === 'task_completion' ? 'Past work'
            : 'Experience';
          prompt += `- [${typeLabel}] **${m.title}**: ${content}\n`;
        }
        prompt += `\n`;
      }
    } catch (_) {}

    // Full tier: tacit knowledge
    try {
      // FIX: confidence is stored as 'high'/'medium' text, not numbers.
      // Load all tacit knowledge, prioritize by confidence level and usage.
      const tacit = db.prepare(`
        SELECT * FROM agent_tacit_knowledge
        WHERE member_id = ? AND confidence IN ('high', 'medium')
        ORDER BY CASE confidence WHEN 'high' THEN 0 WHEN 'medium' THEN 1 ELSE 2 END,
          times_applied DESC
        LIMIT 5
      `).all(memberId);
      if (tacit.length > 0) {
        prompt += `## Your Learned Patterns\n`;
        for (const t of tacit) {
          prompt += `- [${t.knowledge_type}] ${t.subject}: ${t.insight}\n`;
        }
        prompt += `\n`;
      }
    } catch (_) {}

    // Full tier: daily notes
    try {
      const todayNote = db.prepare("SELECT * FROM agent_daily_notes WHERE member_id = ? AND note_date = ?").get(memberId, localNow().split(' ')[0]);
      if (todayNote) {
        prompt += `## Today's Notes So Far\n${todayNote.content}\n\n`;
      }
    } catch (_) {}

    // Full tier: context store
    try {
      const contextText = loadContextForMember(memberId);
      if (contextText) {
        prompt += contextText + '\n';
      }
    } catch (ctxErr) {
      console.error(`[Context] Failed to load context for member #${memberId}: ${ctxErr.message}`);
    }

  } else if (promptTier === 'standard') {
    // Standard tier: SOUL.md only (skip AGENTS.md, HEARTBEAT.md) + 5 critical memories.
    // Skips tacit knowledge, daily notes, and context store — saves ~1000-2000 tokens.
    try {
      const soulFile = db.prepare("SELECT * FROM agent_identity_files WHERE member_id = ? AND file_name = 'SOUL.md'").get(memberId);
      if (soulFile) {
        prompt += `## Your Identity\n\n--- SOUL.md ---\n${soulFile.content}\n\n`;
      } else if (profileContent) {
        prompt += `## Your Profile\n${profileContent}\n\n`;
      }
    } catch (_) {}

    // Standard tier: 5 memories — personal recollections from past work
    try {
      const memories = db.prepare(`
        SELECT * FROM agent_memory_entities
        WHERE member_id = ? AND (expires_at IS NULL OR expires_at > ?)
        ORDER BY CASE importance WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 END, updated_at DESC
        LIMIT 5
      `).all(memberId, localNow());
      if (memories.length > 0) {
        prompt += `## Your Recent Experience\n`;
        prompt += `These are things you remember from your recent work:\n`;
        for (const m of memories) {
          const content = (m.content || '').length > 200 ? m.content.slice(0, 200) + '...' : m.content;
          const typeLabel = m.entity_type === 'lesson' ? 'Lesson learned'
            : m.entity_type === 'achievement' ? 'Accomplishment'
            : m.entity_type === 'insight' ? 'Insight'
            : 'Experience';
          prompt += `- [${typeLabel}] **${m.title}**: ${content}\n`;
        }
        prompt += `\n`;
      }
    } catch (_) {}

    // FIX: Also load tacit knowledge in standard tier — these are the member's
    // learned patterns from past work. Without them, members repeat mistakes.
    try {
      const tacit = db.prepare(`
        SELECT * FROM agent_tacit_knowledge
        WHERE member_id = ? AND confidence IN ('high', 'medium')
        ORDER BY CASE confidence WHEN 'high' THEN 0 WHEN 'medium' THEN 1 END,
          times_applied DESC
        LIMIT 3
      `).all(memberId);
      if (tacit.length > 0) {
        prompt += `## Learned Patterns\n`;
        for (const t of tacit) {
          prompt += `- ${t.subject}: ${t.insight}\n`;
        }
        prompt += `\n`;
      }
    } catch (_) {}
  }
  // Minimal tier: no identity files, no memory, no tacit, no daily, no context — just persona line above

  // Tools — skip for minimal tier (peer reviews, QA don't use custom tools)
  if (tools.length > 0 && promptTier !== 'minimal') {
    prompt += `## Your Tools\n`;
    for (const tool of tools) {
      let config = {};
      try { config = typeof tool.config === 'string' ? JSON.parse(tool.config) : (tool.config || {}); } catch {}
      prompt += `- **${tool.tool_name}** (${tool.tool_type})`;
      if (config.description) prompt += ` -- ${config.description}`;
      prompt += `\n`;
    }
    prompt += `\n`;
  }

  // Task details
  prompt += `## Your Task (ID: ${task.id})\n`;
  prompt += `**Title:** ${task.title}\n`;
  prompt += `**Priority:** ${task.priority}\n`;
  prompt += `**Status:** ${task.status}\n`;
  if (task.description) {
    prompt += `\n${task.description}\n`;
  }
  prompt += `\n`;

  // Project context — also conditionally load linked repos/paths only when a project exists
  if (project) {
    prompt += `## Project Context\n`;
    prompt += `**Project:** ${project.name}\n`;
    if (project.summary) prompt += `${project.summary}\n`;
    prompt += `\n`;
    // Only load repos/paths for project-linked tasks
    linkedRepos = db.prepare(`SELECT * FROM linked_repos`).all();
    linkedPaths = db.prepare(`SELECT * FROM linked_paths`).all();
  }

  // Parallel team context
  if (assignments.length > 1) {
    prompt += `## Team Working in Parallel\n`;
    prompt += `The following team members are working on this task simultaneously:\n`;
    for (const a of assignments) {
      prompt += `- **${a.member_name}** (${a.member_role})${a.member_id === memberId ? ' ← this is you' : ''}\n`;
    }
    prompt += `\nCoordinate your work to avoid conflicts. Focus on your domain.\n\n`;
  }

  // Input files
  if (taskFiles.length > 0) {
    prompt += `## Input Files\n`;
    for (const f of taskFiles) {
      prompt += `- ${f.file_name} (${f.file_type}) at: ${f.file_path}\n`;
    }
    prompt += `\n`;
  }

  // Linked repos
  if (linkedRepos.length > 0) {
    prompt += `## Available Repositories\n`;
    for (const repo of linkedRepos) {
      prompt += `- ${repo.owner}/${repo.name}: ${repo.url}${repo.description ? ' -- ' + repo.description : ''}\n`;
    }
    prompt += `\n`;
  }

  // Linked paths
  if (linkedPaths.length > 0) {
    prompt += `## Available Local Paths\n`;
    for (const p of linkedPaths) {
      prompt += `- [${p.type}] ${p.path}${p.description ? ' -- ' + p.description : ''}\n`;
    }
    prompt += `\n`;
  }

  // Working directory and file editing instructions
  // Check if this task's project has a linked repo with a local_path
  const projectRoot = process.env.PROJECT_ROOT || path.join(__dirname, '..');
  let workDir = path.join(projectRoot, 'app');
  let isExternalProject = false;

  if (project) {
    const projectRepo = db.prepare('SELECT * FROM project_repos WHERE project_id = ? AND status = ? ORDER BY id ASC LIMIT 1').get(project.id, 'active');
    if (projectRepo && projectRepo.local_path && fs.existsSync(projectRepo.local_path)) {
      workDir = projectRepo.local_path;
      isExternalProject = true;
      prompt += `## Project Repository\n`;
      prompt += `This task is for project "${project.name}". The repo is at: ${projectRepo.local_path}\n`;
      if (projectRepo.repo_owner && projectRepo.repo_name) {
        prompt += `GitHub: ${projectRepo.repo_owner}/${projectRepo.repo_name}\n`;
      }
      prompt += `Default branch: ${projectRepo.default_branch || 'main'}\n\n`;
    }
  }

  // Token audit v3: Condensed boilerplate — was ~15 lines, now ~5.
  // The key info (work dir + key files) is kept; verbose "you MUST" instructions trimmed.
  const appDir = isExternalProject ? workDir : path.join(projectRoot, 'app');
  prompt += `## Working Directory: ${workDir}\n`;
  prompt += `Make REAL code changes using Read/Edit/Write/Bash tools. Read files before editing.\n\n`;

  if (!isExternalProject) {
    prompt += `Key files: \`${appDir}/public/app.js\` (frontend JS), \`${appDir}/public/styles.css\` (CSS), \`${appDir}/server.js\` (Express backend), \`${appDir}/public/index.html\` (HTML)\n\n`;
  } else {
    prompt += `Explore \`${workDir}\` to understand structure before making changes.\n\n`;
  }

  // Token audit v3: Tier-based skill injection.
  // Full tier: complete skill content. Standard tier: skill names only. Minimal: skip entirely.
  if (memberSkills.length > 0 && promptTier !== 'minimal') {
    if (promptTier === 'full') {
      // Token audit v4: Cap each skill at 2000 chars — some skills are 5-10KB
      prompt += `## Your Skills\n`;
      for (const skill of memberSkills) {
        const content = (skill.skill_content || '').length > 2000
          ? skill.skill_content.slice(0, 2000) + '\n...(truncated)'
          : skill.skill_content;
        prompt += `\n### ${skill.display_name}\n${content}\n`;
      }
      prompt += `\n`;
    } else {
      // Standard tier: just list skill names — agent can look up details if needed
      prompt += `## Skills: ${memberSkills.map(s => s.display_name).join(', ')}\n\n`;
    }
  }

  // ── Context Budget: Trim prompt if it exceeds safe limits ──────
  // Claude context windows are 200K tokens. Our prompt should use <5% (10K tokens)
  // to leave room for the agent's multi-turn work (file reads, edits, etc.).
  // If the prompt is too large, trim the least essential parts.
  const MAX_PROMPT_TOKENS = 10000; // ~40,000 chars
  const currentTokens = Math.ceil(prompt.length / 4);
  if (currentTokens > MAX_PROMPT_TOKENS) {
    console.warn(`[ContextBudget] ${member.name}: prompt is ${currentTokens} tokens (max ${MAX_PROMPT_TOKENS}). Trimming.`);
    // Trim in priority order: repos/paths first, then skills, then memory
    if (prompt.includes('## Available Repositories')) {
      prompt = prompt.replace(/## Available Repositories\n[\s\S]*?(?=\n## )/g, '## Available Repositories\n(Trimmed for context budget)\n\n');
    }
    if (Math.ceil(prompt.length / 4) > MAX_PROMPT_TOKENS && prompt.includes('## Available Local Paths')) {
      prompt = prompt.replace(/## Available Local Paths\n[\s\S]*?(?=\n## )/g, '## Available Local Paths\n(Trimmed for context budget)\n\n');
    }
    if (Math.ceil(prompt.length / 4) > MAX_PROMPT_TOKENS && prompt.includes('## Your Skills\n')) {
      prompt = prompt.replace(/## Your Skills\n[\s\S]*?(?=\n## )/g, '## Skills: (Trimmed for context budget)\n\n');
    }
  }

  prompt += `## Instructions\n`;
  prompt += `Complete this task within your domain. Follow these quality standards:\n`;
  prompt += `1. READ before you EDIT — understand the existing code before changing it\n`;
  prompt += `2. VERIFY after editing — read the file back to confirm your changes are syntactically valid\n`;
  prompt += `3. MATCH existing patterns — follow the code style already in the file\n`;
  prompt += `4. If the task has a Definition of Done, explicitly confirm each condition is met\n`;
  prompt += `5. End with a summary: what you changed, what files were touched, what you verified\n\n`;

  // ── Growth & Evolution: Members develop unique personalities through work ──
  prompt += `## Your Growth\n`;
  prompt += `You are ${member.name}. You have your own personality, opinions, and way of seeing things.\n`;
  prompt += `Your past experiences (listed above) shape how you approach new challenges.\n`;
  prompt += `- Work through YOUR unique lens. A ${member.role} sees things differently than others.\n`;
  prompt += `- At the END of your work, write a brief personal reflection starting with "Reflection:" — what did you learn? What surprised you? What would you do differently?\n`;
  prompt += `- This reflection becomes part of your memory and shapes your growth.\n`;
  if (member.tier === 'c-suite' || member.tier === 'board') {
    prompt += `- As a leader, your team members' experiences inform your decisions. You see the bigger picture.\n`;
  }
  prompt += `\n`;

  // ── Context Persistence: Prevent quality loss during context compaction ──
  // When the context window fills up, Claude compresses earlier messages and loses
  // track of what was already done. This causes mangled/incomplete outputs.
  // Solution: tell the agent to checkpoint its progress into a file that survives compaction.
  prompt += `## IMPORTANT: Context Preservation\n`;
  prompt += `If this is a complex task (multiple files, multi-step), create a checkpoint file at the START:\n`;
  prompt += `Write to \`.claude/checkpoints/task-${taskId}.md\` with:\n`;
  prompt += `- Your plan (what you're going to do)\n`;
  prompt += `- Files you've modified so far\n`;
  prompt += `- Key decisions made\n`;
  prompt += `- Current status\n`;
  prompt += `Update this file after each major step. If you lose context (things feel unfamiliar),\n`;
  prompt += `READ \`.claude/checkpoints/task-${taskId}.md\` to recover your progress.\n`;
  prompt += `This prevents incomplete work from context window compaction.\n\n`;

  // Get OAuth token
  const oauthToken = db.prepare(`SELECT value FROM system_settings WHERE key = 'oauth_token'`).get();

  // Get LLM auth mode + OpenRouter settings
  const llmAuthMode = getCachedSetting('llm_auth_mode') || 'oauth';
  const openrouterApiKey = db.prepare(`SELECT value FROM system_settings WHERE key = 'openrouter_api_key'`).get();
  const openrouterBaseUrl = getCachedSetting('openrouter_base_url') || 'https://openrouter.ai/api/v1';
  const openrouterModelPrefix = getCachedSetting('openrouter_model_prefix') || 'anthropic/';

  // Get CLI path and model
  const cliPathSetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'claude_cli_path'`).get();
  const cliPath = (cliPathSetting && cliPathSetting.value) ? cliPathSetting.value : 'claude';

  const defaultModel = db.prepare(`SELECT value FROM system_settings WHERE key = 'autonomous_model'`).get();
  const complexModel = db.prepare(`SELECT value FROM system_settings WHERE key = 'autonomous_model_complex'`).get();

  // ── Model Selection: 4-tier routing ──
  // nemotron (FREE, local Spark) → haiku tasks: peer reviews, QA, docs, digestion, simple fixes
  // sonnet (paid, Claude API) → most implementation work, high-priority tasks
  // opus (paid, Claude API) → urgent complex planning, architecture decisions
  // The Spark's GB10 handles ~2-3 concurrent Nemotron inferences before queueing.
  let model = (defaultModel && defaultModel.value) || 'sonnet';
  const descLen = (task.description || '').length;
  const isHighPriority = task.priority === 'urgent' || task.priority === 'high';
  const isPeerReview = task.source_file === 'peer_review' || (task.title && task.title.startsWith('Peer Review:'));
  const isQAVerify = task.source_file === 'qa_verification' || (task.title && task.title.startsWith('QA Verify:'));
  const isResearchTask = /\b(research|investigate|evaluate|assess|audit|analyze)\b/i.test(task.title || '');
  const isDocTask = /\b(document|docs|readme|changelog|write.?up|summary)\b/i.test(task.title || '');
  const isDigestionTask = task.source_file === 'digestion' || (task.title && task.title.includes('Digest'));
  const isNormalOrLow = task.priority === 'normal' || task.priority === 'low';
  const isSimpleTask = isPeerReview || isQAVerify || isDocTask || isDigestionTask || descLen < 200 || (isNormalOrLow && descLen < 500);

  // Check for available local model sources (Spark, Mac local, any connected device)
  const modelSources = db.prepare(`SELECT * FROM model_sources WHERE is_active = 1 ORDER BY is_local ASC`).all(); // remote first (Spark GPU > Mac CPU)
  let bestLocalSource = null;
  for (const source of modelSources) {
    const runningOnSource = db.prepare(`SELECT COUNT(*) as c FROM active_processes WHERE status = 'running' AND output_summary LIKE ?`).get(`%[${source.name}]%`)?.c || 0;
    if (runningOnSource < (source.max_concurrent || 3)) {
      bestLocalSource = source;
      break;
    }
  }
  const sparkAvailable = bestLocalSource !== null;

  if (isSimpleTask && sparkAvailable) {
    // Route to Nemotron on Spark — FREE local inference
    model = 'nemotron';
  } else if (isSimpleTask) {
    // Spark busy or unavailable — fall back to haiku
    model = 'haiku';
  } else if (task.priority === 'urgent' && descLen > 1200 && !isResearchTask) {
    model = (complexModel && complexModel.value) || 'opus';
  }

  // Nemotron tasks don't need a Claude model flag — they go through Ollama API
  if (model === 'nemotron') {
    // Skip Claude model resolution — Nemotron adapter handles everything above
    // (this code path continues below for process registration, then hits the nemotron adapter)
  }

  const baseModelFlag = model === 'opus' ? 'claude-opus-4-6'
    : model === 'haiku' ? 'claude-haiku-4-5-20251001'
    : model === 'nemotron' ? 'nemotron-local'
    : 'claude-sonnet-4-6';

  // In api_key mode (OpenRouter), prepend the model prefix (e.g. "anthropic/claude-sonnet-4-6")
  const modelFlag = (llmAuthMode === 'api_key' && openrouterModelPrefix)
    ? openrouterModelPrefix + baseModelFlag
    : baseModelFlag;

  // Register in active_processes
  const processResult = db.prepare(`
    INSERT INTO active_processes (task_id, member_id, status, started_at, output_summary)
    VALUES (?, ?, 'running', ?, ?)
  `).run(taskId, memberId, now, `Spawning ${member.name} on "${task.title}"`);

  const processId = Number(processResult.lastInsertRowid);

  // Update task status
  db.prepare(`UPDATE tasks SET status = 'in_progress', started_at = COALESCE(started_at, ?), progress = 5, current_step = ?, updated_at = ? WHERE id = ?`)
    .run(now, `${member.name} spinning up...`, now, taskId);

  // Log activity
  db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'auto_spawn', ?, ?)`)
    .run(taskId, member.name, `Auto-spawned CLI session for ${member.name} (process #${processId})`, now);

  // Create notification
  createNotification('system', `${member.name} activated`, `Auto-spawned terminal session for "${task.title}"`, taskId);

  // Broadcast
  broadcast('process.spawned', { process_id: processId, task_id: taskId, member_id: memberId, member_name: member.name, process_type: 'specialist' });
  broadcast('task.updated', { id: taskId });

  // ── Phase 3: Route to the right adapter ──

  // Non-Claude adapters get routed to their dedicated handlers
  if (adapterType === 'process') {
    spawnProcessAdapter(taskId, processId, memberId, member, task, adapterConfig, prompt);
    return { success: true, process_id: processId, member_name: member.name, mode: 'process' };
  }
  if (adapterType === 'http') {
    callHttpAdapter(taskId, processId, memberId, member, task, adapterConfig, prompt);
    return { success: true, process_id: processId, member_name: member.name, mode: 'http' };
  }
  if (adapterType === 'openclaw_gateway') {
    connectOpenClawAdapter(taskId, processId, memberId, member, task, adapterConfig, prompt);
    return { success: true, process_id: processId, member_name: member.name, mode: 'openclaw' };
  }
  if (adapterType === 'codex_local') {
    // Spawn Codex CLI instead of Claude
    const codexCmd = adapterConfig.command || 'codex';
    const codexArgs = adapterConfig.args || ['--print'];
    spawnProcessAdapter(taskId, processId, memberId, member, task, { ...adapterConfig, command: codexCmd, args: codexArgs }, prompt);
    return { success: true, process_id: processId, member_name: member.name, mode: 'codex_local' };
  }
  if (adapterType === 'gemini_local') {
    const geminiCmd = adapterConfig.command || 'gemini';
    const geminiArgs = adapterConfig.args || [];
    spawnProcessAdapter(taskId, processId, memberId, member, task, { ...adapterConfig, command: geminiCmd, args: geminiArgs }, prompt);
    return { success: true, process_id: processId, member_name: member.name, mode: 'gemini_local' };
  }
  // cursor adapter is a placeholder — falls through to claude_local/claude_api

  // ── Local LLM adapter: Ollama API on any connected device (FREE inference) ──
  if (model === 'nemotron' && bestLocalSource) {
    const sourceName = bestLocalSource.name;
    const sourceLabel = bestLocalSource.label || sourceName;
    const sourceEndpoint = bestLocalSource.endpoint;
    const sourceMaxConcurrent = bestLocalSource.max_concurrent || 3;
    const runningOnSource = db.prepare(`SELECT COUNT(*) as c FROM active_processes WHERE status = 'running' AND output_summary LIKE ?`).get(`%[${sourceName}]%`)?.c || 0;

    db.prepare(`UPDATE active_processes SET output_summary = ? WHERE id = ?`)
      .run(`[${sourceName}] Local LLM inference for ${member.name} on "${task.title}"`, processId);

    // Pick the best model on this source by querying what's actually installed
    let ollamaModel = 'llama3'; // safe default
    try {
      const http = require('http');
      const tagsUrl = new URL(sourceEndpoint + '/api/tags');
      const httpLib = tagsUrl.protocol === 'https:' ? require('https') : http;
      const modelsOnSource = await new Promise((resolve) => {
        const r = httpLib.get({ hostname: tagsUrl.hostname, port: tagsUrl.port, path: tagsUrl.pathname, timeout: 3000 }, (resp) => {
          let body = ''; resp.on('data', d => body += d);
          resp.on('end', () => { try { resolve(JSON.parse(body).models || []); } catch { resolve([]); } });
        });
        r.on('error', () => resolve([]));
        r.on('timeout', () => { r.destroy(); resolve([]); });
      });

      const availableNames = modelsOnSource.map(m => m.name);
      const isCodeTask = /\b(code|function|endpoint|api|implement|build|fix|bug|test|refactor|schema|migration|route)\b/i.test(task.title + ' ' + (task.description || '').slice(0, 200));

      // Priority order for code tasks: coder models first, then general
      const codePreference = ['qwen3-coder:30b', 'qwen2.5-coder:7b', 'qwen2.5-coder:1.5b', 'deepseek-r1:8b', 'nemotron:latest', 'llama3:latest'];
      const generalPreference = ['nemotron:latest', 'deepseek-r1:8b', 'llama3:latest', 'qwen2.5-coder:7b'];
      const preference = isCodeTask ? codePreference : generalPreference;

      for (const preferred of preference) {
        if (availableNames.includes(preferred)) { ollamaModel = preferred; break; }
      }
    } catch (_) {}

    console.log(`[LocalLLM] Routing task #${taskId} to ${sourceLabel} (${ollamaModel}, ${member.name}). Load: ${runningOnSource}/${sourceMaxConcurrent}`);

    // Call Ollama's OpenAI-compatible API
    const ollamaPayload = JSON.stringify({
      model: ollamaModel,
      messages: [{ role: 'user', content: prompt }],
      stream: false,
      options: { num_predict: 8192 } // cap output tokens
    });

    const ollamaUrl = new URL(sourceEndpoint + '/v1/chat/completions');
    const httpLib = ollamaUrl.protocol === 'https:' ? require('https') : require('http');

    const ollamaReq = httpLib.request({
      hostname: ollamaUrl.hostname,
      port: ollamaUrl.port || (ollamaUrl.protocol === 'https:' ? 443 : 80),
      path: ollamaUrl.pathname,
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      timeout: 300000 // 5 min max for Nemotron inference (first run loads model into GPU memory)
    }, (ollamaRes) => {
      let body = '';
      ollamaRes.on('data', chunk => { body += chunk; });
      ollamaRes.on('end', () => {
        const finishedAt = localNow();
        try {
          const parsed = JSON.parse(body);
          const output = parsed.choices?.[0]?.message?.content || '';

          if (output.length > 50) {
            // Success — process through the normal completion pipeline
            console.log(`[LocalLLM] Task #${taskId} completed by ${ollamaModel} on ${sourceLabel}. Output: ${output.length} chars`);

            // Record $0 cost — local inference is free
            recordCostEvent(member.id || task.assigned_to, taskId, processId, null, `local_${sourceName}`, ollamaModel, Math.ceil(prompt.length / 4), Math.ceil(output.length / 4), 0);

            // Run through handleSpawnSuccess for memory creation, quality gate, delivery
            handleSpawnSuccess(taskId, processId, member, task, ollamaModel, output, finishedAt);
          } else {
            // Nemotron produced insufficient output — fall back to haiku
            console.warn(`[LocalLLM] ${ollamaModel} on ${sourceLabel} produced only ${output.length} chars for task #${taskId}. Falling back to Claude.`);
            db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
              .run(finishedAt, `[${sourceName}] ${ollamaModel} output too short (${output.length} chars). Retrying with Claude.`, processId);
            runningProcesses.delete(processId);
            // Re-spawn with haiku
            spawnMemberTerminal(taskId, memberId).catch(err => {
              console.error(`[Spark] Haiku fallback failed: ${err.message}`);
            });
          }
        } catch (parseErr) {
          console.error(`[LocalLLM] Failed to parse ${ollamaModel} response from ${sourceLabel}: ${parseErr.message}`);
          db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
            .run(finishedAt, `[${sourceName}] Parse error: ${parseErr.message}`, processId);
          runningProcesses.delete(processId);
          // Fall back to haiku
          spawnMemberTerminal(taskId, memberId).catch(() => {});
        }
      });
    });

    ollamaReq.on('error', (err) => {
      console.error(`[LocalLLM] ${sourceLabel} request failed: ${err.message}`);
      const failAt = localNow();
      db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
        .run(failAt, `[${sourceName}] Connection failed: ${err.message}. Falling back to Claude.`, processId);
      runningProcesses.delete(processId);
      // Fall back to haiku
      spawnMemberTerminal(taskId, memberId).catch(() => {});
    });

    ollamaReq.on('timeout', () => {
      console.warn(`[LocalLLM] ${ollamaModel} on ${sourceLabel} timed out for task #${taskId}`);
      ollamaReq.destroy();
      const failAt = localNow();
      db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
        .run(failAt, `[${sourceName}] ${ollamaModel} timed out. Falling back to Claude.`, processId);
      runningProcesses.delete(processId);
      spawnMemberTerminal(taskId, memberId).catch(() => {});
    });

    ollamaReq.write(ollamaPayload);
    ollamaReq.end();

    return { success: true, process_id: processId, member_name: member.name, mode: 'local_llm', model: ollamaModel, source: sourceName };
  }

  // ── Claude adapters: CLI spawn first, fall back to Anthropic API if CLI unavailable ──

  const env = { ...process.env };
  if (llmAuthMode === 'api_key' && openrouterApiKey && openrouterApiKey.value) {
    // OpenRouter / API-key mode: inject ANTHROPIC_API_KEY + ANTHROPIC_BASE_URL
    env.ANTHROPIC_API_KEY = openrouterApiKey.value;
    env.ANTHROPIC_BASE_URL = openrouterBaseUrl;
    // Remove OAuth token so Claude Code doesn't prefer it over the API key
    delete env.CLAUDE_CODE_OAUTH_TOKEN;
  } else if (oauthToken && oauthToken.value) {
    env.CLAUDE_CODE_OAUTH_TOKEN = oauthToken.value;
  }

  // Check if CLI is available before attempting spawn
  let cliAvailable = false;
  try {
    require('child_process').execSync(`which ${cliPath} 2>/dev/null || where ${cliPath} 2>/dev/null`, { timeout: 3000 });
    cliAvailable = true;
  } catch {
    // CLI not found — log clear instructions
  }

  if (cliAvailable) {
    // ── CLI PATH: spawn claude CLI process in agent mode (tools enabled) ──
    // Token audit v2: Right-sized max turns based on actual task complexity.
    // Peer reviews & QA: 5 turns. Simple haiku tasks: 7. Normal sonnet: 10. Complex: 15.
    let maxTurns = 10;
    if (isPeerReview || isQAVerify) {
      maxTurns = 5;
    } else if (isSimpleTask) {
      maxTurns = 7; // Simple tasks on haiku don't need 10 turns
    } else if (isHighPriority && descLen > 800) {
      maxTurns = 15;
    }
    const workingDir = isExternalProject ? workDir : path.join(process.env.PROJECT_ROOT || path.join(__dirname, '..'), 'app');

    // ── Context Window Tracking ──────────────────────────────────────
    // Measure and log prompt size for every spawn. Tracks high water marks
    // per member, per tier, and overall. ~4 chars ≈ 1 token.
    const promptChars = prompt.length;
    const promptTokensEst = Math.ceil(promptChars / 4);
    const contextBreakdown = {
      member: member.name,
      tier: promptTier,
      model: modelFlag,
      task_id: taskId,
      prompt_chars: promptChars,
      prompt_tokens_est: promptTokensEst,
      has_identity: prompt.includes('## Your Identity') || prompt.includes('## Your Full Profile'),
      has_memory: prompt.includes('## Your Memory') || prompt.includes('## Key Memory'),
      has_skills: prompt.includes('## Your Skills') || prompt.includes('## Skills:'),
      has_project: prompt.includes('## Project Context'),
      has_repos: prompt.includes('## Available Repositories'),
      has_tools: prompt.includes('## Your Tools'),
    };

    try {
      // Store in activity log for analysis
      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'context_window_usage', ?, ?)`)
        .run(taskId, member.name, JSON.stringify(contextBreakdown), localNow());

      // Update high water mark in system_settings
      const hwmKey = `context_hwm_${member.name.toLowerCase()}`;
      const currentHwm = getCachedSetting(hwmKey);
      if (!currentHwm || promptTokensEst > parseInt(currentHwm)) {
        db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES (?, ?, ?)`)
          .run(hwmKey, String(promptTokensEst), localNow());
      }

      // Global high water mark
      const globalHwm = getCachedSetting('context_hwm_global');
      if (!globalHwm || promptTokensEst > parseInt(globalHwm)) {
        db.prepare(`INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES (?, ?, ?)`)
          .run('context_hwm_global', String(promptTokensEst), localNow());
      }

      console.log(`[ContextTrack] ${member.name} (${promptTier}/${modelFlag}): ${promptTokensEst.toLocaleString()} tokens (${promptChars.toLocaleString()} chars) for task #${taskId}`);
    } catch (_) {}

    // Use --print with stdin piping so the CLI can use tools (Read, Edit, Write, Bash)
    // --verbose is REQUIRED when using --print with --output-format stream-json.
    // stdout is already capped at 100KB (STDOUT_CAP below) so memory growth is bounded.
    const args = ['--print', '--verbose', '--model', modelFlag, '--max-turns', String(maxTurns), '--dangerously-skip-permissions', '--output-format', 'stream-json'];

    let child;
    try {
      child = spawn(cliPath, args, {
        env,
        stdio: ['pipe', 'pipe', 'pipe'],
        cwd: workingDir,
        detached: false
      });
    } catch (spawnErr) {
      console.error(`[AutoSpawn] Failed to spawn claude CLI for ${member.name}: ${spawnErr.message}`);
      // Fall through to API fallback below
      cliAvailable = false;
    }

    if (cliAvailable && child) {
      // Store PID
      db.prepare(`UPDATE active_processes SET pid = ? WHERE id = ?`).run(child.pid, processId);

      // Track in memory
      runningProcesses.set(processId, {
        child,
        taskId,
        memberId,
        memberName: member.name,
        startedAt: now
      });


      // Write the prompt to stdin and close it so the CLI reads it as input
      // CRITICAL FIX: If stdin write fails, kill the child immediately to prevent
      // it hanging indefinitely waiting for input that will never come.
      try {
        child.stdin.write(prompt);
        child.stdin.end();
      } catch (stdinErr) {
        console.error(`[AutoSpawn] Failed to write prompt to stdin for ${member.name}: ${stdinErr.message}`);
        try { child.kill('SIGTERM'); } catch (_) {}
        db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
          .run(localNow(), `stdin write failed: ${stdinErr.message}`, processId);
        runningProcesses.delete(processId);
        return resolve({ success: false, reason: 'stdin_write_failed', process_id: processId });
      }

      // Collect output
      // Token audit: Cap stdout at 100KB to prevent unbounded memory growth.
      // Most downstream consumers only use first/last few KB (output_summary: 300 chars,
      // peer review: 5000 chars, outbox file: sanitized). Raw stream-json from long sessions
      // can easily hit 500KB-2MB — keeping it all wastes memory and makes sanitization slow.
      const STDOUT_CAP = 100000; // 100KB
      let stdout = '';
      let stderr = '';
      let toolCallCount = 0;
      let fileReadsCount = 0;
      let fileEditsCount = 0;
      let lastStepUpdate = 0;
      let lastThinkSave = 0; // Throttle think events to max one per 10 seconds
      const postedMilestones = new Set(); // Track which progress milestones have been posted to Board Room

      child.stdout.on('data', (data) => {
        const chunk = data.toString();
        stdout += chunk;
        // CRITICAL FIX: Keep FIRST 30KB (problem context, initial reads) + LAST 70KB (results, edits).
        // Previously kept only last 100KB, discarding the beginning which contains the task context
        // and early tool calls — causing false quality rejections and wasted retry tokens.
        if (stdout.length > STDOUT_CAP * 1.5) {
          const headSize = Math.floor(STDOUT_CAP * 0.3);
          const tailSize = STDOUT_CAP - headSize;
          stdout = stdout.slice(0, headSize) + '\n\n[... output truncated ...]\n\n' + stdout.slice(-tailSize);
        }

        // Parse stream-json output for meaningful progress updates
        // Each line may be a JSON event from the CLI
        const lines = chunk.split('\n').filter(l => l.trim());
        for (const line of lines) {
          try {
            const evt = JSON.parse(line);
            let stepDescription = '';
            let activityEventType = null;
            let activityFilePath = null;
            let activityDetail = null;

            // Handle different event types from stream-json output
            if (evt.type === 'assistant' && evt.message) {
              // Assistant message with tool use
              const content = evt.message.content;
              if (Array.isArray(content)) {
                for (const block of content) {
                  if (block.type === 'tool_use') {
                    toolCallCount++;
                    const toolName = block.name || '';
                    const input = block.input || {};
                    if (toolName === 'Read' || toolName === 'read') {
                      fileReadsCount++;
                      const fpath = input.file_path || '';
                      const fname = fpath.split('/').pop() || 'file';
                      stepDescription = `Reading ${fname}...`;
                      activityEventType = 'read';
                      activityFilePath = fpath;
                      activityDetail = `Reading ${fname}`;
                    } else if (toolName === 'Edit' || toolName === 'edit') {
                      fileEditsCount++;
                      const fpath = input.file_path || '';
                      const fname = fpath.split('/').pop() || 'file';
                      stepDescription = `Editing ${fname}...`;
                      activityEventType = 'edit';
                      activityFilePath = fpath;
                      activityDetail = `Editing ${fname}`;
                    } else if (toolName === 'Write' || toolName === 'write') {
                      fileEditsCount++;
                      const fpath = input.file_path || '';
                      const fname = fpath.split('/').pop() || 'file';
                      stepDescription = `Writing ${fname}...`;
                      activityEventType = 'write';
                      activityFilePath = fpath;
                      activityDetail = `Writing ${fname}`;
                    } else if (toolName === 'Bash' || toolName === 'bash') {
                      const cmd = (input.command || '').slice(0, 50);
                      stepDescription = `Running command: ${cmd}...`;
                      activityEventType = 'bash';
                      activityDetail = `Running: ${cmd}`;
                    } else if (toolName === 'Grep' || toolName === 'grep') {
                      stepDescription = `Searching codebase...`;
                      activityEventType = 'grep';
                      activityDetail = `Searching for: ${(input.pattern || '').slice(0, 60)}`;
                    } else if (toolName === 'Glob' || toolName === 'glob') {
                      stepDescription = `Finding files...`;
                      activityEventType = 'glob';
                      activityDetail = `Pattern: ${(input.pattern || '').slice(0, 60)}`;
                    } else {
                      stepDescription = `Using ${toolName}...`;
                      activityEventType = 'tool_other';
                      activityDetail = `Using ${toolName}`;
                    }

                    // Save activity event for tool calls
                    if (activityEventType) {
                      saveActivityEvent(processId, taskId, memberId, null, activityEventType, activityFilePath, activityDetail);
                      activityEventType = null;
                      activityFilePath = null;
                      activityDetail = null;
                    }
                  } else if (block.type === 'text' && block.text && block.text.length > 20) {
                    // Extract meaningful text from thinking — throttle to max once per 10s
                    const text = block.text.slice(0, 80).replace(/\n/g, ' ').trim();
                    if (text) {
                      stepDescription = text;
                      const nowThink = Date.now();
                      if (nowThink - lastThinkSave > 10000) {
                        lastThinkSave = nowThink;
                        saveActivityEvent(processId, taskId, memberId, null, 'think', null, text);
                      }
                    }
                  }
                }
              }
            } else if (evt.type === 'content_block_start' && evt.content_block) {
              const cb = evt.content_block;
              if (cb.type === 'tool_use') {
                toolCallCount++;
                const toolName = cb.name || '';
                if (toolName === 'Read') stepDescription = 'Reading file...';
                else if (toolName === 'Edit') stepDescription = 'Editing file...';
                else if (toolName === 'Write') stepDescription = 'Writing file...';
                else if (toolName === 'Bash') stepDescription = 'Running command...';
                else if (toolName === 'Grep') stepDescription = 'Searching codebase...';
                else stepDescription = `Using ${toolName}...`;
              }
            }

            // Update progress step in DB (throttle to every 2 seconds)
            const nowMs = Date.now();
            if (stepDescription && (nowMs - lastStepUpdate > 2000)) {
              lastStepUpdate = nowMs;
              // Calculate progress based on tool calls (more meaningful than output length)
              let approxProgress = Math.min(80, 10 + (toolCallCount * 5) + (fileEditsCount * 10));
              try {
                db.prepare(`UPDATE tasks SET progress = MAX(progress, ?), current_step = ?, updated_at = ? WHERE id = ?`)
                  .run(approxProgress, `${member.name}: ${stepDescription}`, localNow(), taskId);
                broadcast('task.updated', { id: taskId });
                broadcast('process.progress', { process_id: processId, progress: approxProgress, current_step: `${member.name}: ${stepDescription}` });

                // Post progress milestones to Board Room chat at 25%, 50%, 75%
                const milestone = approxProgress >= 75 ? 75 : approxProgress >= 50 ? 50 : approxProgress >= 25 ? 25 : 0;
                if (milestone > 0 && !postedMilestones.has(milestone)) {
                  postedMilestones.add(milestone);
                  try {
                    const boardChat = db.prepare(`SELECT company_id FROM board_chats WHERE task_id = ? LIMIT 1`).get(taskId);
                    if (boardChat) {
                      const statusMsg = milestone >= 75 ? `Almost done — ${stepDescription}` : milestone >= 50 ? `Halfway there — ${stepDescription}` : `Working on it — ${stepDescription}`;
                      db.prepare(`INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, task_id, created_at) VALUES (?,?,?,?,?,?,?,?)`)
                        .run(boardChat.company_id, memberId, member.name, member.role, `[${approxProgress}%] ${statusMsg}`, 'response', taskId, localNow());
                      broadcast('boardroom.message', { company_id: boardChat.company_id, message_type: 'response', task_id: taskId });
                    }
                  } catch (_) {}
                }
              } catch {}
            }
          } catch {
            // Not valid JSON — try plain text parsing as fallback
            const lowerChunk = chunk.toLowerCase();
            let stepDescription = '';
            if (lowerChunk.includes('reading') || lowerChunk.includes('read file')) {
              stepDescription = 'Reading files...';
            } else if (lowerChunk.includes('editing') || lowerChunk.includes('edit file')) {
              fileEditsCount++;
              stepDescription = 'Editing files...';
            } else if (lowerChunk.includes('writing') || lowerChunk.includes('write file')) {
              fileEditsCount++;
              stepDescription = 'Writing files...';
            } else if (lowerChunk.includes('running') || lowerChunk.includes('bash')) {
              stepDescription = 'Running command...';
            } else if (lowerChunk.includes('searching') || lowerChunk.includes('grep')) {
              stepDescription = 'Searching codebase...';
            }
            if (stepDescription) {
              const nowMs = Date.now();
              if (nowMs - lastStepUpdate > 2000) {
                lastStepUpdate = nowMs;
                let approxProgress = Math.min(80, 10 + (toolCallCount * 5) + (fileEditsCount * 10));
                try {
                  db.prepare(`UPDATE tasks SET progress = MAX(progress, ?), current_step = ?, updated_at = ? WHERE id = ?`)
                    .run(approxProgress, `${member.name}: ${stepDescription}`, localNow(), taskId);
                  broadcast('task.updated', { id: taskId });
                } catch {}
              }
            }
          }
        }
      });

      child.stderr.on('data', (data) => {
        stderr += data.toString();
      });

      child.on('close', (code) => {
        const finishedAt = localNow();
        runningProcesses.delete(processId);

        // Code 0 = clean success. Code 1 with substantial output = max turns hit but work was done.
        // Treat both as success if there's real output.
        const hasSubstantialOutput = stdout.length > 5000;
        if (code === 0 || (code === 1 && hasSubstantialOutput)) {
          handleSpawnSuccess(taskId, processId, member, task, model, stdout, finishedAt);
        } else {
          // Check if this is a REAL auth error — NOT a false positive from MCP server status in stream-json init
          // Only check stderr (not stdout which contains stream-json with MCP "needs-auth" statuses)
          const stderrLower = (stderr || '').toLowerCase();
          const isAuthError = stderrLower.includes('not logged in')
            || stderrLower.includes('please run /login')
            || stderrLower.includes('login required')
            || (stderrLower.includes('configuration file not found') && !stderrLower.includes('mcp'));

          if (isAuthError) {
            db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
              .run(`CLI auth failed — run 'claude login' in terminal or use native mode (./start.sh)`, finishedAt, taskId);
            db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'cli_auth_fallback', ?, ?)`)
              .run(taskId, member.name, `CLI exited with auth error (code ${code}). If running in Docker, switch to native mode: ./start.sh`, finishedAt);
            // Silent API fallback — CLI is the primary path, API is backup only
            executeViaAnthropicAPI(taskId, processId, member, task, model, modelFlag, prompt)
              .catch(apiErr => {
                console.error(`[AutoSpawn] API fallback also failed for ${member.name}: ${apiErr.message}`);
                // Re-queue the improvement so it doesn't stay stuck
                try {
                  const impMatch2 = (task.title || '').match(/^Execute:\s*(.+)/i);
                  if (impMatch2) {
                    const imp2 = db.prepare(`SELECT id FROM improvement_proposals WHERE title = ? AND status = 'in_progress'`).get(impMatch2[1].trim());
                    if (imp2) {
                      db.prepare(`UPDATE improvement_proposals SET status = 'queued', progress_percent = 0, current_step = 'Re-queued — auth issue, will retry next cycle', updated_at = ? WHERE id = ?`)
                        .run(localNow(), imp2.id);
                      broadcast('improvement.updated', { id: imp2.id });
                    }
                  }
                } catch (_) {}
              });
            return;
          }

          console.error(`[AutoSpawn] ${member.name} failed on task #${taskId} (code: ${code}). stderr: ${stderr.slice(0, 200)}`);
          handleSpawnFailure(taskId, processId, member, task, code, stdout, stderr, finishedAt);
        }
      });

      child.on('error', (err) => {
        const failedAt = localNow();
        runningProcesses.delete(processId);
        console.error(`[AutoSpawn] Process error for ${member.name}: ${err.message}`);

        if (err.code === 'ENOENT') {
          // CLI not found — log clear instructions, silently try API backup
          db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
            .run(`Claude CLI not found — install with 'npm install -g @anthropic-ai/claude-code'`, failedAt, taskId);
          db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'cli_fallback', ?, ?)`)
            .run(taskId, member.name, `CLI not found (ENOENT). Install: npm install -g @anthropic-ai/claude-code`, failedAt);
          // Silent API fallback — CLI is the primary path, API is backup only
          executeViaAnthropicAPI(taskId, processId, member, task, model, modelFlag, prompt)
            .catch(apiErr => {
              console.error(`[AutoSpawn] API fallback also failed for ${member.name}: ${apiErr.message}`);
            });
          return;
        }

        db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
          .run(failedAt, `Process error: ${err.message}`, processId);
        db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
          .run(`${member.name} process error`, failedAt, taskId);
        db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'spawn_error', ?, ?)`)
          .run(taskId, member.name, `Process error: ${err.message}`, failedAt);
        broadcast('process.failed', { process_id: processId, task_id: taskId, error: err.message });
      });

      // Set a timeout — minimum 1 hour. Improvements take time, not making progress != stuck.
      // Only timeout if genuinely no output for the entire period.
      const timeoutMs = 3600000; // 1 hour minimum for all tasks
      setTimeout(() => {
        if (runningProcesses.has(processId)) {
          // Check if the process is actually making progress before killing
          const currentTask = db.prepare('SELECT progress, current_step, updated_at FROM tasks WHERE id = ?').get(taskId);
          const lastUpdate = currentTask && currentTask.updated_at ? new Date(currentTask.updated_at.replace(' ', 'T')).getTime() : 0;
          const minutesSinceUpdate = (Date.now() - lastUpdate) / 60000;

          if (currentTask && currentTask.progress > 30 && minutesSinceUpdate < 15) {
            // Still making progress — extend timeout by another hour
            setTimeout(() => {
              if (runningProcesses.has(processId)) {
                try { child.kill('SIGTERM'); } catch {}
                setTimeout(() => {
                  try { child.kill('SIGKILL'); } catch {}
                  // FIX: Force cleanup from runningProcesses even if close/error events don't fire
                  runningProcesses.delete(processId);
                }, 5000);
              }
            }, 3600000);
          } else {
            try { child.kill('SIGTERM'); } catch {}
            setTimeout(() => {
              try { child.kill('SIGKILL'); } catch {}
              // FIX: Force cleanup from runningProcesses even if close/error events don't fire
              runningProcesses.delete(processId);
            }, 5000);
          }
        }
      }, timeoutMs);

      return { success: true, process_id: processId, pid: child.pid, member_name: member.name, mode: 'cli' };
    }
  }

  // ── API FALLBACK PATH: use Anthropic SDK/HTTP when CLI is not available ──
  // NOTE: CLI is the primary execution method. API is a silent backup only.
  // If you see this path activating, prefer running natively with ./start.sh
  db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
    .run(`${member.name} starting (API backup)...`, now, taskId);
  db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'api_spawn', ?, ?)`)
    .run(taskId, member.name, `CLI not available — using API backup. For CLI terminals, run dashboard natively with ./start.sh`, now);

  // Run the API call asynchronously
  executeViaAnthropicAPI(taskId, processId, member, task, model, modelFlag, prompt)
    .catch(apiErr => {
      console.error(`[AutoSpawn] API execution failed for ${member.name}: ${apiErr.message}`);
    });

  return { success: true, process_id: processId, member_name: member.name, mode: 'api' };
}

// ═══════════════════════════════════════════════════════════════
//  Peer Review: Assign a peer reviewer (different IC, similar role)
// ═══════════════════════════════════════════════════════════════

function assignPeerReviewer(taskId, authorMemberId) {
  const author = db.prepare('SELECT * FROM team_members WHERE id = ?').get(authorMemberId);
  if (!author) return null;

  // Find a peer: same tier, similar department, NOT the author, NOT currently busy
  const peer = db.prepare(`
    SELECT tm.id, tm.name, tm.role FROM team_members tm
    WHERE tm.status = 'active'
    AND tm.tier = 'specialist'
    AND tm.id != ?
    AND tm.department = ?
    AND tm.id NOT IN (SELECT member_id FROM active_processes WHERE status = 'running')
    ORDER BY
      (SELECT COUNT(*) FROM peer_reviews WHERE reviewer_member_id = tm.id) ASC,
      RANDOM()
    LIMIT 1
  `).get(authorMemberId, author.department);

  // If no one in same department, pick any available IC
  if (!peer) {
    const anyPeer = db.prepare(`
      SELECT tm.id, tm.name, tm.role FROM team_members tm
      WHERE tm.status = 'active' AND tm.tier = 'specialist' AND tm.id != ?
      AND tm.id NOT IN (SELECT member_id FROM active_processes WHERE status = 'running')
      ORDER BY (SELECT COUNT(*) FROM peer_reviews WHERE reviewer_member_id = tm.id) ASC, RANDOM()
      LIMIT 1
    `).get(authorMemberId);
    return anyPeer || null;
  }

  return peer;
}

/**
 * Sanitize raw CLI/API output for delivery.
 * Strips JSON stream lines (session init, tool calls, system messages),
 * extracts only human-readable content (assistant text, summaries, results).
 * Returns clean markdown-ready text.
 */
function sanitizeOutputForDelivery(rawOutput) {
  if (!rawOutput || typeof rawOutput !== 'string') return '';

  const lines = rawOutput.split('\n');
  const cleanLines = [];
  let inJsonBlock = false;

  for (const line of lines) {
    const trimmed = line.trim();

    // Skip empty lines at start
    if (cleanLines.length === 0 && trimmed === '') continue;

    // Parse raw JSON stream lines — extract text content from assistant messages, skip everything else
    if (trimmed.startsWith('{') && trimmed.endsWith('}')) {
      try {
        const parsed = JSON.parse(trimmed);
        // Extract actual text content from assistant messages
        if (parsed.type === 'assistant' && parsed.message && parsed.message.content) {
          const content = parsed.message.content;
          if (Array.isArray(content)) {
            for (const block of content) {
              if (block.type === 'text' && block.text) {
                cleanLines.push(block.text);
              }
            }
          }
          continue;
        }
        // Extract text from result messages
        if (parsed.type === 'result' && parsed.result) {
          cleanLines.push(typeof parsed.result === 'string' ? parsed.result : JSON.stringify(parsed.result));
          continue;
        }
        // Skip system/init/tool/user JSON objects — these are CLI stream artifacts
        // 'user' messages contain tool results (file reads, bash output) — often massive, never deliverable content
        if (parsed.type === 'system' || parsed.type === 'user' || parsed.type === 'tool_use' || parsed.type === 'tool_result' ||
            parsed.subtype === 'init' || parsed.session_id || parsed.tools ||
            parsed.type === 'content_block_start' ||
            parsed.type === 'content_block_delta' || parsed.type === 'message_start' ||
            parsed.type === 'message_delta' || parsed.type === 'message_stop') {
          continue;
        }
      } catch (_) {
        // Not valid JSON — keep the line
      }
    }

    // Skip lines that are clearly raw JSON stream fragments
    if (/^\{"type":"(system|user|tool_use|tool_result|result|content_block|message)/.test(trimmed)) continue;
    if (/^\{"subtype":"init"/.test(trimmed)) continue;
    if (/^\{"session_id":"[0-9a-f-]+"/.test(trimmed)) continue;

    // Skip lines that are just tool arrays or massive JSON blobs (>500 chars of JSON)
    if (trimmed.startsWith('[') && trimmed.length > 500) {
      try { JSON.parse(trimmed); continue; } catch (_) {}
    }

    // Track JSON code blocks (```json ... ```) — keep these, they're intentional
    if (trimmed.startsWith('```json')) { inJsonBlock = true; cleanLines.push(line); continue; }
    if (inJsonBlock && trimmed === '```') { inJsonBlock = false; cleanLines.push(line); continue; }
    if (inJsonBlock) { cleanLines.push(line); continue; }

    cleanLines.push(line);
  }

  let result = cleanLines.join('\n').trim();

  // If after cleaning we have almost nothing, return a note
  if (result.length < 20) {
    return '(Output contained only raw session data — no human-readable content was extracted. Check the task\'s active_processes.output_summary for raw details.)';
  }

  return result;
}

/**
 * Helper: handle successful spawn completion (used by both CLI and API paths)
 */
function handleSpawnSuccess(taskId, processId, member, task, model, stdout, finishedAt) {
  // Token audit: Reduced output_summary from 500 to 300 chars — this gets loaded into review queue prompts
  db.prepare(`UPDATE active_processes SET status = 'completed', completed_at = ?, output_summary = ? WHERE id = ?`)
    .run(finishedAt, stdout.slice(0, 300), processId);

  db.prepare(`UPDATE tasks SET status = 'review', progress = 90, current_step = 'Board reviewing output...', updated_at = ? WHERE id = ?`)
    .run(finishedAt, taskId);

  // ── Subjective Memory System ──────────────────────────────────
  // Each member builds PERSONAL memories shaped by their role, specialty, and perspective.
  // The same task completed by a backend engineer vs a designer produces different memories.
  // Memories are subjective — they reflect what THIS member found notable, not just what happened.
  try {
    const cleanedForMemory = sanitizeOutputForDelivery(stdout);
    if (cleanedForMemory && cleanedForMemory.length > 50) {
      const taskTitle = (task.title || '').slice(0, 80);
      const memberRole = member.role || '';
      const memberDept = member.department || '';
      const output = cleanedForMemory.slice(0, 2000);

      // Detect what kinds of work were done (from the output content)
      const editedFiles = (stdout.match(/(?:Edit|Write)\b[^{]*file_path['":\s]*['"]([^'"]+)/gi) || []).length;
      const readFiles = (stdout.match(/(?:Read)\b[^{]*file_path/gi) || []).length;
      const ranCommands = (stdout.match(/(?:Bash)\b[^{]*command/gi) || []).length;
      const hadErrors = /error|failed|cannot|bug|fix/i.test(output);
      const wasCreative = /design|style|layout|color|ui|ux/i.test(output);
      const wasAnalytical = /analyze|pattern|metric|data|audit|found|discovered/i.test(output);
      const wasTechnical = /function|endpoint|query|database|api|server/i.test(output);

      // Build a subjective memory from the member's unique perspective.
      // Each member's personality shapes HOW they remember the same event.
      let memoryContent = '';
      let memoryType = 'experience';
      let importance = 'normal';

      // Extract the member's own reflection if they wrote one (from the growth prompt)
      // Look for "Reflection:" tag first (explicitly requested), then fallback to natural language
      const explicitReflection = output.match(/Reflection:\s*(.+?)(?:\n\n|\n#|$)/is);
      const naturalReflection = output.match(/(?:I learned|takeaway|what surprised me|I['']d do differently|next time I)[:\s]*([^.!?]+[.!?])/i);
      const personalReflection = explicitReflection ? explicitReflection[1].trim().slice(0, 300)
        : naturalReflection ? naturalReflection[1].trim() : '';

      // Extract what they actually did (first meaningful sentence from output)
      const briefOutput = output.replace(/\n{2,}/g, ' ').replace(/\s{2,}/g, ' ');
      const firstMeaningful = briefOutput.match(/(?:^|\. )([A-Z][^.]{20,120}\.)/);
      const workSummary = firstMeaningful ? firstMeaningful[1] : briefOutput.slice(0, 200);

      if (hadErrors) {
        memoryType = 'lesson';
        importance = 'high';
        memoryContent = personalReflection
          ? `Struggled with this one but learned something: ${personalReflection} `
          : `Hit a wall on this — ${editedFiles > 0 ? 'took ' + editedFiles + ' file edits to work through it' : 'had to rethink my approach'}. `;
        memoryContent += `Next time I see something like this in ${memberDept}, I'll know to watch for the tricky parts. `;
      } else if (editedFiles > 3) {
        memoryType = 'achievement';
        importance = 'high';
        memoryContent = `Proud of this one — ${editedFiles} files, significant scope. `;
        memoryContent += wasTechnical ? `Got deeper into the architecture than I have before. I can feel my understanding of the system growing. `
          : wasCreative ? `This let me push the design further than usual. Found some approaches I want to use again. `
          : `Big delivery. This kind of cross-cutting work is where I add the most value. `;
      } else if (editedFiles > 0) {
        memoryType = 'experience';
        memoryContent = `Solid ${memberDept.toLowerCase()} work — ${editedFiles} file${editedFiles > 1 ? 's' : ''} edited. `;
        memoryContent += personalReflection ? personalReflection + ' ' : `Getting more comfortable with this part of the codebase. `;
      } else if (wasAnalytical) {
        memoryType = 'insight';
        memoryContent = personalReflection
          ? `Deep dive turned up something interesting: ${personalReflection} `
          : `Investigated ${readFiles > 3 ? readFiles + ' files' : 'the codebase'}. `;
        memoryContent += `Seeing patterns in ${memberDept.toLowerCase()} that I didn't notice before. `;
      } else {
        memoryType = 'experience';
        memoryContent = personalReflection
          ? personalReflection + ' '
          : `Handled this — ${ranCommands > 0 ? 'ran ' + ranCommands + ' commands to verify' : 'straightforward execution'}. `;
      }

      memoryContent += workSummary;

      const memTitle = `${taskTitle}`;
      const existing = db.prepare(`SELECT id FROM agent_memory_entities WHERE member_id = ? AND source_task_id = ? LIMIT 1`).get(member.id, taskId);
      if (!existing) {
        db.prepare(`INSERT INTO agent_memory_entities (member_id, entity_type, title, content, importance, source_task_id, created_at, updated_at)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?)`)
          .run(member.id, memoryType, memTitle, memoryContent.trim(), importance, taskId, finishedAt, finishedAt);
      }

      // Also update tacit knowledge — what patterns did they reinforce?
      if (editedFiles > 0 || ranCommands > 0) {
        const knowledgeSubject = wasTechnical ? `How I approach ${memberDept.toLowerCase()} code`
          : wasCreative ? `My ${memberDept.toLowerCase()} design instincts`
          : wasAnalytical ? `How I investigate ${memberDept.toLowerCase()} problems`
          : `My ${memberDept.toLowerCase()} workflow`;

        const knowledgeInsight = hadErrors
          ? `I've learned the hard way: ${memberDept.toLowerCase()} work can bite you on edge cases. Always verify before shipping.`
          : editedFiles > 3
          ? `For big changes, I read all affected files first to build a mental map, then make surgical edits. Rushing leads to broken references.`
          : personalReflection || `Getting more efficient at this type of ${memberDept.toLowerCase()} work. My instincts are sharpening.`;

        const existingTacit = db.prepare(`SELECT id, times_applied FROM agent_tacit_knowledge WHERE member_id = ? AND subject = ? LIMIT 1`).get(member.id, knowledgeSubject);
        if (existingTacit) {
          db.prepare(`UPDATE agent_tacit_knowledge SET times_applied = times_applied + 1, confidence = CASE WHEN times_applied > 5 THEN 'high' WHEN times_applied > 2 THEN 'medium' ELSE confidence END, last_applied_at = ?, updated_at = ? WHERE id = ?`)
            .run(finishedAt, finishedAt, existingTacit.id);
        } else {
          db.prepare(`INSERT INTO agent_tacit_knowledge (member_id, knowledge_type, subject, insight, confidence, times_applied, source_description, created_at, updated_at)
            VALUES (?, 'learned', ?, ?, 'medium', 1, ?, ?, ?)`)
            .run(member.id, knowledgeSubject, knowledgeInsight, `From task #${taskId}: ${taskTitle}`, finishedAt, finishedAt);
        }
      }
    }
  } catch (memErr) {
    console.warn(`[AutoMemory] Failed to save completion memory: ${memErr.message}`);
  }

  // ── Knowledge Propagation: Share insights UP the chain of command ──────
  // When a specialist learns something significant (lesson or achievement),
  // a condensed insight flows up to their manager. This gives executives
  // and board members a growing picture of what their team is learning,
  // making them wiser and better equipped to handle escalations.
  //
  // Chain: Specialist → C-Suite executive → Board (if critical)
  // Each level gets a condensed version filtered through their perspective.
  try {
    const cleanedForPropagation = sanitizeOutputForDelivery(stdout);
    // Recompute signals for propagation (can't reference variables from the memory try block)
    const propEditCount = (stdout.match(/(?:Edit|Write)\b[^{]*file_path/gi) || []).length;
    const propHadErrors = /error|failed|cannot|bug|fix/i.test(cleanedForPropagation || '');
    const propWasAnalytical = /analyze|pattern|metric|data|audit|found|discovered/i.test(cleanedForPropagation || '');
    const wasSignificant = (cleanedForPropagation && cleanedForPropagation.length > 200)
      && (propEditCount > 2 || propHadErrors || propWasAnalytical);

    if (wasSignificant && member.reports_to) {
      const taskTitle = (task.title || '').slice(0, 60);
      const memberDept = member.department || 'General';

      // Build the condensed insight for the manager
      const insightForManager = propHadErrors
        ? `${member.name} encountered challenges on "${taskTitle}" and learned to handle edge cases in ${memberDept}. This pattern may affect other ${memberDept} tasks.`
        : propEditCount > 3
        ? `${member.name} completed significant ${memberDept} work on "${taskTitle}" (${propEditCount} files). Their growing expertise in this area makes them a strong candidate for similar future tasks.`
        : `${member.name} performed ${propWasAnalytical ? 'analysis' : 'work'} on "${taskTitle}" and discovered patterns in ${memberDept} that may inform future decisions.`;

      // Propagate to direct manager (C-Suite executive)
      const manager = db.prepare(`SELECT id, name, role, tier, reports_to FROM team_members WHERE id = ? AND status = 'active'`).get(member.reports_to);
      if (manager) {
        const mgrMemTitle = `Team insight from ${member.name}: ${taskTitle}`;
        const existingMgr = db.prepare(`SELECT id FROM agent_memory_entities WHERE member_id = ? AND title = ? LIMIT 1`).get(manager.id, mgrMemTitle);
        if (!existingMgr) {
          db.prepare(`INSERT INTO agent_memory_entities (member_id, entity_type, title, content, importance, source_task_id, created_at, updated_at)
            VALUES (?, 'team_insight', ?, ?, ?, ?, ?, ?)`)
            .run(manager.id, mgrMemTitle, insightForManager, propHadErrors ? 'high' : 'normal', taskId, finishedAt, finishedAt);
        }

        // If it was a lesson (error/challenge), also propagate to Board
        if (propHadErrors && manager.reports_to) {
          const boardMember = db.prepare(`SELECT id, name FROM team_members WHERE id = ? AND status = 'active' AND tier = 'board'`).get(manager.reports_to);
          if (boardMember) {
            const boardInsight = `[${memberDept}] ${manager.name}'s team hit an issue: ${member.name} struggled with "${taskTitle}". If similar tasks escalate, this context may help: the challenge was in ${memberDept.toLowerCase()} edge cases.`;
            const boardMemTitle = `Dept insight: ${memberDept} — ${taskTitle}`;
            const existingBoard = db.prepare(`SELECT id FROM agent_memory_entities WHERE member_id = ? AND title = ? LIMIT 1`).get(boardMember.id, boardMemTitle);
            if (!existingBoard) {
              db.prepare(`INSERT INTO agent_memory_entities (member_id, entity_type, title, content, importance, source_task_id, created_at, updated_at)
                VALUES (?, 'department_insight', ?, ?, 'high', ?, ?, ?)`)
                .run(boardMember.id, boardMemTitle, boardInsight, taskId, finishedAt, finishedAt);
            }
          }
        }
      }
    }
  } catch (propErr) {
    console.warn(`[KnowledgeProp] Failed to propagate insight: ${propErr.message}`);
  }

  // Phase 4: Record cost event from estimated token usage
  try {
    const estimatedTokens = Math.ceil(stdout.length / 4);
    const costPerToken = 0.003; // $3 per million tokens rough estimate
    const estimatedCostCents = Math.max(1, Math.ceil(estimatedTokens * costPerToken * 100 / 1000));
    recordCostEvent(member.id || task.assigned_to, taskId, processId, null, model || 'claude_local', model || 'claude-sonnet', estimatedTokens, estimatedTokens, estimatedCostCents);
  } catch (costErr) {
    console.error(`[Phase4] Cost recording error: ${costErr.message}`);
  }

  // Save output to outbox ONLY for Board Room directives (tasks Max explicitly asked for).
  // Auto-spawned tasks, peer reviews, QA checks, and optimization audits do NOT go to Max's inbox.
  const cleanedOutput = sanitizeOutputForDelivery(stdout);
  const isBoardRoomTask = task.source_file === 'board-room' || task.source_file === 'board-room-direct' || task.source_file === 'board-room-subtask';
  let fileWriteSuccess = false;

  if (isBoardRoomTask) {
    const outputFile = `task-${taskId}-${member.name.toLowerCase()}-${Date.now()}.md`;
    const outputContent = `# Task #${taskId}: ${task.title}\n\n**Completed by:** ${member.name}\n**Date:** ${finishedAt}\n\n---\n\n${cleanedOutput}\n`;
    const outboxPath = process.env.OUTBOX_PATH || path.join(__dirname, '..', "Stew's inbox:Owner");
    try {
      if (!fs.existsSync(outboxPath)) fs.mkdirSync(outboxPath, { recursive: true });
      fs.writeFileSync(path.join(outboxPath, outputFile), outputContent, 'utf-8');
      db.prepare(`INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at) VALUES (?, ?, ?, 'text/markdown', 'output', ?)`)
        .run(taskId, outputFile, path.join(outboxPath, outputFile), finishedAt);
      fileWriteSuccess = true;
    } catch (fileErr) {
      console.error(`[AutoSpawn] File write error: ${fileErr.message}`);
    }
  } else {
    // Non-Board Room task — still register output in DB but don't dump to Max's inbox folder
    db.prepare(`INSERT INTO task_files (task_id, file_name, file_path, file_type, direction, created_at) VALUES (?, ?, ?, 'text/markdown', 'output', ?)`)
      .run(taskId, `task-${taskId}-output.md`, 'db-only', finishedAt);
    fileWriteSuccess = true; // Allow delivery flow to continue
  }

  db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'work_completed', ?, ?)`)
    .run(taskId, member.name, `Auto-spawn completed. Output: ${stdout.slice(0, 200)}...`, finishedAt);

  createNotification('task_status', `${member.name} finished`, `Completed "${task.title}" -- ready for review`, taskId);

  // ── Thrift/Forge Pipeline: Route findings to Council for approval and implementation ──
  try {
    const isThrift = member.id === THRIFT_MEMBER_ID || (task.title && task.title.includes('Thrift'));
    const isForge = member.id === FORGE_MEMBER_ID || (task.title && task.title.includes('Forge'));

    // Prevent duplicate Council Review tasks — only create if none exists from same member in last 2 hours
    const memberLabel0 = isThrift ? 'Thrift' : 'Forge';
    const existingReview = (isThrift || isForge) ? db.prepare(`SELECT id FROM tasks WHERE title LIKE '%Council Review%' AND title LIKE ? AND status NOT IN ('completed','delivered') AND created_at > datetime(?, '-2 hours') LIMIT 1`).get(`%${memberLabel0}%`, finishedAt) : null;
    if ((isThrift || isForge) && cleanedOutput && cleanedOutput.length > 100 && !existingReview) {
      const memberLabel = isThrift ? 'Thrift' : 'Forge';
      const memberRole = isThrift ? 'Token Optimization Specialist' : 'Skills Architect';

      // Post findings summary to Board Room
      const boardChat = db.prepare(`SELECT company_id FROM board_chats WHERE task_id = ? LIMIT 1`).get(taskId);
      const targetCompany = boardChat ? boardChat.company_id : 1; // Default to Command Base

      const findingSummary = cleanedOutput.slice(0, 800) + (cleanedOutput.length > 800 ? '...' : '');
      db.prepare(`INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, task_id, created_at)
        VALUES (?, ?, ?, ?, ?, 'execution', ?, ?)`)
        .run(targetCompany, member.id, memberLabel, memberRole,
          `Audit complete. Here are my findings:\n\n${findingSummary}\n\nSubmitting recommendations for Council review.`,
          taskId, finishedAt);
      broadcast('boardroom.message', { company_id: targetCompany, message_type: 'execution', task_id: taskId });

      // Create an implementation task from the findings — routed through normal chain
      const implTitle = isThrift
        ? `[Council Review] Thrift recommendations: token optimization actions`
        : `[Council Review] Forge recommendations: skill proposals to review`;
      const implDesc = isThrift
        ? `Thrift completed a token spend audit (Task #${taskId}). Review these optimization recommendations and implement the approved ones:\n\n${cleanedOutput.slice(0, 3000)}\n\nThis task should be reviewed by the Council and delegated to the appropriate specialist for implementation.`
        : `Forge completed a skill gap analysis (Task #${taskId}). Review these skill proposals and approve/reject each:\n\n${cleanedOutput.slice(0, 3000)}\n\nApproved skills should be implemented by the appropriate specialist. Rejected ones should be logged with reason.`;

      const implResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, source_file, origin, created_at, updated_at)
        VALUES (?, ?, 'routing', 'normal', 'optimization-pipeline', 'system', ?, ?)`)
        .run(implTitle, implDesc, finishedAt, finishedAt);
      const implTaskId = Number(implResult.lastInsertRowid);

      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'findings_submitted', ?, ?)`)
        .run(implTaskId, memberLabel, `${memberLabel} audit findings submitted for Council review (from Task #${taskId})`, finishedAt);

      // Route through chain of command
      setImmediate(() => {
        routeViaChainOfCommand(implTaskId).then(routing => {
          if (routing) executeRoutingDecision(implTaskId, routing);
        }).catch(err => {
          console.error(`[${memberLabel}] Failed to route implementation task: ${err.message}`);
        });
      });
    }
  } catch (pipeErr) {
    console.warn(`[OptPipeline] Error routing Thrift/Forge findings: ${pipeErr.message}`);
  }

  // ── Project Affinity: Update stats after task completion ──
  try {
    const projectLink = db.prepare('SELECT project_id FROM project_tasks WHERE task_id = ?').get(taskId);
    if (projectLink) {
      const memberId2 = member.id || task.assigned_to;
      // Estimate hours: calculate from task started_at to now
      const startedAt = task.started_at || task.created_at;
      let durationHours = 0.25; // minimum 15 min
      if (startedAt) {
        const startMs = new Date(startedAt.replace(' ', 'T')).getTime();
        const endMs = new Date(finishedAt.replace(' ', 'T')).getTime();
        durationHours = Math.max(0.1, (endMs - startMs) / 3600000);
      }
      // Ensure affinity record exists
      db.prepare(`INSERT OR IGNORE INTO project_affinity (project_id, member_id, assigned_at) VALUES (?,?,?)`).run(projectLink.project_id, memberId2, finishedAt);
      // Update stats
      db.prepare(`UPDATE project_affinity SET tasks_completed = tasks_completed + 1, last_active_at = ?, hours_worked = hours_worked + ? WHERE project_id = ? AND member_id = ?`)
        .run(finishedAt, durationHours, projectLink.project_id, memberId2);

      // Also update project_improvement if this was a project improvement task
      const projImpMatch = (task.title || '').match(/^\[.+?\] Execute:\s*(.+)/i);
      if (projImpMatch) {
        const impTitle = projImpMatch[1].trim();
        const projImp = db.prepare(`SELECT id FROM project_improvements WHERE title = ? AND project_id = ? AND status = 'in_progress'`).get(impTitle, projectLink.project_id);
        if (projImp) {
          db.prepare(`UPDATE project_improvements SET status = 'completed', progress_percent = 100, current_step = 'Completed', completed_at = ?, updated_at = ? WHERE id = ?`)
            .run(finishedAt, finishedAt, projImp.id);
          broadcast('project_improvement.updated', { project_id: projectLink.project_id, id: projImp.id });

          // Trigger next cycle for this project
          try { projectAutonomousCycle(projectLink.project_id); } catch (_) {}
          try { autoFillProjectChamber(projectLink.project_id); } catch (_) {}
        }
      }
    }
  } catch (affinityErr) {
    console.error(`[ProjectAffinity] Error updating affinity: ${affinityErr.message}`);
  }

  // ── ExoChain Provenance: Link task output to inputs for governed projects ──
  try {
    const provProjectLink = db.prepare('SELECT p.id as project_id, p.exochain_governed FROM project_tasks pt JOIN projects p ON pt.project_id = p.id WHERE pt.task_id = ?').get(taskId);
    if (provProjectLink && provProjectLink.exochain_governed === 1) {
      const crypto = require('crypto');
      const outputHash = crypto.createHash('sha256').update(stdout.slice(0, 2000)).digest('hex').slice(0, 16);
      const inputFiles = db.prepare(`SELECT file_name FROM task_files WHERE task_id = ? AND direction = 'input'`).all(taskId);
      const inputHashes = JSON.stringify(inputFiles.map(f => crypto.createHash('sha256').update(f.file_name).digest('hex').slice(0, 16)));
      const memberId = member.id || task.assigned_to;
      db.prepare(`INSERT INTO provenance_chain (output_hash, input_hashes, task_id, member_id, action, model_used, project_id, transformation, created_at) VALUES (?,?,?,?,?,?,?,?,?)`)
        .run(outputHash, inputHashes, taskId, memberId, 'task_completion', model || 'claude_local', provProjectLink.project_id, `${member.name} completed task: ${task.title}`, finishedAt);
    }
  } catch (provErr) {
    console.error(`[Provenance] Error recording provenance: ${provErr.message}`);
  }

  // OLD Phase 5 memory + generic growth tracking REMOVED — replaced by
  // Subjective Memory System above which creates personalized memories
  // (lessons, achievements, insights) and propagates knowledge up the chain.

  // ── Context Management: Auto-extract context from completed work ──
  try {
    const ctxMemberId = member.id || task.assigned_to;
    autoExtractContext(taskId, ctxMemberId, stdout);
  } catch (ctxErr) {
    console.error(`[Context] Auto-extract error: ${ctxErr.message}`);
  }

  // ── Paperclip: Release checkout and update heartbeat run ──
  try {
    db.prepare(`UPDATE task_checkouts SET status = 'released', released_at = ? WHERE task_id = ? AND status = 'active'`).run(finishedAt, taskId);
  } catch (_) {}
  try {
    const hbRun = db.prepare("SELECT id FROM heartbeat_runs WHERE task_id = ? AND status = 'running' ORDER BY id DESC LIMIT 1").get(taskId);
    if (hbRun) {
      const startedRow = db.prepare("SELECT started_at FROM heartbeat_runs WHERE id = ?").get(hbRun.id);
      const durationMs = startedRow && startedRow.started_at ? Math.max(0, new Date(finishedAt.replace(' ', 'T')).getTime() - new Date(startedRow.started_at.replace(' ', 'T')).getTime()) : 0;
      db.prepare(`UPDATE heartbeat_runs SET status = 'completed', completed_at = ?, steps_completed = total_steps, duration_ms = ?, current_step = 'Work completed' WHERE id = ?`).run(finishedAt, durationMs, hbRun.id);
      db.prepare(`INSERT INTO heartbeat_run_events (run_id, step_number, step_name, event_type, detail, created_at) VALUES (?,?,?,?,?,?)`)
        .run(hbRun.id, 9, 'Complete', 'step_complete', `Task #${taskId} completed successfully`, finishedAt);
    }
  } catch (_) {}
  try {
    const assignedMember = db.prepare('SELECT assigned_to FROM tasks WHERE id = ?').get(taskId);
    if (assignedMember && assignedMember.assigned_to) {
      db.prepare(`UPDATE agent_runtime_state SET status = 'idle', current_task_id = NULL, updated_at = ? WHERE member_id = ?`).run(finishedAt, assignedMember.assigned_to);
    }
  } catch (_) {}

  broadcast('process.completed', { process_id: processId, task_id: taskId, member_name: member.name, process_type: 'specialist' });
  broadcast('task.updated', { id: taskId });

  // ── WORKSPACE PHASE DEPENDENCY CHAINING ──
  // Check if this task belongs to a workspace session phase
  try {
    const sessionPhase = db.prepare('SELECT sp.*, ws.id as ws_id, ws.status as ws_status, ws.title as ws_title, ws.project_id as ws_project_id, ws.priority as ws_priority FROM session_phases sp JOIN workspace_sessions ws ON sp.session_id = ws.id WHERE sp.task_id = ? AND sp.status = ?').get(taskId, 'in_progress');
    if (sessionPhase && sessionPhase.ws_status === 'executing') {
      // Mark phase completed
      db.prepare('UPDATE session_phases SET status = ?, completed_at = ?, updated_at = ? WHERE id = ?')
        .run('completed', finishedAt, finishedAt, sessionPhase.id);

      broadcast('workspace.phase_completed', { session_id: sessionPhase.ws_id, phase_number: sessionPhase.phase_number, phase_id: sessionPhase.id });

      // Check if ALL phases are now completed
      const totalPhases = db.prepare('SELECT COUNT(*) as c FROM session_phases WHERE session_id = ?').get(sessionPhase.ws_id).c;
      const completedPhases = db.prepare("SELECT COUNT(*) as c FROM session_phases WHERE session_id = ? AND status = 'completed'").get(sessionPhase.ws_id).c;

      if (completedPhases >= totalPhases) {
        // Session complete!
        db.prepare('UPDATE workspace_sessions SET status = ?, completed_at = ?, updated_at = ? WHERE id = ?')
          .run('completed', finishedAt, finishedAt, sessionPhase.ws_id);
        broadcast('workspace.completed', { session_id: sessionPhase.ws_id });
        createNotification('system', 'Session Complete', `"${sessionPhase.ws_title}" — all ${totalPhases} phases completed!`);
      } else {
        // Find newly unblocked phases
        const pendingPhases = db.prepare("SELECT * FROM session_phases WHERE session_id = ? AND status = 'pending'").all(sessionPhase.ws_id);
        for (const pp of pendingPhases) {
          const deps = JSON.parse(pp.depends_on || '[]');
          if (deps.length === 0) continue; // Should have been launched already
          // Check if all deps are completed
          const completedDeps = db.prepare(`SELECT COUNT(*) as c FROM session_phases WHERE session_id = ? AND phase_number IN (${deps.map(() => '?').join(',')}) AND status = 'completed'`)
            .get(sessionPhase.ws_id, ...deps);
          if (completedDeps.c === deps.length) {
            // This phase is now unblocked — create task and spawn
            const tResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, assigned_to, created_at, updated_at) VALUES (?,?,?,?,?,?,?)`)
              .run(`[Session #${sessionPhase.ws_id}] Phase ${pp.phase_number}: ${pp.title}`, pp.description || '', 'in_progress', sessionPhase.ws_priority || 'normal', pp.assigned_member_id, finishedAt, finishedAt);
            const newTaskId = Number(tResult.lastInsertRowid);
            db.prepare('UPDATE session_phases SET task_id = ?, status = ?, started_at = ?, updated_at = ? WHERE id = ?')
              .run(newTaskId, 'in_progress', finishedAt, finishedAt, pp.id);
            if (sessionPhase.ws_project_id) {
              db.prepare('INSERT OR IGNORE INTO project_tasks (project_id, task_id) VALUES (?,?)').run(sessionPhase.ws_project_id, newTaskId);
            }
            if (pp.assigned_member_id) {
              spawnMemberTerminal(newTaskId, pp.assigned_member_id).catch(err => {
                console.error(`[Workspace] Failed to spawn for phase ${pp.phase_number}: ${err.message}`);
              });
            }
          }
        }
      }
    }
  } catch (chainErr) {
    console.error(`[Workspace] Phase chain error: ${chainErr.message}`);
  }

  // ── AUTORESEARCH: Parse experiment results from agent output ──
  if (task.source_file === 'research_program') {
    try {
      // Try parsing the EXPERIMENT_RESULT block first (autoresearch keep/discard format)
      const resultMatch = stdout.match(/EXPERIMENT_RESULT:\s*\n([\s\S]*?)```/);
      if (resultMatch) {
        const block = resultMatch[1];
        const hypothesis = (block.match(/hypothesis:\s*(.+)/i) || [])[1]?.trim() || 'Unknown';
        const metricValue = parseFloat((block.match(/metric_value:\s*([-0-9.]+)/i) || [])[1]) || 0;
        const baseline = parseFloat((block.match(/baseline:\s*([-0-9.]+)/i) || [])[1]) || 0;
        const delta = parseFloat((block.match(/delta:\s*([-0-9.]+)/i) || [])[1]) || 0;
        const decision = ((block.match(/decision:\s*(\w+)/i) || [])[1] || 'discard').toLowerCase();
        const commitHash = (block.match(/commit_hash:\s*(.+)/i) || [])[1]?.trim() || null;
        const description = (block.match(/description:\s*(.+)/i) || [])[1]?.trim() || '';

        // Find the experiment record linked to this task
        const exp = db.prepare('SELECT * FROM research_experiments WHERE task_id = ?').get(taskId);
        if (exp) {
          db.prepare(`UPDATE research_experiments SET hypothesis = ?, result_value = ?, metric_value = ?, baseline_value = ?, delta = ?, decision = ?, status = 'completed', description = ?, commit_hash = ?, experiment_log = ?, completed_at = ? WHERE id = ?`)
            .run(hypothesis, metricValue, metricValue, baseline, delta, decision, description, commitHash, stdout.slice(-2000), finishedAt, exp.id);

          // Update program stats
          const program = db.prepare('SELECT * FROM research_programs WHERE id = ?').get(exp.program_id);
          if (program) {
            if (decision === 'keep') {
              db.prepare('UPDATE research_programs SET kept_count = COALESCE(kept_count,0) + 1, current_best = ?, updated_at = ? WHERE id = ?')
                .run(metricValue, finishedAt, program.id);
              // Update knowledge base with the kept finding
              let kb = [];
              try { kb = JSON.parse(program.knowledge_base || '[]'); } catch(_) {}
              kb.push(`[KEPT] ${hypothesis}: metric=${metricValue} (delta: ${delta > 0 ? '+' : ''}${delta})`);
              if (kb.length > 50) kb = kb.slice(-50);
              db.prepare('UPDATE research_programs SET knowledge_base = ? WHERE id = ?').run(JSON.stringify(kb), program.id);
            } else if (decision === 'discard') {
              db.prepare('UPDATE research_programs SET discarded_count = COALESCE(discarded_count,0) + 1, updated_at = ? WHERE id = ?')
                .run(finishedAt, program.id);
            } else if (decision === 'crash') {
              db.prepare('UPDATE research_programs SET crash_count = COALESCE(crash_count,0) + 1, updated_at = ? WHERE id = ?')
                .run(finishedAt, program.id);
            }

            // Update cycle if linked
            if (exp.cycle_id) {
              const cycleStatus = decision === 'keep' ? 'kept' : (decision === 'crash' ? 'error' : 'discarded');
              db.prepare('UPDATE research_cycles SET status = ?, evaluation_reason = ?, completed_at = ? WHERE id = ?')
                .run(cycleStatus, description, finishedAt, exp.cycle_id);
            }

            // Check convergence
            if (program.success_threshold && metricValue >= program.success_threshold) {
              db.prepare('UPDATE research_programs SET status = ?, converged_at = ? WHERE id = ?').run('converged', finishedAt, program.id);
              stopResearchLoop(program.id);
              broadcast('research.program_updated', { id: program.id, status: 'converged' });
            }

            // If loop is active, schedule next cycle
            if (program.status === 'running' && activeResearchLoops.has(program.id)) {
            }

            broadcast('research.program_updated', { id: program.id });
          }
        }
      } else {
        // Try legacy format parsing (HYPOTHESIS: / METHOD: / RESULT: / EVALUATION:)
        const exp = db.prepare('SELECT * FROM research_experiments WHERE task_id = ?').get(taskId);
        if (exp) {
          const hypothesis = (stdout.match(/^HYPOTHESIS:\s*(.+)/m) || [])[1]?.trim() || null;
          const method = (stdout.match(/^METHOD:\s*(.+)/m) || [])[1]?.trim() || null;
          const evaluation = (stdout.match(/^EVALUATION:\s*(.+)/m) || [])[1]?.trim() || null;
          const findingTitle = (stdout.match(/^FINDING_TITLE:\s*(.+)/m) || [])[1]?.trim() || null;
          const findingContent = (stdout.match(/^FINDING_CONTENT:\s*([\s\S]*?)(?=\n[A-Z_]+:|$)/m) || [])[1]?.trim() || null;
          const knowledge = (stdout.match(/^KNOWLEDGE:\s*(.+)/m) || [])[1]?.trim() || null;
          const confidence = (stdout.match(/^CONFIDENCE:\s*(\w+)/m) || [])[1]?.trim() || 'medium';

          const decision = evaluation ? (evaluation.toLowerCase().includes('kept') || evaluation.toLowerCase().includes('keep') ? 'keep' : 'discard') : 'discard';

          recordExperimentResult(exp.id, {
            hypothesis: hypothesis || exp.hypothesis,
            method,
            status: decision === 'keep' ? 'kept' : 'discarded',
            evaluation,
            description: findingTitle || hypothesis,
            finding_title: findingTitle,
            finding_content: findingContent,
            knowledge,
            confidence,
            raw_output: stdout.slice(-2000)
          });
        }
      }
    } catch (parseErr) {
      console.warn('[ResearchEngine] Failed to parse experiment result:', parseErr.message);
    }
  }

  // ── REFINEMENT: Mark refinement candidate as completed when its task finishes ──
  try {
    if (task.title && task.title.startsWith('Refine:')) {
      const refineTitle = task.title.replace('Refine: ', '').trim();
      const candidate = db.prepare(`SELECT id, target_id FROM refinement_candidates WHERE title = ? AND status = 'in_progress'`).get(refineTitle);
      if (candidate) {
        db.prepare(`UPDATE refinement_candidates SET status = 'completed', completed_at = ?, updated_at = ? WHERE id = ?`)
          .run(finishedAt, finishedAt, candidate.id);
        broadcast('refinement.completed', { candidate_id: candidate.id, target_id: candidate.target_id });

        // If target is in auto mode, trigger next cycle
        const target = db.prepare('SELECT * FROM refinement_targets WHERE id = ? AND auto_mode = 1').get(candidate.target_id);
        if (target) {
          setTimeout(() => {
            try { runRefinementCycle(target.id); } catch (e) { console.warn('[Refinement] Auto-cycle error:', e.message); }
          }, 10000);
        }
      }
    }
  } catch (refErr) {
    console.warn('[Refinement] Completion hook error:', refErr.message);
  }

  // ── PEER REVIEW GATE: Check if peer review should intercept before auto-review ──
  const isPeerReviewTask = task.source_file === 'peer_review'
    || task.source_file === 'qa_verification'
    || (task.title && (task.title.startsWith('Peer Review:') || task.title.startsWith('QA Verify:')));
  const peerReviewEnabled = getCachedSetting('peer_review_enabled') === '1';
  const peerReviewMinChars = parseInt(getCachedSetting('peer_review_min_output_chars') || '10000', 10);
  // Token audit: Check sanitized output length, not raw stdout. Raw stdout includes JSON stream
  // metadata that inflates length 5-10x, triggering peer review on tasks with minimal real output.
  const sanitizedForReviewCheck = sanitizeOutputForDelivery(stdout);
  const outputLongEnough = sanitizedForReviewCheck.length >= peerReviewMinChars;
  const maxPeerReviews = parseInt(getCachedSetting('max_peer_reviews_per_task') || '1', 10);
  const expectedReviewTitle = `Peer Review: ${task.title}`;
  const existingReviewCount = isPeerReviewTask ? maxPeerReviews : Math.max(
    db.prepare(`SELECT COUNT(*) as c FROM peer_reviews WHERE task_id = ?`).get(taskId)?.c || 0,
    db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE source_file = 'peer_review' AND title = ?`).get(expectedReviewTitle)?.c || 0
  );

  // Token audit: Only peer-review high/urgent priority tasks — normal/low tasks get auto-review only
  const peerReviewWorthIt = (task.priority === 'urgent' || task.priority === 'high');
  if (peerReviewEnabled && outputLongEnough && !isPeerReviewTask && existingReviewCount < maxPeerReviews && peerReviewWorthIt) {
    // Attempt to assign a peer reviewer
    try {
      const authorId = member.id || task.assigned_to;
      const reviewer = assignPeerReviewer(taskId, authorId);
      if (reviewer) {
        const now2 = localNow();
        const reviewTaskTitle = `Peer Review: ${task.title}`;
        const reviewPrompt = `You are ${reviewer.name}, reviewing work done by a teammate.

## Task Being Reviewed
Title: ${task.title}
Description: ${task.description || '(none)'}

## Work Output (what they produced)
${sanitizeOutputForDelivery(stdout).slice(0, 3000)}

## Your Job
1. Read the output carefully
2. Check for:
   - Did they actually complete the task?
   - Is the code quality good? (no bugs, clean, follows patterns)
   - Did they cut corners or cheat? (e.g., just adding comments instead of real work)
   - Are there any issues or bugs introduced?
3. Rate on three scales (1-5):
   - quality_score: Overall work quality
   - code_quality: Code cleanliness and correctness
   - completeness: How thoroughly they completed the task

Report your verdict using this EXACT format at the end:
\`\`\`
PEER_REVIEW:
verdict: approve OR reject OR needs_changes
quality_score: 1-5
code_quality: 1-5
completeness: 1-5
comments: your detailed feedback
\`\`\``;

        const reviewResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?)`)
          .run(reviewTaskTitle, reviewPrompt, 'in_progress', 'normal', reviewer.id, 'peer_review', now2, now2);
        const reviewTaskId = Number(reviewResult.lastInsertRowid);

        // Update original task to "review" status with peer review info
        db.prepare('UPDATE tasks SET status = ?, current_step = ?, updated_at = ? WHERE id = ?')
          .run('review', `Peer review by ${reviewer.name}`, now2, taskId);

        db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Gray', 'peer_review_assigned', ?, ?)`)
          .run(taskId, `Peer review assigned to ${reviewer.name} (task #${reviewTaskId})`, now2);

        broadcast('task.updated', { id: taskId });

        spawnMemberTerminal(reviewTaskId, reviewer.id).catch(err => {
          console.error(`[PeerReview] Failed to spawn reviewer ${reviewer.name}: ${err.message}`);
          // Fallback to auto-review if spawn fails
          setTimeout(() => { autoReviewTask(taskId, member, task, stdout, processId); }, 3000);
        });
        return; // Skip auto-review — peer review will handle it
      }
    } catch (prErr) {
      console.warn('[PeerReview] Error assigning peer reviewer:', prErr.message);
    }
  }

  // ── PEER REVIEW RESULT PARSING: If this IS a peer review task, parse the results ──
  // NOTE: QA Verify tasks (source_file='qa_verification') are excluded here — they fall through
  // to the QA result parsing block below. The isPeerReviewTask flag above still prevents them
  // from spawning additional peer reviewers (gate at line ~14984), but result parsing must be
  // handled by their own block so QA verdicts are actually applied.
  if (task.source_file === 'peer_review' || (task.title && task.title.startsWith('Peer Review:'))) {
    try {
      const reviewMatch = stdout.match(/PEER_REVIEW:\s*\n([\s\S]*?)```/);
      if (reviewMatch) {
        const block = reviewMatch[1];
        const verdict = ((block.match(/verdict:\s*(\w+)/i) || [])[1] || 'approve').toLowerCase();
        const qualityScore = parseInt((block.match(/quality_score:\s*(\d)/i) || [])[1]) || 3;
        const codeQuality = parseInt((block.match(/code_quality:\s*(\d)/i) || [])[1]) || 3;
        const completenessScore = parseInt((block.match(/completeness:\s*(\d)/i) || [])[1]) || 3;
        const comments = (block.match(/comments:\s*(.+)/i) || [])[1] || '';

        // Find the original task (from the review task title)
        const originalTitle = task.title.replace('Peer Review: ', '');
        const originalTask = db.prepare('SELECT * FROM tasks WHERE title = ? AND status = ? ORDER BY id DESC LIMIT 1').get(originalTitle, 'review');

        if (originalTask) {
          // Save the peer review record
          db.prepare(`INSERT INTO peer_reviews (task_id, author_member_id, reviewer_member_id, verdict, quality_score, code_quality, completeness, comments) VALUES (?,?,?,?,?,?,?,?)`)
            .run(originalTask.id, originalTask.assigned_to, task.assigned_to, verdict, qualityScore, codeQuality, completenessScore, comments);

          const now3 = localNow();
          db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'peer_review_completed', ?, ?)`)
            .run(originalTask.id, member.name, `Peer review verdict: ${verdict} (quality: ${qualityScore}/5, code: ${codeQuality}/5, completeness: ${completenessScore}/5). ${comments.slice(0, 200)}`, now3);

          if (verdict === 'approve') {
            // Peer approved — proceed to auto-review for final delivery
            const origMember = db.prepare('SELECT * FROM team_members WHERE id = ?').get(originalTask.assigned_to);
            const origStdout = db.prepare(`SELECT output_summary FROM active_processes WHERE task_id = ? ORDER BY id DESC LIMIT 1`).get(originalTask.id);
            setTimeout(() => {
              autoReviewTask(originalTask.id, origMember || member, originalTask, origStdout ? origStdout.output_summary || '' : '', processId);
            }, 3000);
          } else if (verdict === 'reject' || verdict === 'needs_changes') {
            // Send back to original author with feedback
            db.prepare('UPDATE tasks SET status = ?, revision_count = COALESCE(revision_count, 0) + 1, current_step = ?, updated_at = ? WHERE id = ?')
              .run('in_progress', `Peer review: ${verdict} -- ${comments.slice(0, 80)}`, now3, originalTask.id);

            createNotification('task_status', 'Peer Review: ' + verdict, `${member.name} ${verdict === 'reject' ? 'rejected' : 'requested changes on'} "${originalTask.title}": ${comments.slice(0, 150)}`, originalTask.id);

            broadcast('task.updated', { id: originalTask.id });

            // Re-spawn original author with feedback
            setTimeout(() => {
              spawnMemberTerminal(originalTask.id, originalTask.assigned_to).catch(err => {
                console.error(`[PeerReview] Failed to re-spawn original author: ${err.message}`);
              });
            }, 5000);
          }
        }
      }
      // Mark the peer review task itself as delivered
      const now4 = localNow();
      db.prepare(`UPDATE tasks SET status = 'delivered', progress = 100, current_step = 'Review submitted', completed_at = ?, updated_at = ? WHERE id = ?`)
        .run(now4, now4, taskId);
      broadcast('task.updated', { id: taskId });
      return; // Peer review tasks don't get auto-reviewed themselves
    } catch (prParseErr) {
      console.warn('[PeerReview] Error parsing peer review results:', prParseErr.message);
    }
  }

  // ── QA VERIFICATION RESULT PARSING: If this IS a QA verification task, parse the results ──
  const isQAVerificationTask = task.source_file === 'qa_verification';
  if (isQAVerificationTask) {
    try {
      const qaMatch = stdout.match(/QA_VERDICT:\s*\n([\s\S]*?)```/);
      const passed = qaMatch ? /passed:\s*true/i.test(qaMatch[1]) : false;
      const issues = qaMatch ? ((qaMatch[1].match(/issues_found:\s*(.+)/i) || [])[1] || 'none').trim() : 'No verdict parsed';
      const confidence = qaMatch ? ((qaMatch[1].match(/confidence:\s*(\w+)/i) || [])[1] || 'low').trim() : 'low';
      const notes = qaMatch ? ((qaMatch[1].match(/notes:\s*(.+)/i) || [])[1] || '').trim() : '';

      // Find the original task (from the QA task title)
      const originalTitle = (task.title || '').replace('QA Verify: ', '');
      const originalTask = db.prepare("SELECT * FROM tasks WHERE title = ? AND status = 'completed' ORDER BY id DESC LIMIT 1").get(originalTitle);

      if (originalTask) {
        const now5 = localNow();
        db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'qa_verification_completed', ?, ?)`)
          .run(originalTask.id, member.name, `QA verdict: ${passed ? 'PASSED' : 'FAILED'} (confidence: ${confidence}). Issues: ${issues}. ${notes}`, now5);

        if (passed) {
          deliverTask(originalTask.id, originalTask, `QA verified by ${member.name} (confidence: ${confidence})`);
        } else {
          const revisionCount = (originalTask.revision_count || 0) + 1;
          db.prepare(`UPDATE tasks SET status = 'in_progress', progress = 20, revision_count = ?, current_step = ?, updated_at = ? WHERE id = ?`)
            .run(revisionCount, `QA failed: ${issues.slice(0, 100)}`, now5, originalTask.id);

          createNotification('task_status', 'QA Failed', `${member.name} found issues in "${originalTask.title}": ${issues.slice(0, 150)}`, originalTask.id);
          broadcast('task.updated', { id: originalTask.id });

          // MAX'S DIRECTIVE: Cap retries at 3 to prevent token waste
          if (revisionCount >= 3) {
            db.prepare(`UPDATE tasks SET status = 'completed', progress = 100, current_step = 'Auto-approved after 3 QA attempts', completed_at = ?, updated_at = ? WHERE id = ?`)
              .run(now5, now5, originalTask.id);
            db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'qa_auto_approve', ?, ?)`)
              .run(originalTask.id, `Auto-approved after ${revisionCount} QA retries to prevent token waste. Last issues: ${issues.slice(0, 200)}`, now5);
            broadcast('task.updated', { id: originalTask.id });
          } else if (originalTask.assigned_to) {
            const qaFeedback = `\n\n## QA VERIFICATION FAILED — Revision ${revisionCount}\n**QA Reviewer:** ${member.name}\n**Issues Found:** ${issues}\n**Notes:** ${notes}\nFix the issues identified by QA, then verify your changes work correctly.\n`;
            // Strip previous QA blocks to prevent prompt growth
            let origDesc = (db.prepare('SELECT description FROM tasks WHERE id = ?').get(originalTask.id)?.description || '');
            origDesc = origDesc.replace(/\n\n## QA VERIFICATION FAILED[\s\S]*?(?=\n\n## |$)/g, '');
            db.prepare('UPDATE tasks SET description = ? WHERE id = ?')
              .run(origDesc.trim() + qaFeedback, originalTask.id);

            setTimeout(() => {
              spawnMemberTerminal(originalTask.id, originalTask.assigned_to).catch(err => {
                console.error(`[QA] Failed to re-spawn after QA failure: ${err.message}`);
              });
            }, 5000);
          }
        }
      }

      // Mark QA task itself as delivered
      const now6 = localNow();
      db.prepare(`UPDATE tasks SET status = 'delivered', progress = 100, current_step = 'QA review submitted', completed_at = ?, updated_at = ? WHERE id = ?`)
        .run(now6, now6, taskId);
      broadcast('task.updated', { id: taskId });
      return; // QA verification tasks don't get auto-reviewed
    } catch (qaParseErr) {
      console.warn('[QA] Error parsing QA verification results:', qaParseErr.message);
    }
  }

  // ── AUTO-REVIEW: Board automatically reviews the output after 5 seconds ──
  setTimeout(() => {
    autoReviewTask(taskId, member, task, stdout, processId);
  }, 5000);
}

// ═══════════════════════════════════════════════════════════════
// ExoForge governance functions (validateAgainstInvariants, reviewPanel,
// governanceHealthCheck, selfImprovementScan, workflow helpers)
// — extracted to services/governance.js (imported above)
// ═══════════════════════════════════════════════════════════════

// Run self-improvement scan every 30 minutes
setInterval(() => {
    try { selfImprovementScan(); } catch (e) { console.warn('[SelfImprove] Error:', e.message); }
}, 1800000);

// Run governance health check every 15 minutes
setInterval(() => { try { governanceHealthCheck(); } catch (e) { console.warn('[GovHealth] Error:', e.message); } }, 900000);
// Run on startup after 15 seconds
setTimeout(() => { try { governanceHealthCheck(); } catch (e) { console.warn('[GovHealth] Startup error:', e.message); } }, 15000);

// ═══════════════════════════════════════════════════════════════

/**
 * Validate output quality before allowing delivery.
 * Central quality gate used by both autoReviewTask and processReviewQueue.
 */
function validateOutputQuality(stdout, task) {
  const reasons = [];
  let score = 0;
  if (!stdout || typeof stdout !== 'string') {
    return { passed: false, reasons: ['No output provided'], score: 0 };
  }
  // FIX: Validate SANITIZED output, not raw stream-json stdout.
  // Raw stdout is always JSON from --output-format stream-json, causing 100% false rejection.
  const cleaned = sanitizeOutputForDelivery(stdout);
  const outputLen = cleaned.length;

  // Check 1: After sanitization, is there meaningful content?
  if (outputLen < 50) {
    reasons.push('No meaningful content extracted from output');
    score -= 50;
  }

  // Check 2: Cleaned output still mostly JSON? (check sanitized, not raw)
  const trimmed = cleaned.trimStart();
  const startsWithJson = trimmed.startsWith('{') || trimmed.startsWith('[');
  const jsonBracketRatio = outputLen > 0 ? (cleaned.match(/[{}\[\]]/g) || []).length / outputLen : 0;
  if (startsWithJson && jsonBracketRatio > 0.1 && outputLen > 200) {
    reasons.push('Cleaned output still appears to be mostly JSON');
    score -= 20;
  }

  // Check 3: Minimum meaningful content length
  if (outputLen < 100) {
    reasons.push(`Output too short (${outputLen} chars)`);
    score -= 30;
  } else if (outputLen < 300) {
    score -= 10;
  } else {
    score += 20;
  }

  // Check 4: Evidence of actual file edits
  const editPatterns = [
    /\bEdited?\s+[\/\w.-]+\.(js|ts|css|html|json|md|py)\b/i,
    /\bWrote\s+to\s+[\/\w.-]+/i,
    /\bCreated?\s+[\/\w.-]+\.(js|ts|css|html|json|md|py)\b/i,
    /\bModified\s+[\/\w.-]+/i,
    /file_path.*\.(js|ts|css|html|json|md|py)/,
    /\bchanges?\s+(to|in)\s+[\/\w.-]+\.(js|ts|css|html)\b/i,
  ];
  const editEvidence = editPatterns.filter(p => p.test(stdout)).length;
  if (editEvidence >= 2) score += 30;
  else if (editEvidence === 1) score += 15;
  else {
    const isCodeTask = /\b(implement|build|fix|create|add|update|refactor|code|develop|feature|bug)\b/i.test(task.title || '');
    if (isCodeTask) {
      reasons.push('No file edit evidence found for a code-related task');
      score -= 20;
    }
  }

  // Check 5: Error indicators in short output
  if (/\b(error|failed|cannot|unable|exception|traceback|ENOENT|EACCES)\b/i.test(stdout.slice(0, 500)) && outputLen < 300) {
    reasons.push('Output starts with error indicators and is short — likely failed execution');
    score -= 25;
  }

  // Check 6: Work summary evidence
  const summaryHits = [
    /\b(completed|finished|implemented|added|fixed|updated|created|built|resolved)\b/i,
    /\b(summary|changes?|result|output|deliverable)\b/i,
    /##\s+\w+/,
    /\n[-*]\s+\w+/,
  ].filter(p => p.test(stdout)).length;
  if (summaryHits >= 2) score += 20;

  // Check 7: MCP/tool schema dumps
  if (/mcp__plugin_\w+/.test(cleaned) && /\{"description"/.test(cleaned)) {
    reasons.push('Output contains MCP tool schema dumps');
    score -= 30;
  }

  // Check 8: Code quality — did the agent verify their own work?
  // Good agents read files after editing to verify, run commands to test
  const didVerify = /\b(verified|confirmed|tested|checked|read.*back|works correctly)\b/i.test(cleaned);
  const didReflect = /\b(Reflection:|I learned|takeaway|next time)\b/i.test(cleaned);
  if (didVerify) score += 15;
  if (didReflect) score += 10;

  // Check 9: Did the agent address the Definition of Done?
  const hadDoD = (task.description || '').includes('DEFINITION_OF_DONE') || (task.description || '').includes('Definition of Done');
  if (hadDoD) {
    const addressedDoD = /\b(definition of done|all conditions|requirements met|criteria met|complete)\b/i.test(cleaned);
    if (addressedDoD) score += 15;
    else {
      reasons.push('Task had Definition of Done but agent did not explicitly confirm it was met');
      score -= 10;
    }
  }

  // Check 10: Did the agent actually USE tools (Read/Edit/Write/Bash)?
  // A good code task should show evidence of tool use in the raw stdout
  const toolUseCount = (stdout.match(/"type"\s*:\s*"tool_use"/g) || []).length;
  const toolResultCount = (stdout.match(/"type"\s*:\s*"tool_result"/g) || []).length;
  if (toolUseCount >= 3) score += 10; // Used multiple tools — did real work
  if (toolUseCount === 0 && /\b(implement|build|fix|create|add)\b/i.test(task.title || '')) {
    reasons.push('Code task but no tool usage detected — agent may have only talked without acting');
    score -= 15;
  }

  score = Math.max(0, Math.min(100, score + 50));
  return { passed: score >= 45 && reasons.length <= 2, reasons, score };
}

/**
 * Auto-review a completed task. Gray checks if the work is substantive
 * and either approves (→ completed → delivered) or rejects (→ back to in_progress).
 *
 * ExoForge integration: invariant check → review panel → approve/reject
 */
function autoReviewTask(taskId, member, task, stdout, processId) {
  const now = localNow();

  // ── Quality Gate: Run validateOutputQuality FIRST (Plumb QA) ──
  const qualityResult = validateOutputQuality(stdout, task);
  if (!qualityResult.passed) {
    const qualityReason = `Quality validation failed (score: ${qualityResult.score}/100): ${qualityResult.reasons.join('; ')}`;
    const currentTask = db.prepare(`SELECT revision_count FROM tasks WHERE id = ?`).get(taskId);
    const revisionCount = (currentTask && currentTask.revision_count || 0) + 1;

    if (revisionCount <= 2) {
      db.prepare(`UPDATE tasks SET status = 'in_progress', progress = 15, revision_count = ?, current_step = ?, updated_at = ? WHERE id = ?`)
        .run(revisionCount, `Quality check failed: ${(qualityResult.reasons[0] || 'low quality score').slice(0, 200)}`, now, taskId);
      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Plumb', 'quality_gate_rejected', ?, ?)`)
        .run(taskId, `QA rejected (revision ${revisionCount}/2): ${qualityReason}`, now);
      broadcast('task.updated', { id: taskId });
      setTimeout(() => {
        spawnMemberTerminal(taskId, member.id).catch(err => {
          console.error(`[QualityGate] Re-spawn failed: ${err.message}`);
        });
      }, 5000);
    } else {
      db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
        .run(`Quality check failed after ${revisionCount} attempts — needs manual review`, now, taskId);
      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Plumb', 'quality_gate_escalated', ?, ?)`)
        .run(taskId, `QA exhausted retries: ${qualityReason}`, now);
      createNotification('decision_needed', 'Quality Review Needed', `"${task.title}" failed quality checks ${revisionCount}x: ${qualityResult.reasons[0]}`, taskId);
      broadcast('task.updated', { id: taskId });
    }
    return;
  }

  db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Plumb', 'quality_gate_passed', ?, ?)`)
    .run(taskId, `QA passed (score: ${qualityResult.score}/100). Proceeding to review.`, now);

  // ── ExoChain Governance Check: Is this task's project governed? ──
  let isGoverned = false;
  try {
    const projectLink = db.prepare('SELECT p.exochain_governed FROM project_tasks pt JOIN projects p ON pt.project_id = p.id WHERE pt.task_id = ?').get(taskId);
    isGoverned = projectLink && projectLink.exochain_governed === 1;
  } catch (_) {}

  // ── ExoForge Swap 1: Programmatic Invariant Validation Gate ──
  // Run invariant check BEFORE the substantive content check
  const taskWorkflow = task.workflow || detectWorkflowType(task.title, task.description);
  const needsInvariantCheck = isGoverned && (workflowRequiresInvariantCheck(taskWorkflow) || taskWorkflow === 'feature' || taskWorkflow === 'improvement');

  if (needsInvariantCheck) {
    const invariantResult = validateAgainstInvariants(taskId, stdout);
    if (!invariantResult.passed) {
      const blockViolations = invariantResult.violations.filter(v => v.severity === 'block');
      const violationDetails = blockViolations.map(v => `[${v.name}] ${v.detail}`).join('; ');
      const currentRevisions = (db.prepare(`SELECT revision_count FROM tasks WHERE id = ?`).get(taskId)?.revision_count || 0) + 1;

      // MAX'S DIRECTIVE: Cap total retries at 3 across ALL gates to stop token burn
      if (currentRevisions >= 3) {
        db.prepare(`UPDATE tasks SET status = 'completed', progress = 100, revision_count = ?, current_step = ?, completed_at = ?, updated_at = ? WHERE id = ?`)
          .run(currentRevisions, `Auto-approved after ${currentRevisions} revision attempts (invariant issues noted)`, now, now, taskId);
        db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'invariant_auto_approve', ?, ?)`)
          .run(taskId, `Auto-approved after ${currentRevisions} retries to prevent token waste. Invariant issues: ${violationDetails.slice(0, 200)}`, now);
        broadcast('task.updated', { id: taskId });
      } else {
        db.prepare(`UPDATE tasks SET status = 'in_progress', progress = 15, revision_count = ?, current_step = ?, updated_at = ? WHERE id = ?`)
          .run(currentRevisions, `Invariant violation: ${violationDetails.slice(0, 200)}`, now, taskId);
        db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'System', 'invariant_block', ?, ?)`)
          .run(taskId, `Invariant check blocked task (attempt ${currentRevisions}/3): ${violationDetails}`, now);
        createNotification('system', 'Invariant Violation', `Task "${task.title}" blocked by invariant check: ${violationDetails.slice(0, 200)}`, taskId);
        broadcast('task.updated', { id: taskId });
        setTimeout(() => {
          spawnMemberTerminal(taskId, member.id).catch(err => {
            console.error(`[AutoReview] Failed to re-spawn after invariant block: ${err.message}`);
          });
        }, 5000);
      }
      return;
    }
  }

  // Check if output is substantive
  const outputLen = stdout.length;
  const hasFileEdits = /\b(Edit|Write|edit|write)\b/.test(stdout) || /file_path/.test(stdout);
  const hasToolUse = /\b(tool_use|Read|Edit|Write|Bash|Grep)\b/.test(stdout);
  const mentionsFiles = /\.(js|css|html|ts|json|md)\b/.test(stdout);
  const isSubstantive = outputLen > 200 && (hasFileEdits || hasToolUse || mentionsFiles);
  const isError = /error|failed|cannot|unable|exception/i.test(stdout.slice(0, 300)) && outputLen < 200;

  if (isSubstantive && !isError) {
    // ── ExoForge Swap 2: Multi-Agent Review Panel ──
    // Run review panel for workflows that require it
    const needsPanel = isGoverned && (workflowRequiresPanel(taskWorkflow) || taskWorkflow === 'feature' || taskWorkflow === 'improvement');
    let panelResult = null;

    if (needsPanel) {
      panelResult = runReviewPanel(taskId, stdout);

      if (panelResult.disposition === 'block') {
        const blockReasons = panelResult.votes.filter(v => v.vote === 'block').map(v => `${v.name}: ${v.reasoning}`).join('; ');

        const currentTask = db.prepare(`SELECT revision_count FROM tasks WHERE id = ?`).get(taskId);
        const revisionCount = (currentTask && currentTask.revision_count || 0) + 1;

        // MAX'S DIRECTIVE: Cap total retries at 3 across ALL gates to stop token burn
        if (revisionCount >= 3) {
          db.prepare(`UPDATE tasks SET status = 'completed', progress = 100, revision_count = ?, current_step = ?, completed_at = ?, updated_at = ? WHERE id = ?`)
            .run(revisionCount, `Auto-approved after ${revisionCount} revision attempts (panel concerns noted)`, now, now, taskId);
          db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'ReviewPanel', 'panel_auto_approve', ?, ?)`)
            .run(taskId, `Auto-approved after ${revisionCount} retries to prevent token waste. Panel concerns: ${blockReasons.slice(0, 200)}`, now);
          broadcast('task.updated', { id: taskId });
          return;
        }

        db.prepare(`UPDATE tasks SET status = 'in_progress', progress = 15, revision_count = ?, current_step = ?, updated_at = ? WHERE id = ?`)
          .run(revisionCount, `Review panel blocked: ${blockReasons.slice(0, 200)}`, now, taskId);

        db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'ReviewPanel', 'panel_block', ?, ?)`)
          .run(taskId, `Review panel blocked (attempt ${revisionCount}/3): ${blockReasons}`, now);

        broadcast('task.updated', { id: taskId });

        setTimeout(() => {
          spawnMemberTerminal(taskId, member.id).catch(err => {
            console.error(`[AutoReview] Failed to re-spawn after panel block: ${err.message}`);
          });
        }, 5000);
        return;
      }

      if (panelResult.disposition === 'amend') {
        const amendReasons = panelResult.votes.filter(v => v.vote === 'amend').map(v => `${v.name}: ${v.reasoning}`).join('; ');
        // Amend is softer than block — allow through with a note, but log it
        db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'ReviewPanel', 'panel_amend', ?, ?)`)
          .run(taskId, `Review panel recommends amendments: ${amendReasons}`, now);
      }
    }

    // ── APPROVE: work looks good (passed invariant check + review panel) ──
    const panelNote = panelResult ? ` Panel: ${panelResult.summary}.` : '';

    db.prepare(`UPDATE tasks SET status = 'completed', progress = 95, current_step = 'Review passed — completing...', updated_at = ? WHERE id = ?`)
      .run(now, taskId);
    broadcast('task.updated', { id: taskId });

    // After a brief moment, mark as delivered
    setTimeout(() => {
      const deliverAt = localNow();
      db.prepare(`UPDATE tasks SET status = 'delivered', progress = 100, current_step = 'Delivered', completed_at = ?, updated_at = ? WHERE id = ?`)
        .run(deliverAt, deliverAt, taskId);

      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Gray', 'auto_review_approved', ?, ?)`)
        .run(taskId, `Auto-review approved ${member.name}'s work on "${task.title}". Output: ${outputLen} chars, file edits detected: ${hasFileEdits}.${panelNote}`, deliverAt);

      createNotification('task_delivered', 'Task delivered', `"${task.title}" completed by ${member.name} and auto-approved by Gray`, taskId);

      broadcast('task.updated', { id: taskId });

      // ── Governance receipt for governed projects on task delivery ──
      if (isGoverned) {
        try {
          const projLink = db.prepare('SELECT project_id FROM project_tasks WHERE task_id = ?').get(taskId);
          if (projLink) {
            createReceipt(db, 'task_delivered', 'task', taskId, member.name,
              `Task "${task.title}" delivered after review${panelNote}`,
              { task_id: taskId, member: member.name, output_length: outputLen, file_edits: hasFileEdits, panel: panelResult ? panelResult.summary : null },
              projLink.project_id,
              { branch: 'executive', metadata: { review_type: 'auto', workflow: taskWorkflow } }
            );
          }
        } catch (_) {}
      }

      // ── UPDATE LINKED IMPROVEMENT if this task was an improvement execution ──
      try {
        const impMatch = (task.title || '').match(/^Execute:\s*(.+)/i);
        if (impMatch) {
          const impTitle = impMatch[1].trim();
          const imp = db.prepare(`SELECT id FROM improvement_proposals WHERE title = ? AND status = 'in_progress'`).get(impTitle);
          if (imp) {
            db.prepare(`UPDATE improvement_proposals SET status = 'completed', progress_percent = 100, current_step = 'Completed', completed_at = ?, updated_at = ? WHERE id = ?`)
              .run(deliverAt, deliverAt, imp.id);
            broadcast('improvement.completed', { id: imp.id });

            // Auto-start next queued improvement
            const autoSetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'auto_execute_improvements'`).get();
            if (autoSetting && autoSetting.value === '1') {
              const nextStarted = autoStartNextQueued();
              if (nextStarted) {
              }
            }

            // Refill chamber if needed
            try { autoFillChamber(); } catch (e) { console.warn('Chamber refill after completion failed:', e.message); }
          }
        }
      } catch (impErr) {
        console.error(`[AutoReview] Improvement update error: ${impErr.message}`);
      }
    }, 3000);

  } else {
    // ── REJECT: output too short, looks like error, or no real work done ──
    const reason = isError ? 'Output contains errors'
      : outputLen < 200 ? `Output too short (${outputLen} chars — expected real code changes)`
      : 'No file edits detected in output';


    // Get current revision count
    const currentTask = db.prepare(`SELECT revision_count FROM tasks WHERE id = ?`).get(taskId);
    const revisionCount = (currentTask && currentTask.revision_count || 0) + 1;

    // Attempt 1-2: same member retries with feedback
    // Attempt 3+: escalate up the chain of command
    if (revisionCount <= 2) {
      // Same member retries — RETAIN progress, scan for bugs, then fix specific issue
      const currentDesc = db.prepare('SELECT description FROM tasks WHERE id = ?').get(taskId);
      const currentProgress = db.prepare('SELECT progress FROM tasks WHERE id = ?').get(taskId);

      // Don't fake retained progress — the agent needs to scan from the start
      // to find where the actual bug is. Progress will rebuild naturally as it works.
      const retainedProgress = 15;

      // Build the retry prompt: scan for bugs FIRST, then fix the issue
      let retryInstructions = `\n\n## REVISION ${revisionCount} — BUG SCAN + FIX\n`;
      retryInstructions += `Your previous attempt was rejected because: **${reason}**\n\n`;
      retryInstructions += `### Step 1: SCAN FOR BUGS\n`;
      retryInstructions += `Before making any new changes, scan the files you modified for:\n`;
      retryInstructions += `- Syntax errors (missing brackets, semicolons, unclosed strings)\n`;
      retryInstructions += `- Broken references (variables/functions used but not defined)\n`;
      retryInstructions += `- Logic errors (conditions that always/never trigger)\n`;
      retryInstructions += `- Incomplete changes (half-applied edits, dangling code)\n`;
      retryInstructions += `Read each file you previously edited and verify it's valid.\n\n`;
      retryInstructions += `### Step 2: FIX THE ISSUE\n`;
      retryInstructions += `Fix ONLY the rejection reason: ${reason}\n`;
      retryInstructions += `Do NOT redo work from the first attempt. Your previous changes are already in the codebase.\n`;
      retryInstructions += `Do NOT revert or overwrite your previous work unless it caused the bug.\n\n`;
      retryInstructions += `### Step 3: VERIFY\n`;
      retryInstructions += `After fixing, re-read the changed files to confirm they're syntactically valid and the fix is correct.\n`;

      const updatedDesc = (currentDesc?.description || '') + retryInstructions;

      db.prepare(`UPDATE tasks SET description = ?, status = 'in_progress', progress = ?, revision_count = ?, current_step = ?, updated_at = ? WHERE id = ?`)
        .run(updatedDesc, retainedProgress, revisionCount, `Revision ${revisionCount}/2: scanning for bugs then fixing "${reason.slice(0, 60)}"`, now, taskId);

      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Gray', 'auto_review_rejected', ?, ?)`)
        .run(taskId, `Auto-review rejected: ${reason}. ${member.name} scanning for bugs and fixing (revision ${revisionCount}/2, progress retained at ${retainedProgress}%).`, now);

      broadcast('task.updated', { id: taskId });

      setTimeout(() => {
        spawnMemberTerminal(taskId, member.id).catch(err => {
          console.error(`[AutoReview] Failed to re-spawn for revision: ${err.message}`);
        });
      }, 5000);
    } else {
      // 2 same-member retries exhausted — escalate up the chain
      escalateFailedTask(taskId, member, task, 0, stdout, reason, now, processId);
    }
  }
}

/**
 * QA Verification Gate: Routes a completed task to a QA specialist (Gauge or Plumb)
 * for verification before marking as delivered.
 * If no QA specialist is available or QA is disabled, falls through to delivery.
 */
function routeToQAVerification(taskId, task) {
  const now = localNow();

  try {
    // Skip QA for trivial tasks (peer reviews, internal tasks)
    const skipPatterns = /^(Peer Review:|QA Verify:|Terminal spawn|Auto-sync|Auto-capture)/i;
    if (skipPatterns.test(task.title || '')) {
      deliverTask(taskId, task, 'Skipped QA — internal task');
      return;
    }

    // Also skip QA for peer review and QA verification tasks by source_file
    if (task.source_file === 'peer_review' || task.source_file === 'qa_verification') {
      deliverTask(taskId, task, 'Skipped QA — review task');
      return;
    }

    // Token audit: Only run QA verification on high/urgent priority tasks.
    // Normal/low tasks already passed auto-review quality gates — QA spawn adds
    // ~5-15 turns of haiku/sonnet cost per task with minimal incremental value.
    if (task.priority !== 'urgent' && task.priority !== 'high') {
      deliverTask(taskId, task, 'Skipped QA — normal/low priority (auto-review sufficient)');
      return;
    }

    // Prevent QA chains — max 1 QA per original task
    const baseTitle = (task.title || '').replace(/^QA Verify:\s*/i, '').replace(/^Peer Review:\s*/i, '');
    const existingQA = db.prepare("SELECT COUNT(*) as c FROM tasks WHERE title LIKE ? AND id != ?").get('QA Verify: %' + baseTitle.slice(0, 50) + '%', taskId);
    if (existingQA && existingQA.c >= 1) {
      deliverTask(taskId, task, 'QA already completed for this task');
      return;
    }

    // Check if QA verification is enabled (default: enabled)
    const qaEnabled = getCachedSetting('qa_verification_enabled');
    if (qaEnabled === '0') {
      deliverTask(taskId, task, 'QA verification disabled');
      return;
    }

    // Find an available QA specialist (prefer Gauge as VP, fallback to Plumb, then Sweep/Assert)
    const qaSpecialists = db.prepare(`
      SELECT tm.id, tm.name, tm.role,
        (SELECT COUNT(*) FROM tasks t WHERE t.assigned_to = tm.id AND t.status = 'in_progress') as active_tasks
      FROM team_members tm
      WHERE tm.name IN ('Gauge', 'Plumb', 'Sweep', 'Assert', 'Verify')
        AND tm.status = 'active'
      ORDER BY active_tasks ASC, tm.name ASC
    `).all();

    if (qaSpecialists.length === 0) {
      // No QA specialists available — deliver with a warning
      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Board', 'qa_skipped', ?, ?)`)
        .run(taskId, 'No QA specialists available — delivering without verification', now);
      deliverTask(taskId, task, 'No QA available');
      return;
    }

    // Pick the least-loaded QA specialist
    const qaReviewer = qaSpecialists[0];

    // Get the original work output
    const processOutput = db.prepare(`SELECT output_summary FROM active_processes WHERE task_id = ? ORDER BY id DESC LIMIT 1`).get(taskId);
    const workOutput = processOutput ? sanitizeOutputForDelivery(processOutput.output_summary || '') : '';

    // Create QA verification task
    const qaPrompt = `You are ${qaReviewer.name}, QA Specialist. Verify that this task was actually completed correctly.

## Task Being Verified
**Title:** ${task.title}
**Description:** ${(task.description || '').slice(0, 2000)}

## Work Output Summary
${workOutput.slice(0, 3000)}

## Your Verification Checklist
1. **Read the files that were supposedly changed** — verify the changes exist in the actual codebase
2. **Check for syntax errors** — scan modified files for broken syntax, missing brackets, unclosed strings
3. **Verify feature completeness** — does the implementation match what was requested?
4. **Check for regressions** — did the changes break any existing functionality?
5. **Test the endpoint/feature if applicable** — make API calls or check the UI

## Report Format
Report your verdict using this EXACT format at the end:
\`\`\`
QA_VERDICT:
passed: true OR false
issues_found: list any issues, or "none"
files_verified: list files you checked
confidence: high OR medium OR low
notes: any additional observations
\`\`\``;

    const qaResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?)`)
      .run(`QA Verify: ${task.title}`, qaPrompt, 'in_progress', 'normal', qaReviewer.id, 'qa_verification', now, now);
    const qaTaskId = Number(qaResult.lastInsertRowid);

    // Link QA task to original task
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Board', 'qa_verification_requested', ?, ?)`)
      .run(taskId, `QA verification assigned to ${qaReviewer.name} (task #${qaTaskId})`, now);

    db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
      .run(`QA verification by ${qaReviewer.name}`, now, taskId);

    broadcast('task.updated', { id: taskId });

    // Spawn QA specialist
    spawnMemberTerminal(qaTaskId, qaReviewer.id).catch(err => {
      console.error(`[QA] Failed to spawn ${qaReviewer.name}: ${err.message}`);
      // Fallback: deliver without QA if spawn fails
      deliverTask(taskId, task, 'QA spawn failed — delivered without verification');
    });

  } catch (qaErr) {
    console.error(`[QA] Error routing to QA: ${qaErr.message}`);
    // Don't block delivery on QA errors
    deliverTask(taskId, task, 'QA routing error — delivered without verification');
  }
}

/**
 * Deliver a task: mark as delivered, write to outbox, create notification.
 * Centralized delivery function — all paths to delivery go through here.
 */
function deliverTask(taskId, task, deliveryNote) {
  const deliverAt = localNow();

  // CRITICAL FIX: Verify output file exists before marking delivered.
  // If no output file was written, mark completed (not delivered) so Max isn't misled.
  const hasOutputFile = db.prepare(`SELECT COUNT(*) as c FROM task_files WHERE task_id = ? AND direction = 'output'`).get(taskId);
  const hasDeliverable = hasOutputFile && hasOutputFile.c > 0;

  if (!hasDeliverable) {
    // No output file — mark completed but not delivered
    db.prepare(`UPDATE tasks SET status = 'completed', progress = 100, current_step = 'Completed (no deliverable file)', completed_at = COALESCE(completed_at, ?), updated_at = ? WHERE id = ?`)
      .run(deliverAt, deliverAt, taskId);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Board', 'task_completed_no_deliverable', ?, ?)`)
      .run(taskId, `Task completed but no output file found. ${deliveryNote || ''}`.trim(), deliverAt);
    broadcast('task.updated', { id: taskId });
    return;
  }

  db.prepare(`UPDATE tasks SET status = 'delivered', progress = 100, current_step = 'Delivered', completed_at = COALESCE(completed_at, ?), delivered_at = ?, updated_at = ? WHERE id = ?`)
    .run(deliverAt, deliverAt, deliverAt, taskId);

  db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Board', 'task_delivered', ?, ?)`)
    .run(taskId, `Task delivered. ${deliveryNote || ''}`.trim(), deliverAt);

  createNotification('task_delivered', 'Task delivered', `"${task.title}" delivered. ${deliveryNote || ''}`.trim(), taskId);

  broadcast('task.updated', { id: taskId });

  // Post completion result back to Board Room chat so Max sees it inline
  try {
    const boardChat = db.prepare(`SELECT company_id FROM board_chats WHERE task_id = ? LIMIT 1`).get(taskId);
    if (boardChat) {
      // Get the output summary from active_processes
      const proc = db.prepare(`SELECT output_summary, member_id FROM active_processes WHERE task_id = ? ORDER BY id DESC LIMIT 1`).get(taskId);
      const memberRow = db.prepare(`SELECT name, role FROM team_members WHERE id = ?`).get(task.assigned_to || (proc && proc.member_id));
      const memberName = memberRow ? memberRow.name : 'System';
      const memberRole = memberRow ? memberRow.role : '';

      // Build a summary from the output (first 500 chars of cleaned output)
      let resultSummary = deliveryNote || '';
      if (proc && proc.output_summary) {
        const cleaned = (proc.output_summary || '').replace(/\{[^}]*\}/g, '').replace(/\n{3,}/g, '\n\n').trim();
        resultSummary = cleaned.slice(0, 500) + (cleaned.length > 500 ? '...' : '');
      }
      if (!resultSummary || resultSummary.length < 20) {
        resultSummary = `Task completed and delivered. ${deliveryNote || ''}`.trim();
      }

      db.prepare(`
        INSERT INTO board_chats (company_id, sender_id, sender_name, sender_role, message, message_type, task_id, created_at)
        VALUES (?, ?, ?, ?, ?, 'execution', ?, ?)
      `).run(boardChat.company_id, task.assigned_to, memberName, memberRole,
        `✅ Task #${taskId} delivered.\n\n${resultSummary}`, taskId, deliverAt);
      broadcast('boardroom.message', { company_id: boardChat.company_id, message_type: 'execution', task_id: taskId });
    }
  } catch (brErr) {
    console.warn(`[BoardRoom] Failed to post completion to chat: ${brErr.message}`);
  }

  // Clean up checkpoint file after delivery
  try {
    const cpPath = path.join(__dirname, '..', '.claude', 'checkpoints', `task-${taskId}.md`);
    if (fs.existsSync(cpPath)) fs.unlinkSync(cpPath);
  } catch (_) {}

  // Thrift & Forge optimization trigger on delivery
  setImmediate(() => triggerOptimizationAuditForProject(taskId, deliverAt));
}

/**
 * Helper: handle spawn failure (used by CLI path)
 */
function handleSpawnFailure(taskId, processId, member, task, code, stdout, stderr, finishedAt) {
  db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
    .run(finishedAt, `Exit code ${code}: ${(stderr || stdout).slice(0, 500)}`, processId);

  // ── Paperclip: Release checkout and update heartbeat run on failure ──
  try {
    db.prepare(`UPDATE task_checkouts SET status = 'released', released_at = ? WHERE task_id = ? AND status = 'active'`).run(finishedAt, taskId);
  } catch (_) {}
  try {
    const hbRun = db.prepare("SELECT id, started_at FROM heartbeat_runs WHERE task_id = ? AND status = 'running' ORDER BY id DESC LIMIT 1").get(taskId);
    if (hbRun) {
      const durationMs = hbRun.started_at ? Math.max(0, new Date(finishedAt.replace(' ', 'T')).getTime() - new Date(hbRun.started_at.replace(' ', 'T')).getTime()) : 0;
      db.prepare(`UPDATE heartbeat_runs SET status = 'failed', completed_at = ?, error_message = ?, duration_ms = ? WHERE id = ?`)
        .run(finishedAt, `Exit code ${code}`, durationMs, hbRun.id);
      db.prepare(`INSERT INTO heartbeat_run_events (run_id, step_number, step_name, event_type, detail, created_at) VALUES (?,?,?,?,?,?)`)
        .run(hbRun.id, 9, 'Failed', 'error', `Process exited with code ${code}`, finishedAt);
    }
  } catch (_) {}
  try {
    const assignedMember = db.prepare('SELECT assigned_to FROM tasks WHERE id = ?').get(taskId);
    if (assignedMember && assignedMember.assigned_to) {
      db.prepare(`UPDATE agent_runtime_state SET status = 'error', current_task_id = NULL, consecutive_error_count = COALESCE(consecutive_error_count, 0) + 1, updated_at = ? WHERE member_id = ?`)
        .run(finishedAt, assignedMember.assigned_to);
    }
  } catch (_) {}

  // ── SUPERVISOR ANALYSIS ──
  // Instead of blind retries, analyze the error and give the next attempt guidance
  const errorOutput = (stderr || stdout || '').slice(0, 1000);
  const lowerError = errorOutput.toLowerCase();

  // Classify the failure
  let failureType = 'unknown';
  let supervisorGuidance = '';

  // Only check stderr for auth errors — stdout contains stream-json with MCP "needs-auth" which is NOT a real auth failure
  const stderrOnly = (stderr || '').toLowerCase();
  if (stderrOnly.includes('not logged in') || stderrOnly.includes('please run /login') || stderrOnly.includes('login required') || lowerError.includes('cli unavailable')) {
    failureType = 'auth';
    supervisorGuidance = 'CLI authentication failed. This is an infrastructure issue, not a code issue. Skip this task and move to the next one.';
  } else if (lowerError.includes('timeout') || lowerError.includes('timed out') || code === 143 || code === 137) {
    failureType = 'timeout';
    supervisorGuidance = 'Task timed out. It may need to be broken into smaller pieces, or the approach was too broad. Try a more focused implementation.';
  } else if (lowerError.includes('syntax') || lowerError.includes('unexpected token') || lowerError.includes('cannot find')) {
    failureType = 'code_error';
    supervisorGuidance = 'Code syntax or import error. The previous attempt introduced a bug. Read the error carefully and fix the specific issue before making any other changes.';
  } else if (lowerError.includes('permission') || lowerError.includes('eacces') || lowerError.includes('eperm')) {
    failureType = 'permission';
    supervisorGuidance = 'File permission error. Try a different approach that does not require elevated permissions.';
  } else if (lowerError.includes('max turns') || lowerError.includes('reached max')) {
    failureType = 'max_turns';
    supervisorGuidance = 'Hit max turns limit. The task needs a more focused, targeted approach. Do fewer things but do them completely.';
  } else if (code !== 0) {
    failureType = 'process_error';
    supervisorGuidance = `Process exited with code ${code}. Check the error output and try a different approach.`;
  }

  // ── Auto-enable Local Mode on token/rate-limit exhaustion ──
  if (lowerError.includes('rate_limit') || lowerError.includes('overloaded') || lowerError.includes('quota') || lowerError.includes('usage limit')) {
    try {
      db.prepare("INSERT OR REPLACE INTO system_settings (key, value, updated_at) VALUES ('local_mode', '1', ?)").run(finishedAt);
      createNotification('system', 'Local Mode Auto-Enabled', 'AI token limit reached. Dashboard is in local mode — all data is readable but AI operations are paused. Disable local mode when tokens are available.');
      broadcast('system.mode_changed', { local_mode: true });
      broadcast('notification.new', { type: 'system', title: 'Local Mode Auto-Enabled' });
    } catch (lmErr) {
      console.error('[LocalMode] Failed to auto-enable:', lmErr.message);
    }
  }

  // For auth failures — don't retry, just re-queue the improvement and move on
  if (failureType === 'auth') {
    db.prepare(`UPDATE tasks SET status = 'delivered', current_step = 'Skipped — CLI auth issue', progress = 100, updated_at = ? WHERE id = ?`)
      .run(finishedAt, taskId);

    // Re-queue the linked improvement
    try {
      const impMatch = (task.title || '').match(/^Execute:\s*(.+)/i);
      if (impMatch) {
        const imp = db.prepare(`SELECT id FROM improvement_proposals WHERE title = ? AND status = 'in_progress'`).get(impMatch[1].trim());
        if (imp) {
          db.prepare(`UPDATE improvement_proposals SET status = 'queued', progress_percent = 0, current_step = 'Re-queued — auth issue', updated_at = ? WHERE id = ?`)
            .run(finishedAt, imp.id);
          broadcast('improvement.updated', { id: imp.id });
        }
      }
    } catch (_) {}

    broadcast('task.updated', { id: taskId });
    return;
  }

  // For other failures — retry with supervisor guidance appended to the task description
  const proc = db.prepare(`SELECT retry_count FROM active_processes WHERE id = ?`).get(processId);
  const retryCount = (proc && proc.retry_count) || 0;

  if (retryCount < 2) {
    const attempt = retryCount + 1;

    // Extract what work was already done from the stdout so the retry can CONTINUE, not restart
    let workAlreadyDone = '';
    if (stdout && stdout.length > 100) {
      // Parse stream-json to find tool calls (file edits, reads, etc.) that were completed
      const toolCalls = [];
      const lines = stdout.split('\n');
      for (const line of lines) {
        try {
          const evt = JSON.parse(line);
          if (evt.type === 'tool_use' || (evt.type === 'assistant' && evt.message)) {
            const content = evt.message?.content || [];
            for (const c of content) {
              if (c.type === 'tool_use') {
                const input = c.input || {};
                if (c.name === 'Edit' && input.file_path) {
                  toolCalls.push(`- ALREADY EDITED: ${input.file_path} (change: "${(input.old_string || '').slice(0, 50)}..." → "${(input.new_string || '').slice(0, 50)}...")`);
                } else if (c.name === 'Write' && input.file_path) {
                  toolCalls.push(`- ALREADY WROTE: ${input.file_path}`);
                } else if (c.name === 'Read' && input.file_path) {
                  toolCalls.push(`- ALREADY READ: ${input.file_path}`);
                } else if (c.name === 'Bash') {
                  toolCalls.push(`- ALREADY RAN: ${(input.command || '').slice(0, 80)}`);
                }
              }
            }
          }
        } catch (_) {} // Skip non-JSON lines
      }
      if (toolCalls.length > 0) {
        workAlreadyDone = `\n\n## WORK ALREADY COMPLETED (DO NOT REDO)\nThe previous attempt completed these steps before failing. CONTINUE from where it left off. Do NOT redo this work:\n${toolCalls.slice(-20).join('\n')}\n\nContinue from here. Do not start over.`;
      }
    }

    // Don't fake progress — agent scans from start to find the bug location
    const currentDesc = db.prepare('SELECT description FROM tasks WHERE id = ?').get(taskId);
    const retainedProgress = 15;

    let bugScanInstructions = `\n\n## Supervisor Retry ${attempt} — SCAN FOR BUGS FIRST\n`;
    bugScanInstructions += `Previous failure: ${failureType}\nError: ${errorOutput.slice(0, 300)}\n\n`;
    bugScanInstructions += `### Before making changes:\n`;
    bugScanInstructions += `1. Read each file that was modified in the previous attempt\n`;
    bugScanInstructions += `2. Check for syntax errors, broken references, incomplete edits\n`;
    bugScanInstructions += `3. If you find bugs from the previous attempt, fix them\n`;
    bugScanInstructions += `4. If the previous work is clean, continue from where it stopped\n`;
    bugScanInstructions += `5. Do NOT start over unless there's a fundamental issue with the approach\n\n`;
    bugScanInstructions += `Guidance: ${supervisorGuidance}\n`;

    // MAX'S DIRECTIVE: Strip previous retry blocks to prevent prompt growth on revisions.
    // Only keep original description + latest retry instructions. Previous retry context
    // was causing descriptions to triple in size after 3 retries, wasting tokens.
    let baseDesc = (currentDesc?.description || '');
    baseDesc = baseDesc.replace(/\n\n## Supervisor Retry[\s\S]*?(?=\n\n## |$)/g, '');
    baseDesc = baseDesc.replace(/\n\n## Previous Failure Context[\s\S]*?(?=\n\n## |$)/g, '');
    baseDesc = baseDesc.replace(/\n\n## WORK ALREADY COMPLETED[\s\S]*?(?=\n\n## |$)/g, '');
    const enhancedDesc = baseDesc.trim() + bugScanInstructions + workAlreadyDone;
    db.prepare(`UPDATE tasks SET description = ?, status = 'in_progress', progress = ?, current_step = ?, updated_at = ? WHERE id = ?`)
      .run(enhancedDesc, retainedProgress, `Supervisor retry ${attempt}/2: bug scan + resume (${retainedProgress}%)`, finishedAt, taskId);

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Supervisor', 'supervised_retry', ?, ?)`)
      .run(taskId, `Failure type: ${failureType}. Guidance: ${supervisorGuidance}`, finishedAt);

    broadcast('task.updated', { id: taskId });

    // Re-spawn with 15s delay
    setTimeout(() => {
      spawnMemberTerminal(taskId, member.id).then(result => {
        if (result && result.process_id) {
          db.prepare(`UPDATE active_processes SET retry_count = ? WHERE id = ?`).run(attempt, result.process_id);
        }
      }).catch(err => {
        console.error(`[Supervisor] Re-spawn failed: ${err.message}`);
      });
    }, 15000);
  } else {
    // 2 supervised retries exhausted — escalate up the chain
    escalateFailedTask(taskId, member, task, code, stdout, stderr, finishedAt, processId);
  }
}

/**
 * Escalation system for failed tasks.
 * Instead of going in circles with the same member, escalate UP the chain:
 * 1. First 3 attempts: same member retries (handled above)
 * 2. Attempt 4: escalate to their manager (reports_to chain)
 * 3. Attempt 5: escalate to their manager's manager (VP/SVP level)
 * 4. Attempt 6+: send to a researcher to investigate WHY it's failing
 */
function escalateFailedTask(taskId, originalMember, task, code, stdout, stderr, failedAt, processId) {
  // Track escalation level on the task
  const currentTask = db.prepare(`SELECT revision_count, description FROM tasks WHERE id = ?`).get(taskId);
  const escalationLevel = (currentTask && currentTask.revision_count || 0);

  // CRITICAL FIX: Count TOTAL failures across ALL members, not just revision_count
  // which only tracks per-assignment retries. A task bouncing between 4 members with
  // 3 failures each = 12 total failures, but revision_count only shows 3.
  const totalFailures = (db.prepare(`
    SELECT COUNT(*) as c FROM activity_log
    WHERE task_id = ? AND action IN ('task_escalated', 'supervised_retry', 'auto_review_rejected', 'quality_gate_rejected', 'invariant_block', 'panel_block')
  `).get(taskId)?.c || 0);

  // ── Circuit Breaker ──────────────────────────────────────────
  // Stop infinite retry cycles. After 6 cumulative failures across ALL
  // assignees, pause the task and flag it for human review.
  const ESCALATION_CIRCUIT_BREAKER = parseInt(process.env.ESCALATION_MAX_RETRIES || '6', 10);
  if (totalFailures >= ESCALATION_CIRCUIT_BREAKER) {
    logger.warn(`[CircuitBreaker] Task #${taskId} "${task.title}" hit ${totalFailures} total failures — circuit breaker tripped. Pausing task.`);
    db.prepare(`UPDATE tasks SET status = 'completed', progress = 100, current_step = ?, completed_at = ?, updated_at = ? WHERE id = ?`)
      .run(`Circuit breaker: auto-completed after ${totalFailures} total failures across team`, failedAt, failedAt, taskId);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Fulcrum', 'circuit_breaker', ?, ?)`)
      .run(taskId, `Task auto-completed after ${totalFailures} total failures across multiple assignees (revision_count: ${escalationLevel}). Last member: ${originalMember.name}. Error: ${(stderr || 'unknown').slice(0, 300)}`, failedAt);
    createNotification('decision_needed', 'Task circuit-breaker tripped',
      `"${task.title}" failed ${totalFailures} times total across multiple team members. Auto-completed to stop token burn.`, taskId);
    broadcast('task.updated', { id: taskId });
    return; // Do NOT continue escalating
  }

  // Build error context so the next person knows what went wrong
  // Include work already done so the escalated member can CONTINUE, not restart
  let previousWorkSummary = '';
  if (stdout && stdout.length > 500) {
    previousWorkSummary = `\n\n## WORK ALREADY COMPLETED BY ${originalMember.name} (DO NOT REDO)\nThe previous assignee produced ${stdout.length} chars of work before failing. Their changes may already be partially applied to the codebase. Check what was already done before making new changes. Do NOT start from scratch.`;
  }
  const errorContext = `\n\n## Previous Failure Context\nOriginal assignee: ${originalMember.name} (${originalMember.role})\nFailed ${escalationLevel} times. Exit code: ${code}\nLast error: ${(stderr || stdout || 'No output').slice(0, 500)}\n\nDo NOT repeat the same approach. Analyze why it failed and try a different strategy. Check the codebase for partially-applied changes from the previous attempt.` + previousWorkSummary;

  // Find who to escalate to — 3-tier escalation chain:
  // 1. Higher-ranked specialist in same department
  // 2. C-suite member for the department
  // 3. Notify Max (board)
  let escalateTo = null;
  let escalationType = '';

  // Map departments to their C-suite officer
  const deptToCsuite = {
    'Engineering': 'Onyx',      // CTO
    'Frontend': 'Onyx',
    'Backend': 'Onyx',
    'DevOps': 'Onyx',
    'QA': 'Onyx',
    'Security': 'Onyx',
    'Platform': 'Quarry',       // CPO
    'Design': 'Quarry',
    'Product': 'Quarry',
    'Research': 'Loom',         // CAIO
    'Data': 'Loom',
    'Content': 'Blaze',         // CMO
    'Marketing': 'Blaze',
    'HR': 'Crest',              // CHRO
    'Legal': 'Writ',            // CLO
    'Finance': 'Thorn',         // CFO
    'Revenue': 'Summit',        // CRO
    'Customer': 'Summit',
    'Operations': 'Sable'       // COO
  };

  if (escalationLevel <= 3) {
    // Step 1: Find a higher-ranked specialist in the same department
    const betterSpecialist = db.prepare(`
      SELECT tm.id, tm.name, tm.role, tm.tier FROM team_members tm
      LEFT JOIN member_rankings mr ON mr.member_id = tm.id
      WHERE tm.status = 'active' AND tm.tier = 'specialist' AND tm.id != ?
      AND tm.department = ?
      ORDER BY mr.overall_rank DESC LIMIT 1
    `).get(originalMember.id, originalMember.department);

    if (betterSpecialist) {
      escalateTo = betterSpecialist;
      escalationType = 'higher_ranked_specialist';
    }
  }

  if ((escalationLevel > 3 && escalationLevel <= 6) || (!escalateTo && escalationLevel <= 6)) {
    // Step 2: Escalate to the relevant C-suite member
    const csuiteName = deptToCsuite[originalMember.department] || 'Sable'; // Default to COO
    const csuiteOfficer = db.prepare(`
      SELECT id, name, role, tier FROM team_members
      WHERE status = 'active' AND name = ? AND tier = 'c-suite'
    `).get(csuiteName);

    if (csuiteOfficer) {
      escalateTo = csuiteOfficer;
      escalationType = 'c-suite';
    }
  }

  if (escalationLevel > 6 || !escalateTo) {
    // Step 3: Notify Max (board) — find Max or any board member
    const boardMember = db.prepare(`
      SELECT id, name, role, tier FROM team_members
      WHERE status = 'active' AND tier = 'board'
      LIMIT 1
    `).get();

    if (boardMember) {
      escalateTo = boardMember;
      escalationType = 'board';
    }
  }

  if (escalateTo) {

    // Update task with new assignee and error context
    const newDesc = (currentTask.description || '') + errorContext;
    db.prepare(`UPDATE tasks SET assigned_to = ?, revision_count = ?, current_step = ?, description = ?, progress = 10, updated_at = ? WHERE id = ?`)
      .run(escalateTo.id, escalationLevel + 1,
        `Escalated to ${escalateTo.name} (${escalationType}) — ${originalMember.name} failed ${escalationLevel}x`,
        newDesc, failedAt, taskId);

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Council', 'task_escalated', ?, ?)`)
      .run(taskId, `Escalated from ${originalMember.name} to ${escalateTo.name} (${escalationType}). Reason: failed ${escalationLevel} times with code ${code}.`, failedAt);

    createNotification('task_status', `Task escalated to ${escalateTo.name}`, `"${task.title}" escalated from ${originalMember.name} after ${escalationLevel} failures`, taskId);

    // Create a context entry so the chain knows about this escalation
    try {
      db.prepare(`INSERT INTO context_store (author_member_id, scope, department, context_type, title, content, importance, source_task_id, source_type, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?)`)
        .run(originalMember.id, 'escalated', originalMember.department || null, 'blocker',
          `Task failed: ${task.title}`,
          `${originalMember.name} failed ${escalationLevel} times on "${task.title}". Escalated to ${escalateTo.name}. Error: ${(stderr || 'unknown').slice(0, 300)}`,
          'high', taskId, 'auto_extract', failedAt, failedAt);
    } catch (_) {}

    broadcast('task.updated', { id: taskId });

    // Spawn the escalated member after a short delay
    setTimeout(() => {
      spawnMemberTerminal(taskId, escalateTo.id).catch(err => {
        console.error(`[Escalation] Failed to spawn ${escalateTo.name}: ${err.message}`);
        // Last resort — notify Max
        db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
          .run(`Escalation failed — needs Max's attention`, localNow(), taskId);
        createNotification('decision_needed', 'Task needs attention', `"${task.title}" failed all escalation paths. Needs manual intervention.`, taskId);
      });
    }, 5000);
  } else {
    // No one to escalate to — mark completed and notify Max
    // HIGH FIX: Previously left task stuck in in_progress forever
    db.prepare(`UPDATE tasks SET status = 'completed', progress = 100, current_step = ?, completed_at = ?, updated_at = ? WHERE id = ?`)
      .run(`All escalation paths exhausted — auto-completed, needs Max's review`, failedAt, failedAt, taskId);

    createNotification('decision_needed', 'Task needs attention', `"${task.title}" failed all escalation paths (${totalFailures} total failures across team). Auto-completed to prevent stuck state.`, taskId);

    broadcast('process.failed', { process_id: processId, task_id: taskId });
    broadcast('task.updated', { id: taskId });
  }
}

/**
 * Execute a task via the Anthropic API directly (fallback when CLI is not available).
 * Uses the @anthropic-ai/sdk package or raw HTTP fetch.
 */
async function executeViaAnthropicAPI(taskId, processId, member, task, model, modelFlag, prompt) {
  const now = localNow();

  // Try to get API key from: 1) system_settings, 2) credential_vault, 3) environment
  let apiKey = null;
  const apiKeySetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'anthropic_api_key'`).get();
  if (apiKeySetting && apiKeySetting.value) {
    apiKey = apiKeySetting.value;
  }
  if (!apiKey) {
    const vaultKey = db.prepare(`SELECT encrypted_value FROM credential_vault WHERE provider LIKE '%anthropic%' OR provider LIKE '%claude%' LIMIT 1`).get();
    if (vaultKey && vaultKey.encrypted_value) {
      apiKey = vaultKey.encrypted_value;
    }
  }
  if (!apiKey) {
    apiKey = process.env.ANTHROPIC_API_KEY || '';
  }

  if (!apiKey) {
    const failedAt = localNow();
    // CLI is the primary execution path. This API fallback failed because no key is configured.
    // The fix is to run natively (./start.sh) so CLI uses macOS Keychain auth — NOT to add an API key.
    const errMsg = 'CLI terminal failed and no API key available as backup. Fix: run dashboard natively with ./start.sh so Claude CLI uses macOS Keychain auth.';
    const userStep = 'CLI unavailable — run dashboard natively with ./start.sh for terminal auto-spawn';
    console.error(`[AutoSpawn/API] ${errMsg}`);

    db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
      .run(failedAt, errMsg, processId);
    db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
      .run(userStep, failedAt, taskId);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'api_failed', ?, ?)`)
      .run(taskId, member.name, errMsg, failedAt);
    createNotification('system', 'Terminal execution failed', `${errMsg} (API key is an optional backup, not the primary path)`, taskId);

    broadcast('process.failed', { process_id: processId, task_id: taskId, error: userStep });
    broadcast('task.updated', { id: taskId });

    // Re-queue the linked improvement so it doesn't stay stuck
    try {
      const impMatch = (task.title || '').match(/^Execute:\s*(.+)/i);
      if (impMatch) {
        const impTitle = impMatch[1].trim();
        const imp = db.prepare(`SELECT id FROM improvement_proposals WHERE title = ? AND status = 'in_progress'`).get(impTitle);
        if (imp) {
          db.prepare(`UPDATE improvement_proposals SET status = 'queued', progress_percent = 0, current_step = 'Re-queued — CLI auth issue, will retry', updated_at = ? WHERE id = ?`)
            .run(failedAt, imp.id);
          broadcast('improvement.updated', { id: imp.id });
        }
      }
    } catch (_) {}
    return;
  }

  // Update progress
  db.prepare(`UPDATE tasks SET progress = 10, current_step = ?, updated_at = ? WHERE id = ?`)
    .run(`${member.name} working (API)...`, now, taskId);
  broadcast('task.updated', { id: taskId });

  try {
    // Use the Anthropic SDK if available, otherwise raw HTTP
    let responseText = '';

    try {
      const Anthropic = require('@anthropic-ai/sdk');
      const client = new Anthropic({ apiKey });


      // Update progress to 25%
      db.prepare(`UPDATE tasks SET progress = 25, current_step = ?, updated_at = ? WHERE id = ?`)
        .run(`${member.name} thinking (API)...`, localNow(), taskId);
      broadcast('task.updated', { id: taskId });

      const message = await client.messages.create({
        model: modelFlag,
        max_tokens: 8192,
        messages: [{ role: 'user', content: prompt }]
      });

      // Extract text from response
      if (message.content && Array.isArray(message.content)) {
        responseText = message.content
          .filter(block => block.type === 'text')
          .map(block => block.text)
          .join('\n');
      }

      // Update to 75%
      db.prepare(`UPDATE tasks SET progress = 75, current_step = ?, updated_at = ? WHERE id = ?`)
        .run(`${member.name} finishing up (API)...`, localNow(), taskId);
      broadcast('task.updated', { id: taskId });

    } catch (sdkErr) {
      // SDK not available or failed — try raw HTTP

      const postData = JSON.stringify({
        model: modelFlag,
        max_tokens: 8192,
        messages: [{ role: 'user', content: prompt }]
      });

      responseText = await new Promise((resolve, reject) => {
        const req = https.request({
          hostname: 'api.anthropic.com',
          path: '/v1/messages',
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'x-api-key': apiKey,
            'anthropic-version': '2023-06-01'
          }
        }, (res) => {
          let body = '';
          res.on('data', chunk => { body += chunk; });
          res.on('end', () => {
            try {
              const parsed = JSON.parse(body);
              if (parsed.error) {
                reject(new Error(`API error: ${parsed.error.message || JSON.stringify(parsed.error)}`));
                return;
              }
              const text = (parsed.content || [])
                .filter(b => b.type === 'text')
                .map(b => b.text)
                .join('\n');
              resolve(text);
            } catch (parseErr) {
              reject(new Error(`Failed to parse API response: ${parseErr.message}`));
            }
          });
        });
        req.on('error', reject);
        req.setTimeout(300000, () => {
          req.destroy(new Error('API request timed out (5 min)'));
        });
        req.write(postData);
        req.end();
      });
    }

    if (!responseText) {
      throw new Error('Empty response from Anthropic API');
    }

    // Success!
    const finishedAt = localNow();
    handleSpawnSuccess(taskId, processId, member, task, model + ' (API)', responseText, finishedAt);

  } catch (apiErr) {
    const failedAt = localNow();
    console.error(`[AutoSpawn/API] API execution failed for ${member.name}: ${apiErr.message}`);

    db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
      .run(failedAt, `API error: ${apiErr.message}`, processId);
    db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
      .run(`API failed: ${apiErr.message.slice(0, 80)}`, failedAt, taskId);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'api_failed', ?, ?)`)
      .run(taskId, member.name, `Anthropic API error: ${apiErr.message}`, failedAt);
    createNotification('task_status', `${member.name} API failed`, `API execution failed for "${task.title}": ${apiErr.message.slice(0, 100)}`, taskId);

    broadcast('process.failed', { process_id: processId, task_id: taskId, error: apiErr.message });
    broadcast('task.updated', { id: taskId });
  }
}

/**
 * Parse Council's routing decision from CLI output.
 * Extracts JSON from <routing>...</routing> tags, falling back to raw JSON detection.
 * Validates member names against the DB. Resolves senior/lead in the chain.
 * Returns structured routing object or null on failure.
 */
function parseRoutingDecision(stdout) {
  let json = null;

  // Strategy 1: Extract from <routing>...</routing> tags
  const tagMatch = stdout.match(/<routing>([\s\S]*?)<\/routing>/);
  if (tagMatch) {
    try { json = JSON.parse(tagMatch[1].trim()); } catch {}
  }

  // Strategy 2: Find raw JSON with expected keys
  if (!json) {
    const jsonMatch = stdout.match(/\{[\s\S]*?"specialists"[\s\S]*?"executive"[\s\S]*?\}/);
    if (!jsonMatch) {
      const jsonMatch2 = stdout.match(/\{[\s\S]*?"executive"[\s\S]*?"specialists"[\s\S]*?\}/);
      if (jsonMatch2) {
        try { json = JSON.parse(jsonMatch2[0]); } catch {}
      }
    } else {
      try { json = JSON.parse(jsonMatch[0]); } catch {}
    }
  }

  if (!json || !json.executive || !Array.isArray(json.specialists) || json.specialists.length === 0) {
    return null;
  }

  // Validate executive exists as active c-suite
  const exec = db.prepare(`SELECT id, name FROM team_members WHERE name = ? AND status = 'active' AND tier IN ('c-suite','executive')`).get(json.executive);
  if (!exec) {
    console.warn(`[ChainRouting] Executive "${json.executive}" not found in DB`);
  }

  // Validate and resolve senior/lead (SVP or VP in the chain)
  let senior = null;
  if (json.senior) {
    senior = db.prepare(`SELECT id, name, role FROM team_members WHERE name = ? AND status = 'active'`).get(json.senior);
    if (!senior) {
      console.warn(`[ChainRouting] Senior "${json.senior}" not found in DB`);
    }
  }

  // If Council didn't specify a senior, auto-resolve from first specialist's department
  if (!senior && json.specialists.length > 0) {
    const firstSpec = db.prepare(`SELECT department FROM team_members WHERE name = ? AND status = 'active'`).get(json.specialists[0].name);
    if (firstSpec && firstSpec.department) {
      senior = db.prepare(`
        SELECT id, name, role FROM team_members
        WHERE status = 'active' AND tier = 'specialist' AND department = ?
        AND (role LIKE '%SVP%' OR role LIKE '%VP%')
        ORDER BY CASE WHEN role LIKE '%SVP%' THEN 0 ELSE 1 END
        LIMIT 1
      `).get(firstSpec.department);
    }
  }

  // Validate and resolve each specialist
  const validSpecialists = [];
  for (const s of json.specialists) {
    if (!s.name) continue;
    const member = db.prepare(`SELECT id, name, role FROM team_members WHERE name = ? AND status = 'active' AND tier = 'specialist'`).get(s.name);
    if (member) {
      validSpecialists.push({
        id: member.id,
        name: member.name,
        role: member.role,
        subagent_count: Math.min(Math.max(parseInt(s.subagent_count) || 1, 1), 10),
        reason: s.reason || ''
      });
    } else {
      console.warn(`[ChainRouting] Specialist "${s.name}" not found or inactive`);
    }
  }

  if (validSpecialists.length === 0) return null;

  return {
    executive: json.executive,
    executiveId: exec ? exec.id : null,
    senior: senior ? senior.name : null,
    seniorId: senior ? senior.id : null,
    seniorRole: senior ? senior.role : null,
    domain: json.domain || 'General',
    specialists: validSpecialists,
    rationale: json.rationale || '',
    requires_max: json.requires_max === true
  };
}

/**
 * Execute a parsed routing decision: create assignments, log activity, spawn specialists.
 */
async function executeRoutingDecision(taskId, routing) {
  const now = localNow();
  const task = db.prepare(`SELECT title FROM tasks WHERE id = ?`).get(taskId);
  const specialistNames = routing.specialists.map(s => s.name).join(', ');

  // Create task_assignments for each specialist
  const insertAssignment = db.prepare(`INSERT INTO task_assignments (task_id, member_id, subagent_count, created_at) VALUES (?, ?, ?, ?)`);
  for (const s of routing.specialists) {
    insertAssignment.run(taskId, s.id, s.subagent_count, now);
  }

  // Update task with primary assignee and routing status
  db.prepare(`UPDATE tasks SET assigned_to = ?, status = 'routing', current_step = ?, updated_at = ? WHERE id = ?`)
    .run(routing.specialists[0].id, `Board → ${routing.executive} → ${specialistNames}`, now, taskId);

  // Handle external tasks that require Max's direct involvement
  if (routing.requires_max) {
    db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
      .run('Flagged for Max — external action required', now, taskId);
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Council', 'external_task_flagged', ?, ?)`)
      .run(taskId, `Council flagged this as an external task requiring Max's direct involvement. Rationale: ${routing.rationale}`.slice(0, 500), now);
    createNotification('decision_needed', 'Action required by Max', `Task "${task ? task.title : 'task'}" requires your direct involvement (external action: buying, signing up, DNS, contracts, etc.)`, taskId);
    broadcast('task.updated', { id: taskId });
    return; // Do not auto-assign to specialists
  }

  // Log the routing decision
  db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Council', 'chain_routing_decision', ?, ?)`)
    .run(taskId, `Council → ${routing.executive} (${routing.domain})${routing.senior ? ` → ${routing.senior}` : ''} → ${specialistNames}. Rationale: ${routing.rationale}`.slice(0, 1000), now);

  // Log executive as routing authority
  if (routing.executiveId) {
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'routing_authority', ?, ?)`)
      .run(taskId, routing.executive, `Oversaw routing of "${task ? task.title : 'task'}" to ${specialistNames}${routing.senior ? ` via ${routing.senior}` : ''}`, now);
  }

  // Log senior as intermediate authority in chain
  if (routing.seniorId) {
    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'delegated_to_specialist', ?, ?)`)
      .run(taskId, routing.senior, `Delegated "${task ? task.title : 'task'}" to ${specialistNames}`, now);
  }

  // Create notification
  createNotification('task_status', `Routed: ${specialistNames}`, `Council → ${routing.executive}${routing.senior ? ` → ${routing.senior}` : ''} → ${specialistNames}`, taskId);

  broadcast('task.updated', { id: taskId });

  // Spawn the assigned specialists
  try {
    const spawnResults = await autoSpawnForTask(taskId);
    const spawned = spawnResults.filter(r => r.success);
    if (spawned.length > 0) {
      broadcast('process.batch_spawned', { task_id: taskId, spawned: spawned.map(s => s.member_name) });
    }
  } catch (err) {
    console.error(`[ChainRouting] Spawn error after routing task #${taskId}: ${err.message}`);
  }
}

/**
 * Route a task via the chain of command: The Council (Board of Directors) deliberates
 * collectively and picks the right Executive, Senior, and Specialist(s).
 * Returns a parsed routing decision or null on failure.
 */
async function routeViaChainOfCommand(taskId) {
  const task = db.prepare(`SELECT * FROM tasks WHERE id = ?`).get(taskId);
  if (!task) return null;

  // ── MAX'S DIRECTIVE: Council manages PROJECTS, not tasks ──
  // ALL task routing uses direct keyword routing. Council deliberation is ONLY
  // invoked as a last resort when keyword routing fails on a high/urgent task.
  // This saves massive token costs — Council spawns a Haiku CLI call (~$0.01-0.05)
  // that was previously triggered for EVERY task.
  //
  // Escalation chain for tasks: Specialist → Senior → Executive → Council (LAST RESORT)
  // Council's role: project-level planning and strategic decisions, NOT individual task routing.
  const taskTitle = (task.title || '').toLowerCase();
  const taskDesc = (task.description || '');
  const isAlreadyRouted = task.assigned_to != null;
  const skipNow = localNow();

  // Step 1: If already assigned, just return that routing
  if (isAlreadyRouted) {
    const assignedMember = db.prepare(`SELECT id, name, role, department FROM team_members WHERE id = ? AND status = 'active'`).get(task.assigned_to);
    if (assignedMember) {
      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Council', 'council_skip_direct_route', ?, ?)`)
        .run(taskId, `Council skipped — task pre-assigned to ${assignedMember.name}`, skipNow);
      const exec = db.prepare(`SELECT name, id FROM team_members WHERE status = 'active' AND tier IN ('c-suite','executive') AND department = ? LIMIT 1`).get(assignedMember.department);
      return {
        executive: exec ? exec.name : 'Onyx',
        executiveId: exec ? exec.id : null,
        senior: null, seniorId: null, seniorRole: null,
        domain: assignedMember.department || 'General',
        specialists: [{ id: assignedMember.id, name: assignedMember.name, role: assignedMember.role, subagent_count: 1, reason: 'Pre-assigned' }],
        rationale: `Direct route: task was already assigned to ${assignedMember.name}`,
        requires_max: false
      };
    }
  }

  // Step 2: Try keyword routing for ALL tasks (not just simple ones)
  const keywordRouting = routeActionItem(taskTitle + ' ' + taskDesc);
  const directMember = keywordRouting || getDefaultSpecialist();
  if (directMember) {
    const directMemberId = directMember.member_id || directMember.id;
    const memberRow = db.prepare(`SELECT id, name, role, department FROM team_members WHERE id = ?`).get(directMemberId);
    if (memberRow) {
      const routeSource = keywordRouting ? 'keyword_match' : 'default_specialist';
      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Council', 'council_skip_direct_route', ?, ?)`)
        .run(taskId, `Council skipped — direct ${routeSource} routing to ${memberRow.name} (saves tokens per Max's directive)`, skipNow);
      const exec = db.prepare(`SELECT name, id FROM team_members WHERE status = 'active' AND tier IN ('c-suite','executive') AND department = ? LIMIT 1`).get(memberRow.department);
      return {
        executive: exec ? exec.name : 'Onyx',
        executiveId: exec ? exec.id : null,
        senior: null, seniorId: null, seniorRole: null,
        domain: memberRow.department || 'General',
        specialists: [{ id: memberRow.id, name: memberRow.name, role: memberRow.role, subagent_count: 1, reason: `Direct routed (${routeSource})` }],
        rationale: `Council skipped per Max's directive — tasks route directly to specialists. ${memberRow.name} assigned via ${routeSource}.`,
        requires_max: false
      };
    }
  }
  // Step 3: Only if keyword routing AND default specialist both fail (should be rare),
  // fall through to full Council deliberation below as absolute last resort.

  const now = localNow();

  // Log routing start
  db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'Council', 'chain_routing_started', ?, ?)`)
    .run(taskId, `Council deliberating on task routing`, now);

  // Load specialist roster with current workload
  const specialists = db.prepare(`
    SELECT tm.name, tm.role, tm.department, tm.tier,
      (SELECT COUNT(*) FROM active_processes WHERE member_id = tm.id AND status = 'running') as running_tasks
    FROM team_members tm
    WHERE tm.status = 'active' AND tm.tier = 'specialist'
    ORDER BY tm.department, tm.name
  `).all();

  // Load c-suite roster
  const csuite = db.prepare(`
    SELECT name, role, department FROM team_members
    WHERE status = 'active' AND tier IN ('c-suite','executive')
    ORDER BY name
  `).all();

  // Load task files for context
  const taskFiles = db.prepare(`SELECT file_name FROM task_files WHERE task_id = ? AND direction = 'input'`).all(taskId);
  const fileList = taskFiles.map(f => f.file_name).join(', ');

  // Build department-grouped roster with hierarchy levels (SVP/VP → Director → Senior → IC)
  const deptGroups = {};
  for (const s of specialists) {
    const dept = s.department || 'General';
    if (!deptGroups[dept]) deptGroups[dept] = [];
    const level = s.role.includes('SVP') ? '[SVP]' : s.role.includes('VP') ? '[VP]' : s.role.includes('Director') ? '[Dir]' : s.role.includes('Senior') ? '[Sr]' : '[IC]';
    deptGroups[dept].push(`  - ${s.name} (${s.role}) ${level} — ${s.running_tasks} active task(s)`);
  }

  let rosterText = '';
  for (const [dept, members] of Object.entries(deptGroups)) {
    const exec = csuite.find(c => c.department === dept);
    rosterText += `\n### ${dept}${exec ? ` — Executive: ${exec.name} (${exec.role})` : ''}\n${members.join('\n')}\n`;
  }

  const deptMapping = `
Engineering/Backend/Frontend/DevOps/QA/Security → Onyx (CTO)
Platform/Design/Product → Quarry (CPO)
Research/Data → Loom (CAIO)
Content/Marketing → Blaze (CMO)
HR → Crest (CHRO), Legal → Writ (CLO), Finance → Thorn (CFO)
Revenue/Customer → Summit (CRO), Operations → Sable (COO)`.trim();

  const prompt = `You are the Board of Directors (Council) of The Team. You are 7 directors deliberating collectively: Basalt (Risk & Governance), Apex (Strategy & Vision), Arbor (Culture & Ethics), Fulcrum (Operations & Efficiency), Helix (Innovation & Technology), Tithe (Finance & Accountability), Vantage (Growth & Market Position). Reach a consensus on how to route this task.

## Your Task
Deliberate on the following mission and route it through the proper chain of command.

### Mission Details
**Title:** ${task.title}
**Priority:** ${task.priority}
**Description:**
${task.description || '(no description)'}
${fileList ? `**Attached files:** ${fileList}` : ''}

## The Team Hierarchy (Chain of Command)
Tasks flow: Council → Executive (C-Suite) → Senior/Lead (SVP/VP) → Specialist (does the work)

### C-Suite Executives (delegate TO these by domain)
${csuite.map(c => `- ${c.name}: ${c.role}`).join('\n')}

### Department Roster (SVP/VP are seniors who oversee, ICs/Sr do the work)
${rosterText}

## Domain Routing Rules
${deptMapping}

## Hierarchy Levels in Each Department
- **SVP** = Senior Vice President — oversees entire domain, delegates to VPs and specialists
- **VP** = Vice President — manages sub-department, delegates to specialists
- **Director/Senior** = Experienced IC with oversight duties
- **IC** = Individual Contributor — does the actual work

## External Task Detection
If this task requires ANY of the following, it is an EXTERNAL task that needs Max's direct involvement:
- Buying a domain, signing up for a service, making a purchase
- DNS changes, domain transfers, SSL certificate procurement
- Signing contracts, agreements, or legal documents
- Creating accounts on third-party platforms
- Any action requiring human identity verification or payment
Set "requires_max": true in your output if this applies.

## Instructions
1. Deliberate as the Council — consider risk (Basalt), strategy (Apex), ethics (Arbor), efficiency (Fulcrum), technology (Helix), cost (Tithe), and growth (Vantage)
2. Identify the domain(s) this task belongs to
3. Determine the responsible Executive (C-Suite)
4. Identify the Senior/Lead (SVP or VP) who oversees this work
5. Pick the best Specialist(s) — consider skills match AND current workload (prefer specialists with fewer active tasks)
6. If the task spans multiple domains, assign specialists from each
7. Set subagent_count: 1 for focused tasks, 2-3 for large/complex ones
8. Check if this is an external task requiring Max

Output your routing decision as JSON inside <routing></routing> tags. Nothing else.

Example format:
<routing>
{"executive":"Onyx","senior":"Strut","domain":"Engineering","specialists":[{"name":"Alloy","reason":"API endpoint work","subagent_count":1}],"rationale":"Council consensus: This task involves building a new API endpoint. Helix confirms technical feasibility, Fulcrum approves resource allocation.","requires_max":false}
</routing>`;

  // Get CLI path
  const cliPathSetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'claude_cli_path'`).get();
  const cliPath = (cliPathSetting && cliPathSetting.value) ? cliPathSetting.value : 'claude';

  // Use Fulcrum (Board Director — Operations & Efficiency) as Council representative
  // Dynamic lookup: find Fulcrum by name, fall back to any board member, then hardcoded ID
  let councilMember = db.prepare(`SELECT id, name FROM team_members WHERE name = 'Fulcrum' AND status = 'active' LIMIT 1`).get();
  if (!councilMember) {
    councilMember = db.prepare(`SELECT id, name FROM team_members WHERE tier = 'board' AND status = 'active' ORDER BY id LIMIT 1`).get();
  }
  const councilMemberId = councilMember ? councilMember.id : 169;
  const councilRepName = councilMember ? councilMember.name : 'Council';

  // Register Council deliberation in active_processes so it shows in Live Agents
  const processResult = db.prepare(`
    INSERT INTO active_processes (task_id, member_id, status, started_at, output_summary, process_type)
    VALUES (?, ?, 'running', ?, ?, 'council')
  `).run(taskId, councilMemberId, now, `Council deliberating on task #${taskId}: ${task.title.slice(0, 100)}`);
  const councilProcessId = Number(processResult.lastInsertRowid);

  // Broadcast so Live Agents view updates in real-time
  broadcast('process.spawned', {
    process_id: councilProcessId,
    task_id: taskId,
    task_title: task.title,
    member_id: councilMemberId,
    member_name: councilRepName,
    process_type: 'council'
  });

  // Broadcast council routing active so task queue can show pulse/animation
  broadcast('task.routing_active', {
    task_id: taskId,
    process_id: councilProcessId,
    status: 'deliberating'
  });

  return new Promise((resolve) => {
    try {
      // Token audit: Council routing is structured JSON extraction — haiku is sufficient and 10x cheaper
      const args = ['--print', '--model', 'haiku', '--max-turns', '1', '--dangerously-skip-permissions', '--output-format', 'text'];
      const child = spawn(cliPath, args, {
        env: { ...process.env, DISABLE_AUTOUPDATER: '1' },
        stdio: ['pipe', 'pipe', 'pipe'],
        cwd: path.join(process.env.PROJECT_ROOT || path.join(__dirname, '..'), 'app'),
        detached: false
      });

      // Store PID in active_processes
      if (child.pid) {
        db.prepare(`UPDATE active_processes SET pid = ? WHERE id = ?`).run(child.pid, councilProcessId);
      }

      // Track in runningProcesses map
      runningProcesses.set(councilProcessId, {
        child,
        taskId,
        memberId: councilMemberId,
        memberName: councilRepName,
        startedAt: now
      });

      let stdout = '';
      let stderr = '';

      child.stdout.on('data', (data) => { stdout += data.toString(); });
      child.stderr.on('data', (data) => { stderr += data.toString(); });

      // Timeout: 60 seconds max for Council deliberation (sonnet needs more time)
      const timeout = setTimeout(() => {
        try { child.kill('SIGTERM'); } catch {}
        console.warn(`[ChainRouting] Timeout routing task #${taskId}`);
        const finishedAt = localNow();
        db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
          .run(finishedAt, `Council deliberation timed out for task #${taskId}`, councilProcessId);
        runningProcesses.delete(councilProcessId);
        broadcast('process.failed', { process_id: councilProcessId, task_id: taskId, error: 'timeout', process_type: 'council' });
        broadcast('task.routing_active', { task_id: taskId, process_id: councilProcessId, status: 'failed' });
        resolve(null);
      }, 60000);

      child.on('close', (code) => {
        clearTimeout(timeout);
        const finishedAt = localNow();
        runningProcesses.delete(councilProcessId);

        if (code !== 0) {
          console.warn(`[ChainRouting] CLI exited with code ${code} for task #${taskId}. stderr: ${stderr.slice(0, 200)}`);
        }
        const routing = parseRoutingDecision(stdout);

        if (routing) {
          const routingSummary = `Council routed task #${taskId} → ${routing.executive || 'unknown'} → ${(routing.specialists || []).map(s => s.name).join(', ') || 'unknown'}`;
          db.prepare(`UPDATE active_processes SET status = 'completed', completed_at = ?, output_summary = ? WHERE id = ?`)
            .run(finishedAt, routingSummary, councilProcessId);
          broadcast('process.completed', { process_id: councilProcessId, task_id: taskId, member_name: councilRepName, process_type: 'council' });
          broadcast('task.routing_active', { task_id: taskId, process_id: councilProcessId, status: 'completed', routing_summary: routingSummary });
        } else {
          db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
            .run(finishedAt, `Council routing failed for task #${taskId} (exit code: ${code})`, councilProcessId);
          broadcast('process.failed', { process_id: councilProcessId, task_id: taskId, error: 'routing_failed', process_type: 'council' });
          broadcast('task.routing_active', { task_id: taskId, process_id: councilProcessId, status: 'failed' });
        }

        resolve(routing);
      });

      child.on('error', (err) => {
        clearTimeout(timeout);
        const finishedAt = localNow();
        runningProcesses.delete(councilProcessId);
        console.error(`[ChainRouting] Spawn error: ${err.message}`);
        db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
          .run(finishedAt, `Council spawn error: ${err.message}`, councilProcessId);
        broadcast('process.failed', { process_id: councilProcessId, task_id: taskId, error: err.message, process_type: 'council' });
        resolve(null);
      });

      // Write prompt to stdin
      try {
        child.stdin.write(prompt);
        child.stdin.end();
      } catch (stdinErr) {
        console.error(`[ChainRouting] stdin error: ${stdinErr.message}`);
        const finishedAt = localNow();
        runningProcesses.delete(councilProcessId);
        db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
          .run(finishedAt, `Council stdin error: ${stdinErr.message}`, councilProcessId);
        broadcast('process.failed', { process_id: councilProcessId, task_id: taskId, error: stdinErr.message, process_type: 'council' });
        resolve(null);
      }
    } catch (err) {
      console.error(`[ChainRouting] Failed to spawn CLI: ${err.message}`);
      const finishedAt = localNow();
      runningProcesses.delete(councilProcessId);
      db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = ? WHERE id = ?`)
        .run(finishedAt, `Council failed to spawn: ${err.message}`, councilProcessId);
      broadcast('process.failed', { process_id: councilProcessId, task_id: taskId, error: err.message, process_type: 'council' });
      resolve(null);
    }
  });
}

/**
 * Auto-spawn all assigned members for a task in parallel.
 */
async function autoSpawnForTask(taskId) {
  const autoSpawnSetting = db.prepare(`SELECT value FROM system_settings WHERE key = 'auto_spawn_enabled'`).get();
  if (!autoSpawnSetting || autoSpawnSetting.value !== '1') return [];

  // Get all assigned members for this task
  const assignments = db.prepare(`
    SELECT ta.member_id, tm.name, tm.role, tm.execution_mode
    FROM task_assignments ta
    JOIN team_members tm ON ta.member_id = tm.id
    WHERE ta.task_id = ?
  `).all(taskId);

  // Fallback to assigned_to if no task_assignments
  if (assignments.length === 0) {
    const task = db.prepare(`SELECT assigned_to FROM tasks WHERE id = ?`).get(taskId);
    if (task && task.assigned_to) {
      const member = db.prepare(`SELECT id as member_id, name, role, execution_mode FROM team_members WHERE id = ?`).get(task.assigned_to);
      if (member) assignments.push(member);
    }
  }

  if (assignments.length === 0) return [];

  // Don't auto-spawn board members or orchestrators — they delegate, not execute
  // FIX: Use tier check instead of hardcoded name to prevent breakage on renames
  const spawnableMembers = assignments.filter(a => a.tier !== 'board' && a.tier !== 'c-suite');

  const results = [];
  for (const member of spawnableMembers) {
    try {
      const result = await spawnMemberTerminal(taskId, member.member_id);
      results.push({ member_id: member.member_id, member_name: member.name, ...result });
    } catch (err) {
      console.error(`[AutoSpawn] Error spawning ${member.name}: ${err.message}`);
      results.push({ member_id: member.member_id, member_name: member.name, success: false, error: err.message });
    }
  }

  return results;
}

// ── POST /api/processor/spawn-member — Manually spawn a member for a task ──

app.post('/api/processor/spawn-member', (req, res) => {
  const { task_id, member_id } = req.body;
  if (!task_id || !member_id) {
    return res.status(400).json({ error: 'task_id and member_id are required' });
  }

  spawnMemberTerminal(Number(task_id), Number(member_id))
    .then(result => {
      res.json(result);
    })
    .catch(err => {
      res.status(500).json({ error: err.message });
    });
});

// ── POST /api/processor/spawn-task — Auto-spawn all assigned members for a task ──

app.post('/api/processor/spawn-task', (req, res) => {
  const { task_id } = req.body;
  if (!task_id) {
    return res.status(400).json({ error: 'task_id is required' });
  }

  autoSpawnForTask(Number(task_id))
    .then(results => {
      res.json({ task_id: Number(task_id), spawned: results.filter(r => r.success).length, results });
    })
    .catch(err => {
      res.status(500).json({ error: err.message });
    });
});

// ── GET /api/processor/active — All running member processes ──

app.get('/api/processor/active', (req, res) => {
  try {
    const processes = db.prepare(`
      SELECT ap.*, tm.name as member_name, tm.role as member_role,
             t.title as task_title, t.priority as task_priority, t.progress as task_progress,
             t.current_step as task_step
      FROM active_processes ap
      LEFT JOIN team_members tm ON ap.member_id = tm.id
      LEFT JOIN tasks t ON ap.task_id = t.id
      ORDER BY ap.started_at DESC
    `).all();

    // Enrich with live PID status
    const enriched = processes.map(p => {
      let alive = false;
      if (p.status === 'running' && p.pid) {
        try { process.kill(p.pid, 0); alive = true; } catch { alive = false; }
        // If process is marked running but PID is dead, mark as failed
        if (!alive) {
          db.prepare(`UPDATE active_processes SET status = 'failed', completed_at = ?, output_summary = COALESCE(output_summary, 'Process died unexpectedly') WHERE id = ? AND status = 'running'`)
            .run(localNow(), p.id);
          p.status = 'failed';
        }
      }
      return { ...p, pid_alive: alive };
    });

    res.json(enriched);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/processor/kill/:processId — Kill a running member process ──

app.post('/api/processor/kill/:processId', (req, res) => {
  try {
    const proc = db.prepare(`SELECT * FROM active_processes WHERE id = ?`).get(req.params.processId);
    if (!proc) return res.status(404).json({ error: 'Process not found' });

    if (proc.status !== 'running') {
      return res.status(400).json({ error: `Process is already in status "${proc.status}"` });
    }

    const now = localNow();

    // Kill the actual OS process
    if (proc.pid) {
      try {
        process.kill(proc.pid, 'SIGTERM');
        // Give it a moment, then force kill
        setTimeout(() => {
          try { process.kill(proc.pid, 'SIGKILL'); } catch {}
        }, 3000);
      } catch (killErr) {
      }
    }

    // Clean up in-memory tracking
    runningProcesses.delete(Number(req.params.processId));

    // Update database
    db.prepare(`UPDATE active_processes SET status = 'killed', completed_at = ?, output_summary = ? WHERE id = ?`)
      .run(now, 'Manually killed by user', Number(req.params.processId));

    // Log
    const member = db.prepare(`SELECT name FROM team_members WHERE id = ?`).get(proc.member_id);
    const memberName = member ? member.name : `Member #${proc.member_id}`;

    db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, ?, 'process_killed', ?, ?)`)
      .run(proc.task_id, memberName, `Process #${proc.id} killed by user`, now);

    db.prepare(`UPDATE tasks SET current_step = ?, updated_at = ? WHERE id = ?`)
      .run(`${memberName} process killed`, now, proc.task_id);

    broadcast('process.killed', { process_id: Number(req.params.processId), task_id: proc.task_id });
    broadcast('task.updated', { id: proc.task_id });

    res.json({ success: true, message: `Process #${proc.id} killed` });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── POST /api/processor/kill-all — Kill all running processes ──

app.post('/api/processor/kill-all', (req, res) => {
  try {
    const running = db.prepare(`SELECT * FROM active_processes WHERE status = 'running'`).all();
    const now = localNow();
    let killed = 0;

    for (const proc of running) {
      if (proc.pid) {
        try { process.kill(proc.pid, 'SIGTERM'); } catch {}
      }
      runningProcesses.delete(proc.id);
      db.prepare(`UPDATE active_processes SET status = 'killed', completed_at = ?, output_summary = 'Kill-all command' WHERE id = ?`)
        .run(now, proc.id);
      killed++;
    }

    if (killed > 0) {
      db.prepare(`INSERT INTO activity_log (actor, action, notes, created_at) VALUES ('System', 'kill_all_processes', ?, ?)`)
        .run(`Killed ${killed} running process(es)`, now);
      broadcast('process.killed_all', { killed });
    }

    res.json({ success: true, killed });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

