// List dependencies for a task
app.get('/api/tasks/:id/dependencies', (req, res) => {
  try {
    const taskId = parseInt(req.params.id);
    const deps = db.prepare(`
      SELECT td.id, td.depends_on, td.created_at,
        t.title, t.status, t.priority
      FROM task_dependencies td
      JOIN tasks t ON t.id = td.depends_on
      WHERE td.task_id = ?
      ORDER BY td.created_at ASC
    `).all(taskId);
    res.json(deps);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Add a dependency
app.post('/api/tasks/:id/dependencies', (req, res) => {
  try {
    const taskId = parseInt(req.params.id);
    const { depends_on } = req.body;
    if (!depends_on) return res.status(400).json({ error: 'depends_on is required' });
    if (depends_on === taskId) return res.status(400).json({ error: 'A task cannot depend on itself' });

    // Walk the graph to check for cycles
    function hasCycle(taskId, targetId) {
      const deps = db.prepare(`SELECT depends_on FROM task_dependencies WHERE task_id = ?`).all(targetId);
      for (const dep of deps) {
        if (dep.depends_on === taskId) return true;
        if (hasCycle(taskId, dep.depends_on)) return true;
      }
      return false;
    }
    if (hasCycle(parseInt(req.params.id), depends_on)) {
      return res.status(400).json({ error: 'Circular dependency detected' });
    }

    // Check both tasks exist
    const task = db.prepare('SELECT id FROM tasks WHERE id = ?').get(taskId);
    const dep = db.prepare('SELECT id FROM tasks WHERE id = ?').get(depends_on);
    if (!task) return res.status(404).json({ error: 'Task not found' });
    if (!dep) return res.status(404).json({ error: 'Dependency task not found' });

    const result = db.prepare(
      'INSERT OR IGNORE INTO task_dependencies (task_id, depends_on) VALUES (?, ?)'
    ).run(taskId, depends_on);

    if (result.changes === 0) {
      return res.status(409).json({ error: 'Dependency already exists' });
    }

    res.json({ id: result.lastInsertRowid, task_id: taskId, depends_on });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Remove a dependency
app.delete('/api/tasks/:id/dependencies/:depId', (req, res) => {
  try {
    const taskId = parseInt(req.params.id);
    const depId = parseInt(req.params.depId);
    const result = db.prepare(
      'DELETE FROM task_dependencies WHERE task_id = ? AND depends_on = ?'
    ).run(taskId, depId);
    if (result.changes === 0) return res.status(404).json({ error: 'Dependency not found' });
    res.json({ success: true });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Check if a task is blocked
app.get('/api/tasks/:id/blocked', (req, res) => {
  try {
    const taskId = parseInt(req.params.id);
    const blockingTasks = db.prepare(`
      SELECT td.depends_on, t.title, t.status, t.priority
      FROM task_dependencies td
      JOIN tasks t ON t.id = td.depends_on
      WHERE td.task_id = ?
        AND t.status NOT IN ('completed', 'delivered')
    `).all(taskId);

    res.json({
      blocked: blockingTasks.length > 0,
      blocking_tasks: blockingTasks
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

