app.get('/api/packets', (req, res) => {
  try {
    const conditions = [];
    const values = [];
    if (req.query.status) { conditions.push('ep.status = ?'); values.push(req.query.status); }
    if (req.query.phase) { conditions.push('ep.active_phase = ?'); values.push(req.query.phase); }
    if (req.query.project_id) { conditions.push('ep.project_id = ?'); values.push(req.query.project_id); }
    const where = conditions.length > 0 ? 'WHERE ' + conditions.join(' AND ') : '';
    const rows = db.prepare(`
      SELECT ep.*, p.name as project_name, t.title as task_title,
             d.name as director_name, s.name as specialist_name
      FROM execution_packets ep
      LEFT JOIN projects p ON ep.project_id = p.id
      LEFT JOIN tasks t ON ep.task_id = t.id
      LEFT JOIN team_members d ON ep.assigned_director_id = d.id
      LEFT JOIN team_members s ON ep.assigned_specialist_id = s.id
      ${where}
      ORDER BY ep.created_at DESC
    `).all(...values);
    res.json(rows);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

