function maskApiKey(key) {
  if (!key) return null;
  if (key.length <= 8) return '••••';
  return '••••' + key.slice(-8);
}

// ── Member LLM Assignment ─────────────────────────────────────────

// ── LLM Usage Tracking ───────────────────────────────────────────

// ── MCP Servers ──────────────────────────────────────────────────

// ── WebSocket Live Updates ────────────────────────────────────────

const { WebSocketServer } = require('ws');

const server = http.createServer(app);

// ── Connection Timeout Policy ──────────────────────────────────
// Prevent hung connections from blocking the event loop.
// All values are configurable via environment variables.
//
//   SERVER_TIMEOUT    (default 120 s) — idle socket timeout; closes a socket
//                     that has been inactive for this long.
//   KEEP_ALIVE_TIMEOUT (default 65 s) — how long to hold a keep-alive socket
//                     open waiting for the next request.  65 s sits just above
//                     the 60 s default of most load-balancers/proxies so the
//                     server always closes first, avoiding ECONNRESET errors.
//   HEADERS_TIMEOUT   (default 60 s) — max time to receive the full HTTP
//                     request headers; guards against slow-header attacks.
//   REQUEST_TIMEOUT   (default 300 s) — max time for the whole request/
//                     response cycle; allows large file uploads while still
//                     bounding runaway handlers.
server.timeout          = parseInt(process.env.SERVER_TIMEOUT      || '120000', 10);
server.keepAliveTimeout = parseInt(process.env.KEEP_ALIVE_TIMEOUT  || '65000',  10);
server.headersTimeout   = parseInt(process.env.HEADERS_TIMEOUT     || '60000',  10);
server.requestTimeout   = parseInt(process.env.REQUEST_TIMEOUT     || '300000', 10);

const wss = new WebSocketServer({ noServer: true, path: '/ws' });

const wsClients = new Set();

// -- Message replay ring buffer for graceful reconnection --
const WS_RING_BUFFER_SIZE = parseInt(process.env.WS_RING_BUFFER_SIZE || '500', 10); // default 500 messages
const wsRingBuffer = [];
let wsEventCounter = 0;

// -- WS token store: short-lived tokens for authenticating WS upgrades --
const wsTokens = new Map(); // token -> { createdAt }
const WS_TOKEN_TTL_MS = parseInt(process.env.WS_TOKEN_TTL_MS || '30000', 10); // default 30 s

// Prune expired tokens every 60s
setInterval(() => {
  const now = Date.now();
  for (const [token, meta] of wsTokens) {
    if (now - meta.createdAt > WS_TOKEN_TTL_MS) wsTokens.delete(token);
  }
}, 60000);

// GET /api/ws-token — issue a short-lived token for WebSocket auth
app.get('/api/ws-token', authRateLimiter, (req, res) => {
  const token = crypto.randomBytes(24).toString('hex');
  wsTokens.set(token, { createdAt: Date.now() });
  res.json({ token });
});

// -- Manual upgrade handler: validate origin + token --
server.on('upgrade', (req, socket, head) => {
  const { pathname, searchParams } = new URL(req.url, `http://${req.headers.host}`);
  if (pathname !== '/ws') {
    socket.write('HTTP/1.1 404 Not Found\r\n\r\n');
    socket.destroy();
    return;
  }

  // Origin validation — only allow same-origin connections
  const origin = req.headers.origin;
  if (origin) {
    try {
      const originHost = new URL(origin).host;
      const serverHost = req.headers.host;
      if (originHost !== serverHost) {
        logger.warn(`[WS] Rejected connection from foreign origin: ${origin}`);
        socket.write('HTTP/1.1 403 Forbidden\r\n\r\n');
        socket.destroy();
        return;
      }
    } catch (_) {
      socket.write('HTTP/1.1 403 Forbidden\r\n\r\n');
      socket.destroy();
      return;
    }
  }

  // Token authentication
  const token = searchParams.get('token');
  if (!token || !wsTokens.has(token)) {
    logger.warn('[WS] Rejected connection — missing or invalid token');
    socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n');
    socket.destroy();
    return;
  }

  // Consume the token (single-use)
  const meta = wsTokens.get(token);
  wsTokens.delete(token);

  // Check expiry
  if (Date.now() - meta.createdAt > WS_TOKEN_TTL_MS) {
    logger.warn('[WS] Rejected connection — expired token');
    socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n');
    socket.destroy();
    return;
  }

  wss.handleUpgrade(req, socket, head, (ws) => {
    wss.emit('connection', ws, req);
  });
});

// ── WebSocket server-side heartbeat ───────────────────────────
// Detects and terminates stale/dead WebSocket clients that have silently
// disconnected without sending a close frame.  Without this, dead connections
// accumulate until the OS eventually times out the TCP socket.
//
//   WS_PING_INTERVAL_MS (default 30 s) — how often the server sends a ping
//   frame to every connected client.  Clients that do not pong back within
//   one interval are terminated.
const WS_PING_INTERVAL_MS = parseInt(process.env.WS_PING_INTERVAL_MS || '30000', 10);

wss.on('connection', (ws) => {
  ws.isAlive = true;
  // Reset the liveness flag on every pong received from the client
  ws.on('pong', () => { ws.isAlive = true; });

  wsClients.add(ws);
  ws.on('close', () => wsClients.delete(ws));
  ws.on('error', () => wsClients.delete(ws));

  ws.on('message', (raw) => {
    try {
      const msg = JSON.parse(raw);
      if (msg.type === 'ping') {
        if (ws.readyState === 1) ws.send(JSON.stringify({ type: 'pong' }));
        return;
      }
      if (msg.type === 'replay' && typeof msg.last_event_id === 'number') {
        // Replay missed messages from ring buffer
        const missed = wsRingBuffer.filter(entry => entry.event_id > msg.last_event_id);
        for (const entry of missed) {
          if (ws.readyState === 1) ws.send(entry.raw);
        }
        return;
      }
    } catch (_) { /* ignore malformed messages */ }
  });
});

// Periodic heartbeat: ping all clients, terminate those that didn't pong back
const wsHeartbeatInterval = setInterval(() => {
  for (const ws of wss.clients) {
    if (!ws.isAlive) {
      // Client missed the last ping — connection is stale, terminate it
      ws.terminate();
      wsClients.delete(ws);
      continue;
    }
    ws.isAlive = false;
    try { ws.ping(); } catch (_) { /* client may have closed between iterations */ }
  }
}, WS_PING_INTERVAL_MS);

// Clean up the heartbeat interval when the WSS server closes
wss.on('close', () => clearInterval(wsHeartbeatInterval));

function broadcast(eventType, payload) {
  const eventId = ++wsEventCounter;
  const message = JSON.stringify({ type: eventType, data: payload, event_id: eventId, timestamp: new Date().toISOString() });
  // Store in ring buffer for replay on reconnect
  wsRingBuffer.push({ event_id: eventId, raw: message });
  if (wsRingBuffer.length > WS_RING_BUFFER_SIZE) {
    wsRingBuffer.shift();
  }
  for (const client of wsClients) {
    if (client.readyState === 1) { // OPEN
      client.send(message);
    }
  }
}

