// ── Phase 4: Approval Endpoints ─────────────────────────────────────

// ── Auto-Research Engine ───────────────────────────────────────────

// ── Autonomous Research Engine ────────────────────────────────────
// Inspired by iterative hypothesis-experiment-evaluate research loops.
// Programs define a research goal with methodology. The engine runs cycles
// autonomously: each cycle formulates a hypothesis, runs an experiment
// (via spawned agent), evaluates results, keeps or discards, and refines.

// In-memory tracking of active research program loops
const activeResearchLoops = new Map(); // programId -> { interval, status }

// Core: Run a single research cycle for a program
// Implements the REAL autoresearch loop: modify code, measure metric, keep improvements, revert failures
async function runResearchCycle(programId) {
  if (isLocalMode()) return;
  const now = localNow();
  const program = db.prepare(`SELECT * FROM research_programs WHERE id = ?`).get(programId);
  if (!program || program.status !== 'running') return { skipped: true, reason: 'not running' };

  // Check limits
  if (program.experiment_count >= program.max_experiments) {
    db.prepare(`UPDATE research_programs SET status = 'converged', converged_at = ? WHERE id = ?`).run(now, programId);
    stopResearchLoop(programId);
    broadcast('research.program_updated', { id: programId, status: 'converged' });
    return { completed: true, reason: 'max_experiments_reached' };
  }

  // Check time budget
  if (program.started_at && program.time_budget_minutes > 0) {
    const startTime = new Date(program.started_at).getTime();
    const elapsed = (Date.now() - startTime) / 60000;
    if (elapsed >= program.time_budget_minutes) {
      db.prepare(`UPDATE research_programs SET status = 'converged', converged_at = ? WHERE id = ?`).run(now, programId);
      stopResearchLoop(programId);
      broadcast('research.program_updated', { id: programId, status: 'converged' });
      return { completed: true, reason: 'time_budget_exceeded' };
    }
  }

  // Load accumulated knowledge from previous experiments
  let knowledgeBase = [];
  try { knowledgeBase = JSON.parse(program.knowledge_base || '[]'); } catch(e) {}

  const pastExperiments = db.prepare(`
    SELECT experiment_number, hypothesis, status, result_value, metric_value, delta, decision, description, evaluation
    FROM research_experiments WHERE program_id = ? ORDER BY experiment_number DESC LIMIT 20
  `).all(programId);

  const nextExpNum = program.experiment_count + 1;

  // Create cycle in the session (if linked)
  let cycleId = null;
  if (program.session_id) {
    const cycleResult = db.prepare(`
      INSERT INTO research_cycles (session_id, cycle_number, hypothesis, status, created_at)
      VALUES (?, ?, ?, 'running', ?)
    `).run(program.session_id, nextExpNum, `Auto-cycle #${nextExpNum} for program "${program.title}"`, now);
    cycleId = Number(cycleResult.lastInsertRowid);
    db.prepare(`UPDATE research_sessions SET current_cycle = ?, status = 'running' WHERE id = ?`)
      .run(nextExpNum, program.session_id);
  }

  // Create experiment record
  const expResult = db.prepare(`
    INSERT INTO research_experiments (program_id, session_id, cycle_id, experiment_number, hypothesis, baseline_value, status, decision, created_at)
    VALUES (?, ?, ?, ?, ?, ?, 'running', 'pending', ?)
  `).run(programId, program.session_id || null, cycleId, nextExpNum, 'Autonomous experiment cycle', program.current_best, now);
  const experimentId = Number(expResult.lastInsertRowid);

  // Build past experiments context for the agent
  let pastContext = '';
  if (pastExperiments.length > 0) {
    pastContext = '\n\n## Past Experiments (most recent first)\n';
    for (const exp of pastExperiments) {
      const dec = exp.decision || exp.status;
      const val = exp.metric_value !== null && exp.metric_value !== undefined ? exp.metric_value : exp.result_value;
      const d = exp.delta !== null && exp.delta !== undefined ? exp.delta : '';
      pastContext += `- [${dec}] ${exp.hypothesis || exp.description || 'unknown'} -> metric: ${val !== null && val !== undefined ? val : 'N/A'} (delta: ${d !== '' ? (d > 0 ? '+' : '') + d : 'N/A'})\n`;
    }
  }

  // Determine if this is a code-modifying autoresearch program (has target_file or metric_command)
  const isCodeExperiment = !!(program.target_file || program.metric_command);

  // Build the research agent prompt — the KEY part
  let researchPrompt;

  if (isCodeExperiment) {
    // ── AUTORESEARCH MODE: modify code, measure metric, keep/discard ──
    researchPrompt = `You are an autonomous researcher. Your job is to improve a measurable metric through iterative experimentation on real code.

## Your Research Program
**Goal:** ${program.goal}
**Metric:** ${program.metric_name || 'quality'} (${program.success_metric || 'lower is better'})
**Current baseline:** ${program.current_best !== null && program.current_best !== undefined ? program.current_best : (program.baseline_value !== null && program.baseline_value !== undefined ? program.baseline_value : 'not yet established')}
**Target file:** ${program.target_file || 'the main implementation file'}
**Working directory:** ${program.working_directory || '/Users/maxstewart/Desktop/The Team/app'}
${program.working_branch ? `**Working branch:** ${program.working_branch}` : ''}

## The Experiment Loop

You MUST follow this exact process:

1. **Read the target file** to understand the current state
2. **Form a hypothesis** — what specific change might improve the metric?
3. **Make the change** — edit the target file
4. **Git commit the change** (so we can revert if it fails)
5. **Measure the result** — run the metric command: \`${program.metric_command || 'run tests or evaluate quality'}\`
6. **Compare to baseline** (${program.current_best !== null && program.current_best !== undefined ? program.current_best : 'establish baseline on first run'})
7. **If the metric IMPROVED** — decision = keep (leave the commit in place)
8. **If the metric got WORSE or STAYED THE SAME** — decision = discard, and revert: \`git revert HEAD --no-edit\`
9. **If the code CRASHED** — decision = crash, revert, try something different next time
10. **Report your result** using this EXACT format at the very end of your output:

\`\`\`
EXPERIMENT_RESULT:
hypothesis: [what you tried]
metric_value: [number — the measured metric value]
baseline: [the baseline you compared against]
delta: [improvement or regression as a number]
decision: [keep or discard or crash]
commit_hash: [the git commit hash of your change, or 'reverted']
description: [one line summary]
\`\`\`

## Rules
- If the metric IMPROVED: decision = keep
- If the metric got WORSE or STAYED THE SAME: decision = discard, and REVERT your changes
- If the code CRASHED: decision = crash, revert, and try something different
- NEVER stop to ask if you should continue
- Focus on SMALL, targeted changes that are measurable
- Simpler code that performs equally = keep (simplification win)
- Your changes are REAL. If you keep a change, the next cycle builds on it. If you discard, the code reverts.
- This is NOT theoretical research — you are modifying actual code and measuring actual results.
${pastContext}

## Accumulated Knowledge
${knowledgeBase.length > 0 ? knowledgeBase.map((k, i) => `${i + 1}. ${k}`).join('\n') : 'No accumulated knowledge yet.'}

## Important
${program.methodology || 'Open experimentation — use your best judgment on approach.'}`;

  } else {
    // ── KNOWLEDGE RESEARCH MODE: original behavior for topic-based research ──
    const experimentLog = pastExperiments.map(e =>
      `  Exp #${e.experiment_number}: ${e.hypothesis} -> ${e.status}${e.result_value !== null ? ` (value: ${e.result_value}, delta: ${e.delta})` : ''} | ${e.description || ''}`
    ).join('\n');
    const keptFindings = pastExperiments.filter(e => e.status === 'kept' || e.decision === 'keep');
    const discardedFindings = pastExperiments.filter(e => e.status === 'discarded' || e.decision === 'discard');

    researchPrompt = `You are conducting autonomous research experiment #${nextExpNum} for the program: "${program.title}"

## Research Goal
${program.goal}

## Methodology
${program.methodology || 'Open investigation — use your best judgment on approach.'}

## Success Metric
${program.success_metric || 'Quality and depth of findings'}
${program.success_threshold ? `Target threshold: ${program.success_threshold}` : ''}
${program.current_best !== null ? `Current best result: ${program.current_best}` : ''}
${program.baseline_value !== null ? `Baseline: ${program.baseline_value}` : ''}

## Previous Experiment Log (${pastExperiments.length} experiments so far)
${experimentLog || '  No experiments yet — this is the first.'}

## Accumulated Knowledge
${knowledgeBase.length > 0 ? knowledgeBase.map((k, i) => `  ${i + 1}. ${k}`).join('\n') : '  No accumulated knowledge yet.'}

## What Worked (${keptFindings.length} kept)
${keptFindings.map(f => `  - ${f.hypothesis}: ${f.evaluation || f.description || 'kept'}`).join('\n') || '  Nothing yet.'}

## What Failed (${discardedFindings.length} discarded)
${discardedFindings.map(f => `  - ${f.hypothesis}: ${f.evaluation || f.description || 'discarded'}`).join('\n') || '  Nothing yet.'}

## Your Task for This Cycle
1. Based on the research goal and what has been learned so far, formulate a NEW hypothesis to test.
2. Design and execute an experiment to test this hypothesis.
3. Evaluate the results.
4. Report your findings in the following structured format:

HYPOTHESIS: [your hypothesis]
METHOD: [what you did]
RESULT: [what happened — be specific with data/evidence]
EVALUATION: [kept/discarded — did this improve our understanding?]
FINDING_TITLE: [one-line title if this is a keepable finding]
FINDING_CONTENT: [detailed finding content if kept]
KNOWLEDGE: [one sentence of accumulated knowledge from this experiment]
CONFIDENCE: [low/medium/high]

OR, if using the experiment format:

\`\`\`
EXPERIMENT_RESULT:
hypothesis: [what you tried]
metric_value: [number]
baseline: [the baseline you compared against]
delta: [improvement or regression]
decision: [keep or discard or crash]
description: [one line summary]
\`\`\`

IMPORTANT: Build on what was learned. Do NOT repeat experiments that already failed. Try novel approaches. If you are stuck, try a radically different angle.`;
  }

  // Spawn an agent to run this cycle
  try {
    const researcherName = program.assigned_to || 'Briar';
    const researcher = db.prepare(`SELECT id FROM team_members WHERE name = ? AND status = 'active'`).get(researcherName);
    if (researcher) {
      const taskResult = db.prepare(`
        INSERT INTO tasks (title, description, status, priority, source_file, assigned_to, started_at, progress, current_step, created_at, updated_at)
        VALUES (?, ?, 'in_progress', 'high', 'research_program', ?, ?, 10, ?, ?, ?)
      `).run(
        `Research Exp #${nextExpNum}: ${program.title}`,
        researchPrompt,
        researcher.id, now,
        `Running experiment #${nextExpNum}`, now, now
      );
      const taskId = Number(taskResult.lastInsertRowid);

      db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at, category) VALUES (?, ?, 'research_cycle', ?, ?, 'research')`)
        .run(taskId, researcherName, `Auto-cycle #${nextExpNum} for research program: ${program.title}`, now);

      broadcast('task.created', { id: taskId });

      // Update experiment with task link
      db.prepare(`UPDATE research_experiments SET hypothesis = ?, task_id = ? WHERE id = ?`)
        .run(`Experiment #${nextExpNum} — agent spawned (task #${taskId})`, taskId, experimentId);

      // Spawn terminal
      spawnMemberTerminal(taskId, researcher.id).catch(err => {
        console.error(`[ResearchEngine] Spawn error for program #${programId}: ${err.message}`);
        db.prepare(`UPDATE research_experiments SET status = 'crash', decision = 'crash', evaluation = ? WHERE id = ?`)
          .run(`Spawn failed: ${err.message}`, experimentId);
      });
    }
  } catch (spawnErr) {
    console.error(`[ResearchEngine] Cycle error for program #${programId}: ${spawnErr.message}`);
    db.prepare(`UPDATE research_experiments SET status = 'crash', decision = 'crash', evaluation = ? WHERE id = ?`)
      .run(`Error: ${spawnErr.message}`, experimentId);
  }

  // Update program counters
  db.prepare(`UPDATE research_programs SET experiment_count = experiment_count + 1, last_cycle_at = ? WHERE id = ?`)
    .run(now, programId);

  broadcast('research.program_updated', { id: programId });
  if (program.session_id) broadcast('research.updated', { id: program.session_id });

  return { success: true, experiment_id: experimentId, experiment_number: nextExpNum };
}

// Record results from a completed experiment
function recordExperimentResult(experimentId, results) {
  const now = localNow();
  const experiment = db.prepare(`SELECT * FROM research_experiments WHERE id = ?`).get(experimentId);
  if (!experiment) return null;

  const program = db.prepare(`SELECT * FROM research_programs WHERE id = ?`).get(experiment.program_id);
  if (!program) return null;

  const { hypothesis, method, result_value, evaluation, status, description, finding_title, finding_content, knowledge, confidence, raw_output } = results;

  const delta = result_value !== undefined && experiment.baseline_value !== null
    ? result_value - experiment.baseline_value : null;

  const finalStatus = status || (delta !== null && delta > 0 ? 'kept' : 'discarded');

  // Update the experiment
  db.prepare(`
    UPDATE research_experiments
    SET hypothesis = ?, method = ?, result_value = ?, delta = ?, status = ?, evaluation = ?,
        description = ?, raw_output = ?, completed_at = ?
    WHERE id = ?
  `).run(
    hypothesis || experiment.hypothesis, method || null,
    result_value !== undefined ? result_value : null,
    delta, finalStatus, evaluation || null,
    description || null, raw_output || null, now, experimentId
  );

  // Update program counters and best value
  if (finalStatus === 'kept') {
    db.prepare(`UPDATE research_programs SET kept_count = kept_count + 1 WHERE id = ?`).run(program.id);
    if (result_value !== undefined && (program.current_best === null || result_value > program.current_best)) {
      db.prepare(`UPDATE research_programs SET current_best = ? WHERE id = ?`).run(result_value, program.id);
    }
  } else if (finalStatus === 'discarded') {
    db.prepare(`UPDATE research_programs SET discarded_count = discarded_count + 1 WHERE id = ?`).run(program.id);
  } else if (finalStatus === 'crash') {
    db.prepare(`UPDATE research_programs SET crash_count = crash_count + 1 WHERE id = ?`).run(program.id);
  }

  // Update knowledge base
  if (knowledge) {
    let kb = [];
    try { kb = JSON.parse(program.knowledge_base || '[]'); } catch(e) {}
    kb.push(knowledge);
    if (kb.length > 50) kb = kb.slice(-50); // Keep last 50
    db.prepare(`UPDATE research_programs SET knowledge_base = ? WHERE id = ?`)
      .run(JSON.stringify(kb), program.id);
  }

  // Create finding if kept
  if (finalStatus === 'kept' && finding_title && program.session_id) {
    db.prepare(`
      INSERT INTO research_findings (session_id, cycle_id, title, content, confidence, status, created_at)
      VALUES (?, ?, ?, ?, ?, 'kept', ?)
    `).run(program.session_id, experiment.cycle_id, finding_title, finding_content || '', confidence || 'medium', now);

    // Update cycle
    if (experiment.cycle_id) {
      db.prepare(`UPDATE research_cycles SET status = 'kept', finding_title = ?, finding_content = ?, evaluation_reason = ?, completed_at = ? WHERE id = ?`)
        .run(finding_title, finding_content || '', evaluation || '', now, experiment.cycle_id);
    }
  } else if (experiment.cycle_id) {
    db.prepare(`UPDATE research_cycles SET status = ?, evaluation_reason = ?, completed_at = ? WHERE id = ?`)
      .run(finalStatus === 'crash' ? 'error' : 'discarded', evaluation || '', now, experiment.cycle_id);
  }

  // Check convergence
  if (program.success_threshold && result_value !== undefined && result_value >= program.success_threshold) {
    db.prepare(`UPDATE research_programs SET status = 'converged', converged_at = ? WHERE id = ?`).run(now, program.id);
    stopResearchLoop(program.id);
    broadcast('research.program_updated', { id: program.id, status: 'converged' });
  }

  broadcast('research.program_updated', { id: program.id });
  return db.prepare(`SELECT * FROM research_experiments WHERE id = ?`).get(experimentId);
}

// Start autonomous loop for a program
function startResearchLoop(programId) {
  if (activeResearchLoops.has(programId)) return;

  const program = db.prepare(`SELECT * FROM research_programs WHERE id = ?`).get(programId);
  if (!program) return;

  const intervalMs = (program.loop_interval_seconds || 30) * 1000;

  const interval = setInterval(async () => {
    try {
      const current = db.prepare(`SELECT status FROM research_programs WHERE id = ?`).get(programId);
      if (!current || current.status !== 'running') {
        stopResearchLoop(programId);
        return;
      }

      // Skip this cycle if a previous experiment is still running (avoid pileup)
      const runningExp = db.prepare(`SELECT id FROM research_experiments WHERE program_id = ? AND status = 'running' LIMIT 1`).get(programId);
      if (runningExp) {
        return;
      }

      await runResearchCycle(programId);
    } catch (err) {
      console.error(`[ResearchEngine] Loop error for program #${programId}:`, err.message);
    }
  }, intervalMs);

  activeResearchLoops.set(programId, { interval, status: 'running' });
}

function stopResearchLoop(programId) {
  const loop = activeResearchLoops.get(programId);
  if (loop) {
    clearInterval(loop.interval);
    activeResearchLoops.delete(programId);
  }
}

