// GET /api/tool-catalog — list catalog entries, filterable by ?category=&type=
app.get('/api/tool-catalog', (req, res, next) => {
  try {
    let sql = 'SELECT * FROM tool_catalog WHERE 1=1';
    const params = [];
    if (req.query.category) {
      sql += ' AND category = ?';
      params.push(req.query.category);
    }
    if (req.query.type) {
      sql += ' AND type = ?';
      params.push(req.query.type);
    }
    sql += ' ORDER BY category, name';
    const rows = db.prepare(sql).all(...params);
    const parsed = rows.map(r => ({
      ...r,
      config_template: JSON.parse(r.config_template || '{}')
    }));
    res.json(parsed);
  } catch (err) { next(err); }
});

// GET /api/tool-catalog/:id — single catalog entry
app.get('/api/tool-catalog/:id', (req, res, next) => {
  try {
    const entry = db.prepare('SELECT * FROM tool_catalog WHERE id = ?').get(req.params.id);
    if (!entry) throw notFound('Catalog entry not found');
    entry.config_template = JSON.parse(entry.config_template || '{}');
    res.json(entry);
  } catch (err) { next(err); }
});

// POST /api/tool-catalog/:id/install — one-click install: creates a member_tool from a catalog entry
// Auto-links existing vault credentials for the provider if found
app.post('/api/tool-catalog/:id/install', (req, res, next) => {
  try {
    const { member_id } = req.body;
    if (!member_id) throw badRequest('member_id is required');

    const entry = db.prepare('SELECT * FROM tool_catalog WHERE id = ?').get(req.params.id);
    if (!entry) throw notFound('Catalog entry not found');

    const member = db.prepare('SELECT id FROM team_members WHERE id = ?').get(member_id);
    if (!member) throw notFound('Team member not found');

    const tool_type = entry.type === 'mcp' ? 'mcp_server' : 'api_key';
    const config = JSON.parse(entry.config_template || '{}');

    // For MCP tools, inject setup_command into config
    if (entry.type === 'mcp' && entry.setup_command) {
      config.setup_command = entry.setup_command;
    }

    // Check if a vault credential already exists for this provider — auto-link it
    let linkedVaultId = null;
    const vaultMatch = db.prepare(
      'SELECT id, encrypted_value FROM credential_vault WHERE provider = ? ORDER BY updated_at DESC LIMIT 1'
    ).get(entry.name);
    if (vaultMatch) {
      linkedVaultId = vaultMatch.id;
      // Inject the stored key into config so the tool works immediately
      if (tool_type === 'api_key' && vaultMatch.encrypted_value) {
        config.key = vaultMatch.encrypted_value;
      }
    }

    const now = localNow();
    const configStr = JSON.stringify(config);
    const result = db.prepare(`
      INSERT INTO member_tools (member_id, tool_name, tool_type, config, enabled, vault_id, created_at, updated_at)
      VALUES (?, ?, ?, ?, 1, ?, ?, ?)
    `).run(member_id, entry.name, tool_type, configStr, linkedVaultId, now, now);

    res.json({
      id: Number(result.lastInsertRowid),
      member_id: Number(member_id),
      tool_name: entry.name,
      tool_type,
      config,
      enabled: 1,
      vault_id: linkedVaultId,
      catalog_entry_id: entry.id,
      created_at: now,
      updated_at: now
    });
  } catch (err) { next(err); }
});

