// POST /api/tools/:id/copy — copy a tool to multiple team members
app.post('/api/tools/:id/copy', (req, res, next) => {
  try {
    const { member_ids } = req.body;
    if (!Array.isArray(member_ids) || member_ids.length === 0) {
      throw badRequest('member_ids must be a non-empty array');
    }

    const source = db.prepare('SELECT * FROM member_tools WHERE id = ?').get(req.params.id);
    if (!source) throw notFound('Tool not found');

    let copied = 0;
    let skipped = 0;
    const now = localNow();

    for (const mid of member_ids) {
      // Check if tool with same name already exists for this member
      const existing = db.prepare(
        'SELECT id FROM member_tools WHERE member_id = ? AND tool_name = ?'
      ).get(mid, source.tool_name);

      if (existing) {
        skipped++;
        continue;
      }

      db.prepare(`
        INSERT INTO member_tools (member_id, tool_name, tool_type, config, enabled, use_cases, guidelines, usage_limits, daily_limit, daily_used, last_reset_date, created_at, updated_at)
        VALUES (?, ?, ?, ?, 1, ?, ?, ?, ?, 0, ?, ?, ?)
      `).run(
        mid, source.tool_name, source.tool_type, source.config,
        source.use_cases || null, source.guidelines || null,
        source.usage_limits || null, source.daily_limit != null ? source.daily_limit : null,
        now.split(' ')[0], now, now
      );
      copied++;
    }

    res.json({ copied, skipped });
  } catch (err) { next(err); }
});

// ── Shared Helper: generate guidelines from tool name + type (no DB record needed) ──
function generateGuidelinesForTool(toolName, toolType) {
  const name = toolName || 'Unknown Tool';
  let use_cases, guidelines, usage_limits, daily_limit;

  // Look up tool_catalog for extra context
  let catalogEntry = null;
  try {
    catalogEntry = db.prepare('SELECT * FROM tool_catalog WHERE LOWER(name) = LOWER(?)').get(name);
  } catch (e) { /* catalog lookup is optional */ }
  const catalogDesc = catalogEntry ? catalogEntry.description : '';

  if (toolType === 'api_key') {
    const capability = catalogDesc || `${name}'s API capabilities`;
    use_cases = `Use ${name} when the task requires ${capability}. Do not use for tasks Claude can handle directly without external calls.`;
    const rules = [
      '1. Always check daily limit before making a request',
      '2. Cache results to avoid redundant queries — never repeat the same query within a session',
      '3. Use the most cost-effective model/tier available for the task',
      '4. Cite the source in your output — include URLs or reference identifiers',
      '5. Summarize results in structured format',
      '6. Batch related queries into a single request when possible',
      '7. Do not use for personal or non-work queries'
    ];
    guidelines = rules.join('\n');
    usage_limits = 'Respect the daily cap. If approaching the limit, prioritize high-impact queries over speculative ones. Prefer cheaper models/tiers when top-tier quality is not required.';
    daily_limit = 25;
  } else if (toolType === 'mcp_server') {
    const capability = catalogDesc || 'direct integration tasks';
    use_cases = `Use ${name} for ${capability}. Prefer this over manual workarounds when the MCP server can handle the operation directly.`;
    const rules = [
      '1. Use the minimum number of tool calls needed — consolidate operations',
      '2. Batch operations when possible to reduce round-trips',
      '3. Handle errors gracefully — do not retry more than 3 times',
      '4. Log what actions were taken and their outcomes',
      '5. Verify results before reporting success',
      '6. Never perform destructive operations without explicit confirmation',
      '7. Prefer read-only operations when gathering information'
    ];
    guidelines = rules.join('\n');
    usage_limits = 'Keep tool calls minimal. If an operation fails 3 times, stop and report the issue.';
    daily_limit = 50;
  } else if (toolType === 'session_token' || toolType === 'oauth_token') {
    use_cases = `Use ${name} for authenticated requests to the associated service. Only use within the scope of assigned tasks.`;
    const rules = [
      '1. Never expose the token in outputs or logs',
      '2. Check token validity before making requests',
      '3. If token expires, notify Max immediately',
      '4. Respect rate limits of the service',
      '5. Do not make requests outside of assigned tasks'
    ];
    guidelines = rules.join('\n');
    usage_limits = 'Respect service rate limits. Monitor token expiry.';
    daily_limit = null;
  } else {
    const capability = catalogDesc || `${name}'s capabilities`;
    use_cases = `Use ${name} when the task specifically requires ${capability}. Evaluate whether simpler alternatives exist first.`;
    const rules = [
      '1. Follow configured usage patterns',
      '2. Log actions taken with this tool',
      '3. Handle errors gracefully',
      '4. Verify results before reporting success'
    ];
    guidelines = rules.join('\n');
    usage_limits = null;
    daily_limit = null;
  }

  return { use_cases, guidelines, usage_limits, daily_limit };
}

// POST /api/tools/:id/generate-guidelines — generate guideline templates based on tool type
// Supports ID=0 for new (unsaved) tools by falling back to body parameters
app.post('/api/tools/:id/generate-guidelines', (req, res, next) => {
  try {
    let tool = null;
    if (parseInt(req.params.id) > 0) {
      tool = db.prepare('SELECT id, tool_name, tool_type FROM member_tools WHERE id = ?').get(req.params.id);
    }
    const toolName = (tool && tool.tool_name) || req.body.tool_name || 'Unknown Tool';
    const toolType = (tool && tool.tool_type) || req.body.tool_type || 'api_key';

    const result = generateGuidelinesForTool(toolName, toolType);
    res.json(result);
  } catch (err) { next(err); }
});

