// ── Tool Test Endpoint ─────────────────────────────────────────────

app.post('/api/tools/:id/test', async (req, res, next) => {
  try {
    const tool = db.prepare('SELECT * FROM member_tools WHERE id = ?').get(req.params.id);
    if (!tool) throw notFound('Tool not found');

    let config = {};
    try { config = typeof tool.config === 'string' ? JSON.parse(tool.config) : (tool.config || {}); } catch {}

    // Resolve the actual API key: prefer vault, fall back to config
    let apiKey = config.key || config.api_key || config.apiKey || '';
    if (tool.vault_id) {
      const vault = db.prepare('SELECT encrypted_value FROM credential_vault WHERE id = ?').get(tool.vault_id);
      if (vault) apiKey = vault.encrypted_value;
    }

    const endpoint = config.endpoint || config.base_url || '';

    // ── API Key tools: actually try to connect ──
    if (tool.tool_type === 'api_key') {
      if (!apiKey) return res.json({ success: false, error: 'No API key configured' });
      if (!endpoint) return res.json({ success: false, error: 'No endpoint URL configured' });

      const url = new URL(endpoint);
      const proto = url.protocol === 'https:' ? https : http;

      // Helper: make an HTTP request and return { status, body }
      const makeRequest = (opts, body) => new Promise((resolve) => {
        const r = proto.request(opts, (resp) => {
          let data = '';
          resp.on('data', c => data += c);
          resp.on('end', () => resolve({ status: resp.statusCode, body: data }));
        });
        r.on('error', e => resolve({ status: 0, body: e.message }));
        r.on('timeout', () => { r.destroy(); resolve({ status: 0, body: 'Timeout' }); });
        if (body) r.write(body);
        r.end();
      });

      const baseOpts = {
        hostname: url.hostname,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        timeout: 10000,
        headers: { 'Authorization': 'Bearer ' + apiKey, 'Accept': 'application/json' }
      };

      let result;

      // Perplexity: POST a tiny test query to their dedicated API
      if (endpoint.includes('perplexity')) {
        const body = JSON.stringify({ model: 'sonar', messages: [{ role: 'user', content: 'ping' }], max_tokens: 1 });
        result = await makeRequest({
          hostname: 'api.perplexity.ai',
          port: 443,
          path: '/chat/completions',
          method: 'POST',
          timeout: 10000,
          headers: {
            'Authorization': 'Bearer ' + apiKey,
            'Content-Type': 'application/json',
            'Accept': 'application/json',
            'User-Agent': 'TheTeam/1.0'
          }
        }, body);
        if (result.status === 200) {
          return res.json({ success: true, message: 'Perplexity API responding', status: 200, response_preview: result.body.slice(0, 200) });
        }
        return res.json({ success: false, error: `API returned ${result.status}`, details: result.body.slice(0, 500) });
      }

      // OpenAI-compatible APIs: GET /v1/models
      if (/openai|groq|together|openrouter|mistral/i.test(endpoint)) {
        result = await makeRequest({ ...baseOpts, path: '/v1/models', method: 'GET' });
        if (result.status === 200) {
          let modelCount = 0;
          try { modelCount = JSON.parse(result.body).data?.length || 0; } catch {}
          return res.json({ success: true, message: `API responding. ${modelCount} models available.`, status: 200 });
        }
        return res.json({ success: false, error: `API returned ${result.status}`, details: result.body.slice(0, 500) });
      }

      // Generic: just try connecting to the endpoint
      result = await makeRequest({ ...baseOpts, path: url.pathname || '/', method: 'GET' });
      if (result.status >= 200 && result.status < 400) {
        return res.json({ success: true, message: 'Connection successful', status: result.status });
      } else if (result.status === 0) {
        return res.json({ success: false, error: 'Connection failed', details: result.body });
      }
      return res.json({ success: false, error: `HTTP ${result.status}`, details: result.body.slice(0, 500) });
    }

    // ── MCP Server: verify the command exists ──
    if (tool.tool_type === 'mcp_server') {
      const cmd = config.setup_command || config.command || '';
      if (!cmd) return res.json({ success: false, error: 'No command configured' });
      // Extract the binary name (first token) and check if it exists on PATH
      const binary = cmd.split(/\s+/)[0];
      const { execSync } = require('child_process');
      let found = false;
      try { execSync('which ' + binary, { timeout: 5000 }); found = true; } catch {}
      if (found) {
        return res.json({ success: true, message: `MCP server command "${binary}" found on PATH`, note: 'Full connectivity is tested when activated in the terminal.' });
      }
      return res.json({ success: false, error: `Command "${binary}" not found on PATH`, note: 'Install the binary or update the command in tool config.' });
    }

    // ── Other tool types: confirm configuration ──
    return res.json({ success: true, message: 'Tool configured. Type: ' + tool.tool_type, note: 'Manual verification required for this tool type.' });
  } catch (err) { next(err); }
});

// POST /api/tools/:id/report-error — create a task from a tool error
app.post('/api/tools/:id/report-error', (req, res, next) => {
  try {
    const { error_message, error_details, tool_name } = req.body;
    if (!error_message) return res.status(400).json({ error: 'error_message is required' });

    const now = localNow();
    const title = `Fix tool error: ${tool_name || 'Unknown tool'}`;
    const description = `Tool ID: ${req.params.id}\n\nError: ${error_message}\n\nDetails: ${error_details || 'No additional details'}`;

    // Create a high-priority task assigned to Hone
    const result = db.prepare(`
      INSERT INTO tasks (title, description, status, priority, source_file, assigned_to, created_at, updated_at)
      VALUES (?, ?, 'new', 'high', 'tool-error', (SELECT id FROM team_members WHERE name = 'Lathe'), ?, ?)
    `).run(title, description, now, now);

    const taskId = Number(result.lastInsertRowid);

    // Create a notification so Gray knows about it
    createNotification('system', title, description, taskId);

    broadcast('notification.created', { id: taskId, title });

    res.json({ task_id: taskId, message: 'Error reported — Hone will investigate' });
  } catch (err) { next(err); }
});

// ── Shared Helper: prompt-based guideline generation (no DB record needed) ──
function generateGuidelinesFromPrompt(toolName, prompt) {
  const p = prompt.trim().toLowerCase();
  const name = toolName;

  // ── Extract numbers (used for limits) ──
  const numbers = p.match(/\d+/g) || [];
  const dailyLimit = numbers.length > 0 ? parseInt(numbers[0], 10) : null;

  // ── Keyword detection ──
  const has = (kw) => p.includes(kw);
  const wantsResearch    = has('research') || has('investigate') || has('look up') || has('find out');
  const wantsCitations   = has('cite') || has('source') || has('reference') || has('citation');
  const wantsDeep        = has('deep research') || has('thorough') || has('exhaustive') || has('comprehensive');
  const wantsRestriction = has('only');
  const wantsProhibition = has('never') || has('do not') || has("don't") || has('must not') || has('forbidden');
  const wantsSummary     = has('summarize') || has('summary') || has('brief') || has('concise');
  const wantsCost        = has('cost') || has('cheap') || has('budget') || has('efficient');
  const wantsCode        = has('code') || has('programming') || has('develop');
  const wantsCreative    = has('creative') || has('writing') || has('draft') || has('brainstorm');

  // ── Build use_cases ──
  const useParts = [];
  if (wantsResearch)  useParts.push('deep research and investigation tasks');
  if (wantsCode)      useParts.push('code-related queries and development assistance');
  if (wantsCreative)  useParts.push('creative writing and content drafting');
  if (wantsSummary)   useParts.push('summarization and distillation of information');
  if (useParts.length === 0) useParts.push(`tasks that specifically require ${name}'s capabilities`);
  const use_cases = `Use ${name} for: ${useParts.join('; ')}. Evaluate whether simpler alternatives exist before invoking.`;

  // ── Build guidelines ──
  const rules = [];
  let ruleNum = 1;

  if (dailyLimit) {
    rules.push(`${ruleNum++}. Limit usage to ${dailyLimit} queries per cycle/day`);
  }
  rules.push(`${ruleNum++}. Always check daily limit before making a request`);

  if (wantsCitations) {
    rules.push(`${ruleNum++}. Always cite sources in your output — include URLs or reference identifiers`);
    rules.push(`${ruleNum++}. Verify source credibility before citing`);
  }

  if (wantsDeep) {
    rules.push(`${ruleNum++}. Conduct thorough multi-angle investigation — do not stop at the first result`);
    rules.push(`${ruleNum++}. Cross-reference findings across multiple sources`);
    rules.push(`${ruleNum++}. Provide confidence levels for each finding`);
  }

  if (wantsResearch) {
    rules.push(`${ruleNum++}. Structure research output with clear sections: findings, evidence, gaps`);
    rules.push(`${ruleNum++}. Distinguish between facts and inferences`);
  }

  if (wantsSummary) {
    rules.push(`${ruleNum++}. Summarize results concisely — lead with the key takeaway`);
  }

  if (wantsCost) {
    rules.push(`${ruleNum++}. Use the most cost-effective model or tier available`);
    rules.push(`${ruleNum++}. Cache results to avoid redundant queries`);
  }

  // Extract "only" restrictions
  if (wantsRestriction) {
    const onlyMatch = p.match(/only\s+(?:for\s+|when\s+|use\s+(?:for\s+|when\s+))?(.+?)(?:[.,;!]|$)/);
    if (onlyMatch) {
      rules.push(`${ruleNum++}. RESTRICTION: Only use ${onlyMatch[1].trim()}`);
    }
  }

  // Extract "never" prohibitions
  if (wantsProhibition) {
    const neverPatterns = p.match(/(?:never|do not|don't|must not)\s+(.+?)(?:[.,;!]|$)/g) || [];
    for (const np of neverPatterns) {
      const cleaned = np.replace(/^(never|do not|don't|must not)\s+/i, '').trim();
      if (cleaned.length > 2) {
        rules.push(`${ruleNum++}. PROHIBITION: Never ${cleaned}`);
      }
    }
  }

  if (wantsCode) {
    rules.push(`${ruleNum++}. Include code examples in output when relevant`);
  }

  if (wantsCreative) {
    rules.push(`${ruleNum++}. Maintain the requested tone and style throughout`);
  }

  rules.push(`${ruleNum++}. Do not use for personal or non-work queries`);
  rules.push(`${ruleNum++}. Log what was queried and summarize the result`);

  const guidelines = rules.join('\n');

  // ── Build usage_limits ──
  let usage_limits = 'Respect the daily cap.';
  if (dailyLimit) {
    usage_limits = `Max ${dailyLimit} uses per day/cycle. Prioritize high-impact queries over speculative ones.`;
  }
  if (wantsCost) {
    usage_limits += ' Prefer cheaper models/tiers when the task does not require top-tier quality.';
  }

  return { use_cases, guidelines, usage_limits, daily_limit: dailyLimit, source_prompt: prompt.trim() };
}

