// POST /api/tools/:id/generate-guidelines-from-prompt — supports ID=0 for new tools
app.post('/api/tools/:id/generate-guidelines-from-prompt', (req, res, next) => {
  try {
    let tool = null;
    if (parseInt(req.params.id) > 0) {
      tool = db.prepare('SELECT id, tool_name, tool_type FROM member_tools WHERE id = ?').get(req.params.id);
    }
    const toolName = (tool && tool.tool_name) || req.body.tool_name || 'Unknown Tool';

    const { prompt } = req.body;
    if (!prompt || !prompt.trim()) throw badRequest('prompt is required');

    const result = generateGuidelinesFromPrompt(toolName, prompt);
    res.json(result);
  } catch (err) { next(err); }
});

