// GET /api/agent-stream/:processId — events for a process
app.get('/api/agent-stream/:processId', (req, res, next) => {
  try {
    const { processId } = req.params;
    const limit = parseInt(req.query.limit) || 50;
    const since = parseInt(req.query.since) || 0;

    let query = `SELECT * FROM agent_activity_stream WHERE process_id = ?`;
    const params = [processId];
    if (since > 0) {
      query += ` AND id > ?`;
      params.push(since);
    }
    query += ` ORDER BY id DESC LIMIT ?`;
    params.push(limit);

    const events = db.prepare(query).all(...params);
    res.json({ events: events.reverse() });
  } catch (err) { next(err); }
});

// GET /api/agent-stream/summary/:processId — summary for a process
app.get('/api/agent-stream/summary/:processId', (req, res, next) => {
  try {
    const { processId } = req.params;

    const counts = db.prepare(`
      SELECT event_type, COUNT(*) as cnt FROM agent_activity_stream
      WHERE process_id = ? GROUP BY event_type
    `).all(processId);
    const event_counts = {};
    for (const c of counts) event_counts[c.event_type] = c.cnt;

    const files = db.prepare(`
      SELECT DISTINCT file_name FROM agent_activity_stream
      WHERE process_id = ? AND file_name IS NOT NULL
      ORDER BY created_at DESC
    `).all(processId);

    const last_event = db.prepare(`
      SELECT * FROM agent_activity_stream WHERE process_id = ? ORDER BY id DESC LIMIT 1
    `).get(processId);

    res.json({ event_counts, files_touched: files.map(f => f.file_name), last_event: last_event || null });
  } catch (err) { next(err); }
});

// ── Workspace Phase 2: Project Submission + Plan Generation + Execution ──

// digestSessionPrompt — takes big prompt, generates phased execution plan via Claude CLI
async function digestSessionPrompt(sessionId) {
  const session = db.prepare('SELECT * FROM workspace_sessions WHERE id = ?').get(sessionId);
  if (!session) return;

  const digestPrompt = `You are Gray, the orchestrator for The Team. You have received a large project prompt. Your job is to break it into executable phases.

## The Prompt
${(session.raw_prompt || '').slice(0, 50000)}${(session.raw_prompt || '').length > 50000 ? '\n\n[TRUNCATED - full prompt is ' + (session.raw_prompt || '').length + ' chars]' : ''}

## Your Team
- Clamp (VP Backend Engineering) — server.js, API routes, database, worker service
- Flare (VP Frontend Engineering) — app.js, DOM logic, events, client-side state
- Fret (Director of UI Engineering) — HTML, CSS, design systems, responsive layout
- Onyx (CTO) — architecture plans, ADRs, technical strategy
- Gauge (VP QA & Testing) — testing, quality assurance, test strategy
- Grit (VP DevOps & Infrastructure) — Docker, CI/CD, monitoring, deployment
- Briar (Director of Research) — research, investigation, analysis
- Lathe (VP Platform) — improvements, polish, developer experience
- Barb (VP Security) — security audits, auth, vulnerability testing
- Quill (Director of Content) — documentation, guides, content

## Instructions
Break this project into 5-15 sequential phases. Each phase should be:
- Completable by 1-3 team members
- Independently testable
- Building on previous phases

Output ONLY a JSON array (no markdown, no explanation) in this exact format:
[
  {
    "phase_number": 1,
    "title": "Phase title",
    "description": "What needs to be done in this phase",
    "assigned_member": "member_name",
    "complexity": "simple|moderate|complex",
    "depends_on": []
  },
  ...
]

Each phase's "depends_on" is an array of phase numbers that must complete first. Phase 1 always has empty depends_on.
Assign the right team member based on the work type (backend=Anvil, frontend=Spark, UI/CSS=Lumen, testing=Rivet, etc.)
Keep phases focused — one domain per phase when possible.`;

  const { spawn } = require('child_process');
  const cliPath = (db.prepare("SELECT value FROM system_settings WHERE key = 'claude_cli_path'").get() || {}).value || 'claude';

  // Token audit: Workspace digest is structured JSON extraction — haiku is sufficient and ~10x cheaper than sonnet
  const child = spawn(cliPath, ['-p', digestPrompt, '--output-format', 'text', '--model', 'claude-haiku-4-5-20251001', '--max-turns', '1'], {
    stdio: ['ignore', 'pipe', 'pipe'],
    cwd: process.env.PROJECT_ROOT || path.join(__dirname, '..')
  });

  let stdout = '';
  let stderr = '';
  child.stdout.on('data', d => stdout += d.toString());
  child.stderr.on('data', d => stderr += d.toString());

  child.on('close', (code) => {
    const now = localNow();
    if (code !== 0 && !stdout.trim()) {
      db.prepare('UPDATE workspace_sessions SET status = ?, updated_at = ? WHERE id = ?').run('failed', now, sessionId);
      broadcast('workspace.digest_failed', { session_id: sessionId });
      console.error(`[Workspace] Digest failed for session #${sessionId}: code ${code}, stderr: ${stderr.slice(0, 200)}`);
      return;
    }

    try {
      // Extract JSON from response (might have surrounding text)
      const jsonMatch = stdout.match(/\[[\s\S]*\]/);
      if (!jsonMatch) throw new Error('No JSON array found in response');

      const phases = JSON.parse(jsonMatch[0]);

      // Save plan as markdown
      let planMd = `# Execution Plan\n\n`;
      for (const phase of phases) {
        planMd += `## Phase ${phase.phase_number}: ${phase.title}\n`;
        planMd += `**Assigned:** ${phase.assigned_member} | **Complexity:** ${phase.complexity}\n`;
        if (phase.depends_on && phase.depends_on.length > 0) {
          planMd += `**Depends on:** Phase${phase.depends_on.length > 1 ? 's' : ''} ${phase.depends_on.join(', ')}\n`;
        }
        planMd += `\n${phase.description}\n\n`;
      }

      // Save phases to database
      for (const phase of phases) {
        const member = db.prepare('SELECT id, name FROM team_members WHERE LOWER(name) = LOWER(?)').get(phase.assigned_member);
        db.prepare(`INSERT INTO session_phases (session_id, phase_number, title, description, assigned_member_id, assigned_member_name, complexity, depends_on, status, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?)`)
          .run(sessionId, phase.phase_number, phase.title, phase.description, member ? member.id : null, phase.assigned_member, phase.complexity || 'moderate', JSON.stringify(phase.depends_on || []), 'pending', now, now);
      }

      // Update session
      db.prepare('UPDATE workspace_sessions SET status = ?, plan_markdown = ?, plan_json = ?, updated_at = ? WHERE id = ?')
        .run('pending_approval', planMd, JSON.stringify(phases), now, sessionId);

      broadcast('workspace.plan_ready', { session_id: sessionId });

      // Create notification
      createNotification('system', 'Plan Ready', `Execution plan for "${session.title}" is ready for review (${phases.length} phases)`);

    } catch (parseErr) {
      // Save raw output even if JSON parse fails
      db.prepare('UPDATE workspace_sessions SET status = ?, plan_markdown = ?, updated_at = ? WHERE id = ?')
        .run('pending_approval', stdout, now, sessionId);
      broadcast('workspace.plan_ready', { session_id: sessionId });
      console.error(`[Workspace] Plan parse error for session #${sessionId}: ${parseErr.message}`);
    }
  });

  child.on('error', (err) => {
    const now = localNow();
    db.prepare('UPDATE workspace_sessions SET status = ?, updated_at = ? WHERE id = ?').run('failed', now, sessionId);
    broadcast('workspace.digest_failed', { session_id: sessionId });
    console.error(`[Workspace] Digest spawn error for session #${sessionId}: ${err.message}`);
  });
}

// ── Project Intake: Drop files/folders/repos, analyze, generate plan ──

// POST /api/intake/analyze — accepts JSON with file contents, repo URLs, folder paths, context
// Uses a higher body limit since file contents are sent inline
app.post('/api/intake/analyze', express.json({ limit: '25mb' }), (req, res, next) => {
  try {
    const { project_name, context, repo_urls, folder_paths, files, exochain } = req.body;
    const now = localNow();

    // 1. Collect all text content from sources
    let allContent = '';
    let sources = [];

    // From uploaded/pasted file contents (read client-side, sent as {name, content, size})
    if (files && files.length > 0) {
      for (const file of files) {
        allContent += `\n\n--- FILE: ${file.name} ---\n${file.content}`;
        sources.push({ type: 'file', name: file.name, size: file.content.length });
      }
    }

    // From folder paths (server reads files from local filesystem)
    if (folder_paths && folder_paths.length > 0) {
      for (const folderPath of folder_paths) {
        try {
          const foundFiles = require('child_process').execSync(
            `find "${folderPath}" -type f \\( -name "*.md" -o -name "*.txt" -o -name "*.js" -o -name "*.py" -o -name "*.json" -o -name "*.ts" -o -name "*.toml" -o -name "*.yaml" -o -name "*.yml" -o -name "*.css" -o -name "*.html" \\) -not -path "*/node_modules/*" -not -path "*/.git/*" -not -path "*/dist/*" -not -path "*/.next/*" | head -30`,
            { timeout: 10000 }
          ).toString().trim().split('\n').filter(Boolean);

          let folderContent = '';
          let fileCount = 0;
          for (const f of foundFiles) {
            try {
              const content = fs.readFileSync(f, 'utf-8');
              if (content.length < 50000) {
                folderContent += `\n\n--- ${f} ---\n${content}`;
                fileCount++;
              }
            } catch (_) {}
          }
          allContent += folderContent;
          sources.push({ type: 'folder', path: folderPath, files: fileCount });
        } catch (e) {
          sources.push({ type: 'folder', path: folderPath, error: e.message });
        }
      }
    }

    // From repo URLs (clone to temp, read key files)
    if (repo_urls && repo_urls.length > 0) {
      for (const url of repo_urls) {
        try {
          const repoName = url.split('/').pop().replace('.git', '');
          const tmpDir = `/tmp/intake-${Date.now()}-${repoName}`;
          require('child_process').execSync(`git clone --depth 1 "${url}" "${tmpDir}" 2>/dev/null`, { timeout: 30000 });

          // Read README and key files
          const readmeFiles = ['README.md', 'readme.md', 'README.txt', 'CLAUDE.md', 'package.json', 'pyproject.toml'];
          for (const rf of readmeFiles) {
            try {
              const content = fs.readFileSync(path.join(tmpDir, rf), 'utf-8');
              allContent += `\n\n--- REPO ${repoName}: ${rf} ---\n${content}`;
            } catch (_) {}
          }

          // List structure
          const structure = require('child_process').execSync(`find "${tmpDir}" -type f -not -path "*/.git/*" | head -50`, { timeout: 5000 }).toString();
          allContent += `\n\n--- REPO ${repoName}: FILE STRUCTURE ---\n${structure}`;

          sources.push({ type: 'repo', url, name: repoName });

          // Cleanup
          require('child_process').execSync(`rm -rf "${tmpDir}"`, { timeout: 5000 });
        } catch (e) {
          sources.push({ type: 'repo', url, error: e.message });
        }
      }
    }

    // Add user context
    if (context) {
      allContent += `\n\n--- USER CONTEXT ---\n${context}`;
    }

    // 2. Create a workspace session for this intake
    const sessionResult = db.prepare(`
      INSERT INTO workspace_sessions (title, raw_prompt, prompt_chars, prompt_tokens_est, status, priority, created_at, updated_at)
      VALUES (?, ?, ?, ?, 'digesting', 'normal', ?, ?)
    `).run(project_name || 'New Project Intake', allContent, allContent.length, Math.ceil(allContent.length / 4), now, now);

    const sessionId = Number(sessionResult.lastInsertRowid);

    // 3. Trigger digestion (generates the plan)
    setImmediate(() => digestSessionPrompt(sessionId));

    res.json({
      session_id: sessionId,
      sources,
      total_chars: allContent.length,
      estimated_tokens: Math.ceil(allContent.length / 4),
      status: 'digesting',
      message: 'Gray is analyzing your sources and building a plan...'
    });
  } catch (err) { next(err); }
});

// GET /api/intake/:sessionId/status — check analysis status
app.get('/api/intake/:sessionId/status', (req, res, next) => {
  try {
    const session = db.prepare('SELECT id, title, status, plan_json, plan_markdown, prompt_chars, prompt_tokens_est, created_at, updated_at FROM workspace_sessions WHERE id = ?').get(req.params.sessionId);
    if (!session) return res.status(404).json({ error: 'Session not found' });

    let phases = [];
    if (session.plan_json) {
      try { phases = JSON.parse(session.plan_json); } catch (_) {}
    }
    // Also fetch saved phases from session_phases table
    if (phases.length === 0) {
      phases = db.prepare('SELECT * FROM session_phases WHERE session_id = ? ORDER BY phase_number').all(req.params.sessionId);
    }

    res.json({
      session_id: session.id,
      title: session.title,
      status: session.status,
      phases,
      plan_markdown: session.plan_markdown,
      prompt_chars: session.prompt_chars,
      prompt_tokens_est: session.prompt_tokens_est,
      created_at: session.created_at,
      updated_at: session.updated_at
    });
  } catch (err) { next(err); }
});

// POST /api/intake/:sessionId/execute — approve and start execution (delegates to workspace execute)
app.post('/api/intake/:sessionId/execute', async (req, res, next) => {
  try {
    const session = db.prepare('SELECT * FROM workspace_sessions WHERE id = ?').get(req.params.sessionId);
    if (!session) return res.status(404).json({ error: 'Session not found' });

    const now = localNow();
    const phases = db.prepare('SELECT * FROM session_phases WHERE session_id = ? ORDER BY phase_number').all(req.params.sessionId);

    if (phases.length === 0) return res.status(400).json({ error: 'No phases to execute' });

    // Approve and set to executing
    db.prepare('UPDATE workspace_sessions SET status = ?, updated_at = ? WHERE id = ?')
      .run('executing', now, req.params.sessionId);

    broadcast('workspace.executing', { session_id: Number(req.params.sessionId) });

    // Find launchable phases (no unmet dependencies)
    const launchable = [];
    for (const phase of phases) {
      const deps = JSON.parse(phase.depends_on || '[]');
      if (deps.length === 0) {
        launchable.push(phase);
      }
    }

    const spawned = [];
    for (const phase of launchable) {
      const taskResult = db.prepare(`INSERT INTO tasks (title, description, status, priority, assigned_to, created_at, updated_at) VALUES (?,?,?,?,?,?,?)`)
        .run(`[Phase ${phase.phase_number}] ${phase.title}`, phase.description || '', 'in_progress', session.priority || 'normal', phase.assigned_member_id || null, now, now);

      const taskId = Number(taskResult.lastInsertRowid);
      db.prepare('UPDATE session_phases SET status = ?, task_id = ?, updated_at = ? WHERE id = ?')
        .run('in_progress', taskId, now, phase.id);

      spawned.push({ phase_number: phase.phase_number, task_id: taskId, assigned: phase.assigned_member_name });
    }

    // Log activity
    db.prepare(`INSERT INTO activity_log (actor, action, notes, created_at) VALUES (?, ?, ?, ?)`)
      .run('Gray', 'intake_execute', `Executing intake plan "${session.title}" with ${phases.length} phases (${launchable.length} launched)`, now);

    res.json({ success: true, status: 'executing', spawned });
  } catch (err) { next(err); }
});

// ── Process Watchdog ──────────────────────────────────────────────

// ── Heartbeat & Watchdog — extracted to services/heartbeat.js ──
const heartbeatService = require('./services/heartbeat')(db, broadcast, { localNow, isLocalMode }, { spawnMemberTerminal, runningProcesses });
const { processWatchdog, heartbeatScheduler, executeHeartbeat } = heartbeatService;

// Run watchdog every 60 seconds
setInterval(processWatchdog, 60000);

// Heartbeat scheduler — runs every 30 seconds
setInterval(heartbeatScheduler, 30000);

// ── Ghost Process Detector — catches agents stuck in "running" with no actual CLI process ──
// Runs every 2 minutes. If agent_runtime_state says "running" but:
//   - No active_processes entry exists for the task
//   - No actual CLI process is alive
//   - Last heartbeat was >10 minutes ago
// Then the agent is a ghost — reset it to idle and complete the task.
setInterval(function ghostProcessDetector() {
  try {
    const now = localNow();
    const ghosts = db.prepare(`
      SELECT ars.member_id, ars.current_task_id, ars.last_heartbeat_at,
        tm.name as member_name,
        t.id as task_id, t.title as task_title, t.progress
      FROM agent_runtime_state ars
      JOIN team_members tm ON ars.member_id = tm.id
      LEFT JOIN tasks t ON ars.current_task_id = t.id
      WHERE ars.status = 'running'
      AND ars.last_heartbeat_at < datetime(?, '-10 minutes')
      AND ars.member_id NOT IN (SELECT member_id FROM active_processes WHERE status = 'running')
    `).all(now);

    for (const ghost of ghosts) {
      console.warn(`[GhostDetector] ${ghost.member_name} is stuck "running" on task #${ghost.task_id} but no CLI process exists. Last heartbeat: ${ghost.last_heartbeat_at}. Cleaning up.`);

      // Reset agent to idle
      db.prepare(`UPDATE agent_runtime_state SET status = 'idle', current_task_id = NULL, updated_at = ? WHERE member_id = ?`)
        .run(now, ghost.member_id);

      // RESTART the stuck task instead of completing it — the work wasn't finished
      if (ghost.task_id) {
        const task = db.prepare(`SELECT status, revision_count, assigned_to FROM tasks WHERE id = ?`).get(ghost.task_id);
        if (task && task.status === 'in_progress') {
          const revisions = task.revision_count || 0;
          if (revisions >= 3) {
            // Already retried 3 times — complete it, don't loop forever
            db.prepare(`UPDATE tasks SET status = 'completed', progress = 100, current_step = ?, completed_at = ?, updated_at = ? WHERE id = ?`)
              .run(`Auto-completed after ${revisions} ghost restarts`, now, now, ghost.task_id);
            db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'GhostDetector', 'ghost_abandoned', ?, ?)`)
              .run(ghost.task_id, `Abandoned after ${revisions} ghost restarts. Process keeps dying.`, now);
          } else {
            // Restart — re-spawn the specialist
            db.prepare(`UPDATE tasks SET revision_count = ?, current_step = ?, updated_at = ? WHERE id = ?`)
              .run(revisions + 1, `Ghost restart ${revisions + 1}/3 — process died, restarting...`, now, ghost.task_id);
            db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'GhostDetector', 'ghost_restart', ?, ?)`)
              .run(ghost.task_id, `${ghost.member_name}'s process died at ${ghost.progress || 0}%. Restarting (attempt ${revisions + 1}/3).`, now);
            spawnMemberTerminal(ghost.task_id, ghost.member_id).catch(err => {
              console.error(`[GhostDetector] Restart failed for ${ghost.member_name}: ${err.message}`);
            });
          }
          broadcast('task.updated', { id: ghost.task_id });
        }
      }
    }

    if (ghosts.length > 0) {
      console.log(`[GhostDetector] Cleaned ${ghosts.length} ghost process(es)`);
    }
  } catch (err) {
    console.warn(`[GhostDetector] Error: ${err.message}`);
  }
}, 120000); // Every 2 minutes

// Thrift & Forge periodic optimization audit — runs every hour, triggers if 24h+ and 5+ delivered tasks
setInterval(periodicOptimizationAuditCheck, 3600000);

// ── Routing Watchdog — catches tasks stuck in 'routing' with no Council process ──
// If a Board Room directive's Council CLI dies before responding, the task stays
// in 'routing' forever. This catches it after 5 minutes and falls back to C-Suite.
setInterval(function routingWatchdog() {
  try {
    const now = localNow();
    const stuck = db.prepare(`
      SELECT t.id, t.title, t.assigned_to, t.source_file FROM tasks t
      WHERE t.status = 'routing' AND t.updated_at < datetime(?, '-5 minutes')
    `).all(now);

    for (const task of stuck) {
      console.warn(`[RoutingWatchdog] Task #${task.id} stuck in routing for 5+ min. Rescuing.`);

      // Find best-fit C-Suite exec via keyword matching
      const routing = routeActionItem((task.title || '') + ' ' + (task.source_file || ''));
      const fallback = routing || getDefaultSpecialist();

      if (fallback) {
        const memberId = fallback.member_id || fallback.id;
        db.prepare(`UPDATE tasks SET status = 'in_progress', assigned_to = ?, priority = 'high',
          current_step = ?, updated_at = ? WHERE id = ?`)
          .run(memberId, `Routing watchdog rescued — assigned to ${fallback.member_name || fallback.name}`, now, task.id);
        db.prepare(`INSERT OR IGNORE INTO task_assignments (task_id, member_id, subagent_count, created_at) VALUES (?,?,1,?)`)
          .run(task.id, memberId, now);
        db.prepare(`INSERT INTO activity_log (task_id, actor, action, notes, created_at) VALUES (?, 'RoutingWatchdog', 'routing_rescue', ?, ?)`)
          .run(task.id, `Task stuck in routing 5+ min. Council CLI likely died. Rescued to ${fallback.member_name || fallback.name}.`, now);

        spawnMemberTerminal(task.id, memberId).catch(err => {
          console.error(`[RoutingWatchdog] Spawn failed: ${err.message}`);
        });
      } else {
        // No fallback — mark completed to prevent permanent stuck state
        db.prepare(`UPDATE tasks SET status = 'completed', progress = 100, current_step = ?, completed_at = ?, updated_at = ? WHERE id = ?`)
          .run('Routing failed — no available specialist', now, now, task.id);
      }
    }
  } catch (err) { console.warn(`[RoutingWatchdog] Error: ${err.message}`); }
}, 120000); // Every 2 minutes

// ── Spawn Retry on Failure — if spawnMemberTerminal fails, retry once after 10s ──
// Wraps the spawn call with a single retry to handle transient CLI failures.
const _originalSpawnMemberTerminal = spawnMemberTerminal;
async function spawnMemberTerminalWithRetry(taskId, memberId) {
  try {
    return await _originalSpawnMemberTerminal(taskId, memberId);
  } catch (err) {
    console.warn(`[SpawnRetry] First spawn attempt failed for task #${taskId}: ${err.message}. Retrying in 10s.`);
    return new Promise((resolve) => {
      setTimeout(async () => {
        try {
          const result = await _originalSpawnMemberTerminal(taskId, memberId);
          resolve(result);
        } catch (retryErr) {
          console.error(`[SpawnRetry] Retry also failed for task #${taskId}: ${retryErr.message}`);
          resolve({ success: false, reason: 'spawn_retry_failed' });
        }
      }, 10000);
    });
  }
}
// Reassign the function name so all callers get the retry wrapper
spawnMemberTerminal = spawnMemberTerminalWithRetry;

// ── Pipeline Health Check — end-to-end verification every 30 minutes ──
// Confirms the full pipeline works: can create a task, route it, and spawn it.
// If any step fails, creates a notification so Max knows the system is degraded.
setInterval(function pipelineHealthCheck() {
  try {
    const now = localNow();
    const checks = [];

    // Check 1: Can we write to the database?
    try {
      db.prepare(`INSERT INTO activity_log (actor, action, notes, created_at) VALUES ('PipelineHealth', 'health_check', 'Routine pipeline check', ?)`).run(now);
      checks.push({ name: 'database_write', passed: true });
    } catch (e) {
      checks.push({ name: 'database_write', passed: false, error: e.message });
    }

    // Check 2: Is the CLI available?
    try {
      const cliPath = (db.prepare(`SELECT value FROM system_settings WHERE key = 'claude_cli_path'`).get() || {}).value || 'claude';
      require('child_process').execSync(`which ${cliPath} 2>/dev/null`, { timeout: 3000 });
      checks.push({ name: 'cli_available', passed: true });
    } catch (e) {
      checks.push({ name: 'cli_available', passed: false, error: 'Claude CLI not found' });
    }

    // Check 3: Are there tasks stuck > 30 min?
    const stuckCount = db.prepare(`SELECT COUNT(*) as c FROM tasks WHERE status IN ('in_progress','routing') AND updated_at < datetime(?, '-30 minutes')`).get(now).c;
    checks.push({ name: 'no_stuck_tasks', passed: stuckCount === 0, count: stuckCount });

    // Check 4: FK integrity
    const fkCount = db.prepare(`SELECT COUNT(*) as c FROM pragma_foreign_key_check()`).get().c;
    checks.push({ name: 'fk_integrity', passed: fkCount === 0, count: fkCount });

    const allPassed = checks.every(c => c.passed);
    const failedChecks = checks.filter(c => !c.passed);

    if (!allPassed) {
      const failMsg = failedChecks.map(c => `${c.name}: ${c.error || c.count + ' issues'}`).join(', ');
      console.error(`[PipelineHealth] DEGRADED: ${failMsg}`);
      createNotification('system', 'Pipeline Health Warning', `System degraded: ${failMsg}`, null);
    }
  } catch (err) { console.warn(`[PipelineHealth] Error: ${err.message}`); }
}, 1800000); // Every 30 minutes

