// GET /api/tasks/:id/time — list time entries + totals
app.get('/api/tasks/:id/time', (req, res) => {
  try {
    const taskId = Number(req.params.id);
    const task = db.prepare('SELECT id, estimated_hours FROM tasks WHERE id = ?').get(taskId);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    const entries = db.prepare('SELECT * FROM task_time_entries WHERE task_id = ? ORDER BY started_at DESC').all(taskId);

    // Check for an active (running) timer
    const active = entries.find(e => !e.stopped_at) || null;

    // Sum completed durations
    const totalSeconds = entries.reduce((sum, e) => sum + (e.duration_seconds || 0), 0);

    res.json({
      entries,
      active,
      total_seconds: totalSeconds,
      estimated_hours: task.estimated_hours || null
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// POST /api/tasks/:id/timer/start — start a timer session
app.post('/api/tasks/:id/timer/start', (req, res) => {
  try {
    const taskId = Number(req.params.id);
    const task = db.prepare('SELECT id FROM tasks WHERE id = ?').get(taskId);
    if (!task) return res.status(404).json({ error: 'Task not found' });

    // Stop any existing active timer first
    const active = db.prepare('SELECT id, started_at FROM task_time_entries WHERE task_id = ? AND stopped_at IS NULL').get(taskId);
    const now = localNow();
    if (active) {
      const startedMs = new Date(active.started_at.replace(' ', 'T')).getTime();
      const durationSeconds = Math.round((Date.now() - startedMs) / 1000);
      db.prepare('UPDATE task_time_entries SET stopped_at = ?, duration_seconds = ? WHERE id = ?')
        .run(now, durationSeconds, active.id);
    }

    const result = db.prepare('INSERT INTO task_time_entries (task_id, started_at, created_at) VALUES (?, ?, ?)')
      .run(taskId, now, now);
    const entry = db.prepare('SELECT * FROM task_time_entries WHERE id = ?').get(result.lastInsertRowid);
    res.status(201).json(entry);
    broadcast('task.timer.started', { task_id: taskId, entry_id: entry.id });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// POST /api/tasks/:id/timer/stop — stop the active timer
app.post('/api/tasks/:id/timer/stop', (req, res) => {
  try {
    const taskId = Number(req.params.id);
    const active = db.prepare('SELECT id, started_at FROM task_time_entries WHERE task_id = ? AND stopped_at IS NULL').get(taskId);
    if (!active) return res.status(400).json({ error: 'No active timer' });

    const now = localNow();
    const startedMs = new Date(active.started_at.replace(' ', 'T')).getTime();
    const durationSeconds = Math.round((Date.now() - startedMs) / 1000);

    db.prepare('UPDATE task_time_entries SET stopped_at = ?, duration_seconds = ? WHERE id = ?')
      .run(now, durationSeconds, active.id);

    // Recompute and persist actual_hours
    const total = db.prepare('SELECT SUM(duration_seconds) as s FROM task_time_entries WHERE task_id = ? AND duration_seconds IS NOT NULL').get(taskId);
    const totalHours = ((total && total.s) || 0) / 3600;
    db.prepare('UPDATE tasks SET actual_hours = ? WHERE id = ?').run(totalHours, taskId);

    const entry = db.prepare('SELECT * FROM task_time_entries WHERE id = ?').get(active.id);
    res.json(entry);
    broadcast('task.timer.stopped', { task_id: taskId, entry_id: entry.id, duration_seconds: durationSeconds });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// DELETE /api/tasks/:id/time/:entryId — delete a time entry
app.delete('/api/tasks/:id/time/:entryId', (req, res) => {
  try {
    const taskId = Number(req.params.id);
    const entryId = Number(req.params.entryId);
    db.prepare('DELETE FROM task_time_entries WHERE id = ? AND task_id = ?').run(entryId, taskId);
    // Recompute actual_hours
    const total = db.prepare('SELECT SUM(duration_seconds) as s FROM task_time_entries WHERE task_id = ? AND duration_seconds IS NOT NULL').get(taskId);
    const totalHours = ((total && total.s) || 0) / 3600;
    db.prepare('UPDATE tasks SET actual_hours = ? WHERE id = ?').run(totalHours, taskId);
    res.json({ ok: true });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

