// POST /api/skills/import — import a SKILL.md file
app.post('/api/skills/import', (req, res) => {
  try {
    const { content, name_override } = req.body;
    if (!content) return res.status(400).json({ error: 'content is required (SKILL.md content)' });

    let skillName = name_override || 'imported-skill-' + Date.now();
    let skillDesc = '';
    let skillContent = content;
    let skillCategory = 'imported';

    // Parse frontmatter
    const fmMatch = content.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
    if (fmMatch) {
      const fm = fmMatch[1];
      skillContent = fmMatch[2].trim();
      const nameMatch = fm.match(/^name:\s*(.+)$/m);
      if (nameMatch) skillName = name_override || nameMatch[1].trim();
      const descMatch = fm.match(/description:\s*>\s*\n([\s\S]*?)(?=\n\w|$)/);
      if (descMatch) skillDesc = descMatch[1].trim().replace(/\n\s*/g, ' ');
      else {
        const descSimple = fm.match(/^description:\s*(.+)$/m);
        if (descSimple) skillDesc = descSimple[1].trim();
      }
    }

    const displayName = skillName.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
    const now = localNow();
    const result = db.prepare('INSERT INTO skills (name, display_name, description, category, skill_content, version, status, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?)')
      .run(skillName, displayName, skillDesc, skillCategory, skillContent, '1.0', 'active', now, now);
    const skill = db.prepare('SELECT * FROM skills WHERE id = ?').get(result.lastInsertRowid);
    res.status(201).json(skill);
  } catch (err) {
    if (err.message && err.message.includes('UNIQUE')) return res.status(409).json({ error: 'Skill with that name already exists' });
    res.status(500).json({ error: err.message });
  }
});

// GET /api/skills/:id/export — export as SKILL.md format
app.get('/api/skills/:id/export', (req, res) => {
  try {
    const skill = db.prepare('SELECT * FROM skills WHERE id = ?').get(Number(req.params.id));
    if (!skill) return res.status(404).json({ error: 'Skill not found' });
    const exported = `---\nname: ${skill.name}\ndescription: >\n  ${(skill.description || '').replace(/\n/g, '\n  ')}\n---\n\n${skill.skill_content}`;
    res.set('Content-Type', 'text/markdown');
    res.set('Content-Disposition', `attachment; filename="${encodeURIComponent(skill.name)}.skill.md"`);
    res.send(exported);
  } catch (err) { res.status(500).json({ error: err.message }); }
});

