// GET /api/skills-proposals — list all proposals with optional filters
app.get('/api/skills-proposals', (req, res) => {
  try {
    let sql = 'SELECT sp.*, tm.name AS proposed_by_name, s.name AS parent_skill_name FROM skills_proposals sp LEFT JOIN team_members tm ON sp.proposed_by = tm.id LEFT JOIN skills s ON sp.parent_skill_id = s.id WHERE 1=1';
    const params = [];
    if (req.query.status) { sql += ' AND sp.status = ?'; params.push(req.query.status); }
    if (req.query.proposal_type) { sql += ' AND sp.proposal_type = ?'; params.push(req.query.proposal_type); }
    if (req.query.category) { sql += ' AND sp.category = ?'; params.push(req.query.category); }
    if (req.query.proposed_by) { sql += ' AND sp.proposed_by = ?'; params.push(Number(req.query.proposed_by)); }
    sql += ' ORDER BY CASE sp.proposal_type WHEN \'upgrade\' THEN 0 WHEN \'merge\' THEN 1 WHEN \'deprecate\' THEN 2 WHEN \'new\' THEN 3 END, sp.created_at DESC';
    if (req.query.limit) { sql += ' LIMIT ?'; params.push(Number(req.query.limit)); }
    const rows = db.prepare(sql).all(...params);
    res.json(rows);
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// GET /api/skills-proposals/stats — aggregate counts by type and status
