// ── Optimization Hub API — unified endpoints for the Optimization Hub page ──

// GET /api/optimization-hub/proposals — list skill proposals (with optional ?status filter)
app.get('/api/optimization-hub/proposals', (req, res) => {
  try {
    let sql = `SELECT sp.*, tm.name AS proposed_by_name, s.name AS parent_skill_name
      FROM skills_proposals sp
      LEFT JOIN team_members tm ON sp.proposed_by = tm.id
      LEFT JOIN skills s ON sp.parent_skill_id = s.id WHERE 1=1`;
    const params = [];
    if (req.query.status) { sql += ' AND sp.status = ?'; params.push(req.query.status); }
    if (req.query.proposal_type) { sql += ' AND sp.proposal_type = ?'; params.push(req.query.proposal_type); }
    sql += " ORDER BY CASE sp.proposal_type WHEN 'upgrade' THEN 0 WHEN 'merge' THEN 1 WHEN 'deprecate' THEN 2 WHEN 'new' THEN 3 END, sp.created_at DESC";
    if (req.query.limit) { sql += ' LIMIT ?'; params.push(Number(req.query.limit)); }
    res.json(db.prepare(sql).all(...params));
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// GET /api/optimization-hub/proposals/:id — single proposal detail
app.get('/api/optimization-hub/proposals/:id', (req, res) => {
  try {
    const row = db.prepare(`SELECT sp.*, tm.name AS proposed_by_name, s.name AS parent_skill_name, s.skill_content AS parent_skill_content
      FROM skills_proposals sp
      LEFT JOIN team_members tm ON sp.proposed_by = tm.id
      LEFT JOIN skills s ON sp.parent_skill_id = s.id WHERE sp.id = ?`).get(Number(req.params.id));
    if (!row) return res.status(404).json({ error: 'Proposal not found' });
    res.json(row);
  } catch (err) { res.status(500).json({ error: err.message }); }
});

