// POST /api/memory/cleanup — bulk cleanup old/low-importance memories
app.post('/api/memory/cleanup', (req, res) => {
  try {
    const { action } = req.body; // 'expire_old', 'archive_low', 'all'
    const now = localNow();
    let cleaned = 0;
    if (action === 'expire_old' || action === 'all') {
      // Archive notes older than 30 days
      // Use local timezone so cutoff aligns with created_at (stored in local time)
      const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toLocaleString('sv-SE', { timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone }).slice(0, 10) + ' 00:00:00';
      const result = db.prepare("UPDATE agent_memory_entities SET entity_type = 'archive', updated_at = ? WHERE entity_type = 'note' AND importance = 'low' AND created_at < ?").run(now, thirtyDaysAgo);
      cleaned += result.changes;
    }
    if (action === 'archive_low' || action === 'all') {
      // Archive low-importance items older than 14 days
      const fourteenDaysAgo = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000).toLocaleString('sv-SE', { timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone }).slice(0, 10) + ' 00:00:00';
      const result = db.prepare("UPDATE agent_memory_entities SET entity_type = 'archive', updated_at = ? WHERE importance = 'low' AND entity_type != 'archive' AND created_at < ?").run(now, fourteenDaysAgo);
      cleaned += result.changes;
    }
    // Remove expired entries
    const expResult = db.prepare("DELETE FROM agent_memory_entities WHERE expires_at IS NOT NULL AND expires_at < ?").run(now);
    cleaned += expResult.changes;
    res.json({ success: true, cleaned });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

