// POST /api/memory/import — import memory data from JSON
app.post('/api/memory/import', (req, res) => {
  try {
    const { entities, daily_notes, tacit_knowledge } = req.body;
    const now = localNow();
    let imported = 0;
    if (entities && Array.isArray(entities)) {
      for (const e of entities) {
        db.prepare('INSERT INTO agent_memory_entities (member_id, entity_type, title, content, tags, importance, project_id, source_task_id, expires_at, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?)')
          .run(e.member_id, e.entity_type, e.title, e.content, e.tags || '[]', e.importance || 'normal', e.project_id || null, e.source_task_id || null, e.expires_at || null, e.created_at || now, now);
        imported++;
      }
    }
    if (daily_notes && Array.isArray(daily_notes)) {
      for (const n of daily_notes) {
        try {
          db.prepare('INSERT INTO agent_daily_notes (member_id, note_date, content, tasks_worked, files_touched, lessons_learned, blockers, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?)')
            .run(n.member_id, n.note_date, n.content, n.tasks_worked || '[]', n.files_touched || '[]', n.lessons_learned || null, n.blockers || null, n.created_at || now, now);
          imported++;
        } catch (_) { /* skip duplicates */ }
      }
    }
    if (tacit_knowledge && Array.isArray(tacit_knowledge)) {
      for (const t of tacit_knowledge) {
        db.prepare('INSERT INTO agent_tacit_knowledge (member_id, knowledge_type, subject, insight, confidence, source_description, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?)')
          .run(t.member_id, t.knowledge_type, t.subject, t.insight, t.confidence || 'medium', t.source_description || null, t.created_at || now, now);
        imported++;
      }
    }
    res.json({ success: true, imported });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

