// Simple cron parser: calculates next run time from a cron expression
function parseCronExpression(cronExpr) {
  const parts = cronExpr.trim().split(/\s+/);
  if (parts.length !== 5) return null;
  return { minute: parts[0], hour: parts[1], dayOfMonth: parts[2], month: parts[3], dayOfWeek: parts[4] };
}

function cronFieldMatches(fieldExpr, value, max) {
  if (fieldExpr === '*') return true;
  // */N — every N
  if (fieldExpr.startsWith('*/')) {
    const step = parseInt(fieldExpr.slice(2));
    return step > 0 && value % step === 0;
  }
  // Range: 1-5
  if (fieldExpr.includes('-')) {
    const [low, high] = fieldExpr.split('-').map(Number);
    return value >= low && value <= high;
  }
  // List: 1,3,5
  if (fieldExpr.includes(',')) {
    return fieldExpr.split(',').map(Number).includes(value);
  }
  return parseInt(fieldExpr) === value;
}

function getNextCronRun(cronExpr, fromDate) {
  const cron = parseCronExpression(cronExpr);
  if (!cron) return null;
  const d = fromDate ? new Date(fromDate) : new Date();
  d.setSeconds(0, 0);
  d.setMinutes(d.getMinutes() + 1); // start from next minute
  // Search up to 366 days ahead
  for (let i = 0; i < 527040; i++) { // 366 days * 24 * 60
    const min = d.getMinutes();
    const hr = d.getHours();
    const dom = d.getDate();
    const mon = d.getMonth() + 1;
    const dow = d.getDay(); // 0=Sun
    if (cronFieldMatches(cron.minute, min, 59) &&
        cronFieldMatches(cron.hour, hr, 23) &&
        cronFieldMatches(cron.dayOfMonth, dom, 31) &&
        cronFieldMatches(cron.month, mon, 12) &&
        cronFieldMatches(cron.dayOfWeek, dow, 6)) {
      return d.toLocaleString('sv-SE', { timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone }).replace('T', ' ').slice(0, 19).replace('T', ' ');
    }
    d.setMinutes(d.getMinutes() + 1);
  }
  return null;
}

function describeCron(expr) {
  const parts = expr.trim().split(/\s+/);
  if (parts.length !== 5) return expr;
  const [min, hr, dom, mon, dow] = parts;
  if (min.startsWith('*/')) return `Every ${min.slice(2)} minutes`;
  if (min === '0' && hr === '*') return 'Every hour';
  if (min === '0' && hr !== '*' && dom === '*' && mon === '*' && dow === '*') return `Daily at ${hr}:00`;
  if (min === '0' && hr !== '*' && dow === '1-5') return `Weekdays at ${hr}:00`;
  if (dow !== '*' && dom === '*') return `${hr}:${min.padStart(2,'0')} on days ${dow}`;
  return expr;
}

