// POST /api/routines
app.post('/api/routines', (req, res) => {
  try {
    const { name, description, cron_expression, timezone, assigned_member_id, task_template, project_id, catch_up_policy, max_runs } = req.body;
    if (!name || !cron_expression) return res.status(400).json({ error: 'name and cron_expression are required' });
    const now = localNow();
    const next = getNextCronRun(cron_expression);
    const result = db.prepare(`INSERT INTO routines (name, description, cron_expression, timezone, assigned_member_id, task_template, project_id, catch_up_policy, max_runs, next_run_at, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`)
      .run(name, description || null, cron_expression, timezone || 'America/New_York', assigned_member_id || null, task_template || null, project_id || null, catch_up_policy || 'skip', max_runs || null, next, now, now);
    // Create default cron trigger
    db.prepare('INSERT INTO routine_triggers (routine_id, trigger_type, trigger_config, created_at) VALUES (?,?,?,?)')
      .run(result.lastInsertRowid, 'cron', JSON.stringify({ expression: cron_expression }), now);
    const routine = db.prepare('SELECT * FROM routines WHERE id = ?').get(result.lastInsertRowid);
    broadcast('routine.created', routine);
    res.status(201).json(routine);
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// PUT /api/routines/:id
app.put('/api/routines/:id', (req, res) => {
  try {
    const id = Number(req.params.id);
    const existing = db.prepare('SELECT * FROM routines WHERE id = ?').get(id);
    if (!existing) return res.status(404).json({ error: 'Routine not found' });
    const { name, description, cron_expression, timezone, assigned_member_id, task_template, project_id, catch_up_policy, max_runs, status } = req.body;
    const now = localNow();
    const newCron = cron_expression || existing.cron_expression;
    const next = cron_expression ? getNextCronRun(newCron) : existing.next_run_at;
    db.prepare(`UPDATE routines SET name = ?, description = ?, cron_expression = ?, timezone = ?, assigned_member_id = ?, task_template = ?, project_id = ?, catch_up_policy = ?, max_runs = ?, status = ?, next_run_at = ?, updated_at = ? WHERE id = ?`)
      .run(name || existing.name, description !== undefined ? description : existing.description, newCron, timezone || existing.timezone, assigned_member_id !== undefined ? assigned_member_id : existing.assigned_member_id, task_template !== undefined ? task_template : existing.task_template, project_id !== undefined ? project_id : existing.project_id, catch_up_policy || existing.catch_up_policy, max_runs !== undefined ? max_runs : existing.max_runs, status || existing.status, next, now, id);
    const updated = db.prepare('SELECT * FROM routines WHERE id = ?').get(id);
    broadcast('routine.updated', updated);
    res.json(updated);
  } catch (err) { res.status(500).json({ error: err.message }); }
});

