// POST /api/routines/:id/trigger — manually trigger a run
app.post('/api/routines/:id/trigger', (req, res) => {
  try {
    const id = Number(req.params.id);
    const routine = db.prepare('SELECT * FROM routines WHERE id = ?').get(id);
    if (!routine) return res.status(404).json({ error: 'Routine not found' });
    const now = localNow();

    // Create a task from the template if provided
    let taskId = null;
    if (routine.task_template) {
      const taskResult = db.prepare(`INSERT INTO tasks (title, description, assigned_to, status, priority, origin, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?)`)
        .run(`[Routine] ${routine.name}`, routine.task_template, routine.assigned_member_id || null, 'new', 'normal', 'routine', now, now);
      taskId = taskResult.lastInsertRowid;
      if (routine.project_id) {
        db.prepare('INSERT OR IGNORE INTO project_tasks (project_id, task_id) VALUES (?,?)').run(routine.project_id, taskId);
      }
    }

    // Record the run
    const runResult = db.prepare('INSERT INTO routine_runs (routine_id, task_id, status, triggered_at) VALUES (?,?,?,?)')
      .run(id, taskId, 'running', now);

    // Update routine
    const next = getNextCronRun(routine.cron_expression);
    db.prepare('UPDATE routines SET last_run_at = ?, next_run_at = ?, run_count = run_count + 1, updated_at = ? WHERE id = ?')
      .run(now, next, now, id);

    // Complete the run immediately for manual triggers
    db.prepare('UPDATE routine_runs SET status = ?, completed_at = ?, output_summary = ? WHERE id = ?')
      .run('completed', now, 'Manual trigger', runResult.lastInsertRowid);

    broadcast('routine.triggered', { routine_id: id, run_id: runResult.lastInsertRowid, task_id: taskId });
    res.json({ success: true, run_id: runResult.lastInsertRowid, task_id: taskId });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

