// ── Phase 6: Routine Scheduler (runs every 60 seconds) ──────────
setInterval(() => {
  try {
    const now = localNow();
    const dueRoutines = db.prepare(`SELECT * FROM routines WHERE status = 'active' AND next_run_at IS NOT NULL AND next_run_at <= ?`).all(now);
    for (const routine of dueRoutines) {
      // Check max_runs
      if (routine.max_runs && routine.run_count >= routine.max_runs) {
        db.prepare("UPDATE routines SET status = 'disabled', updated_at = ? WHERE id = ?").run(now, routine.id);
        continue;
      }
      // Create task from template
      let taskId = null;
      if (routine.task_template) {
        const taskResult = db.prepare(`INSERT INTO tasks (title, description, assigned_to, status, priority, origin, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?)`)
          .run(`[Routine] ${routine.name}`, routine.task_template, routine.assigned_member_id || null, 'new', 'normal', 'routine', now, now);
        taskId = taskResult.lastInsertRowid;
        if (routine.project_id) {
          db.prepare('INSERT OR IGNORE INTO project_tasks (project_id, task_id) VALUES (?,?)').run(routine.project_id, taskId);
        }
      }
      // Record run
      db.prepare('INSERT INTO routine_runs (routine_id, task_id, status, triggered_at, completed_at, output_summary) VALUES (?,?,?,?,?,?)')
        .run(routine.id, taskId, 'completed', now, now, 'Scheduled execution');
      // Update routine
      const next = getNextCronRun(routine.cron_expression);
      db.prepare('UPDATE routines SET last_run_at = ?, next_run_at = ?, run_count = run_count + 1, updated_at = ? WHERE id = ?')
        .run(now, next, now, routine.id);
      broadcast('routine.executed', { routine_id: routine.id, task_id: taskId });
    }
  } catch (err) {
    console.error('[RoutineScheduler] Error:', err.message);
  }
}, 60000);

