// POST /api/team/export
app.post('/api/team/export', (req, res) => {
  try {
    const { name, description, include_members, include_tasks, include_memory, include_skills } = req.body;
    const now = localNow();
    const exportData = { exported_at: now, version: '1.0' };

    if (include_members !== 0) {
      exportData.members = db.prepare("SELECT id, name, role, status, adapter_type, adapter_config, runtime_config, capabilities, permissions, icon, metadata FROM team_members").all();
    }
    if (include_skills !== 0) {
      exportData.skills = db.prepare("SELECT name, display_name, description, category, skill_content, version, status FROM skills").all();
      exportData.adapters = db.prepare("SELECT name, display_name, description, config_schema, capabilities, status FROM adapter_types").all();
    }
    if (include_tasks) {
      exportData.tasks = db.prepare("SELECT title, description, status, priority, origin FROM tasks WHERE status NOT IN ('completed','delivered') ORDER BY created_at DESC LIMIT 100").all();
    }
    if (include_memory) {
      exportData.memory = db.prepare('SELECT * FROM agent_memory_entities ORDER BY member_id').all();
      exportData.tacit_knowledge = db.prepare('SELECT * FROM agent_tacit_knowledge ORDER BY member_id').all();
    }
    // Identity files
    exportData.identity_files = db.prepare('SELECT member_id, file_type, file_name, content FROM agent_identity_files').all();
    // System settings (non-sensitive — exclude webhook_secret, api keys)
    exportData.settings = db.prepare("SELECT key, value FROM system_settings WHERE key NOT LIKE '%secret%' AND key NOT LIKE '%key%' AND key NOT LIKE '%token%'").all();

    const exportJson = JSON.stringify(exportData, null, 2);
    const exportPath = path.join(__dirname, '..', 'backups', `team_export_${Date.now()}.json`);
    fs.writeFileSync(exportPath, exportJson);

    const result = db.prepare(`INSERT INTO team_exports (name, description, format, file_path, include_members, include_tasks, include_memory, include_skills, export_size_bytes, created_at) VALUES (?,?,?,?,?,?,?,?,?,?)`)
      .run(name || `Export ${now}`, description || null, 'json', exportPath, include_members !== 0 ? 1 : 0, include_tasks ? 1 : 0, include_memory ? 1 : 0, include_skills !== 0 ? 1 : 0, Buffer.byteLength(exportJson), now);
    const record = db.prepare('SELECT * FROM team_exports WHERE id = ?').get(result.lastInsertRowid);
    res.status(201).json(record);
  } catch (err) { res.status(500).json({ error: err.message }); }
});

