// POST /api/openclaw/connections/:id/test
app.post('/api/openclaw/connections/:id/test', (req, res) => {
  try {
    const id = Number(req.params.id);
    const conn = db.prepare('SELECT * FROM openclaw_connections WHERE id = ?').get(id);
    if (!conn) return res.status(404).json({ error: 'Connection not found' });
    const now = localNow();

    // Update to testing status
    db.prepare("UPDATE openclaw_connections SET status = 'testing', updated_at = ? WHERE id = ?").run(now, id);

    // Attempt HTTP ping to the gateway
    const gatewayUrl = conn.gateway_url.endsWith('/') ? conn.gateway_url : conn.gateway_url + '/';
    const pingUrl = new URL('health', gatewayUrl);
    const protocol = pingUrl.protocol === 'https:' ? https : http;

    const pingReq = protocol.get(pingUrl.toString(), { timeout: 5000 }, (pingRes) => {
      let body = '';
      pingRes.on('data', chunk => body += chunk);
      pingRes.on('end', () => {
        const success = pingRes.statusCode >= 200 && pingRes.statusCode < 400;
        db.prepare(`UPDATE openclaw_connections SET status = ?, last_ping_at = ?, updated_at = ? WHERE id = ?`)
          .run(success ? 'connected' : 'error', now, now, id);
        // Log the test as a message
        db.prepare('INSERT INTO openclaw_messages (connection_id, direction, message_type, content, created_at) VALUES (?,?,?,?,?)')
          .run(id, 'outbound', 'heartbeat', JSON.stringify({ action: 'ping', status: pingRes.statusCode, response: body.slice(0, 200) }), now);
        res.json({ success, status_code: pingRes.statusCode, response: body.slice(0, 200) });
      });
    });
    pingReq.on('error', (err) => {
      db.prepare("UPDATE openclaw_connections SET status = 'error', last_ping_at = ?, updated_at = ? WHERE id = ?").run(now, now, id);
      db.prepare('INSERT INTO openclaw_messages (connection_id, direction, message_type, content, created_at) VALUES (?,?,?,?,?)')
        .run(id, 'outbound', 'error', JSON.stringify({ action: 'ping', error: err.message }), now);
      res.json({ success: false, error: err.message });
    });
    pingReq.on('timeout', () => {
      pingReq.destroy();
      db.prepare("UPDATE openclaw_connections SET status = 'error', last_ping_at = ?, updated_at = ? WHERE id = ?").run(now, now, id);
      res.json({ success: false, error: 'Connection timeout' });
    });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

