    const runs = db.prepare('SELECT id FROM eval_runs WHERE suite_id = ?').all(id);
    for (const run of runs) {
      db.prepare('DELETE FROM eval_test_results WHERE run_id = ?').run(run.id);
    }
    db.prepare('DELETE FROM eval_runs WHERE suite_id = ?').run(id);
    db.prepare('DELETE FROM eval_suites WHERE id = ?').run(id);
