// POST /api/evals/suites/:id/run — execute eval run
app.post('/api/evals/suites/:id/run', (req, res) => {
  try {
    const id = Number(req.params.id);
    const suite = db.prepare('SELECT * FROM eval_suites WHERE id = ?').get(id);
    if (!suite) return res.status(404).json({ error: 'Eval suite not found' });
    const { member_id } = req.body;
    const now = localNow();

    let testCases = [];
    try { testCases = JSON.parse(suite.test_cases); } catch (_) {}

    // Create run
    const runResult = db.prepare('INSERT INTO eval_runs (suite_id, member_id, status, total_tests, started_at, created_at) VALUES (?,?,?,?,?,?)')
      .run(id, member_id || null, 'running', testCases.length, now, now);
    const runId = runResult.lastInsertRowid;

    // Execute each test case (simulated — actual evaluation would involve agent execution)
    let passed = 0;
    let failed = 0;
    for (const tc of testCases) {
      // For now, create pending test results — actual eval would be async
      const testPassed = 0; // Pending — needs actual execution
      db.prepare('INSERT INTO eval_test_results (run_id, test_name, input, expected_output, passed, created_at) VALUES (?,?,?,?,?,?)')
        .run(runId, tc.name || 'unnamed', tc.input || '', tc.expected || '', testPassed, now);
      if (testPassed) passed++; else failed++;
    }

    const score = testCases.length > 0 ? passed / testCases.length : 0;
    db.prepare('UPDATE eval_runs SET status = ?, passed = ?, failed = ?, score = ?, results_json = ?, completed_at = ? WHERE id = ?')
      .run('completed', passed, failed, score, JSON.stringify({ passed, failed, total: testCases.length }), now, runId);

    const run = db.prepare('SELECT * FROM eval_runs WHERE id = ?').get(runId);
    run.test_results = db.prepare('SELECT * FROM eval_test_results WHERE run_id = ?').all(runId);
    broadcast('eval.run_completed', { suite_id: id, run_id: runId, score });
    res.status(201).json(run);
  } catch (err) { res.status(500).json({ error: err.message }); }
});

