// ── Health Check ─────────────────────────────────────────────────

app.get('/health', (req, res) => {
  const uptimeSeconds = Math.floor((Date.now() - SERVER_START_TIME) / 1000);

  // Human-readable uptime breakdown
  const uptimeDays = Math.floor(uptimeSeconds / 86400);
  const uptimeHours = Math.floor((uptimeSeconds % 86400) / 3600);
  const uptimeMinutes = Math.floor((uptimeSeconds % 3600) / 60);
  const uptimeSecondsRemainder = uptimeSeconds % 60;
  const uptimeHuman = [
    uptimeDays > 0 ? `${uptimeDays}d` : null,
    uptimeHours > 0 || uptimeDays > 0 ? `${uptimeHours}h` : null,
    `${uptimeMinutes}m`,
    `${uptimeSecondsRemainder}s`
  ].filter(Boolean).join(' ');

  // DB connectivity + latency
  let dbStatus = 'ok';
  let dbError = null;
  let dbLatencyMs = null;
  const dbStart = Date.now();
  try {
    db.prepare('SELECT 1').get();
    dbLatencyMs = Date.now() - dbStart;
  } catch (err) {
    dbStatus = 'error';
    dbError = err.message;
    dbLatencyMs = Date.now() - dbStart;
  }

  // Memory usage
  const mem = process.memoryUsage();
  const toMB = (bytes) => Math.round(bytes / 1024 / 1024 * 10) / 10;

  const status = dbStatus === 'ok' ? 'ok' : 'degraded';
  const payload = {
    status,
    uptime: {
      seconds: uptimeSeconds,
      human: uptimeHuman
    },
    database: {
      status: dbStatus,
      latency_ms: dbLatencyMs,
      path: DB_PATH,
      ...(dbError ? { error: dbError } : {})
    },
    request_counts: {
      total: requestCounters.total,
      by_status: { ...requestCounters.by_status },
      by_method: { ...requestCounters.by_method }
    },
    latency: requestLatency.stats(),
    slow_endpoints: requestLatency.topSlow(5),
    task_pipeline: (() => {
      try {
        const counts = db.prepare(`SELECT status, COUNT(*) as c FROM tasks GROUP BY status`).all();
        const pipeline = {};
        for (const r of counts) pipeline[r.status] = r.c;
        const activeProcs = db.prepare(`SELECT COUNT(*) as c FROM active_processes WHERE status = 'running'`).get().c;
        const unreadNotifs = db.prepare(`SELECT COUNT(*) as c FROM notifications WHERE read = 0`).get().c;
        return { ...pipeline, active_processes: activeProcs, unread_notifications: unreadNotifs };
      } catch (_) { return {}; }
    })(),
    cache: {
      stmt_cache_size: _stmtCache.size,
      mem_cache_team_members_fresh: Date.now() < _memCache.team_members.expiresAt,
      mem_cache_settings_fresh: Date.now() < _memCache.system_settings.expiresAt
    },
    memory: {
      rss_mb: toMB(mem.rss),
      heap_used_mb: toMB(mem.heapUsed),
      heap_total_mb: toMB(mem.heapTotal),
      external_mb: toMB(mem.external)
    },
    process: {
      pid: process.pid,
      node_version: process.version,
      port: process.env.PORT || 3000
    },
    timestamp: new Date().toISOString()
  };
  res.status(status === 'ok' ? 200 : 503).json(payload);
});

