// ── Refinement System ─────────────────────────────────────────────

// Auto-scan a target for refinement candidates
function scanForRefinementCandidates(targetId) {
  const target = db.prepare('SELECT * FROM refinement_targets WHERE id = ?').get(targetId);
  if (!target) return { files_scanned: 0, candidates_found: 0 };

  const now = localNow();
  const targetPath = target.target_path || path.join(__dirname, '..');
  const scanPatterns = JSON.parse(target.scan_patterns || '["*.js","*.css","*.html"]');
  const excludePatterns = JSON.parse(target.exclude_patterns || '["node_modules","*.lock",".git"]');

  db.prepare('UPDATE refinement_targets SET status = ?, last_scanned_at = ?, updated_at = ? WHERE id = ?')
    .run('scanning', now, now, targetId);

  const { execSync } = require('child_process');
  let files = [];
  for (const pattern of scanPatterns) {
    try {
      const result = execSync(`find "${targetPath}" -name "${pattern}" ${excludePatterns.map(p => `-not -path "*/${p}/*"`).join(' ')} 2>/dev/null | head -50`, { timeout: 10000 }).toString().trim();
      if (result) files.push(...result.split('\n'));
    } catch (_) {}
  }

  const candidates = [];
  for (const filePath of files) {
    try {
      const content = fs.readFileSync(filePath, 'utf-8');
      const lines = content.split('\n').length;
      const fileName = path.basename(filePath);
      const ext = path.extname(filePath);

      if (ext === '.js') {
        if (content.includes('innerHTML') && lines > 100) {
          candidates.push({ file_path: filePath, category: 'performance', title: `Optimize DOM updates in ${fileName}`, description: `${fileName} uses innerHTML which causes full DOM re-renders. Consider using targeted DOM updates or document fragments for better performance.`, priority: 'medium', metric_name: 'render_time', metric_command: `time curl -s http://localhost:${PORT} > /dev/null` });
        }
        if ((content.match(/fetch\(/g) || []).length > 10) {
          candidates.push({ file_path: filePath, category: 'performance', title: `Consolidate API calls in ${fileName}`, description: `${fileName} has ${(content.match(/fetch\(/g) || []).length} fetch calls. Consider batching or caching to reduce network overhead.`, priority: 'medium' });
        }
        if (content.includes('setInterval') && !content.includes('clearInterval')) {
          candidates.push({ file_path: filePath, category: 'reliability', title: `Fix interval leak in ${fileName}`, description: `${fileName} has setInterval without corresponding clearInterval. This can cause memory leaks over time.`, priority: 'high' });
        }
        const codeOnly = content.replace(/\/\/[^\n]*/g, '').replace(/\/\*[\s\S]*?\*\//g, '').replace(/'(?:[^'\\]|\\.)*'/g, "''").replace(/"(?:[^"\\]|\\.)*"/g, '""').replace(/`(?:[^`\\$]|\\.|\$(?!\{))*`/g, '``');
        if (codeOnly.includes('eval(')) {
          candidates.push({ file_path: filePath, category: 'security', title: `Remove direct eval call in ${fileName}`, description: `Direct eval calls are a security risk. Replace with JSON.parse, Function constructor, or other safe alternatives.`, priority: 'critical' });
        }
        if (content.includes('innerHTML') && content.includes('user')) {
          candidates.push({ file_path: filePath, category: 'security', title: `Sanitize user input in ${fileName}`, description: `Potential XSS: innerHTML used with user-controlled data.`, priority: 'critical' });
        }
        if ((content.match(/console\.log/g) || []).length > 5) {
          candidates.push({ file_path: filePath, category: 'quality', title: `Clean debug logs in ${fileName}`, description: `${fileName} has ${(content.match(/console\.log/g) || []).length} console.log statements. Remove debug logging.`, priority: 'low', estimated_effort: 'small' });
        }
      }

      if (lines > 5000) {
        candidates.push({ file_path: filePath, category: 'refactor', title: `Split large file ${fileName} (${lines} lines)`, description: `${fileName} is ${lines} lines which is very large. Consider splitting into modules for maintainability.`, priority: 'medium', estimated_effort: 'large' });
      }

      if (ext === '.html' && !content.includes('aria-label') && content.includes('<button')) {
        candidates.push({ file_path: filePath, category: 'accessibility', title: `Add ARIA labels to buttons in ${fileName}`, description: `Buttons in ${fileName} lack aria-label attributes for screen readers.`, priority: 'medium' });
      }

      if (ext === '.css' && lines > 1000) {
        const duplicates = content.match(/([a-z-]+)\s*\{[^}]+\}[\s\S]*?\1\s*\{/g);
        if (duplicates && duplicates.length > 3) {
          candidates.push({ file_path: filePath, category: 'refactor', title: `Deduplicate CSS selectors in ${fileName}`, description: `${fileName} has multiple duplicate selector definitions that could be consolidated.`, priority: 'low' });
        }
      }
    } catch (_) {}
  }

  let newCount = 0;
  for (const c of candidates) {
    const existing = db.prepare('SELECT id FROM refinement_candidates WHERE target_id = ? AND title = ? AND status IN (?, ?)').get(targetId, c.title, 'pending', 'in_progress');
    if (!existing) {
      db.prepare(`INSERT INTO refinement_candidates (target_id, file_path, category, title, description, priority, estimated_impact, estimated_effort, metric_name, metric_command, status, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)`)
        .run(targetId, c.file_path, c.category, c.title, c.description, c.priority, c.estimated_impact || 'medium', c.estimated_effort || 'medium', c.metric_name || null, c.metric_command || null, 'pending', now, now);
      newCount++;
    }
  }

  db.prepare('UPDATE refinement_targets SET status = ?, updated_at = ? WHERE id = ?')
    .run('inactive', now, targetId);

  broadcast('refinement.scanned', { target_id: targetId, candidates: newCount });

  return { files_scanned: files.length, candidates_found: newCount };
}

// Auto-refine loop: pick next candidate, assign, spawn
function runRefinementCycle(targetId) {
  if (isLocalMode()) return;
  const target = db.prepare('SELECT * FROM refinement_targets WHERE id = ?').get(targetId);
  if (!target || target.status === 'inactive') return;

  const now = localNow();

  const candidate = db.prepare(`
    SELECT rc.*, rt.target_path FROM refinement_candidates rc
    JOIN refinement_targets rt ON rc.target_id = rt.id
    WHERE rc.target_id = ? AND rc.status = 'pending'
    ORDER BY CASE rc.priority WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'medium' THEN 2 WHEN 'low' THEN 3 END, rc.created_at ASC
    LIMIT 1
  `).get(targetId);

  if (!candidate) {
    scanForRefinementCandidates(targetId);
    return;
  }

  const assignment = db.prepare(`
    SELECT tm.id, tm.name FROM refinement_team_assignments rta
    JOIN team_members tm ON rta.member_id = tm.id
    WHERE rta.target_id = ? AND rta.enabled = 1 AND tm.status = 'active'
    ORDER BY RANDOM() LIMIT 1
  `).get(targetId);

  if (!assignment) {
    return;
  }

  const programResult = db.prepare(`
    INSERT INTO research_programs (title, goal, target_file, metric_name, metric_command,
      experiment_timeout_seconds, working_directory, max_experiments, status, created_at)
    VALUES (?,?,?,?,?,?,?,?,?,?)
  `).run(candidate.title, candidate.description, candidate.file_path,
    candidate.metric_name || 'quality', candidate.metric_command || null,
    300, candidate.target_path || path.join(__dirname, '..'), 3, 'running', now);

  const programId = Number(programResult.lastInsertRowid);

  db.prepare('UPDATE refinement_candidates SET status = ?, assigned_member_id = ?, program_id = ?, updated_at = ? WHERE id = ?')
    .run('in_progress', assignment.id, programId, now, candidate.id);

  const taskResult = db.prepare(`
    INSERT INTO tasks (title, description, status, priority, assigned_to, source_file, created_at, updated_at)
    VALUES (?,?,?,?,?,?,?,?)
  `).run(`Refine: ${candidate.title}`, candidate.description, 'in_progress',
    candidate.priority === 'critical' ? 'urgent' : candidate.priority,
    assignment.id, 'refinement', now, now);

  const taskId = Number(taskResult.lastInsertRowid);

  spawnMemberTerminal(taskId, assignment.id).catch(err => {
    console.error(`[Refinement] Spawn failed: ${err.message}`);
  });

  broadcast('refinement.started', { target_id: targetId, candidate_id: candidate.id, task_id: taskId });
}

// Refinement auto-mode timers
const refinementTimers = {};

function startRefinementLoop(targetId) {
  if (refinementTimers[targetId]) return;
  db.prepare('UPDATE refinement_targets SET status = ?, updated_at = ? WHERE id = ?')
    .run('active', localNow(), targetId);
  refinementTimers[targetId] = setInterval(() => {
    try { runRefinementCycle(targetId); } catch (e) { console.error(`[Refinement] Cycle error: ${e.message}`); }
  }, 60000);
  try { runRefinementCycle(targetId); } catch (e) { console.error(`[Refinement] Cycle error: ${e.message}`); }
}

function stopRefinementLoop(targetId) {
  if (refinementTimers[targetId]) {
    clearInterval(refinementTimers[targetId]);
    delete refinementTimers[targetId];
  }
  db.prepare('UPDATE refinement_targets SET status = ?, updated_at = ? WHERE id = ?')
    .run('inactive', localNow(), targetId);
}

