// ── Data Export ────────────────────────────────────────────────────────

function rowsToCsv(rows) {
  if (!rows || rows.length === 0) return '';
  const keys = Object.keys(rows[0]);
  const escape = (val) => {
    if (val === null || val === undefined) return '';
    const str = String(val);
    if (str.includes(',') || str.includes('"') || str.includes('\n') || str.includes('\r')) {
      return '"' + str.replace(/"/g, '""') + '"';
    }
    return str;
  };
  const header = keys.map(escape).join(',');
  const body = rows.map(row => keys.map(k => escape(row[k])).join(',')).join('\n');
  return header + '\n' + body;
}

// ═══════════════════════════════════════════════════════════════
//  Merit-Based Competition System — Leaderboard & Rankings
// ═══════════════════════════════════════════════════════════════

function calculateMemberScore(memberId, periodDays) {
  const now = localNow();
  const modifier = `-${periodDays} days`;

  // Use tasks table consistently for completed/failed/quality counts
  const taskStats = db.prepare(`
    SELECT
      COUNT(CASE WHEN status IN ('completed','delivered') THEN 1 END) as completed,
      COUNT(CASE WHEN status IN ('completed','delivered') AND revision_count = 0 THEN 1 END) as no_revisions
    FROM tasks
    WHERE assigned_to = ? AND updated_at > datetime(?, ?)
  `).get(memberId, now, modifier);

  // Count actual process failures from active_processes
  const processFails = db.prepare(`
    SELECT COUNT(DISTINCT task_id) as c FROM active_processes
    WHERE member_id = ? AND status = 'failed'
    AND completed_at > datetime(?, ?)
  `).get(memberId, now, modifier).c;

  const completed = taskStats.completed || 0;
  const failed = processFails || 0;

  // 1. Success rate (25% weight) — completed / (completed + failed)
  const successRate = (completed + failed) > 0 ? completed / (completed + failed) : 0;

  // 2. Efficiency (20% weight) — tasks completed per day (capped at 1.0)
  const efficiency = Math.min(1, completed / Math.max(periodDays, 1));

  // 3. Quality (20% weight) — how often their work passes review without revision
  const noRevisions = taskStats.no_revisions || 0;
  const qualityRate = completed > 0 ? Math.min(1, noRevisions / completed) : 0;

  // 4. Growth (10% weight) — new knowledge gained
  const newKnowledge = db.prepare(`
    SELECT COUNT(*) as c FROM agent_tacit_knowledge
    WHERE member_id = ? AND created_at > datetime(?, ?)
  `).get(memberId, now, modifier).c;
  const growthScore = Math.min(1, newKnowledge / 10);

  // 5. Escalation handling (5% weight) — successfully resolved escalated tasks
  const escalationsResolved = db.prepare(`
    SELECT COUNT(*) as c FROM tasks
    WHERE assigned_to = ? AND status IN ('completed','delivered')
    AND revision_count > 2
    AND completed_at > datetime(?, ?)
  `).get(memberId, now, modifier).c;
  const escalationScore = Math.min(1, escalationsResolved / 3);

  // 6. Peer review score (15% weight) — average score from peers
  let peerScore = 0.5; // Default 50% if no reviews yet
  try {
    const peerReviews = db.prepare(`
      SELECT AVG(quality_score) as avg_quality, AVG(code_quality) as avg_code, AVG(completeness) as avg_complete, COUNT(*) as review_count
      FROM peer_reviews WHERE author_member_id = ? AND created_at > datetime(?, ?)
    `).get(memberId, now, modifier);
    if (peerReviews && peerReviews.review_count > 0) {
      peerScore = ((peerReviews.avg_quality + peerReviews.avg_code + peerReviews.avg_complete) / 15); // Normalize 3-15 to 0-1
    }
  } catch (_) {}

  // 7. Reviewer reputation (5% weight) — how good are they at reviewing others?
  let reviewerScore = 0.5; // Default 50% if no reviews given
  try {
    const reviewsGiven = db.prepare(`
      SELECT COUNT(*) as total,
        SUM(CASE WHEN verdict = 'reject' AND (SELECT status FROM tasks WHERE id = peer_reviews.task_id) IN ('completed','delivered') THEN 1 ELSE 0 END) as false_rejects
      FROM peer_reviews WHERE reviewer_member_id = ? AND created_at > datetime(?, ?)
    `).get(memberId, now, modifier);
    if (reviewsGiven && reviewsGiven.total > 0) {
      reviewerScore = Math.max(0, 1 - ((reviewsGiven.false_rejects || 0) / reviewsGiven.total)); // Penalize false rejects
    }
  } catch (_) {}

  const overall = (successRate * 0.25) + (efficiency * 0.20) + (qualityRate * 0.20) + (peerScore * 0.15) + (growthScore * 0.10) + (reviewerScore * 0.05) + (escalationScore * 0.05);

  return {
    completed, failed,
    successRate: Math.round(successRate * 100),
    efficiency: Math.round(efficiency * 100) / 100,
    qualityRate: Math.round(qualityRate * 100),
    growthScore: Math.round(growthScore * 100),
    escalationScore: Math.round(escalationScore * 100),
    peerScore: Math.round(peerScore * 100),
    reviewerScore: Math.round(reviewerScore * 100),
    overall: Math.round(overall * 10000) / 100
  };
}

