// GET /api/peer-reviews — list all reviews (supports ?member_id=&task_id=)
app.get('/api/peer-reviews', (req, res) => {
  try {
    let query = `
      SELECT pr.*,
        ta.name as author_name, ta.role as author_role,
        tr.name as reviewer_name, tr.role as reviewer_role
      FROM peer_reviews pr
      LEFT JOIN team_members ta ON pr.author_member_id = ta.id
      LEFT JOIN team_members tr ON pr.reviewer_member_id = tr.id
      WHERE 1=1
    `;
    const params = [];
    if (req.query.member_id) {
      query += ' AND (pr.author_member_id = ? OR pr.reviewer_member_id = ?)';
      params.push(parseInt(req.query.member_id), parseInt(req.query.member_id));
    }
    if (req.query.task_id) {
      query += ' AND pr.task_id = ?';
      params.push(parseInt(req.query.task_id));
    }
    if (req.query.author_id) {
      query += ' AND pr.author_member_id = ?';
      params.push(parseInt(req.query.author_id));
    }
    if (req.query.reviewer_id) {
      query += ' AND pr.reviewer_member_id = ?';
      params.push(parseInt(req.query.reviewer_id));
    }
    query += ' ORDER BY pr.created_at DESC LIMIT 100';
    const reviews = db.prepare(query).all(...params);
    res.json(reviews);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/peer-reviews/stats — aggregate stats per member
app.get('/api/peer-reviews/stats', (req, res) => {
  try {
    // Reviews received (as author)
    const received = db.prepare(`
      SELECT pr.author_member_id as member_id, tm.name,
        COUNT(*) as reviews_received,
        ROUND(AVG(pr.quality_score), 1) as avg_quality,
        ROUND(AVG(pr.code_quality), 1) as avg_code_quality,
        ROUND(AVG(pr.completeness), 1) as avg_completeness,
        SUM(CASE WHEN pr.verdict = 'approve' THEN 1 ELSE 0 END) as approvals,
        SUM(CASE WHEN pr.verdict = 'reject' THEN 1 ELSE 0 END) as rejections,
        SUM(CASE WHEN pr.verdict = 'needs_changes' THEN 1 ELSE 0 END) as needs_changes
      FROM peer_reviews pr
      LEFT JOIN team_members tm ON pr.author_member_id = tm.id
      GROUP BY pr.author_member_id
      ORDER BY reviews_received DESC
    `).all();

    // Reviews given (as reviewer)
    const given = db.prepare(`
      SELECT pr.reviewer_member_id as member_id, tm.name,
        COUNT(*) as reviews_given,
        SUM(CASE WHEN pr.verdict = 'reject' AND (SELECT status FROM tasks WHERE id = pr.task_id) IN ('completed','delivered') THEN 1 ELSE 0 END) as false_rejects,
        SUM(CASE WHEN pr.verdict = 'approve' THEN 1 ELSE 0 END) as approved,
        SUM(CASE WHEN pr.verdict = 'reject' THEN 1 ELSE 0 END) as rejected,
        SUM(CASE WHEN pr.verdict = 'needs_changes' THEN 1 ELSE 0 END) as requested_changes
      FROM peer_reviews pr
      LEFT JOIN team_members tm ON pr.reviewer_member_id = tm.id
      GROUP BY pr.reviewer_member_id
      ORDER BY reviews_given DESC
    `).all();

    res.json({ received, given });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/peer-reviews/:taskId — reviews for a specific task
app.get('/api/peer-reviews/:taskId', (req, res) => {
  try {
    const reviews = db.prepare(`
      SELECT pr.*,
        ta.name as author_name, ta.role as author_role,
        tr.name as reviewer_name, tr.role as reviewer_role
      FROM peer_reviews pr
      LEFT JOIN team_members ta ON pr.author_member_id = ta.id
      LEFT JOIN team_members tr ON pr.reviewer_member_id = tr.id
      WHERE pr.task_id = ?
      ORDER BY pr.created_at DESC
    `).all(parseInt(req.params.taskId));
    res.json(reviews);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── Business Overview Dashboard ─────────────────────────────────────
app.get('/api/business/overview', (req, res) => {
  try {
    const now = localNow();

    // Revenue/spending
    const spending = {
      this_month: (db.prepare("SELECT COALESCE(SUM(cost_cents),0) as c FROM cost_events WHERE strftime('%Y-%m',created_at) = strftime('%Y-%m',?)").get(now) || {}).c || 0,
      last_month: (db.prepare("SELECT COALESCE(SUM(cost_cents),0) as c FROM cost_events WHERE strftime('%Y-%m',created_at) = strftime('%Y-%m',datetime(?,'-1 month'))").get(now) || {}).c || 0,
      daily: db.prepare("SELECT date(created_at) as day, SUM(cost_cents) as total FROM cost_events WHERE created_at > datetime(?,'-30 days') GROUP BY day ORDER BY day").all(now)
    };

    // Budget
    const budget = db.prepare("SELECT * FROM budget_policies WHERE scope='global' AND status='active' LIMIT 1").get() || {};

    // Projects as "business units"
    let projects = [];
    try {
      projects = db.prepare(`
        SELECT p.*, pe.member_id as exec_id, tm.name as exec_name,
            (SELECT COUNT(*) FROM tasks t JOIN project_tasks pt ON pt.task_id = t.id WHERE pt.project_id = p.id AND t.status IN ('completed','delivered')) as completed_tasks,
            (SELECT COUNT(*) FROM tasks t JOIN project_tasks pt ON pt.task_id = t.id WHERE pt.project_id = p.id AND t.status = 'in_progress') as active_tasks,
            (SELECT COALESCE(SUM(ce.cost_cents),0) FROM cost_events ce JOIN tasks t ON ce.task_id = t.id JOIN project_tasks pt ON pt.task_id = t.id WHERE pt.project_id = p.id) as project_cost
        FROM projects p
        LEFT JOIN project_executives pe ON pe.project_id = p.id
        LEFT JOIN team_members tm ON pe.member_id = tm.id
        WHERE p.status = 'active'
      `).all();
    } catch (e) { /* projects query may fail if tables don't exist yet */ }

    // Team utilization
    const totalSpecialists = (db.prepare("SELECT COUNT(*) as c FROM team_members WHERE status='active' AND tier='specialist'").get() || {}).c || 0;
    const activeSpecialists = (db.prepare("SELECT COUNT(DISTINCT member_id) as c FROM active_processes WHERE status='running'").get() || {}).c || 0;
    const utilization = Math.round((activeSpecialists / Math.max(totalSpecialists, 1)) * 100);

    // Task throughput
    const tasksThisWeek = (db.prepare("SELECT COUNT(*) as c FROM tasks WHERE status IN ('completed','delivered') AND completed_at > datetime(?,'-7 days')").get(now) || {}).c || 0;
    const tasksLastWeek = (db.prepare("SELECT COUNT(*) as c FROM tasks WHERE status IN ('completed','delivered') AND completed_at BETWEEN datetime(?,'-14 days') AND datetime(?,'-7 days')").get(now, now) || {}).c || 0;

    // Top expense categories (by department)
    let topExpenses = [];
    try {
      topExpenses = db.prepare(`
        SELECT tm.department, COALESCE(SUM(ce.cost_cents),0) as total
        FROM cost_events ce
        JOIN team_members tm ON ce.member_id = tm.id
        WHERE ce.created_at > datetime(?,'-30 days')
        GROUP BY tm.department
        ORDER BY total DESC LIMIT 6
      `).all(now);
    } catch (e) { /* may fail if no cost events */ }

    // Improvement pipeline as "operations"
    const improvements = {
      completed: (db.prepare("SELECT COUNT(*) as c FROM improvement_proposals WHERE status='completed'").get() || {}).c || 0,
      queued: (db.prepare("SELECT COUNT(*) as c FROM improvement_proposals WHERE status IN ('queued','proposed','approved')").get() || {}).c || 0,
      in_progress: (db.prepare("SELECT COUNT(*) as c FROM improvement_proposals WHERE status='in_progress'").get() || {}).c || 0
    };

    // Governance health
    const govHealth = db.prepare("SELECT status, score FROM governance_health ORDER BY id DESC LIMIT 1").get() || { status: 'unknown', score: 0 };

    // Governance receipts count
    let receiptsCount = 0;
    try {
      receiptsCount = (db.prepare("SELECT COUNT(*) as c FROM governance_receipts").get() || {}).c || 0;
    } catch (e) { /* table may not exist */ }

    res.json({
      spending,
      budget,
      projects,
      team: { total: totalSpecialists, active: activeSpecialists, utilization },
      throughput: { this_week: tasksThisWeek, last_week: tasksLastWeek, change: tasksThisWeek - tasksLastWeek },
      top_expenses: topExpenses,
      improvements,
      governance: { ...govHealth, receipts: receiptsCount },
      timestamp: now
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

