// ── 404 handler for unmatched API routes ─────────────────────────
// Must be registered AFTER all API routes and BEFORE the global error
// boundary. Without this, unmatched /api/* requests fall through to
// express.static which serves HTML — callers get a page instead of JSON.
app.use('/api', (req, res) => {
  res.status(404).json({
    error: `API endpoint not found: ${req.method} ${req.path}`,
    status: 404,
    timestamp: new Date().toISOString(),
  });
});

// ── Global Error Boundary ─────────────────────────────────────────
// Catches any error passed to next(err) or thrown in async route
// handlers that propagate to Express. Returns structured JSON so
// clients always get a machine-readable response instead of an HTML
// stack trace. Must be registered AFTER all routes (4-parameter
// signature is required by Express to recognise it as an error handler).
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  const status = err.status || err.statusCode || 500;
  const isServerError = status >= 500;

  if (isServerError) {
    logger.error(`[error-boundary] ${req.method} ${req.path} → ${status}: ${err.message}`, {
      stack: err.stack,
    });
  } else {
    logger.warn(`[error-boundary] ${req.method} ${req.path} → ${status}: ${err.message}`);
  }

  // Never expose internal stack traces to clients in production.
  const body = {
    error: err.message || 'Internal Server Error',
    status,
    timestamp: new Date().toISOString(),
  };
  if (process.env.NODE_ENV !== 'production' && err.stack) {
    body.stack = err.stack;
  }

  res.status(status).json(body);
});

