// ── Graceful Shutdown ────────────────────────────────────────────
// Intercepts SIGTERM/SIGINT, drains in-flight HTTP requests, flushes
// the SQLite WAL, then closes the DB and exits cleanly.
// Force-exits after 10 s if anything is still hanging.

function gracefulShutdown(signal) {
  if (isShuttingDown) return;
  isShuttingDown = true;
  console.info(`[Shutdown] ${signal} received — starting graceful shutdown`);

  // Stop accepting new connections immediately (existing keep-alive
  // sockets remain open until their in-flight request finishes).
  server.close((serverCloseErr) => {
    if (serverCloseErr) console.error('[Shutdown] HTTP server close error:', serverCloseErr.message);
    else console.info('[Shutdown] HTTP server closed (no new connections accepted)');
  });

  // Kill all spawned member processes
  for (const [id, info] of runningProcesses) {
    try {
      info.child.kill('SIGTERM');
    } catch {}
  }
  runningProcesses.clear();

  // Mark all running processes as killed in DB
  try {
    db.prepare(`UPDATE active_processes SET status = 'killed', completed_at = datetime('now', 'localtime'), output_summary = 'Server shutdown' WHERE status = 'running'`).run();
  } catch {}

  // Terminate all open WebSocket client connections so wss.close() resolves promptly
  for (const client of wss.clients) {
    try { client.terminate(); } catch {}
  }

  // Flush WAL writes and close DB, then exit.
  function finalizeShutdown() {
    // Checkpoint and truncate WAL so all committed writes land in the main DB
    // file before we close — prevents data loss on abrupt restarts.
    try { db.pragma('wal_checkpoint(TRUNCATE)'); } catch {}

    // Close WebSocket server — callback fires once all clients are gone
    wss.close(() => {
      try {
        db.close();
        console.info('[Shutdown] Database closed cleanly');
      } catch (e) {
        console.error('[Shutdown] Database close error:', e.message);
      }
      process.exit(0);
    });
  }

  // Drain in-flight requests before flushing DB.  The middleware at the top
  // of the file increments/decrements activeRequestCount on each request, and
  // already gates new requests with 503 once isShuttingDown is true.
  if (activeRequestCount === 0) {
    console.info('[Shutdown] No in-flight requests — finalizing immediately');
    finalizeShutdown();
  } else {
    console.info(`[Shutdown] Waiting for ${activeRequestCount} in-flight request(s) to complete...`);
    const poll = setInterval(() => {
      if (activeRequestCount === 0) {
        clearInterval(poll);
        console.info('[Shutdown] All in-flight requests completed — finalizing');
        finalizeShutdown();
      }
    }, 100);
  }

  // Force-exit safety net after 10 seconds in case something hangs
  const forceExit = setTimeout(() => {
    console.error('[Shutdown] Graceful shutdown timed out after 10 s — forcing exit');
    process.exit(1);
  }, 10_000);
  // Unref so this timer doesn't prevent natural exit if everything closes cleanly
  forceExit.unref();
}

process.on('SIGINT', () => gracefulShutdown('SIGINT'));
process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
